gameforge.dragon_soul = {}
gameforge.dragon_soul._010_sayTitle = "Od\179amek Smoczego Kamienia+?! "
gameforge.dragon_soul._020_say = "W twojej d\179oni spoczywa fragment kamienia. Mieni[ENTER]si\234 on dziwnym blaskiem, a ty czujesz jak[ENTER]przepe\179nia ci\234 jego moc.[ENTER]C\243\191 to za tajemniczy kamie\241? Zanie\156 go do[ENTER]alchemika. Na pewno b\234dzie w stanie ci pom\243c. "
gameforge.dragon_soul._030_npcChat = "Od\179amek Smoczego Kamienia+?! "
gameforge.dragon_soul._040_say = "Jest to fragment Smoczego Kamienia, bardzo[ENTER]rzadkiego i cennego kryszta\179u o niebywa\179ej mocy.[ENTER]M\243wi si\234, \191e drzemie w nim dusza smoka. Ach,[ENTER]jakie to pi\234kne![ENTER]Czujesz, jak przepe\179nia ci\234 jego moc?[ENTER]Przynie\156 mi \179\185cznie dziesi\234\230 takich fragment\243w, a[ENTER]zespol\234 je w jeden kamie\241. "
gameforge.dragon_soul._050_npcChat = "Transmutacja Smoczego Kamienia "
gameforge.dragon_soul._060_say = "Nie tak chy\191o. Potrzebuj\234 dziesi\234ciu od\179amk\243w,[ENTER]aby po\179\185czy\230 je w Smoczy Kamie\241.[ENTER]Kontynuuj poszukiwania! "
gameforge.dragon_soul._070_say = "Aaa, \156wietnie! Uda\179o ci si\234 znale\159\230 dziesi\234\230[ENTER]Od\179amk\243w Smoczego Kamienia. Poczekaj chwilk\234.[ENTER]...[ENTER]Uda\179o si\234! Niesamowite... w wyniku transmutacji[ENTER]powsta\179o Cor Draconis, kryszta\179owe smocze serce,[ENTER]kt\243re otula smoczy kamie\241.[ENTER]Musisz wpierw rozbi\230, aby si\234 przekona\230, jaki[ENTER]znajduje si\234 w \156rodku kamie\241. Natychmiast[ENTER]zostanie on dodany do ekwipunku alchemii Smoczych[ENTER]Kamieni.[ENTER]Pami\234taj, \191e Smocze Kamienie mo\191na uszlachetnia\230. "
gameforge.dragon_soul._080_say = "Chcesz jeszcze jedno Cor Draconis?[ENTER]C\243\191, nie jestem ju\191 m\179odzikiem a fuzja tak[ENTER]skomplikowanego przedmiotu wymaga wielkiego[ENTER]wysi\179ku.[ENTER]Ale dla ciebie mog\234 si\234 nieco po\156wi\234ci\230.[ENTER]Pami\234taj jednak, \191e wi\234cej ni\191 dziesi\234\230 sztuk[ENTER]dziennie nie wchodzi w rachub\234! "
gameforge.dragon_soul._090_say = "Na dzisiaj ju\191 wystarczy. Wi\234cej ni\191 dziesi\234\230 Cor[ENTER]Draconis na dzie\241 jest ponad moje si\179y.[ENTER]Jestem wycie\241czony i musz\234 troch\234 odpocz\185\230.[ENTER]Przyjd\159 ponownie jutro. "
gameforge.dragon_soul._100_npcChat = "Otw\243rz sklep "
gameforge.dragon_soul._1010_sendLetter = "Przybycie Od\179amka Smoczego Kamienia "
gameforge.dragon_soul._1020_say = "Szuka ci\234 alchemik, posiadaj\185cy dog\179\234bn\185 wiedz\234 o[ENTER]minera\179ach w ca\179ym kraju. Id\159 szybko do niego. "
gameforge.dragon_soul._1030_npcChat = "Od\179amek Smoczego Kamienia+?! "
gameforge.dragon_soul._1040_say = "Ach, jeste\156! Odkry\179em co\156 niesamowitego: fragment[ENTER]smoczego kamienia! Smoczy Kamie\241 to bardzo rzadki[ENTER]i drogocenny klejnot, posiadaj\185cy ogromn\185 moc.[ENTER]Zwany jest te\191 Dusz\185 Smoka. Niesamowicie pi\234kny![ENTER]Obdarz\234 ci moc\185 Smoczego Oka, aby\156 m\243g\179 odnale\159\230[ENTER]od\179amki.[ENTER]Przynie\156 mi \179\185cznie 10 od\179amk\243w Smoczego[ENTER]Kamienia.A ja zrobi\234 z tego ca\179y kamie\241. "
gameforge.dragon_soul._1050_sendLetter = "Zbieraj Od\179amki Smoczego Kamienia "
gameforge.dragon_soul._1060_say = "Zanie\156 alchemikowi 10 Od\179amk\243w Smoczego Kamienia. "
gameforge.dragon_soul._1070_say = "Aaa, \156wietnie! Uda\179o ci si\234 znale\159\230 dziesi\234\230[ENTER]Od\179amk\243w Smoczego Kamienia. Poczekaj chwilk\234...[ENTER]Niesamowite! W wyniku transmutacji powsta\179o Cor[ENTER]Draconis, kryszta\179owe smocze serce, kt\243re otula[ENTER]Smoczy Kamie\241.[ENTER]Gdy je rozbijesz, Smoczy Kamie\241 natychmiast[ENTER]zostanie on dodany do ekwipunku Alchemii Smoczych[ENTER]Kamieni.[ENTER]Aby odnale\159\230 i po\179\185czy\230 Od\179amki Smoczego[ENTER]Kamienia, potrzebujesz mocy Smoczego Oka. Raz[ENTER]dziennie mog\234 ci\234 obdarzy\230 t\185 moc\185.[ENTER]Stworzy\179em ju\191 dla ciebie jeden Smoczy Kamie\241.[ENTER]Pozosta\179e %d zrobisz sam. "
gameforge.dragon_soul._1080_say = "Hej, nie marnuj czasu! Lepiej id\159 i poszukaj[ENTER]Od\179amk\243w Smoczego Kamienia! "
gameforge.dragon_soul._1090_sendLetter = "Moc Smoczego Oka "
gameforge.dragon_soul._1100_say = "Pozosta\179a Moc Smoczego Oka: %d "
gameforge.dragon_soul._110_say = "Wybierz "
gameforge.dragon_soul._1110_notice = "Nie ma wi\234cej od\179amk\243w smoczego kamienia+. "
gameforge.dragon_soul._1120_npcChat = "Obdarz mnie Moc\185 Smoczego Oka "
gameforge.dragon_soul._1130_say = "Witaj! Otrzyma\179e\156 ju\191 dzisiaj Moc Smoczego Oka.[ENTER]Ta czynno\156\230 bardzo mnie os\179abia i dlatego mog\234[ENTER]ci\234 obdarza\230 moc\185 tylko raz na dzie\241. Przyjd\159[ENTER]jutro! "
gameforge.dragon_soul._1140_say = "Witaj! Mog\234 si\234 za\179o\191y\230, \191e przyszed\179e\156 z powodu[ENTER]Mocy Smoczego Oka. Mam racj\234? A wi\234c dobrze,[ENTER]prosz\234, oto ona. Powodzenia podczas poszukiwa\241![ENTER]Mam nadziej\234, \191e znajdziesz wystarczaj\185c\185 ilo\156\230[ENTER]od\179amk\243w, aby stworzy\230 10 Smoczych Kamieni! "
gameforge.dragon_soul._1150_sendLetter = "Brakuje Mocy Smoczego Oka "
gameforge.dragon_soul._1160_say = "Opu\156ci\179a ci\234 Moc Smoczego Oka "
gameforge.dragon_soul._1170_say = "Wr\243\230 jutro do alchemika, aby odebra\230 Moc Smoczego[ENTER]Oka! "
gameforge.dragon_soul._1180_say = "Udaj si\234 do alchemika, aby odebra\230 Moc Smoczego[ENTER]Oka! "
