gameforge.energy_system = {}
gameforge.energy_system._001_npcChat = "Nowa technika! "
gameforge.energy_system._010_say = "Nareszcie![ENTER]Uda\179o mi si\234 opracowa\230 zupe\179nie now\185 technik\234.[ENTER]Za jej pomoc\185 mog\234 demontowa\230 przedmioty,[ENTER]ekstrahuj\185c z nich diametralnie czyst\185 energi\234.[ENTER]Jestem geniuszem! "
gameforge.energy_system._020_say = "Demontuj\185c przedmiot za pomoc\185 mojej techniki,[ENTER]otrzymasz od\179amek energii. Z\179\243\191 30 takich[ENTER]od\179amk\243w, a powstanie z nich pot\234\191ny kryszta\179[ENTER]energii - diametralnie czysta energia skupiona w[ENTER]jednym klejnocie. Moc ta przeniesie si\234 na twoje[ENTER]ca\179e uzbrojenie.[ENTER]Brzmi nie\159le, co? "
gameforge.energy_system._030_say = "Przyno\156 mi bro\241, bi\191uteri\234, zbroj\234 i inne cz\234\156ci[ENTER]uzbrojenia, a ja zamieni\234 je w od\179amki energii.[ENTER]Ta technika to przysz\179o\156\230 naszego imperium![ENTER]B\234dziemy niezwyci\234\191eni! "
gameforge.energy_system._035_npcChat = "Ekstrahuj od\179amki energii "
gameforge.energy_system._040_say = "I jak? Zadzia\179a\179o? Masz ju\191 od\179amek energii?[ENTER]Przynie\156 mi wi\234cej przedmiot\243w, a ja zdemontuje[ENTER]je za pomoc\185 mojej alchemii.[ENTER]Wiedz jednak, \191e ta technika nie jest jeszcze[ENTER]udoskonalona. Dlatego te\191 nie mog\234 ci powiedzie\230,[ENTER]ile od\179amk\243w otrzymasz za dany przedmiot. "
gameforge.energy_system._050_say = "Jest jeden warunek: zar\243wno tw\243j poziom jak i[ENTER]poziom przedmiotu musi by\230 co najmniej 35.[ENTER]Hmm, zobaczmy... "
gameforge.energy_system._060_say = "Musisz jeszcze nieco potrenowa\230! Wr\243\230, gdy[ENTER]osi\185gniesz co najmniej poziom 35. "
gameforge.energy_system._070_say = "Ach, \156wietnie! Widz\234, \191e posiadasz ju\191[ENTER]wystarczaj\185c\185 ilo\156\230 do\156wiadczenia. Daj mi[ENTER]przedmiot, kt\243ry mam zdemontowa\230. "
gameforge.energy_system._080_say = "Nie masz jeszcze wystarczaj\185co du\191o mocy, aby[ENTER]kontrolowa\230 magi\234 drzemi\185c\185 w od\179amkach energii.[ENTER]Wr\243\230 do mnie, gdy osi\185gniesz co najmniej poziom[ENTER]35. "
gameforge.energy_system._090_say = "Ten przedmiot nie nadaje si\234 do demonta\191u za[ENTER]pomoc\185 mojej techniki. Daj mi co\156 innego. "
gameforge.energy_system._100_say = "Ten przedmiot nie posiada zbyt wiele energii. Daj[ENTER]mi przedmiot o poziomie 35 lub wy\191szym, je\156li[ENTER]chcesz, abym u\191y\179 swojej techniki. "
gameforge.energy_system._110_say = "Chcesz, aby zdemontowa\179 ten przedmiot? "
gameforge.energy_system._120_select = "Tak "
gameforge.energy_system._130_select = "Nie, jeszcze nie! "
gameforge.energy_system._140_say = "Ech, niestety nie uda\179o mi si\234 ekstrahowa\230[ENTER]od\179amku energii. By\230 mo\191e uda si\234 nast\234pnym[ENTER]razem. "
gameforge.energy_system._150_say = "Fantastycznie! Uda\179o mi si\234 ekstrahowa\230 %d x[ENTER]od\179amek energii.[ENTER]Prosz\234 bardzo! "
gameforge.energy_system._160_npcChat = "Z\179\243\191 kryszta\179 energii "
gameforge.energy_system._170_say = "Powoli opadasz ju\191 z si\179, co? Nie pracuj tak[ENTER]ostro, bo przyp\179acisz to kiedy\156 \191yciem. Aby[ENTER]stworzy\230 kryszta\179 energii, potrzebuje %d x[ENTER]od\179amek energii. "
gameforge.energy_system._180_say = "Nie posiadasz jeszcze wystarczaj\185cej ilo\156ci[ENTER]od\179amk\243w energii, aby z\179o\191y\230 z nich kryszta\179[ENTER]energii.[ENTER]Wr\243\230, gdy b\234dziesz w posiadaniu co najmniej %d x[ENTER]od\179amek energii. "
gameforge.energy_system._190_say = "\140wietnie, widz\234, \191e masz ju\191 %d x od\179amek[ENTER]energii. W takim razie mog\234 z nich stworzy\230[ENTER]kryszta\179 energii. Zaczekaj chwilk\234. Spr\243buj\234, ale[ENTER]nie gwarantuj\234, \191e si\234 uda. "
gameforge.energy_system._200_say = "Wszystko ju\191 gotowe. Mo\191emy przetopi\230 od\179amki na[ENTER]kryszta\179 energii.[ENTER]No ale ja sam musz\234 przecie\191 z czego\156 \191y\230,[ENTER]prawda? Ten wyj\185tkowy zabieg wyniesie ci\234 %d[ENTER]Yang. Zap\179acisz tyle? "
gameforge.energy_system._210_select = "Oczywi\156cie. "
gameforge.energy_system._220_select = "Nie, nie teraz. "
gameforge.energy_system._230_say = "Dobrze, szanuj\234 twoj\185 decyzj\234.[ENTER]Wr\243\230, je\156li si\234 rozmy\156lisz i b\234dziesz potrzebowa\230[ENTER]kryszta\179u energii. "
gameforge.energy_system._240_say = "Przykro mi, ale wpierw musisz zap\179aci\230. Nie[ENTER]jestem przecie\191 organizacj\185 charytatywn\185.[ENTER]Interes to interes - za us\179ugi trzeba p\179aci\230. "
gameforge.energy_system._250_say = "Prosz\234, oto tw\243j kryszta\179 energii. Ale tylko[ENTER]pierwsze podej\156cie zawsze si\234 udaj\234. Alchemia to[ENTER]bardzo nieobliczalna dziedzina nauki. Zawsze[ENTER]zatem istnieje pewne prawdopodobie\241stwo, \191e[ENTER]eksperyment nie wypali. "
gameforge.energy_system._260_say = "No niestety, nie uda\179o si\234 mi si\234 stworzy\230[ENTER]kryszta\179u energii. Moja technika jest genialna,[ENTER]ale niestety jeszcze niedopracowana. Tak to ju\191[ENTER]jest z alchemi\185.[ENTER]Nast\234pnym razem na pewno si\234 uda! "
gameforge.energy_system._270_say = "Wiedzia\179em! Moja technika jest genialna![ENTER]Oto tw\243j kryszta\179 energii.[ENTER]Niez\179e cacko, co? Czujesz t\234 pulsuj\185c\185 energi\234? "
