gameforge.fortune_telling = {}
gameforge.fortune_telling._100_sayTitle = "Starsza Pani "
gameforge.fortune_telling._10_npcChat = "S\179ysza\179em, \191e jeste\156 Wr\243\191k\185. "
gameforge.fortune_telling._110_say = "Jeste\156 za m\179ody by oddycha\230 tak g\179\234boko![ENTER]Czy chcesz pozna\230 swoj\185 przysz\179o\156\230, przeczytan\185[ENTER]przez mistyczn\185 si\179\234? Powiniene\156 wiedzie\230, \191e[ENTER]istniej\185 moce, kt\243re s\185 w stanie odpowiedzie\230 Ci[ENTER]na najtrudniejsze pytania. "
gameforge.fortune_telling._120_select = "Powiedz mi "
gameforge.fortune_telling._130_select = "Nie chc\234 wiedzie\230... "
gameforge.fortune_telling._140_say = "Dobrze. Pod\185\191a\230 swoj\185 w\179asn\185 drog\185 i dawa\230 z[ENTER]siebie wszystko to najwa\191niejsza rzecz w \191yciu.[ENTER]Powodzenia! "
gameforge.fortune_telling._150_select = "Tak, chcia\179bym. "
gameforge.fortune_telling._160_select = "Nie, dzi\234ki. "
gameforge.fortune_telling._170_say = "Mog\234 by\230 przyjazna, ale nie mog\234 rozdawa\230 ich za[ENTER]darmo. Je\191eli chcesz unikn\185\230 z\179ego losu i[ENTER]nieszcz\234\156cia, b\234dziesz musia\179 zap\179aci\230 mi za ten[ENTER]Amulet Karmy.[ENTER]Amulet Karmy kosztuje %s Yang. "
gameforge.fortune_telling._180_say = "Odchodzisz? Prawdopodobnie masz racj\234. Z\179y los i[ENTER]smutek to cz\234\156\230 naszego \191ycia. Powodzenia i[ENTER]\191egnaj! Je\191eli zmienisz zdanie, wr\243\230. "
gameforge.fortune_telling._20_say = "Twoja twarz m\243wi mi, \191e nie by\179e\156 w okolicy zbyt[ENTER]d\179ugo... Dlaczego chcesz pozna\230 swoj\185 przysz\179o\156\230[ENTER]tak szybko? Czy masz jakie\156 problemy? Twoja[ENTER]przysz\179o\156\230 nie jest jeszcze mi znana...[ENTER]Prosz\234, przyjd\159 p\243\159niej. "
gameforge.fortune_telling._30_say = "Czy na pewno chcesz prze\191y\230 ca\179e swoje \191ycie[ENTER]s\179uchaj\185c rad Wr\243\191ki? Nigdy nie powiniene\156 bra\230[ENTER]wr\243\191b na serio. Najwa\191niejsz\185 rzecz\185 to by\230 po[ENTER]prostu sob\185. Je\191eli stosujesz si\234 do tej zasady[ENTER]wszystko b\234dzie dobrze. Je\191eli nadal b\234dziesz[ENTER]chcia\179 pozna\230 swoj\185 przysz\179o\156\230, przyjd\159 jutro. "
gameforge.fortune_telling._40_sayTitle = "Starsza Pani "
gameforge.fortune_telling._50_say = "Jak ju\191 ci powiedzia\179am, twoja przepowiednia na[ENTER]dzisiaj brzmi nast\234puj\185co: "
gameforge.fortune_telling._60_say = "B\234dziesz nieszcz\234\156liwy i nie kupi\179e\156 jeszcze[ENTER]swojego Talizmanu przeciw z\179u... Czy przypadkiem[ENTER]nie chcia\179by\156 kupi\230 takiego Talizmanu? "
gameforge.fortune_telling._70_select = "Tak, kupuj\234. "
gameforge.fortune_telling._80_select = "Nie, dzi\234ki! "
gameforge.fortune_telling._90_say = "Mog\234 by\230 przyjazna, ale nie mog\234 tego rozdawa\230 za[ENTER]darmo. Je\191eli chcesz unikn\185\230 z\179ego losu i[ENTER]nieszcz\234\156cia, musisz zap\179aci\230 za Talizman. "
