gameforge.ghost_story = {}
gameforge.ghost_story._010_sayTitle = "Duch Sura: "
gameforge.ghost_story._020_npcChat = "Jeste\156 duchem? "
gameforge.ghost_story._030_say = "Nie, jestem Twoj\185 babci\185... Pewnie, \191e jestem[ENTER]duchem! Wysoki jak brzoza, a g\179upi jak koza! "
gameforge.ghost_story._040_npcChat = "Pomocy! Duch! "
gameforge.ghost_story._050_say = "Popatrz, co za nieustraszony wojownik! Eh!! "
gameforge.ghost_story._060_npcChat = "Kim jeste\156? "
gameforge.ghost_story._070_say = "Nazywam si\234 Akuma. Niegdy\156 by\179em wielkim[ENTER]wojownikiem, m\243wiono nawet, \191e by\179em najlepszym.[ENTER]Wierzy\179em w to, \191e jestem kim\156 wyj\185tkowym! A[ENTER]teraz sp\243jrz na mnie, co pozosta\179o po[ENTER]odnalezieniu groty... i zgin\234\179o. "
gameforge.ghost_story._080_npcChat = "Znasz histori\234 tego miejsca? "
gameforge.ghost_story._090_say = "O tak, wiem dok\179adnie co si\234 wtedy wydarzy\179o.[ENTER]Kiedy jeszcze \191y\179em prowadzi\179em d\179ugie badania,[ENTER]by odkry\230 przyczyny i odnale\159\230 grot\234. A po mojej[ENTER]\156mierci mia\179em sporo czasu na rozmy\156lanie o tym.[ENTER]Powiedz mi, co ci\234 interesuje! "
gameforge.ghost_story._100_npcChat = "Co to za portal? "
gameforge.ghost_story._110_say = "Portal ten prowadzi do jaskini mrocznego smoka,[ENTER]upad\179ego boga Beran-Setaou. Uaktywni\230 mo\191na go za[ENTER]pomoc\185 magicznego klucza, kt\243ry otrzymuj\185 jedynie[ENTER]przyw\243dcy jednostek Beran-Setaou... "
gameforge.ghost_story._120_npcChat = "Trzej Bogowie "
gameforge.ghost_story._130_say = "Niegdy\156 boskie rodze\241stwo tworzy\179o filar[ENTER]istnienia. Bahar-Taraji, Bogini Stworzenia, by\179a[ENTER]najm\179odsza z tr\243jki rodze\241stwa. Jej zadaniem by\179o[ENTER]stwarzanie \191ycia - gdzie si\234 tylko pojawi\179a[ENTER]kie\179kowa\179y kwiaty i rozwija\179o si\234 bujne \191ycie. "
gameforge.ghost_story._140_say = "Najstarszy brat nazywa\179 si\234 Beran-Setaou. By\179 on[ENTER]odpowiedzialny za koniec i rozk\179ad. Gdy tylko[ENTER]cykl \191ycia zbli\191a\179 ku ko\241cowi, rozdziela\179 on[ENTER]cia\179o od duszy i kierowa\179 j\185 w za\156wiaty.[ENTER]Tak oto \191ycie toczy\179o si\234 swoim rytmem - narodzin[ENTER]i przemijania - i tak by\179y zachowane podstawy[ENTER]\191ycia wszystkich istot. "
gameforge.ghost_story._150_say = "Drugi z braci to Baljit-Elvedin, B\243g Ochrony i[ENTER]R\243wnowagi po\156redniczy\179 on mi\234dzy swoim[ENTER]rodze\241stwem i zapewnia\179 istotom ziemskim[ENTER]nieprzerwany cykl \191ycia. Do jego obowi\185zk\243w[ENTER]nale\191a\179o np. czuwanie nad przemijaniem p\243r roku. "
gameforge.ghost_story._160_npcChat = "K\179\243tnia "
gameforge.ghost_story._170_say = "Ludzie modlili si\234 \191arliwie do Bog\243w i b\179agali o[ENTER]pomoc. Lecz nie wszystkim oddawali nale\191n\185 cze\156\230.[ENTER]Ju\191 na sam\185 my\156l o Beran-Setaou ogarnia\179 ich[ENTER]strach. Nie mogli zrozumie\230, \191e jest on[ENTER]niezb\234dnym elementem do zachowania odpowiedniego[ENTER]cyklu \191ycia. Tak jak \156wiat\179o i cie\241, tak te\191[ENTER]musz\185 egzystowa\230 narodziny i \156mier\230. "
gameforge.ghost_story._180_say = "Przez d\179ugi czas b\243g wybacza\179 to ludziom, jednak[ENTER]z czasem zazdro\156\230, kt\243ra ros\179a w Beran-Setaou,[ENTER]przemieni\179a si\234 w z\179o i nienawi\156\230. W ko\241cu zes\179a\179[ENTER]plag\234 chor\243b i krwawych wojen. Ludzie jednak[ENTER]ogarni\234ci \156mierteln\185 trwog\185 ca\179kowicie odwr\243cili[ENTER]si\234 od rozgniewanego Beran-Setaou i szukali[ENTER]pomocy u Bahar-Taraji, bogini nowego \191ycia. Tak[ENTER]oto powsta\179o b\179\234dnie ko\179o, kt\243re doprowadzi\179o do[ENTER]zguby. "
gameforge.ghost_story._190_say = "A\191 w ko\241cu gniew b\243stwa sta\179 si\234 tak silny, \191e[ENTER]Beran-Setaou zamordowa\179 swoj\185 siostr\234, kt\243ra by\179a[ENTER]ulubienic\185 ludzi. Nie potrzebowa\179 do tego \191adnego[ENTER]planu. Jego dobroduszna siostra nie podejrzewa\179a[ENTER]niczego, pe\179na zaufania spotka\179a si\234 z[ENTER]Beran-Setaou, kt\243ry za\156lepiony zazdro\156ci\185[ENTER]spogl\185daj\185c prosto w jej niewinne i kochaj\185ce[ENTER]oczy dokona\179 \156miertelnego uderzenia. "
gameforge.ghost_story._200_npcChat = "Nast\234pstwa "
gameforge.ghost_story._210_say = "\140mier\230 bogini mia\179a straszliwe konsekwencje[ENTER]zar\243wno w \156wiecie bog\243w, jak r\243wnie\191 ludzi.[ENTER]Nadesz\179a d\179uga i okrutna zima pozbawiaj\185c \191ycia[ENTER]wiele istot na l\185dzie i w wodzie. Ziemia zamarz\179a[ENTER]tak mocno, \191e ska\179y p\234ka\179y z hukiem i nawet[ENTER]olbrzymie stare drzewa nie wytrzymywa\179y si\179y[ENTER]mrozu. "
gameforge.ghost_story._220_say = "Kiedy w ko\241cu ziemi\234 zacz\234\179y ogrzewa\230 pierwsze[ENTER]promienie s\179oneczne liczba nowo narodzonych by\179a[ENTER]tak niska jak nigdy dot\185d. Wyja\179owiona ziemia nie[ENTER]rodzi\179a wystarczaj\185co du\191o plon\243w, by wy\191ywi\230[ENTER]wycie\241czony z g\179odu i zimna nar\243d. Ludzie[ENTER]stracili wszelk\185 nadziej\234 i potrzebowali wiele[ENTER]czasu, by ponownie odzyska\230 si\179y zaufanie. "
gameforge.ghost_story._230_say = "R\243wnie\191 bogowie cierpieli, chocia\191 czas up\179ywa\179[ENTER]im wolniej ni\191 ludziom. Gdy Beran-Setaou[ENTER]zrozumia\179 co uczyni\179 szuka\179 samotno\156ci. W jego[ENTER]sercu przeplata\179y si\234 uczucia g\179\234boki \191alu i[ENTER]satysfakcji - a\191 w ko\241cu przewa\191y\179o ostanie. Jego[ENTER]serce zamarz\179o i z Boga Rozpadu powsta\179 B\243g Lodu[ENTER]i Ch\179odu, Nienawi\156ci i Strachu. "
gameforge.ghost_story._240_npcChat = "Walka "
gameforge.ghost_story._250_say = "Baljit-Elvedin, B\243g Ochrony, d\179ugo op\179akiwa\179[ENTER]\156mier\230 ukochanej siostry. Gdy w ko\241cu rozlu\159ni\179y[ENTER]si\234 \191elazne szpony cierpienia, wyruszy\179 na[ENTER]poszukiwanie swojego brata. Jego \156cie\191ka \191ycia[ENTER]naznaczona by\179a ci\185gle jeszcze rozwag\185 i[ENTER]m\185dro\156ci\185 i pomimo cierpienia i \191alu po utracie[ENTER]siostry zrozumia\179, \191e \191ycie nie ma \191adnych szans[ENTER]w \156wiecie, w kt\243rym panuje chaos i brak[ENTER]r\243wnowagi. "
gameforge.ghost_story._260_say = "Pod\185\191a\179 \156ladami swojego brata, a\191 w ko\241cu po[ENTER]latach poszukiwa\241 znalaz\179 go w jaskini z lodu[ENTER]przepe\179nionej nienawi\156ci\185 oraz samotno\156ci\185, z[ENTER]dala od wszelkich \191yj\185cych istot. Baljit-Elvedin[ENTER]uczyni\179 to, co uczyni\230 musia\179, chocia\191 kolejny[ENTER]raz krwawi\179o mu serce z \191alu wyzwa\179 swojego brata[ENTER]na pojedynek. Beran-Setaou by\179o ju\191 wszystko[ENTER]jedno i nie zwlekaj\185c ani sekund przyj\185\179[ENTER]wyzwanie... "
gameforge.ghost_story._270_say = "M\243wi si\234, \191e tak okrutniej i zaci\234tej walki nie[ENTER]mo\191na sobie nawet wyobrazi\230. Zwyci\234\191y\179[ENTER]Baljit-Elvedin. Wierny swoim zasadom nie zabi\179[ENTER]jednak swojego brata, lecz odebra\179 mu jego moc i[ENTER]uwi\234zi\179 go w tej grocie. Od tego czasu \191yje tutaj[ENTER]Beran-Setaou razem ze swoimi kreaturami, kt\243re[ENTER]stworzy\179 w przeci\185gu wiek\243w... "
gameforge.ghost_story._280_npcChat = "Ju\191 wystarczaj\185co du\191o us\179ysza\179em. "
gameforge.ghost_story._290_say = "Niech Ci los sprzyja. Powodzenia! "
gameforge.ghost_story._300_sayTitle = "Duch Wojownika: "
gameforge.ghost_story._310_npcChat = "Dlaczego jeste\156 przezroczysty? "
gameforge.ghost_story._320_say = "A co my\156la\179e\156? Jestem duchem zamkni\234tym w skale[ENTER]ju\191 od tysi\185ca lat... "
gameforge.ghost_story._330_say = "Pomocy! Duch! "
gameforge.ghost_story._340_say = "Masz racj\234, duch. Uciekaj, bo Ci\234 po\191r\234! "
gameforge.ghost_story._350_npcChat = "Kim jeste\156? "
gameforge.ghost_story._360_say = "Niegdy\156 by\179em najemnikiem, prostym cz\179owiekiem.[ENTER]Moi rodzice mieli ma\179e gospodarstwo. Ja jednak[ENTER]nie chcia\179em przez ca\179e \191ycie ora\230 pola, a wi\234c[ENTER]poszed\179em do wojska. Wprawdzie by\179o ci\234\191ko, ale[ENTER]pi\234kne czasy. Jednak po pewnym czasie mia\179em[ENTER]dosy\230 tego, \191e nic niewarci arystokraci wydawali[ENTER]mi rozkazy i zdezerterowa\179em. To, \191e si\234[ENTER]znalaz\179em w tym mrocznym miejscu, to tylko[ENTER]przypadek. "
gameforge.ghost_story._370_npcChat = "Czy znasz histori\234 groty? "
gameforge.ghost_story._380_say = "Nie, nic nie wiem, po prostu mia\179em pecha. Po tym[ENTER]jak zdezerterowa\179em, szuka\179em kryj\243wki w g\243rach i[ENTER]znalaz\179em t\234 jaskini\234. Ju\191 od pocz\185tku wydawa\179a[ENTER]mi si\234 podejrzana, ale po\179o\191ona by\179a korzystnie i[ENTER]do tego ca\179kowicie opuszczona. Po kilku dniach[ENTER]by\179em \156wiadkiem - i ofiar\185 - niesamowitej walki.[ENTER]Je\156li chcesz opowiem Ci o tym. "
gameforge.ghost_story._390_npcChat = "Pocz\185tek walki "
gameforge.ghost_story._400_say = "Pewnego dnia - zbiera\179em w\179a\156nie korzonki na[ENTER]zboczu - gdy, bez ostrze\191enia spad\179 z nieba[ENTER]srebrny smok. I ju\191 my\156la\179em, \191e po mnie, ale o[ENTER]dziwo, on nawet na mnie nie spojrza\179 - utkwi\179[ENTER]wzrok w jaskini. Nawet nie zwolni\179, tylko prosto[ENTER]skierowa\179 si\234 w stron\234 doliny i wpad\179 do jaskini. "
gameforge.ghost_story._410_say = "Przez pewien czas by\179o zupe\179nie cicho. Nie[ENTER]wiedzia\179em co mam zrobi\230. Wszystkie moje rzeczy[ENTER]znajdowa\179y si\234 w jaskini, ale nie chcia\179em stan\185\230[ENTER]oko w oko ze smokiem! Nagle zatrz\234s\179a si\234 ziemia,[ENTER]a z g\179\234bi jaskini us\179ysza\179em przyt\179umiony ryk -[ENTER]ale o dziwo, to by\179y dwa g\179osy, a nie jeden![ENTER]Kr\243tko po tym wylecia\179y z jaskini jak b\179yskawica[ENTER]dwa smoki, najpierw srebrny, a tu\191 za nim[ENTER]niebieski. "
gameforge.ghost_story._420_say = "Mi\234dzy smokami rozgorza\179a zaciek\179a walka, kt\243r\185[ENTER]trudno opisa\230 s\179owami. Szponami rozdziera\179y sobie[ENTER]skrzyd\179a, zakleszczy\179y si\234 w sobie, zatopi\179y[ENTER]swoje ogromne z\234by w szyi przeciwnika... Krew[ENTER]la\179a si\234 strumieniami na wszystkie strony...[ENTER]Jednak \191aden ze smok\243w nie ust\185pi\179 nawet przez[ENTER]chwil\234. "
gameforge.ghost_story._430_npcChat = "Koniec walki "
gameforge.ghost_story._440_say = "Obydwa smoki przewala\179y si\234 nad g\243rami jak[ENTER]ogromna burza z piorunami i zr\243wnywa\179y szczyty[ENTER]g\243rskie z dolinami. Ogniste b\179yskawice opali\179y[ENTER]pysk srebrnego smoka, a lodowy grad doszcz\234tnie[ENTER]zniszczy\179 skrzyd\179a niebieskiego. Gruby pancerz[ENTER]lodowy, kt\243ry ju\191 od wiek\243w pokrywa\179 ziemi\234,[ENTER]stopi\179 si\234 w mieniu oka pozostawiaj\185c cuchn\185ce[ENTER]b\179oto. Zdr\234twia\179y z przera\191enia, zd\185\191y\179em si\234[ENTER]jeszcze schowa\230 za ska\179\185, ale nie by\179em ju\191 w[ENTER]stanie odwr\243ci\230 wzroku. "
gameforge.ghost_story._450_say = "Dopiero po kilku godzinach walki powoli[ENTER]opuszcza\179y je si\179y. Musia\179em wykorzysta\230 t\234[ENTER]jedyn\185 szans\234, wyskoczy\179em za ska\179y i co si\179[ENTER]bieg\179em w d\243\179 w kierunku doliny, by zabra\230 z[ENTER]jaskini moje rzeczy. To przypiecz\234towa\179o m\243j los.[ENTER]Znajdowa\179em si\234 ju\191 w powrotnej drodze, gdy jak[ENTER]strza\179y stoczy\179y si\234 z g\243r obydwa smoki, z przodu[ENTER]niebieski, okropnie pokaleczony. "
gameforge.ghost_story._460_say = "Kr\243tko przed znikni\234ciem w jaskini, dogoni\179 go[ENTER]srebrny smok i wydarzy\179o si\234 co\156 bardzo dziwnego:[ENTER]W powietrzu unosi\179o si\234 co\156 b\179yszcz\185cego, co[ENTER]przeobrazi\179o si\234 w pr\185d powietrza, a nast\234pnie w[ENTER]k\179\185b energii, w \156rodku uwi\234ziony by\179 niebieski[ENTER]smok wyj\185cy z b\243lu i w\156ciek\179o\156ci... Powoli[ENTER]kurczy\179 si\234, jego wycie stawa\179o si\234 s\179absze, a[ENTER]jego \179uski traci\179y blask, stawa\179y si\234 matowe i[ENTER]bezbarwne... "
gameforge.ghost_story._470_say = "W ko\241cu ostatkiem si\179 dowl\243k\179 si\234 niebieski smok[ENTER]do mrocznej jaskini i znikn\185\179 w jej g\179\234bi.[ENTER]Srebrny smok uwolni\179 pot\234\191n\185, magiczn\185 wichur\234,[ENTER]kt\243ra zapiecz\234towa\179a barier\185 energii wej\156cie do[ENTER]jaskini oraz osun\234\179a cz\234\156\230 g\243ry. Ja i mroczny[ENTER]smok byli\156my uwi\234zieni. Skazani na powoln\185 i[ENTER]bolesn\185 \156mier\230 g\179odow\185... "
