gameforge.heavens_cave_keyquest._080_say = "Wszystko zacz\234\179o si\234 od \163ez, kt\243rymi Smoczy B\243g[ENTER]op\179akiwa\179 \156mier\230 swojej siostry. Z chwil\185 upadku[ENTER]na ziemi\234 nagle skamienia\179y.[ENTER]Nadal mo\191na je znale\159\230 na Ognistej Ziemi[ENTER]Doyyumhwan. Zdob\185d\159 siedem \163ez i cztery kawa\179ki[ENTER]Obsydianu od P\179omieni, kt\243re tam \191yj\185. Gdy tylko[ENTER]uporasz si\234 z tym zadaniem, wr\243\230 do mnie. "
gameforge.heavens_cave_keyquest._090_say_reward = "Zbierz 7 Skamienia\179ych \163ez i 4 sztuki Obsydianu w[ENTER]Doyyumhwan. "
gameforge.heavens_cave_keyquest._100_say = "Potrzebujesz Krwistego Kamienia aby Stra\191nik[ENTER]Zakonu Ci\234 przepu\156ci\179? W takim razie zdob\185d\159[ENTER]siedem Skamienia\179ych \163ez i cztery kawa\179ki[ENTER]Obsydianu na Ognistej Ziemi Doyyumhwan. "
gameforge.heavens_cave_keyquest._110_say = "Potrzebujesz Krwistego Kamienia? Koe-Pung nie[ENTER]jest zbyt sprytny, ale lepiej troch\234 odczeka\230...[ENTER]w innym przypadku mo\191e si\234 zorientowa\230, \191e nie[ENTER]nale\191ysz do jego zakonu. "
gameforge.heavens_cave_keyquest._120_say = "Kilka godzin, powiedzia\179bym: %s "
gameforge.heavens_cave_keyquest._130_say = "Jedna godzina i %s minut. "
gameforge.heavens_cave_keyquest._140_say = "Odczekaj jeszcze %s minut. "
