gameforge.heavens_cave_keyquest._200_say = "Postanowi\179e\156 poszuka\230 wi\234cej \163ez i znale\159\230: %s "
gameforge.heavens_cave_keyquest._210_say = "Stworzenia na tym obszarze s\185 teraz bardzo[ENTER]ostro\191ne! "
gameforge.heavens_cave_keyquest._220_say = "Udaj si\234 na Ogniste Ziemie Doyyumhwan i poszukaj[ENTER]Skamienia\179ych \163ez Smoczego Boga Baljit Elvedin.[ENTER]Zbierz od razu troch\234 Obsydianu, znajdziesz go u[ENTER]P\179omieni. "
