gameforge.heavens_cave_keyquest._290_say = "Seon-Hae jest w: %s "
gameforge.heavens_cave_keyquest._300_say = "\163zy Baljit-Elvedin! Przemieni\234 je z powrotem w[ENTER]ciek\179\185 form\234 i umieszcz\234 w Obsydianie.[ENTER]Ich moc pozwala przywo\179a\230 Bogini\234 Bahar-Taraji! "
gameforge.heavens_cave_keyquest._310_say = "Jej dusza wci\185\191 b\179\185ka si\234 po ziemi. Je\191eli ma si\234[ENTER]ze sob\185 \163zy, mo\191na us\179ysze\230 jej g\179os. Poszukaj[ENTER]jej w Czerwonym Lesie Lungsam! "
gameforge.heavens_cave_keyquest._320_say = "Trzymaj, we\159 t\234 waz\234 i poszukaj g\179osu[ENTER]Bahar-Taraji. "
gameforge.heavens_cave_keyquest._330_say = "Pod\185\191aj za g\179osem Bahar-Taraji w Czerwonym Lesie[ENTER]Lungsam. Nawet je\156li nie uda Ci si\234 zobaczy\230[ENTER]ducha bogini, b\234dziesz w stanie wyczu\230 jej[ENTER]obecno\156\230. "
gameforge.heavens_cave_keyquest._335_say = "Cichy szept przenoszony przez wiatr: Udaj si\234 do[ENTER]bezpiecznego miejsca... Nie mo\191emy tutaj[ENTER]rozmawia\230... Kliknij na zw\243j misji aby[ENTER]porozmawia\230 z duchem. "
gameforge.heavens_cave_keyquest._340_say = "W oddali s\179ycha\230 g\179os zamordowanej bogini[ENTER]Bahar-Taraji... "
gameforge.heavens_cave_keyquest._350_say = "\163zy mojego brata... tak d\179ugo mnie op\179akiwa\179,[ENTER]jednak nadal nie uda\179o mu si\234 ukara\230[ENTER]Beran-Setaou. "
gameforge.heavens_cave_keyquest._360_say = "On przecie\191 nie m\243g\179 przeciwstawi\230 si\234 swojemu[ENTER]bratu Beran-Setaou, zwanemu Niszczycielem.[ENTER]Miejcie si\234 przed nim na baczno\156ci, ludzie. "
gameforge.heavens_cave_keyquest._370_say = "Ale ty... kim w og\243le jeste\156? Jeste\156 inny![ENTER]Nie boisz si\234 go. Wr\234cz przeciwnie, widz\234, \191e[ENTER]szukasz walki. "
gameforge.heavens_cave_keyquest._380_say = "%s! We\159 kropl\234 mojej krwi. Wytw\243rz Krwisty Kamie\241[ENTER]i upewnij si\234, \191e Beran-Setaou zap\179aci za swoje[ENTER]z\179e czyny. St\185d, Grota Wygna\241c\243w jest ca\179kiem[ENTER]blisko. "
gameforge.heavens_cave_keyquest._390_say = "W oddali s\179ycha\230 g\179os zamordowanej bogini[ENTER]Bahar-Taraji... "
gameforge.heavens_cave_keyquest._400_say = "%s! Poznaj\234 Ci\234! "
gameforge.heavens_cave_keyquest._410_say = "Przynie\156 na pocieszenie \163zy mojego brata a[ENTER]otrzymasz za to moj\185 krew, aby\156 m\243g\179 dalej[ENTER]walczy\230. "
gameforge.heavens_cave_keyquest._420_say = "Wr\243\230 do Seon-Hae z Kropl\185 Krwi Bahar-Taraji. "
gameforge.heavens_cave_keyquest._430_say = "Oczy Seon-Hae staj\185 si\234 szkliste i bierze od[ENTER]Ciebie Kropl\234 Krwi... "
gameforge.heavens_cave_keyquest._440_say = "Krew prawdziwej Bogini! Szybko, zrobi\234 z niej[ENTER]Krwisty Kamie\241 zanim wyschnie. "
gameforge.heavens_cave_keyquest._450_say = "Dzi\234ki Krwistemu Kamieniowi stra\191nik Koe-Pung[ENTER]udost\234pni Ci portal, kt\243ry zaprowadz\185 Ci\234 do[ENTER]Groty Wygna\241c\243w. Pami\234taj jednak, \191e to zadzia\179a[ENTER]tylko raz. Je\191eli b\234dziesz potrzebowa\179 wi\234kszej[ENTER]ilo\156ci Krwistych Kamieni, wr\243\230 do mnie.[ENTER]Niestety, aby kto\156 nie zacz\185\179 czego\156 podejrzewa\230,[ENTER]mog\234 wytworzy\230 tylko jeden Krwisty Kamie\241 na[ENTER]dzie\241. "
gameforge.heavens_cave_keyquest._460_say_reward = "Seon-Hae mo\191e wyprodukowa\230 dla Ciebie kolejne[ENTER]Krwiste Kamienie, jednak tylko jeden dziennie. "
gameforge.heavens_cave_keyquest._470_say = "Przekszta\179c\234 t\234 Kropl\234 Krwi Bahar-Taraji w[ENTER]Krwisty Kamie\241. Niech Ci dobrze s\179u\191y. "
gameforge.heavens_cave_keyquest._480_say_reward = "Ka\191dego dnia mog\234 wytworzy\230 dla Ciebie tylko[ENTER]jeden Krwisty Kamie\241. W innym przypadku Koe-Pung[ENTER]m\243g\179by zacz\185\230 co\156 podejrzewa\230. "
