gameforge.horse_guard._30_say = "Konie dobiera si\234 wed\179ug nast\234puj\185cych poziom\243w[ENTER]je\159d\159ca: pocz\185tkuj\185cy, zaawansowany oraz ekspert.[ENTER]Jak poczujesz si\234 na si\179ach, aby awansowa\230 do[ENTER]wy\191szej kategorii, musisz zda\230 egzamin[ENTER]kwalifikacyjny. "
gameforge.horse_guard._40_say = "Konie potrzebuj\185 specjalnego jedzenia, w[ENTER]zale\191no\156ci od ich poziomu rozwoju.[ENTER]Ko\241 Zwyk\179y je Siano. Ko\241 Opancerzony je Marchewki[ENTER]a Ko\241 Wojskowy je Czerwony \175e\241-sze\241.[ENTER][ENTER]Jak widzisz, potrafi\185 one by\230 bardziej wybredne[ENTER]ni\191 niekt\243rzy ludzie. "
gameforge.horse_guard._50_say = "Je\191eli Ko\241 jest najedzony, jego ikonka \156wieci si\234[ENTER]na zielono. Je\191eli ikonka Konia jest \191\243\179ta,[ENTER]oznacza, \191e Ko\241 jest g\179odny. Je\191eli jest[ENTER]czerwona, tw\243j Ko\241 jest bliski \156mierci.[ENTER]Aby zmieni\230 ikonk\234 z koloru \191\243\179tego lub[ENTER]czerwonego na zielony, wystarczy nakarmi\230 Konia[ENTER]odpowiedni\185 ilo\156ci\185 pokarmu.[ENTER]Gdy tw\243j Ko\241 umrze, mo\191esz mie\230 problem... "
gameforge.horse_guard._60_say = "Podczas jazdy Ko\241 si\234 m\234czy i podupada na[ENTER]zdrowiu. Nie mo\191esz je\159dzi\230 na Koniu, kt\243ry jest[ENTER]wycie\241czony. W\179a\156nie dlatego czasami musisz da\230[ENTER]odpocz\185\230 swojemu Koniowi. "
gameforge.horse_guard._70_say = "Istniej\185 pog\179oski, \191e martwego konia da si\234[ENTER]wskrzesi\230 przy u\191yciu odpowiednich zi\243\179. Jednak[ENTER]zio\179a te s\185 strze\191one przez Ma\179py, wi\234c zdobycie[ENTER]ich jest bardzo trudne. Podobno je\191eli Ma\179py Ci\234[ENTER]z\179api\185, to dosi\234gnie Ci\234 ich kl\185twa! "
gameforge.horse_guard._80_say = "Istniej\185 r\243\191ne Umiej\234tno\156ci Konne.[ENTER]Mo\191esz trenowa\230 konia, aby stawa\179 si\234 coraz[ENTER]silniejszy. Jednak tylko osoby posiadaj\185ce Medal[ENTER]Konny mog\185 trenowa\230 poziom swojego Konia. "
