gameforge.locale.bookworm.aranyeo_complete_say = "Co za idiota da\179 t\234 Ksi\234g\234 mojemu m\234\191owi?[ENTER]Ca\179e dnie si\234 na ni\185 gapi! Nic innego nie robi![ENTER]Jak si\234 nim zajm\234 to po\179ami\234 mu wszystkie ko\156ci! "
