gameforge.locale.bookworm.aranyeo_start_say = "Gdzie on polaz\179?! Ju\191 mnie to denerwuje![ENTER]Marnuje dnie i noce na czytanie ksi\185\191ek, a przez[ENTER]ostatnie lata nie zarobi\179 nawet 1 Yang![ENTER]Jak to mo\191liwe, \191e mu nie wstyd?! "
