gameforge.locale.bookworm.do_you_mean_this_book = "Masz na my\156li t\185 Ksi\234g\234? "
gameforge.locale.bookworm.etc_shop_start_say = "Wczoraj t\234dy przechodzi\179. Uhm, co chcia\179? M\243wi\179[ENTER]co\156 o Ksi\234dze Milgyo czy jako\156 tak... Nie mia\179[ENTER]Yang, ale i tak o ni\185 pyta\179. Milgyo mo\191e mie\230[ENTER]zwi\185zek z brutalnymi potworami z Doliny[ENTER]Seungryong. Nie mam poj\234cia dlaczego m\243g\179by si\234[ENTER]tym interesowa\230. "
