gameforge.locale.bookworm.order_refuse_answer = "Soon: Czemu nie chcesz spr\243bowa\230?[ENTER]Wiem, \191e dasz rad\234! "
gameforge.locale.bookworm.order_say1 = "Soon: Chcesz us\179ysze\230 co\156 dziwnego?[ENTER]Mog\234 powiedzie\230, \191e przeczyta\179em wszystkie[ENTER]ksi\185\191ki tego \156wiata! Obecnie studiuj\234 teksty[ENTER]spisane przez \156wi\234tych. Plotki g\179osz\185, \191e[ENTER]wskaz\243wki do ich rozszyfrowania mog\185 znajdowa\230[ENTER]si\234 w Ksi\234dze Milgyo. "
gameforge.locale.bookworm.order_say2 = "Soon: Chc\234 mie\230 t\185 Ksi\234g\234! Musz\234 j\185 przeczyta\230![ENTER]Jak my\156lisz? Mo\191esz j\185 dla mnie zdoby\230?[ENTER]Je\191eli j\185 dla mnie zdob\234dziesz, wynagrodz\234 Ci\234![ENTER]Nawet je\156li b\234d\234 musia\179 sprzeda\230 dom! "
