gameforge.locale.forked_condition2 = "Teraz, jedyne co musimy zrobi\230 to zabi\230 tych,[ENTER]kt\243rzy zbezcze\156cili \140wi\234t\185 Ziemi\234! Do ataku! "
gameforge.locale.forked_enter = "Wejd\159 "
gameforge.locale.forked_kill_boss = "Jestem Thorr Sarch! Czego ode mnie chcesz?[ENTER]Nie umar\179em, wr\243c\234 do \191ywych. B\234d\185 mnie wspiera\230[ENTER]legiony wojownik\243w![ENTER][ENTER]Zako\241czy\179e\156 Wojn\234 Kr\243lestw.[ENTER]Wszyscy uczestnicy zostan\185 przeniesieni do miasta. "
gameforge.locale.forked_man_chat = "We\159 udzia\179 w Wojnie Kr\243lestw "
gameforge.locale.forked_man_say = "Ostatnio zosta\179 odkryty nowy obszar. Znajduje si\234[ENTER]on w \156rodku kontynentu - mo\191liwe, \191e \179\185czy[ENTER]wszystkie Kr\243lestwa. Jednak miejsce to jest[ENTER]zape\179nione pot\234\191nymi potworami. Mo\191e si\234 tam[ENTER]udasz i stawisz im czo\179a? Pokonaj wszystkich i[ENTER]przywr\243\230 pok\243j w naszym Kr\243lestwie. "
gameforge.locale.forked_man_say_cant = "Ha! Ostatnio zosta\179 odkryty nowy obszar.[ENTER]Znajduje si\234 on w \156rodku kontynentu - mo\191liwe, \191e[ENTER]\179\185czy wszystkie Kr\243lestwa. Zaraz po zako\241czeniu[ENTER]bada\241 tego terenu b\234dziesz m\243g\179 wej\156\230. "
gameforge.locale.forked_no_enter = "Nie wchod\159 "
gameforge.locale.forked_open_gate = "Wrota, kt\243re do tej pory by\179y zamkni\234te, w ko\241cu[ENTER]si\234 otworzy\179y. Naprz\243d, czas podbi\230 nowe ziemie![ENTER]Wszyscy wojownicy zostaj\185 przeniesieni do \140wi\234tej[ENTER]Ziemi. "
gameforge.locale.forked_rule = "Zasady Udzia\179u w Wojnie Kr\243lestw:[ENTER]1. Je\156li zginiesz w strefie Wojny, zostajesz[ENTER]automatycznie przenoszony do wioski. Egzekutor[ENTER]Bitewny mo\191e jednak natychmiast odes\179a\230 ci\234 z[ENTER]powrotem.[ENTER]2. Gdy drzwi do \140wi\234tej Ziemi zostan\185 otwarte,[ENTER]teren ten zostaje zamkni\234ty.[ENTER]3. Aby otworzy\230 wrota do \140wi\234tej Ziemi, musi[ENTER]zosta\230 znaleziony odpowiedni Klucz. "
gameforge.locale.forked_rule_sungzi = "Zasady Wojny Kr\243lestw:[ENTER]1. W pierwszej kolejno\156ci odpada Kr\243lestwo, kt\243re[ENTER]osi\185gn\234\179o najmniejsz\185 liczb\234 zwyci\234stw.[ENTER]2. Po tym pojawi\185 si\234 potwory. Wygrywa Kr\243lestwo,[ENTER]kt\243re jako pierwsze je pokona.[ENTER]3. Bitwa ko\241czy si\234, gdy zostanie zabity potw\243r[ENTER]Dziewi\234\230 Ogon\243w.[ENTER]4. Podczas Wojny nie da si\234 zdoby\230 przedmiot\243w.[ENTER]5. Kto po raz trzeci zginie na \140wi\234tej Ziemi, ten[ENTER]zostaje przeniesiony do wioski i odpada z Wojny[ENTER]Kr\243lestw. "
gameforge.locale.fortune_words_1_body = "W rzeczy samej! Fortuna si\234 do ciebie u\156miecha![ENTER]Dzisiaj masz \"Ogromne Szcz\234\156cie\"![ENTER]Dzi\234ki harmonijnemu przep\179ywowi si\179 Chi, spotka[ENTER]ci\234 dzisiaj co\156 dobrego! "
gameforge.locale.fortune_words_1_title = "Ogromne Szcz\234\156cie! "
gameforge.locale.fortune_words_2_body = "Ca\179kiem nie\159le. Jak g\179osi nasze ludowe[ENTER]przys\179owie: jak Kuba Bogu, tak B\243g Kubie. Masz[ENTER]dzisiaj \"Wielkie Szcz\234\156cie\"! Bardzo mnie to[ENTER]cieszy. Dzisiaj nawet niewielki wysi\179ek[ENTER]przyniesie ci stukrotne wynagrodzenie! "
gameforge.locale.fortune_words_2_title = "Wielkie Szcz\234\156cie! "
gameforge.locale.fortune_words_3_body = "Nie jest \159le. Masz dzisiaj \"Troch\234 Szcz\234\156cia\".[ENTER]Tw\243j dzie\241 potoczy si\234 nieco lepiej ni\191[ENTER]zazwyczaj, ale nie oczekuj, \191e los obsypie ci\234[ENTER]dobrodziejstwami! "
gameforge.locale.fortune_words_3_title = "Troch\234 Szcz\234\156cia! "
gameforge.locale.fortune_words_4_body = "C\243\191, ani to \159le ani dobrze! Masz dzisiaj[ENTER]\"Normalne Szcz\234\156cie\". Nie pomo\191e ci to zbyt du\191o,[ENTER]ale przynajmniej nie b\234dziesz mia\179 pecha.[ENTER]Normalny dzie\241 to dobry dzie\241, ciesz si\234 nim! "
gameforge.locale.fortune_words_4_title = "Normalne Szcz\234\156cie! "
gameforge.locale.fortune_words_5_body = "Dzi\156 nie dopisze ci szcz\234\156cie. Nawet je\156li[ENTER]dzisiaj zarzucisz sie\230, nie z\179apiesz wielu ryb.[ENTER]Jednak nie oznacza to, \191e b\234dziesz chodzi\179[ENTER]g\179odny. Dzisiaj masz \"Lekkiego Pecha\"! Dobrze by\230[ENTER]przygotowanym na wszystko. Je\191eli chcesz, mog\234[ENTER]zrobi\230 dla ciebie specjalny przedmiot, kt\243ry[ENTER]odstrasza pecha. Czy chcesz kupi\230 talizman? "
gameforge.locale.fortune_words_5_title = "Lekki Pech! "
gameforge.locale.fortune_words_6_body = "Dzisiaj jest naprawd\234 z\179y dzie\241. Dzie\241, w kt\243rym[ENTER]mo\191esz robi\230 wszystko, a i tak prawie nic nie[ENTER]otrzymasz. Masz dzisiaj \"Pecha\"![ENTER]Musisz unika\230 z\179ych rzeczy. Je\156li chcesz, mog\234[ENTER]przygotowa\230 dla ciebie przedmiot zwi\234kszaj\185cy[ENTER]szcz\234\156cie, aby\156 m\243g\179 normalnie funkcjonowa\230. Czy[ENTER]jeste\156 zainteresowany? "
gameforge.locale.fortune_words_6_title = "Pech! "
gameforge.locale.fortune_words_7_body = "To najgorszy z mo\191liwych dla ciebie dni. Wszyscy[ENTER]bogowie na ziemi i w niebie odwr\243cili si\234 do[ENTER]ciebie plecami. Nic ci si\234 nie uda. Je\191eli[ENTER]b\234dziesz chcia\179 rozpali\230 ognisko, zacznie pada\230,[ENTER]je\191eli b\234dziesz spragniony, s\179o\241ce zacznie grza\230.[ENTER]B\234dziesz pracowa\230 tak ci\234\191ko jak inni, ale nie[ENTER]przyniesie to \191adnych efekt\243w. Masz \"Wielkiego[ENTER]Pecha\"! Bez Talizmanu czeka ci\234 koszmar. By\179by\156[ENTER]zainteresowany kupnem takiego talizmanu? "
gameforge.locale.fortune_words_7_title = "Wielki Pech! "
