gameforge.locale.monster_chat_1001_1 = "Hehe, wszyscy zgin\185! Kyaaaa! "
gameforge.locale.monster_chat_1001_2 = "*gryzie* "
gameforge.locale.monster_chat_1001_3 = "Hehehehe "
gameforge.locale.monster_chat_1001_4 = "Kukieh! Gi\241! Hehe. "
gameforge.locale.monster_chat_1001_5 = "hehehe "
gameforge.locale.monster_chat_1001_6 = "Co za twarz! Zdeformowana przez strach! Hehehe. "
gameforge.locale.monster_chat_1002_1 = "Haha! "
gameforge.locale.monster_chat_1002_2 = "\140winie! "
gameforge.locale.monster_chat_1002_3 = "Naprawd\234 dzia\179aj\185 mi na nerwy... "
gameforge.locale.monster_chat_1002_4 = {}
gameforge.locale.monster_chat_1002_5 = "To krew, hehe! "
gameforge.locale.monster_chat_1003_1 = "Hehe! (g\179o\156ny \156miech) "
gameforge.locale.monster_chat_1003_2 = "W\179\243cznia jest gorsza ni\191 miecz, huh? "
gameforge.locale.monster_chat_1003_3 = "Hej, nie odchod\159! No dalej! "
gameforge.locale.monster_chat_1003_4 = "Ju\191 samo patrzenie sprawia, \191e cieknie mi \156linka... "
gameforge.locale.monster_chat_1003_5 = "Prowokujesz mnie! "
gameforge.locale.monster_chat_1003_6 = "Zginieeesz! "
gameforge.locale.monster_chat_1004_1 = "Zabi\230! Zabi\230! Zabiiiiiiiii\230! "
gameforge.locale.monster_chat_1004_2 = "Niez\179a pr\243ba. "
gameforge.locale.monster_chat_1004_3 = "Czuj\234, \191e szykuje si\234 zabawa! "
gameforge.locale.monster_chat_1004_4 = "Jeszcze nie! Nie umieraj tak szybko! Hehehe. "
gameforge.locale.monster_chat_1004_5 = "Co tam? Twoje r\234ce dr\191\185! "
gameforge.locale.monster_chat_1004_6 = "Nie boisz si\234 nas odwiedza\230? Nie martw si\234! "
gameforge.locale.monster_chat_1035_1 = "Zemszcz\234 si\234 zanim umr\234! "
gameforge.locale.monster_chat_1035_2 = "Tak, graj powoli... "
gameforge.locale.monster_chat_1035_3 = "Jeste\156 nasz\185 rado\156ci\185... "
gameforge.locale.monster_chat_1035_4 = "Twoje cia\179o dr\191y ze strachu. (\156miech) "
gameforge.locale.monster_chat_1035_5 = "Strach, huh? (\156miech) "
gameforge.locale.monster_chat_1035_6 = "Huh, wygl\185da na to, \191e kilka g\179\243w spadnie na ziemie. Czy to ju\191 koniec? "
gameforge.locale.monster_chat_1036_1 = "Z kim ty do diab\179a chodzisz?! "
gameforge.locale.monster_chat_1036_2 = "Psy! Doprowadz\234 was do szale\241stwa! "
gameforge.locale.monster_chat_1036_3 = "(\140miech) "
gameforge.locale.monster_chat_1036_4 = "B\179agaj o \191ycie oddaj\185c swoj\185 dusz\234! "
gameforge.locale.monster_chat_1036_5 = {}
gameforge.locale.monster_chat_1036_6 = "Nie odr\243\191niasz prawej strony od lewej! (\156miech) "
gameforge.locale.monster_chat_1037_1 = "Dlaczego ci\185gle tak spacerujesz? "
gameforge.locale.monster_chat_1037_2 = "Co tam? Nie przepadasz za ciemno\156ci\185? "
gameforge.locale.monster_chat_1037_3 = "Witaj w piekle (\156miech) "
gameforge.locale.monster_chat_1037_4 = "Pewnie, pewnie! Krzycz dalej! "
gameforge.locale.monster_chat_1037_5 = "Tym mnie nie zabijesz! (\156miech) "
gameforge.locale.monster_chat_1037_6 = "Taaaaak, od razu lepiej! "
gameforge.locale.monster_chat_1038_1 = "To piek\179o. "
gameforge.locale.monster_chat_1038_2 = "Witaj w piekle. "
gameforge.locale.monster_chat_1038_3 = "Prosz\234, nie umieraj tak szybko... "
gameforge.locale.monster_chat_1038_4 = "Atakowanie mnie jest bezcelowe! (\156miech) "
gameforge.locale.monster_chat_1038_5 = {}
gameforge.locale.monster_chat_1038_6 = "Nie umieraj za szybko, chcemy si\234 tob\185 pobawi\230... "
gameforge.locale.monster_chat_1039_1 = "Do czasu a\191 przyjdzie kto\156 nowy... "
gameforge.locale.monster_chat_1039_2 = "Naprawd\234 my\156lisz, \191e mo\191esz uciec? "
gameforge.locale.monster_chat_1039_3 = "Wszystko tutaj wywo\179uje strach u ludzi... "
gameforge.locale.monster_chat_1039_4 = "Witaj w naszym domu! (\156miech) "
gameforge.locale.monster_chat_1039_5 = "Widzisz? Przegapi\179e\156 to... "
gameforge.locale.monster_chat_1039_6 = "Hmm... taki \156wie\191y... "
gameforge.locale.monster_chat_1040_1 = "Widzimy wszystkie twoje ruchy. "
gameforge.locale.monster_chat_1040_2 = "Spokojnie... "
gameforge.locale.monster_chat_1040_3 = "Je\156li kogo\156 dotkniesz, zginiesz. (\156miech) "
gameforge.locale.monster_chat_1040_4 = "Czy s\179yszysz dzwonienie mojego dzwonka? To b\234dzie ostatnia rzecz jak\185 us\179yszysz! "
gameforge.locale.monster_chat_1040_5 = "Je\191eli nie zatamujesz krwi, mo\191e si\234 zrobi\230 niebezpiecznie... "
gameforge.locale.monster_chat_1040_6 = "Tak! Walka, walka! (\156miech) "
gameforge.locale.monster_chat_1041_1 = "(\156miech)(\156miech)(\156miech) "
gameforge.locale.monster_chat_1041_2 = "Przyby\179y nowe cia\179a... "
gameforge.locale.monster_chat_1041_3 = "Tak, to dobry czas na zdobycie nowych cia\179... "
gameforge.locale.monster_chat_1041_4 = "Prze\191yjemy! My nigdy nie umieramy! "
gameforge.locale.monster_chat_1041_5 = "Atakowanie nas jest bez sensu! (\156miech) "
gameforge.locale.monster_chat_1041_6 = "Co Ci\234 tu sprowadza? Chcesz umrze\230? "
gameforge.locale.monster_chat_1091_1 = "Kt\243\191 potrafi lata\230 i atakowa\230 lepiej ni\191 ja? "
gameforge.locale.monster_chat_1091_2 = "Mo\191esz sta\230 si\234 taki jak ja. "
gameforge.locale.monster_chat_1091_3 = "Nie chcesz by\230 taki jak ja? "
gameforge.locale.monster_chat_1091_4 = "Twoje cia\179o i dusza nale\191\185 do mnie! (\156miech) "
gameforge.locale.monster_chat_1091_5 = "Wyczerpany? Twoje nogi dr\191\185... "
gameforge.locale.monster_chat_1091_6 = "Ile czasu tak wytrzymasz? (\156miech) "
gameforge.locale.monster_chat_1093_1 = "Czy jest co\156 gorszego od \156mierci? "
gameforge.locale.monster_chat_1093_2 = "Witaj, spragniony \156mierci! "
gameforge.locale.monster_chat_1093_3 = "M\243dl si\234... "
gameforge.locale.monster_chat_1093_4 = "Po\191r\234 twoje cia\179o i dusz\234! "
gameforge.locale.monster_chat_1093_5 = "Jak d\179ugo wytrzymasz? Huh? "
gameforge.locale.monster_chat_1093_6 = "\140mier\230 \156mieje si\234 za twoimi plecami. (\156miech) "
gameforge.locale.monster_chat_11000_1 = "Wszyscy kt\243rym zale\191y na rozwoju postaci, s\179uchajcie! "
gameforge.locale.monster_chat_11000_10 = "Je\191eli chcesz kontrolowa\230 moc natury i b\179yskawic, wybierz Leczenie. "
gameforge.locale.monster_chat_11000_11 = "Ka\191dy wojownik jest inny na sw\243j spos\243b! Skup si\234 na rozwijaniu cia\179a! "
gameforge.locale.monster_chat_11000_12 = "Jako pot\234\191ny Sura, powiniene\156 rozwija\230 Inteligencj\234, szybko\156\230 i si\179\234 cia\179a! "
gameforge.locale.monster_chat_11000_13 = "U\191ywaj umiej\234tno\156ci ninja! Skup si\234 na szybko\156ci i sile cia\179a! "
gameforge.locale.monster_chat_11000_14 = "Szamani potrafi\185 leczy\230, cz\234sto pe\179ni\185 role pomocnik\243w. Ich si\179\185 jest inteligencja! "
gameforge.locale.monster_chat_11000_15 = "Nie zapominaj o trenowaniu! "
gameforge.locale.monster_chat_11000_16 = "Trenuj je\156li chcesz wzmocni\230 swoje umiej\234tno\156ci! "
gameforge.locale.monster_chat_11000_17 = "Poziom M uaktywni si\234 po dodaniu do umiej\234tno\156ci od 17 do 20 punkt\243w! "
gameforge.locale.monster_chat_11000_18 = "Chcesz zosta\230 Wielkim Mistrzem? W takim razie potrzebujesz specjaln\185 Ksi\234g\234 Umiej\234tno\156ci! "
gameforge.locale.monster_chat_11000_19 = "Po przeczytaniu Ksi\234ga Umiej\234tno\156ci znika! "
gameforge.locale.monster_chat_11000_2 = "Wojownicy poni\191ej 5. poziomu, s\179uchajcie! "
gameforge.locale.monster_chat_11000_20 = "Chcesz przeczyta\230 kolejn\185 Ksi\234g\234 Umiej\234tno\156ci? Musisz odczeka\230 jeden dzie\241! "
gameforge.locale.monster_chat_11000_21 = "Podwy\191sz parametr Inteligencji, aby ulepszy\230 swoje Umiej\234tno\156ci Sura. "
gameforge.locale.monster_chat_11000_22 = "Sprawd\159 wspania\179\185 moc Sura w walce! "
gameforge.locale.monster_chat_11000_23 = "Wiesz, gdzie si\234 znajduje \140wi\185tynia Mrocznych Ezoteryk\243w? Znajduje si\234 po\156rodku Doliny Seungryong! "
gameforge.locale.monster_chat_11000_24 = "Szukasz Lochu Paj\185k\243w! Znajdziesz go na Pustyni! "
gameforge.locale.monster_chat_11000_25 = "Wykonuj zadania a nagrody przeznaczaj na ulepszenia! "
gameforge.locale.monster_chat_11000_26 = "\163owienie? Brzmi \156wietnie! Masz ju\191 W\234dk\234 i przyn\234ty od Rybaka? "
gameforge.locale.monster_chat_11000_27 = "Chcesz zapolowa\230 na co\156 lepszego? Id\159 w stron\234 portalu! Znajd\159 sobie miejsce do polowania odpowiednie dla twojego poziomu! "
gameforge.locale.monster_chat_11000_28 = "Uwa\191aj na wrog\243w z innych Kr\243lestw. Nigdy nie wiesz, kiedy zjawi\185 si\234 za tob\185! "
gameforge.locale.monster_chat_11000_29 = "Chcesz zresetowa\230 swoje Umiej\234tno\156ci? Id\159 do Starszej Pani. Nie zapomnij zabra\230 za sob\185 wystarczaj\185co du\191o Yang! "
gameforge.locale.monster_chat_11000_3 = "Je\156li chcesz by\230 pot\234\191ny, udaj si\234 do Trenera Mocy Ostrza! "
gameforge.locale.monster_chat_11000_30 = "Sta\241 si\234 wielkim mistrzem! Tylko tak mo\191esz zapisa\230 si\234 na kartach historii! "
gameforge.locale.monster_chat_11000_31 = "Je\191eli chcesz przej\156\230 na jaki\156 inny obszar, porozmawiaj ze Staruszkiem! "
gameforge.locale.monster_chat_11000_4 = "Je\156li chcesz by\230 prawdziwym wojownikiem, musisz spr\243bowa\230 Si\179y Duchowej. "
gameforge.locale.monster_chat_11000_5 = "Je\156li chcesz zosta\230 Sur\185 mog\185cym w\179ada\230 Magicznym Mieczem, wybierz Trenera Mocy Broni! "
gameforge.locale.monster_chat_11000_6 = "Je\156li chcesz kszta\179ci\230 si\234 w dziedzinie czarnej magii, wybierz Trenera Czarnej Magii! "
gameforge.locale.monster_chat_11000_7 = "Trening Mocy \163uku to kierunek, w kt\243rym mo\191e i\156\230 Ninja po osi\185gni\234ciu 5 poziomu! "
gameforge.locale.monster_chat_11000_8 = "Je\156li chcesz mie\230 mo\191liwo\156\230 Krycia Si\234, wybierz Walk\234 W Zwarciu! "
gameforge.locale.monster_chat_11000_9 = "Je\156li chcesz by\230 osob\185 posiadaj\185c\185 moc Smoka, to wybierz drog\234 Boga Smoka! "
