gameforge.locale.monster_chat_11004_24 = "Szukasz Lochu Paj\185k\243w! Znajdziesz go na Pustyni! "
gameforge.locale.monster_chat_11004_25 = "Wykonuj zadania a nagrody przeznaczaj na ulepszenia! "
gameforge.locale.monster_chat_11004_26 = "\163owienie? Brzmi \156wietnie! Masz ju\191 W\234dk\234 i przyn\234ty od Rybaka? "
gameforge.locale.monster_chat_11004_27 = "Chcesz zapolowa\230 na co\156 lepszego? Id\159 w stron\234 portalu! Znajd\159 sobie miejsce do polowania odpowiednie dla twojego poziomu! "
gameforge.locale.monster_chat_11004_28 = "Uwa\191aj na wrog\243w z innych Kr\243lestw. Nigdy nie wiesz, kiedy zjawi\185 si\234 za tob\185! "
gameforge.locale.monster_chat_11004_29 = "Chcesz zresetowa\230 swoje Umiej\234tno\156ci? Id\159 do Starszej Pani. Nie zapomnij zabra\230 za sob\185 wystarczaj\185co du\191o Yang! "
gameforge.locale.monster_chat_11004_3 = "Je\156li chcesz by\230 pot\234\191ny, udaj si\234 do Trenera Mocy Ostrza! "
gameforge.locale.monster_chat_11004_30 = "Sta\241 si\234 wielkim mistrzem! Tylko tak mo\191esz zapisa\230 si\234 na kartach historii! "
gameforge.locale.monster_chat_11004_31 = "Je\191eli chcesz przej\156\230 na jaki\156 inny obszar, porozmawiaj ze Staruszkiem! "
gameforge.locale.monster_chat_11004_4 = "Je\156li chcesz by\230 prawdziwym wojownikiem, musisz spr\243bowa\230 Si\179y Duchowej. "
gameforge.locale.monster_chat_11004_5 = "Je\156li chcesz zosta\230 Sur\185 mog\185cym w\179ada\230 Magicznym Mieczem, wybierz Trenera Mocy Broni! "
gameforge.locale.monster_chat_11004_6 = "Je\156li chcesz kszta\179ci\230 si\234 w dziedzinie czarnej magii, wybierz Trenera Czarnej Magii! "
gameforge.locale.monster_chat_11004_7 = "Trening Mocy \163uku to kierunek, w kt\243rym mo\191e i\156\230 Ninja po osi\185gni\234ciu 5 poziomu! "
gameforge.locale.monster_chat_11004_8 = "Je\156li chcesz mie\230 mo\191liwo\156\230 Krycia Si\234, wybierz Trening Mocy Ostrza! "
gameforge.locale.monster_chat_11004_9 = "Je\156li chcesz by\230 osob\185 posiadaj\185c\185 moc Smoka, to wybierz Trening Mocy Smoka! "
gameforge.locale.monster_chat_1105_1 = "Zima jest super. "
gameforge.locale.monster_chat_1105_2 = "G\243ra Sohan jest najlepsza. "
gameforge.locale.monster_chat_1105_3 = "Co za pi\234kna pogoda. "
gameforge.locale.monster_chat_1105_4 = "B\234dziesz taki sam jak ja. "
gameforge.locale.monster_chat_1105_5 = "Mo\191esz \191y\230 wiecznie... przynajmniej do ocieplenia si\234 klimatu... "
gameforge.locale.monster_chat_1105_6 = "Jak my\156lisz, ile czasu musi min\185\230 aby\156 w ko\241cu zamarz\179? "
gameforge.locale.monster_chat_1106_1 = "Ludzie... tutaj?! "
gameforge.locale.monster_chat_1106_2 = "Jestem bardzo zm\234czony... ale i tak Ci\234 pokonam! "
gameforge.locale.monster_chat_1106_3 = "Czy kto\156 mnie s\179yszy? "
gameforge.locale.monster_chat_1106_4 = "Nie pochodzisz st\185d! "
gameforge.locale.monster_chat_1106_5 = "Lepiej si\234 wycofaj! "
gameforge.locale.monster_chat_1106_6 = "Obcy... taki samotny? "
gameforge.locale.monster_chat_1191_1 = "Zobaczymy, mo\191e zjawi si\234 jaki\156 przystojniak. "
gameforge.locale.monster_chat_1191_2 = "Tak mi zimno i smutno. Gdzie jest m\243j przysz\179y m\185\191? "
gameforge.locale.monster_chat_1191_3 = "Powinnam nad nim popracowa\230? "
gameforge.locale.monster_chat_1191_4 = {}
gameforge.locale.monster_chat_1191_5 = "Czego\156 brakuje, nie jestem szcz\234\156liwa... "
gameforge.locale.monster_chat_1191_6 = "Odbior\234 Ci \191ycie! "
gameforge.locale.monster_chat_1301_1 = "To cz\179owiek...! "
gameforge.locale.monster_chat_1301_2 = "Zaraz sprawi\234, \191e twoja twarz stanie si\234 jeszcze bladsza! "
gameforge.locale.monster_chat_1301_3 = "Chcesz mnie wyzwa\230 na pojedynek? Zgadzam si\234! "
gameforge.locale.monster_chat_1301_4 = "Zaatakowa\179e\156 mnie! Kwik! Nie daruj\234 Ci tego! "
gameforge.locale.monster_chat_1301_5 = "S\179aby, s\179aby cz\179owiek! "
gameforge.locale.monster_chat_1301_6 = "Zobaczmy ile jeste\156 w stanie znie\156\230! "
gameforge.locale.monster_chat_1302_1 = "Ucieczka? Nawet o tym nie my\156l! "
gameforge.locale.monster_chat_1302_2 = "Taaa... podejd\159 bli\191ej... KWIK! "
gameforge.locale.monster_chat_1302_3 = "Miecz dr\191y w mojej r\234ce. Kwik!! "
gameforge.locale.monster_chat_1302_4 = "Nie prze\191yjesz tej walki! "
gameforge.locale.monster_chat_1302_5 = "Nadchodzi m\243j miecz! "
gameforge.locale.monster_chat_1302_6 = "Bolesne, prawda? (\156miech) "
gameforge.locale.monster_chat_1303_1 = "Niebezpiecze\241stwo mo\191e czai\230 si\234 nawet w trawie! "
gameforge.locale.monster_chat_1303_2 = "Uwa\191aj na traw\234! "
gameforge.locale.monster_chat_1303_3 = "Dobra. Chod\159 do mnie. (\156miech) "
gameforge.locale.monster_chat_1303_4 = "Jak \156miesz do mnie podchodzi\230?! Musisz ponie\156\230 konsekwencje! "
gameforge.locale.monster_chat_1303_5 = "Gi\241! Gi\241! "
gameforge.locale.monster_chat_1303_6 = "\175a\179ujesz, \191e tu przyszed\179e\156? "
gameforge.locale.monster_chat_1305_1 = "Kto mnie pokona? "
gameforge.locale.monster_chat_1305_2 = "Ty?! Ty chcesz walczy\230? "
gameforge.locale.monster_chat_1305_3 = "Podejd\159 tutaj je\156li chcesz walczy\230! "
gameforge.locale.monster_chat_1305_4 = "Chyba nie my\156lisz o ucieczce, prawda? "
gameforge.locale.monster_chat_1305_5 = "Nie doceniasz pot\234gi mojego miecza. "
gameforge.locale.monster_chat_1305_6 = "Boisz si\234? (\156miech) "
gameforge.locale.monster_chat_1901_1 = "My\156l\234, \191e dzisiaj umrzesz na moich r\234kach. "
gameforge.locale.monster_chat_1901_2 = "Oh, lubi\234 Ci\234... "
gameforge.locale.monster_chat_1901_3 = "No to jak b\234dzie? M\243j kochany obiedzie... "
gameforge.locale.monster_chat_1901_4 = "Hey! Uciekanie jak zwyk\179y tch\243rz Ci nie pomo\191e. "
gameforge.locale.monster_chat_1901_5 = "Jeste\156 ju\191 pod wp\179ywem mojego zakl\234cia? Hmm? "
gameforge.locale.monster_chat_1901_6 = "Czy nie chcesz troszk\234 pokrzycze\230? (\156miech) "
gameforge.locale.monster_chat_20001_1 = "Chyba jeste\156 lekko zdenerwowany... nie b\243j si\234, nie powinno nic wybuchn\185\230. "
gameforge.locale.monster_chat_20001_2 = "Czasami mam tego wszystkiego do\156\230... "
gameforge.locale.monster_chat_20001_3 = "Nuuuuuuuda. Moje wnuki ju\191 nawet mnie nie odwiedzaj\185. "
gameforge.locale.monster_chat_20001_4 = "Kiedy si\234 starzejesz, potrzebujesz towarzystwa. "
gameforge.locale.monster_chat_20001_5 = "Moje najlepsze dni ju\191 min\234\179y. "
gameforge.locale.monster_chat_20002_1 = "S\179o\241ce jest takie gor\185ce... "
gameforge.locale.monster_chat_20002_2 = "Doskona\179a pogoda! Musz\234 zrobi\230 pranie. "
gameforge.locale.monster_chat_20002_3 = "Gdzie jest ten m\243j leniwy m\185\191?! "
gameforge.locale.monster_chat_20002_4 = "Nazywa siebie ojcem... a od dawna nie ma kontaktu ze swoimi dzie\230mi! "
gameforge.locale.monster_chat_20002_5 = "On w og\243le nie zarabia pieni\234dzy. Czyta tylko ksi\185\191ki... "
gameforge.locale.monster_chat_20003_1 = "Oooh, dudu, dziecko. Czy spa\179e\156 dobrze? "
gameforge.locale.monster_chat_20003_2 = "Pachniesz jak malutki anio\179ek. "
gameforge.locale.monster_chat_20003_3 = "Twoja mama jest taka szcz\234\156liwa, \191e jeste\156 zdrowy. "
gameforge.locale.monster_chat_20003_4 = "Chcesz zwr\243ci\230 na siebie uwag\234? A mo\191e jeste\156 g\179odny? "
gameforge.locale.monster_chat_20003_5 = "Dobre dziecko... spij kochanie, \156pij. "
gameforge.locale.monster_chat_20004_1 = "Kolejny nudny dzie\241... "
gameforge.locale.monster_chat_20004_2 = "Gdzie dzisiaj dostan\234 jakie\156 jedzenie? "
gameforge.locale.monster_chat_20004_3 = "Przeciwnicy ju\191 mnie nudz\185... "
gameforge.locale.monster_chat_20004_4 = "Zobaczymy. Mo\191e powinienem wpa\156\230 do lokalu Octavios? "
gameforge.locale.monster_chat_20004_5 = "Oh, przy okazji, wygl\185da na to, \191e nie b\234dzie ju\191 wojen. "
gameforge.locale.monster_chat_20005_1 = "Dusza Mistrza Garncarstwa przebiega przez koniuszki jego palc\243w. "
gameforge.locale.monster_chat_20005_2 = "Od kiedy kraina pogr\185\191y\179a si\234 w chaosie, wsz\234dzie panoszy si\234 z\179o. "
gameforge.locale.monster_chat_20005_3 = "Ka\191dy chce walczy\230. "
gameforge.locale.monster_chat_20005_4 = "Modl\234 si\234 o spokojny i wolny od wojen kraj. "
gameforge.locale.monster_chat_20005_5 = "Hej, my\156l\234 \191e powiniene\156 sobie troszk\234 odpocz\185\230. "
gameforge.locale.monster_chat_20006_1 = "Oh, co powinienem teraz zrobi\230? "
gameforge.locale.monster_chat_20006_2 = "Wci\185\191 szukam mojego brata. A obiecywa\179, \191e zawsze przy mnie b\234dzie! "
gameforge.locale.monster_chat_20006_3 = "Teraz widz\234 tylko wojownik\243w z mieczami. "
gameforge.locale.monster_chat_20006_4 = "T\234skni\234 za bratem. "
gameforge.locale.monster_chat_20006_5 = "Czy kto\156 widzia\179 mojego brata? "
gameforge.locale.monster_chat_20007_1 = "Hmm, to naprawd\234 \156wie\191e mi\234sko! "
gameforge.locale.monster_chat_20007_2 = "To dobrze, \191e ludzie zacz\234li je\156\230 wi\234cej mi\234sa. "
gameforge.locale.monster_chat_20007_3 = "Biznes idzie dobrze, ale dalej trudno jest zdoby\230 mi\234so. "
gameforge.locale.monster_chat_20007_4 = "Co si\234 dzieje z mi\234sem, kt\243re zam\243wili\156my? "
gameforge.locale.monster_chat_20007_5 = "Je\156li nie dotrze na czas, b\234dziemy musieli i\156\230 na polowanie. "
gameforge.locale.monster_chat_20008_1 = "Mam nadziej\234, \191e dzisiaj b\234d\234 mia\179 du\191o klient\243w. Jest pi\234kna pogoda. "
gameforge.locale.monster_chat_20008_2 = "Ten leniwy pies na pewno nied\179ugo przyjdzie i b\234dzie chcia\179 co\156 zje\156\230. "
gameforge.locale.monster_chat_20008_3 = "Oh, co za biedaczysko! "
gameforge.locale.monster_chat_20008_4 = "Kiedy\156 by\179 naprawd\234 wielkim wojownikiem. "
gameforge.locale.monster_chat_20008_5 = "Zastanawiam si\234, czemu ju\191 nie walczy. "
gameforge.locale.monster_chat_20009_1 = "Ech, ci m\179odzi faceci... tacy \191ywi i pe\179ni zapa\179u! "
gameforge.locale.monster_chat_20009_2 = "Wojownik wygl\185da o wiele lepiej kiedy niesie sw\185 bro\241. "
gameforge.locale.monster_chat_20009_3 = "Teraz wszyscy maj\185 taki zbrodniczy umys\179. "
gameforge.locale.monster_chat_20009_4 = "Poskrom swe serce, skoncentruj umys\179 i uko\179ysz sw\185 dusz\234. "
gameforge.locale.monster_chat_20009_5 = "Nie ma niezawodnej recepty na szcz\234\156cie. Jest jednak par\234 prostych zasad, kt\243rych nale\191y stale przestrzega\230. "
gameforge.locale.monster_chat_20010_1 = "Przynosz\234 Ci wspania\179y przedmiot. "
gameforge.locale.monster_chat_20010_2 = "Towary z dalekich kraj\243w! Pi\234kne, egzotyczne przedmioty! "
gameforge.locale.monster_chat_20010_3 = "Podejd\159cie! Chod\159cie tutaj wszyscy! "
gameforge.locale.monster_chat_20010_4 = "Chod\159cie ludzie, kupujcie! Taka okazja si\234 nie powt\243rzy! "
gameforge.locale.monster_chat_20010_5 = "Wok\243\179 mnie jest za du\191o z\179odziei. Powinni trzyma\230 si\234 z dala od mojego maj\185tku! "
gameforge.locale.monster_chat_20011_1 = "Wszystko tutaj wysch\179o... "
gameforge.locale.monster_chat_20011_2 = "Jako\156\230 zbo\191a jest gorsza ni\191 kiedy\156. "
gameforge.locale.monster_chat_20011_3 = "Co powoduje, \191e zbo\191e ro\156nie wolniej? "
gameforge.locale.monster_chat_20011_4 = "To zbo\191e jest kruche i smakuje zgnilizn\185. "
gameforge.locale.monster_chat_20011_5 = "To z\179y znak. W naszej wiosce rolnictwo to podstawa. "
gameforge.locale.monster_chat_20012_1 = "Ciastka Ry\191owe! Smaczne Ciastka Ry\191owe! "
gameforge.locale.monster_chat_20012_2 = "Sprzedaj\234 s\179odkie Ciastka Ry\191owe. "
gameforge.locale.monster_chat_20012_3 = "Zgadza si\234, interes nie idzie za dobrze... "
gameforge.locale.monster_chat_20012_4 = "A mo\191e spr\243buj\234 w innym mie\156cie? "
gameforge.locale.monster_chat_20012_5 = "Ale dooko\179a mnie jest tyle dzikich drapie\191nik\243w... "
gameforge.locale.monster_chat_20013_1 = "W takie dni, przebywanie na \179odzi to najlepszy pomys\179. "
gameforge.locale.monster_chat_20013_2 = "\140wietna pogoda na w\234dkowanie! "
gameforge.locale.monster_chat_20013_3 = "Jeszcze tylko w\234ze\179... gotowe! \175adna ryba nie odgryzie tego haka! "
gameforge.locale.monster_chat_20013_4 = "Ten przekl\234ty nied\159wied\159 zniszczy\179 moj\185 W\234dk\234! "
gameforge.locale.monster_chat_20013_5 = "Przyda\179oby si\234 kiedy\156 znowu po\179ata\230 te sieci. "
gameforge.locale.monster_chat_20014_1 = "Huh! "
gameforge.locale.monster_chat_20014_2 = "Nie martw si\234, taki ju\191 jestem. "
gameforge.locale.monster_chat_20014_3 = "Haaaaa! "
gameforge.locale.monster_chat_20014_4 = "I co ja mam uczyni\230, aby... O nie, co ja akurat powiedzia\179em? "
gameforge.locale.monster_chat_20014_5 = "Nie jestem odwa\191ny... "
gameforge.locale.monster_chat_20015_1 = "Ten top\243r s\179u\191y mi od ponad 20 lat. "
gameforge.locale.monster_chat_20015_2 = "Ci\185gle ostry, ale mo\191e ju\191 nie tak jak kiedy\156... "
gameforge.locale.monster_chat_20015_3 = "Chc\234 si\234 wzmocni\230 poprzez u\191ywanie go. "
gameforge.locale.monster_chat_20015_4 = "Ale potrzebuj\234 skamielin z minera\179ami. "
gameforge.locale.monster_chat_20015_5 = "Gdzie mog\234 je znale\159\230? "
gameforge.locale.monster_chat_20016_1 = "Klientela przychodzi t\179umnie. "
gameforge.locale.monster_chat_20016_2 = "Mam nadziej\234, \191e zd\185\191\234 ze wszystkim na czas. "
gameforge.locale.monster_chat_20016_3 = "Stal o stal, mocniej wal... "
gameforge.locale.monster_chat_20016_4 = "Tak powinien brzmie\230 m\179ot! "
gameforge.locale.monster_chat_20016_5 = "Gor\185co tutaj. "
gameforge.locale.monster_chat_20017_1 = "Nie mam ochoty gra\230 na instrumencie. "
gameforge.locale.monster_chat_20017_2 = "M\243j instrument nie jest w dobrym stanie. "
gameforge.locale.monster_chat_20017_3 = "Mo\191e powinienem sobie za\179atwi\230 nowy instrument? "
gameforge.locale.monster_chat_20017_4 = "M\243j instrument jest stary i wys\179u\191ony... kocham stare rzeczy! "
gameforge.locale.monster_chat_20017_5 = "Musz\234 niezw\179ocznie znale\159\230 nowe struny, aby wymieni\230 te zerwane. "
gameforge.locale.monster_chat_20018_1 = "Jestem taki zaj\234ty! "
gameforge.locale.monster_chat_20018_2 = "Ka\191dego dnia, przychodz\185 do mnie ranni ludzie. "
gameforge.locale.monster_chat_20018_3 = "Nawet nie mam czasu \191eby gdzie\156 wyj\156\230! "
gameforge.locale.monster_chat_20018_4 = "Sko\241czy\179y si\234 nam lekarstwa. "
gameforge.locale.monster_chat_20018_5 = "Chcia\179bym, aby kto\156 dostarczy\179 mi sk\179adniki na lekarstwo... "
gameforge.locale.monster_chat_20019_1 = "Od 30 lat chodz\234 w G\243ry z moim \179ukiem! "
gameforge.locale.monster_chat_20019_2 = "Dzi\234ki temu mog\179em wspom\243c \191on\234 i wychowa\230 tr\243jk\234 dzieci. "
gameforge.locale.monster_chat_20019_3 = "\175ycie jest ci\234\191kie, ale i tak warto je \191y\230. "
gameforge.locale.monster_chat_20019_4 = "A teraz p\234k\179a ci\234ciwa, nie mog\234 polowa\230... jak mam wy\191ywi\230 rodzin\234?! "
gameforge.locale.monster_chat_20019_5 = "Je\191eli nie naprawi\234 \179uku, b\234d\234 musia\179 odej\156\230 na emerytur\234... "
gameforge.locale.monster_chat_20020_1 = "Hey! Na co si\234 tak gapisz?! "
gameforge.locale.monster_chat_20020_2 = "Odejd\159 st\185d! "
gameforge.locale.monster_chat_20020_3 = "Oh, jak d\179ugo jeszcze b\234d\234 si\234 musia\179 ukrywa\230? "
gameforge.locale.monster_chat_20020_4 = "Czy umr\234 jako samotnik, ca\179kiem zapomniany? "
gameforge.locale.monster_chat_20020_5 = "Aaaaah, mam nadziej\234, \191e kto\156 mi pomo\191e... "
gameforge.locale.monster_chat_20021_1 = "Ten dzie\241 sko\241czy si\234 tak jak wszystkie inne. "
gameforge.locale.monster_chat_20021_2 = "Co teraz mog\234 zrobi\230, huh? "
gameforge.locale.monster_chat_20021_3 = "Nigdy nie my\156la\179em, \191e to tak si\234 sko\241czy. "
gameforge.locale.monster_chat_20021_4 = "Nie! On nie mo\191e by\230 jedynym, kt\243ry tak sko\241czy! "
gameforge.locale.monster_chat_20021_5 = "Mam nadziej\234, \191e kto\156 go pom\156ci! "
gameforge.locale.monster_chat_20022_1 = "Znowu pi\234kny dzie\241! "
gameforge.locale.monster_chat_20022_2 = "Zagin\185\179 m\185\191 Ariyoung. "
gameforge.locale.monster_chat_20022_3 = "Chcia\179em pom\243c, ale ten up\243r... "
gameforge.locale.monster_chat_20022_4 = "Je\156li by mnie po\156lubi\179a, mia\179aby znacznie lepsze \191ycie. "
gameforge.locale.monster_chat_20022_5 = "Mo\191e powinienem okazywa\230 swoje uczucia lepiej... "
gameforge.locale.monster_chat_20023_1 = "Oh nie! Co ja zrobi\234 kiedy moja \191ona si\234 o tym dowie?! "
gameforge.locale.monster_chat_20023_2 = "Gdybym tylko m\243g\179 \191y\230 z czytania ksi\185\191ek... "
gameforge.locale.monster_chat_20023_3 = "Ksi\185\191ki s\185 takie tajemnicze. "
gameforge.locale.monster_chat_20023_4 = "Nie mog\234 tak \191y\230 ca\179y czas, ale... "
gameforge.locale.monster_chat_20023_5 = "My\156l\234, \191e mog\234 co\156 zrobi\230 dla mojej \191ony, ale... "
gameforge.locale.monster_chat_20024_1 = "No dawaj! W\179\243\191 wi\234cej uczucia w swoje ruchy! "
gameforge.locale.monster_chat_20024_2 = "Co ty tam robisz?! Nie mo\191esz si\234 pospieszy\230? "
gameforge.locale.monster_chat_20024_3 = "Wyobra\159 sobie po prostu, jak wojownik w\179ada mieczem i powt\243rz ten ruch! "
gameforge.locale.monster_chat_20024_4 = "Gdzie jest ten gamo\241 z mieczem? "
gameforge.locale.monster_chat_20024_5 = "To pies! Nie jeste\156 m\234\191czyzn\185, ha! "
gameforge.locale.monster_chat_2091_1 = "ciach, ciach... w\179osy, szyje... "
gameforge.locale.monster_chat_2091_2 = "Mam co\156 dla ciebie: wieczny sen! "
gameforge.locale.monster_chat_2091_3 = "G\179\234boki wdech i.... wydech. Nie martw si\234, to tylko trucizna! "
gameforge.locale.monster_chat_2091_4 = "Pozostawi\234 jedynie twoj\185 twarz! Tak ku ozdobie... "
gameforge.locale.monster_chat_2091_5 = {}
gameforge.locale.monster_chat_2091_6 = "Zawini\234ty paj\234czyn\185 b\234dziesz w sam raz na p\243\159niejsz\185 przek\185sk\234... "
gameforge.locale.monster_chat_2092_1 = "Nie mog\234 znie\156\230 j\234k\243w mojej \191ony... "
gameforge.locale.monster_chat_2092_2 = "Dlaczego nie mog\234 spa\230? "
