gameforge.locale.monster_chat_2092_6 = "Nikt mi tutaj nie dor\243wnuje! "
gameforge.locale.monster_chat_2104_1 = "Ech, dlaczego ludzie maj\185 tyle tej krwi? Jak tak dalej p\243jdzie to m\243j miecz zupe\179nie zerdzewieje! "
