gameforge.locale.monster_chat_2106_3 = "To lubi\234! Tak bardzo to lubi\234! (\156miech) "
gameforge.locale.monster_chat_2106_4 = "Ten tam jest fajnie t\179u\156ciutki. Jest m\243j! "
gameforge.locale.monster_chat_2106_5 = {}
gameforge.locale.monster_chat_2106_6 = "Lubi\234 zapach krwi. "
