gameforge.locale.monster_chat_2107_2 = "Hej! Ten jest naprawd\234 gruby! "
gameforge.locale.monster_chat_2107_3 = "To si\234 spodoba dow\243dcy... "
gameforge.locale.monster_chat_2107_4 = {}
gameforge.locale.monster_chat_2107_5 = "Ruszajmy! "
gameforge.locale.monster_chat_2107_6 = "Nadci\185ga strza\179a! "
