gameforge.locale.monster_chat_2291_6 = "Za p\243\159no na ucieczk\234! I tak to Ci nic nie pomo\191e! "
gameforge.locale.monster_chat_301_1 = "Nuda! Nie ma ju\191 nic ciekawego do roboty? "
gameforge.locale.monster_chat_301_2 = "Dwa dni temu, przyszed\179 tu bardzo przystojny facet! "
