gameforge.locale.monster_chat_302_6 = "Oh! Chc\234 i\156\230 na zakupy! "
gameforge.locale.monster_chat_303_1 = "Nasze dzieci s\185 ostatnio bardzo leniwe. "
gameforge.locale.monster_chat_303_2 = "Co si\234 stanie, gdy \191o\179nierze zdecyduj\185 si\234 na atak?! "
