gameforge.locale.monster_chat_303_6 = "Ta walka b\234dzie ci\234\191sza ni\191 mo\191na by\179o przypuszcza\230. "
gameforge.locale.monster_chat_304_1 = "Kobiety, nie mo\191ecie by\230 ci\185gle zale\191ne od m\234\191czyzn! "
gameforge.locale.monster_chat_304_2 = "Nie ma dobrych facet\243w! "
