gameforge.locale.monster_chat_305_5 = "Oh! Jestem tylko s\179ab\185 kobiet\185! "
gameforge.locale.monster_chat_305_6 = "Zm\234czony? Czemu si\234 po prostu nie poddasz? Hehe. "
gameforge.locale.monster_chat_306_1 = "Co zrobi dzi\156 nasz przyw\243dca, hm? "
