gameforge.locale.monster_chat_306_6 = "B\243l potrwa tylko chwil\234... "
gameforge.locale.monster_chat_307_1 = "Chc\234 si\234 st\185d wydosta\230 za wszelk\185 cen\234! "
gameforge.locale.monster_chat_307_2 = "A jak s\185 zabezpieczone ich domy? "
gameforge.locale.monster_chat_307_3 = "Zamknij si\234! "
