gameforge.locale.monster_chat_307_6 = "Wi\234c, dlaczego jeszcze nie zacz\234li\156my? "
gameforge.locale.monster_chat_394_1 = "Pami\234tajcie: wszyscy m\234\191czy\159ni s\185 wrogami! "
gameforge.locale.monster_chat_394_2 = "Je\156li kto\156 ma \179adn\185 bu\159k\234, mo\191emy by\230 mniej wredne. "
