gameforge.locale.monster_chat_405_4 = "Pierwsze, tw\243j brzuch! "
gameforge.locale.monster_chat_405_5 = "U\191yj\234 Ci\234 jako tarczy. "
gameforge.locale.monster_chat_405_6 = "U\191yj\234 Ci\234 jako tarczy. "
