gameforge.locale.monster_chat_492_5 = "Widzia\179e\156 m\243j styl ataku? Nie? Twoja strata! "
gameforge.locale.monster_chat_492_6 = "Nawet najmniejsze zadrapanie b\234dzie dla Ciebie \156miertelne! "
