gameforge.locale.monster_chat_493_6 = "Wiem, \191e gapisz si\234 na moj\185 r\234k\234! "
gameforge.locale.monster_chat_494_1 = "Hey, ty! Je\191eli chcesz walczy\230, podejd\159 tu! "
