gameforge.locale.monster_chat_603_6 = "To b\234dzie ostatni cios, wyko\241cz\234 Ci\234! "
gameforge.locale.monster_chat_604_1 = "Przyrz\185dzi\179em pyszn\185 now\185 trucizn\234. Mo\191e skosztujesz? "
