gameforge.locale.monster_chat_604_4 = "Zatruj\234 Ci\234! "
gameforge.locale.monster_chat_604_5 = "Hej, chcesz by\230 moim kr\243likiem do\156wiadczalnym? "
gameforge.locale.monster_chat_604_6 = "Ju\191 si\234 podda\179e\156? A gdzie zabawa?! No dalej, bro\241 si\234! "
gameforge.locale.monster_chat_631_1 = "Chwileczk\234, szukam czego\156 do upolowania. "
gameforge.locale.monster_chat_631_2 = "Nie uda Ci si\234, je\191eli b\234dziesz tak powolny! "
gameforge.locale.monster_chat_631_3 = "Jestem taki g\179odny! "
gameforge.locale.monster_chat_631_4 = "Super, w ko\241cu mam na kogo polowa\230! "
gameforge.locale.monster_chat_631_5 = "Niech ma nadziej\234, \191e prze\191yje! "
gameforge.locale.monster_chat_631_6 = "Pozwol\234 Ci poczu\230 prawdziwy b\243l! "
gameforge.locale.monster_chat_632_1 = "Nuuuuda! "
gameforge.locale.monster_chat_632_2 = "Jest tam co\156 nadaj\185cego si\234 na przyn\234t\234? "
gameforge.locale.monster_chat_632_3 = "Chod\159 i walcz je\156li masz ochot\234! "
gameforge.locale.monster_chat_632_4 = "Jeste\156 wojownikiem? Udowodnij! "
gameforge.locale.monster_chat_632_5 = {}
gameforge.locale.monster_chat_632_6 = "Je\191eli chcesz prze\191y\230, uciekaj do wioski! "
gameforge.locale.monster_chat_633_1 = "Umiera\230 z g\179odu, to boli... "
gameforge.locale.monster_chat_633_2 = "Oh, dobieraj\185 si\234 do nas. "
gameforge.locale.monster_chat_633_3 = "Co powiesz na pojedynek? "
gameforge.locale.monster_chat_633_4 = "Nie por\243wnuj mnie do tych drani! "
gameforge.locale.monster_chat_633_5 = "A oto cios jak b\179yskawica! "
gameforge.locale.monster_chat_633_6 = "Kto teraz ucieknie, nie jest prawdziwym wojownikiem! "
gameforge.locale.monster_chat_634_1 = "Tym razem trucizna jest silniejsza! "
gameforge.locale.monster_chat_634_2 = "Nie masz co je\156\230? Nietoperze s\185 bardzo smaczne. "
gameforge.locale.monster_chat_634_3 = "Co powiesz na walk\234? "
gameforge.locale.monster_chat_634_4 = "Je\156li trucizna dostanie si\234 do cia\179a, nie da si\234 tego uleczy\230! "
gameforge.locale.monster_chat_634_5 = "Moja magia spali wszystko, hehehe! "
gameforge.locale.monster_chat_634_6 = "P\179o\241! Ha, ha! "
gameforge.locale.monster_chat_635_1 = "Tylko nie zapomnij naostrzy\230 miecza! Zawsze mo\191esz z kim\156 powalczy\230! "
gameforge.locale.monster_chat_635_2 = "Omdlenie? "
gameforge.locale.monster_chat_635_3 = "Zgi\241, aby\156 m\243g\179 si\234 przebudzi\230! "
gameforge.locale.monster_chat_635_4 = "Pokona\230 mnie? Wierzysz w cuda? "
gameforge.locale.monster_chat_635_5 = "Walcz jak wojownik! "
gameforge.locale.monster_chat_635_6 = "No dalej, jeszcze tylko troszk\234. "
gameforge.locale.monster_chat_636_1 = "Widz\234, \191e czeka mnie ciekawa walka. "
gameforge.locale.monster_chat_636_2 = "Pojedynki to sama rado\156\230. "
gameforge.locale.monster_chat_636_3 = "Chc\234 walczy\230 ca\179y czas! "
gameforge.locale.monster_chat_636_4 = "A to dobre! Spr\243buj jeszcze raz! "
gameforge.locale.monster_chat_636_5 = "Sp\243jrz na moj\185 bro\241! Nie masz szans! "
gameforge.locale.monster_chat_636_6 = "Przeprosisz za to uderzenie! "
gameforge.locale.monster_chat_636_7 = "Taki s\179aby! Taki \191a\179osny! "
gameforge.locale.monster_chat_637_1 = "Nie chc\234, aby mi kto\156 przeszkadza\179. "
gameforge.locale.monster_chat_637_2 = "Id\159 spa\230. Na zawsze! "
gameforge.locale.monster_chat_637_3 = "Jeszcze nie \156pisz? "
gameforge.locale.monster_chat_637_4 = "Pozosta\179o wiele do zrobienia! Zaczynajmy! "
gameforge.locale.monster_chat_637_5 = "Nie martw si\234 o moj\185 moc! "
gameforge.locale.monster_chat_637_6 = "Zmiel\234 Ci\234 na drobny mak! "
gameforge.locale.monster_chat_691_1 = "Wspaniale, silni przeciwnicy wytrzymuj\185 d\179u\191ej! Bro\241 si\234! "
gameforge.locale.monster_chat_691_2 = "\175e co? \175e jak wygl\185dam? "
gameforge.locale.monster_chat_691_3 = "Nie por\243wnuj mnie do tego nowicjusza! "
gameforge.locale.monster_chat_691_4 = "On Ci\234 nie lubi, ja zreszt\185 te\191! "
gameforge.locale.monster_chat_691_5 = "Walczmy! "
gameforge.locale.monster_chat_691_6 = "A\191 do \156mierci! "
gameforge.locale.monster_chat_701_1 = "Sp\243jrz, motyl! Jaki pi\234kny! "
gameforge.locale.monster_chat_701_2 = "Nie znasz jeszcze prawdy o Niebie i Piekle? "
gameforge.locale.monster_chat_701_3 = "Uwierz teraz! P\243\159niej b\234dzie ju\191 za p\243\159no! "
gameforge.locale.monster_chat_701_4 = "Uwierz w doktryn\234 mistycyzmu! "
gameforge.locale.monster_chat_701_5 = "Ten kto zw\185tpi, zginie! "
gameforge.locale.monster_chat_701_6 = "B\185d\159 o\156wiecony przed nadej\156ciem \156mierci! "
gameforge.locale.monster_chat_702_1 = "Prawda wierze\241 ezoterycznych spoczywa w zrozumieniu \179adu nieba. "
gameforge.locale.monster_chat_702_2 = "Filozofia wierze\241 mistycznych jest darem z niebios! "
gameforge.locale.monster_chat_702_3 = "Mistyczna prawda, prawda Boga Tygrysa! Sabaha! Sabaha! "
gameforge.locale.monster_chat_702_4 = "\140miesz w\185tpi\230 w prawd\234 o Niebie i Ziemi?! "
gameforge.locale.monster_chat_702_5 = {}
gameforge.locale.monster_chat_702_6 = "Nadci\185ga moja bro\241! "
gameforge.locale.monster_chat_703_1 = "Je\156li zawsze b\234dziemy powtarza\230 dogmaty Boga Tygrysa, nasze cierpienie si\234 zako\241czy. "
gameforge.locale.monster_chat_703_2 = "Prawda wierze\241 ezoterycznych spoczywa w zrozumieniu \179adu nieba. "
gameforge.locale.monster_chat_703_3 = "Sabaha! Sabaha! Za\156lij na nas sw\185 wiedz\234! "
gameforge.locale.monster_chat_703_4 = "Nie w\185tp! "
gameforge.locale.monster_chat_703_5 = "Ze\156lij grom z nieba! "
gameforge.locale.monster_chat_703_6 = "Cios sprawiedliwo\156ci! "
gameforge.locale.monster_chat_704_1 = "Prawda wierze\241 ezoterycznych spoczywa w zrozumieniu \179adu nieba. "
gameforge.locale.monster_chat_704_2 = "Mistyczna prawda, prawda Boga Tygrysa! Sabaha! Sabaha! "
gameforge.locale.monster_chat_704_3 = "My\156lisz, \191e wygl\185dam jak klown? Zaraz zmienisz zdanie! "
gameforge.locale.monster_chat_704_4 = "Lider kultu jest \156wi\234tym! Jest ponad wszystkimi. "
gameforge.locale.monster_chat_704_5 = "Sp\179o\241 w ogniach piekielnych! "
gameforge.locale.monster_chat_704_6 = "Zgaduj\234, \191e nigdy nie widzia\179e\156 tak silnego przeciwnika, huh? "
gameforge.locale.monster_chat_705_1 = "Mistyczna prawda, prawda Boga Tygrysa! Sabaha! Sabaha! "
gameforge.locale.monster_chat_705_2 = "Prawda wierze\241 ezoterycznych spoczywa w zrozumieniu \179adu nieba. "
gameforge.locale.monster_chat_705_3 = "To, \191e jestem mniejszy od mojego brata nie oznacza, \191e jestem s\179abszy! "
gameforge.locale.monster_chat_705_4 = "Czeka na Ciebie wieczna ciemno\156\230 i b\243l! "
gameforge.locale.monster_chat_705_5 = {}
gameforge.locale.monster_chat_705_6 = "To nie koniec, b\234dzie lepiej! "
gameforge.locale.monster_chat_706_1 = "Chcemy pokoju i prywatno\156ci! Prosimy! "
gameforge.locale.monster_chat_706_2 = "Kiedy panuje strach, prawda Boga Tygrysa nam pomaga! "
gameforge.locale.monster_chat_706_3 = "Prawda mistycyzmu jest jednocze\156nie darem i przekle\241stwem niebios! "
gameforge.locale.monster_chat_706_4 = "Wszyscy znajdziemy si\234 w piekle! "
gameforge.locale.monster_chat_706_5 = "Nie pozwol\234 Ci odej\156\230! "
gameforge.locale.monster_chat_706_6 = "Dam Ci wszystko co mam. "
gameforge.locale.monster_chat_707_1 = "B\179agam, ocal nas! "
gameforge.locale.monster_chat_707_2 = "Prawda wierze\241 ezoterycznych spoczywa w zrozumieniu \179adu nieba. "
gameforge.locale.monster_chat_707_3 = "Mistyczna prawda, prawda Boga Tygrysa! Sabaha! Sabaha! "
gameforge.locale.monster_chat_707_4 = "Bramy piek\179a stoj\185 otworem, gi\241! (gro\159ny \156miech) "
gameforge.locale.monster_chat_707_5 = "Ostrzegam: nie zmuszaj mnie do u\191ycia si\179y! "
gameforge.locale.monster_chat_707_6 = "Ju\191 widz\234 twoj\185 \156mier\230! "
gameforge.locale.monster_chat_791_1 = "Jak\191e m\243g\179bym opowiedzie\230 ci w skr\243cie o drodze Boga Tygrysa? "
gameforge.locale.monster_chat_791_2 = "S\179ysz\234 monotonne \156piewy wierz\185cych. "
gameforge.locale.monster_chat_791_3 = "To prawda! B\185d\159 pe\179en wyrzut\243w sumienia a b\234dziesz zbawiony! "
gameforge.locale.monster_chat_791_4 = "B\234dziesz cierpia\179, poniewa\191 zw\185tpi\179e\156! "
gameforge.locale.monster_chat_791_5 = "Pozw\243l, \191e Ci\234 czego\156 naucz\234... "
gameforge.locale.monster_chat_791_6 = "Nie my\156l, \191e to b\243l, to instrukcje! "
gameforge.locale.monster_chat_901_1 = "Mo\191e nie wygl\185dam atrakcyjnie, ale mam poczucie humoru, hihihihi! "
gameforge.locale.monster_chat_901_2 = "Staniesz si\234 taki jak my! "
gameforge.locale.monster_chat_901_3 = "Podejd\159 tutaj, hihi! "
gameforge.locale.monster_chat_901_4 = "Haaa, haha! "
gameforge.locale.monster_chat_901_5 = "Zaczyna si\234... "
gameforge.locale.monster_chat_903_1 = "Tak wygl\185da piek\179o! "
gameforge.locale.monster_chat_903_2 = "Ahhhhh! "
gameforge.locale.monster_chat_903_3 = "Nie mo\191emy zrobi\230 tego sami! Nie! "
gameforge.locale.monster_chat_903_4 = "Musisz posmakowa\230 b\243lu! "
gameforge.locale.monster_chat_903_5 = "Co powiesz na ma\179\185 wymian\234? Twoja dusza za moje cierpienie! "
gameforge.locale.monster_chat_903_6 = "Wkr\243tce dost\185pisz wiecznego spokoju... "
gameforge.locale.monster_chat_904_1 = "To boli! Oh, to boli! "
gameforge.locale.monster_chat_904_2 = "Aargghh, cholera! Moja r\234ka p\179onie! "
