gameforge.locale.old_pirate.etc_shop_start_say = "Handlarka R\243\191no\156ci:[ENTER]Stary Pirat? Oczywi\156cie, \191e go znam. To ten go\156\230,[ENTER]kt\243ry zawsze przeklina i si\234 drapie, prawda?[ENTER]Zawsze przychodzi kupi\230 jakie\156 p\179ynne lekarstwo.[ENTER]Wyda\179 wiele tysi\234cy Yang na Czerwone Mikstury. "
