gameforge.locale.old_pirate.order_accept_answer = "Stary Pirat:[ENTER]\140wietnie. Powodzenia![ENTER]Lekarz na pewno jest w mie\156cie. "
gameforge.locale.old_pirate.order_find_medicine_label = "Lekarstwo dla Starego Pirata "
gameforge.locale.old_pirate.order_find_medicine_text_1 = "Zdob\185d\159 lekarstwo dla Starego Pirata. "
gameforge.locale.old_pirate.order_find_medicine_text_2 = "Udaj si\234 do Baek-Go w mie\156cie i spytaj si\234 go o[ENTER]lekarstwo dla Starego Pirata. "
gameforge.locale.old_pirate.order_refuse = "Niestety, nie mog\234. "
gameforge.locale.old_pirate.order_refuse_answer = "Stary Pirat:[ENTER]W takim razie, nie mam nic wi\234cej do powiedzenia! "
gameforge.locale.old_pirate.order_say1 = "Stary Pirat:[ENTER]Cholera! Czego chcesz? Cholera! Ten rupie\230[ENTER]sprzedawca sklepowy powiedzia\179 Ci co\156 o mnie,[ENTER]tak?[ENTER]Taa, to prawda. Ale ja nie mam czasu, \191eby i\156\230 do[ENTER]lekarza. Mam tylu wrog\243w! "
gameforge.locale.old_pirate.order_say2 = "Stary Pirat:[ENTER]Nigdy nie wiesz, czy jaki\156 dra\241 nagle nie[ENTER]znajdzie si\234 przy tobie i nie d\159gnie Ci\234! Ale to[ENTER]naprawd\234 sw\234dzi... Nie mog\234 wytrzyma\230... Wi\234c -[ENTER]czy m\243g\179by\156 p\243j\156\230 do lekarza i przynie\156\230 mi[ENTER]lekarstwo na t\185 chorob\234? Zostaniesz sowicie[ENTER]wynagrodzony... "
gameforge.locale.old_pirate.order_too_late = "Stary Pirat:[ENTER]Kto\156 inny przyni\243s\179 mi ju\191 lekarstwo. Wi\234c nie[ENTER]dostaniesz ode mnie nagrody! "
gameforge.locale.old_pirate.start_find_old_pirate_label = "Id\159 do Starego Pirata. "
gameforge.locale.old_pirate.start_find_old_pirate_text_1 = "Id\159 do Starego Pirata. "
gameforge.locale.old_pirate.start_find_old_pirate_text_2 = "Id\159 do Starego Pirata i zapytaj, dlaczego nie[ENTER]p\243jdzie do lekarza. "
gameforge.locale.old_pirate.start_say = "Stary Pirat:[ENTER]Wszystko mnie sw\234dzi!!! Nie powinienem by\179 wpada\230[ENTER]na tego go\156cia. To by\179 jeden dotyk! Od tamtego[ENTER]czasu ta cz\234\156\230 ropieje i ca\179e moje cia\179o sw\234dzi![ENTER]Wydaje mi si\234, \191e gnij\234 za \191ycia. Cholerny dra\241! "
gameforge.locale.old_pirate.success_thanks = "Stary Pirat:[ENTER]Co? Zosta\179em zara\191ony tajemnicz\185 chorob\185? To jest[ENTER]potrzebne lekarstwo! Bardzo, bardzo dzi\234kuj\234![ENTER]Uratowa\179e\156 mi \191ycie! Jestem Ci bardzo wdzi\234czny! "
