gameforge.locale.questscroll5.mission_10_text = "Oh, prosz\234, pom\243\191 nam. Ostatnio wzros\179a liczba[ENTER]Czarnych Nied\159wiedzi i Nied\159wiedzi Grizzly.[ENTER]Niszcz\185 nasze sady i ule. Prosz\234, pom\243\191 nam. Bez[ENTER]miodu i owoc\243w umrzemy z g\179odu. Zabij te bestie[ENTER]dla nas. "
