gameforge.locale.questscroll5.mission_39_text = "Czy 's\179ysza\179e\156 o Wie\191y Demon\243w?[ENTER]Ezoteryczne Sekty przywo\179a\179y tam Demonicznych[ENTER]\175o\179nierzy swoimi pot\234\191nymi czarami. Zwalcz je i[ENTER]dowiedz si\234 jak mocne one s\185. "
gameforge.locale.questscroll5.mission_3_hunt = "Atak Szarych Wilk\243w 2 "
gameforge.locale.questscroll5.mission_3_mis = "Zabij 30 Szarych Alfa Wilk\243w. "
gameforge.locale.questscroll5.mission_3_text = "S\179ysza\179e\156 o Szarych Alfa Wilkach? Przewa\191nie[ENTER]podr\243\191uj\185 gdzie\156 same, ale wp\179yw z\179ej mocy Chi w[ENTER]ostatnich tygodniach sprawi\179, \191e zacz\234\179y polowa\230[ENTER]na podr\243\191nych. Czy m\243g\179by\156 wyeliminowa\230 te Szare[ENTER]Alfa Wilki? Bardzo Ci\234 o to prosz\234. Oczywi\156cie[ENTER]otrzymasz nagrod\234. "
gameforge.locale.questscroll5.mission_40_hunt = "Kompania Martwych 2 "
gameforge.locale.questscroll5.mission_40_mis = "Zabij 30 Demon W\179\243cznik\243w i 25 Demon Szaman\243w. "
gameforge.locale.questscroll5.mission_40_text = "Czy 's\179ysza\179e\156 o Wie\191y Demon\243w?[ENTER]Ezoteryczne Sekty przywo\179a\179y tam Demonicznych[ENTER]\175o\179nierzy swoimi pot\234\191nymi czarami. Zwalcz je i[ENTER]dowiedz si\234 jak mocne one s\185. "
gameforge.locale.questscroll5.mission_41_hunt = "Tajemnica Trudnego Lochu 2 "
gameforge.locale.questscroll5.mission_41_mis = "Zabij 15 Silnych Ma\179pich Wojownik\243w i 15 Silnych[ENTER]Ma\179pich Genera\179\243w. "
gameforge.locale.questscroll5.mission_41_text = "W ko\241cu odnaleziono Trudny Ma\179pi Loch. Na co[ENTER]dzie\241 te ma\179py nie s\185 zagro\191eniem, jednak je\156li[ENTER]pozostawimy je w spokoju, mog\185 si\234 nim sta\230. Id\159[ENTER]do Trudnego Lochu Ma\179p i dowiedz si\234 jak wygl\185da[ENTER]sytuacja. "
gameforge.locale.questscroll5.mission_42_hunt = "Pewnego dnia l\243d stopnieje "
gameforge.locale.questscroll5.mission_42_mis = "Zabij 25 Lodowych Golem\243w na G\243rze Sohan. "
gameforge.locale.questscroll5.mission_42_text = "Znasz pokryt\185 wiecznym lodem G\243r\234 Sohan? Wielu[ENTER]wojownik\243w i badaczy wyruszy\179o na jej podbicie,[ENTER]lecz s\179uch o nich zagin\185\179 bezpowrotnie. Dowiedz[ENTER]si\234 dlaczego tak si\234 sta\179o, i czy zostali przez[ENTER]kogo\156 zaatakowani. By\230 mo\191e uzyskasz jakie\156[ENTER]informacje poluj\185c na tamtejsze potwory. "
gameforge.locale.questscroll5.mission_43_hunt = "Tajemnica Trudnego Lochu 1 "
gameforge.locale.questscroll5.mission_43_mis = "Zabij 30 Silnych Ma\179pich \175o\179nierzy i 30 Silnych[ENTER]Ma\179pich Miotaczy. "
gameforge.locale.questscroll5.mission_43_text = "W ko\241cu odnaleziono Trudny Ma\179pi Loch. Na co[ENTER]dzie\241 te ma\179py nie s\185 zagro\191eniem, jednak je\156li[ENTER]pozostawimy je w spokoju, mog\185 si\234 nim sta\230. Id\159[ENTER]do Trudnego Lochu Ma\179p i dowiedz si\234 jak wygl\185da[ENTER]sytuacja. "
gameforge.locale.questscroll5.mission_44_hunt = "Prawa r\234ka Zjawy \175\243\179tego Tygrysa "
gameforge.locale.questscroll5.mission_44_mis = "Zabij 30 Ropuszych Genera\179\243w. "
gameforge.locale.questscroll5.mission_44_text = "Zjawa \175\243\179tego Tygrysa, kr\243l istnie\241 na tym[ENTER]kontynencie, ostatnio zmobilizowa\179 swoich[ENTER]poddanych. Tajna policja Kr\243lestwa uwa\191a, \191e to[ENTER]w\179a\156nie jest powodem szale\241stwa okolicznych[ENTER]potwor\243w i zwierz\185t. Trzeba zredukowa\230 oddzia\179y[ENTER]Zjawy \175\243\179tego Tygrysa. Zabij przyw\243dc\243w[ENTER]powstania, to znacznie os\179abi si\179\234 Tygrysa. "
gameforge.locale.questscroll5.mission_45_hunt = "Pan G\243ry Sohan? "
gameforge.locale.questscroll5.mission_45_mis = "Zabij 35 Mro\159nych Lodowych Ludzi i 30 Yeti. "
gameforge.locale.questscroll5.mission_45_text = "Plotka g\179osi, \191e Lis o Dziewi\234ciu Ogonach, pan[ENTER]G\243ry Sohan, gromadzi demoniczne bestie wok\243\179[ENTER]siebie. Zanim zdo\179a zebra\230 ich wystarczaj\185c\185[ENTER]ilo\156\230, musimy wyeliminowa\230 Lodowych Ludzi i Yeti,[ENTER]stanowi\185 oni filar jego oddzia\179\243w. Prosz\234, pom\243\191[ENTER]nam, nagroda Ci\234 nie ominie. "
gameforge.locale.questscroll5.mission_46_hunt = "Chunwa Bong-ki "
gameforge.locale.questscroll5.mission_46_mis = "Zabij 45 Drzewnych \175abich \175o\179nierzy i 35[ENTER]Drzewnych \175abich Przyw\243dc\243w. "
gameforge.locale.questscroll5.mission_46_text = "Zjawa \175\243\179tego Tygrysa wydaje si\234 knu\230 spisek z[ENTER]Drzewnymi \175abami. Wytrzeb ich zjednoczone si\179y, w[ENTER]przeciwnym razem mo\191e si\234 to \159le sko\241czy\230 dla[ENTER]Kr\243lestwa! "
gameforge.locale.questscroll5.mission_47_hunt = "Lodowe Potwory! Ich prawdziwy charakter "
gameforge.locale.questscroll5.mission_47_mis = "Zabij 45 Zaczarowanych Lod\243w. "
gameforge.locale.questscroll5.mission_47_text = "Wiemy w jaki spos\243b Potwory z Gory Sohan si\234[ENTER]porozumiewaj\185. Najwa\191niejsz\185 rol\234 pe\179ni\185[ENTER]Zaczarowane Lody. Pilnie musimy os\179abi\230 ich[ENTER]oddzia\179y na G\243rze Sohan. Prosz\234, zredukuj ilo\156\230[ENTER]Zaczarowanych Lod\243w! "
gameforge.locale.questscroll5.mission_48_hunt = "Tajemnica Wie\191y Demon\243w "
gameforge.locale.questscroll5.mission_48_mis = "Zabij 45 Brutalnych Demon W\179\243cznik\243w. "
gameforge.locale.questscroll5.mission_48_text = "Kr\185\191\185 plotki, \191e Podli W\179\243cznicy w Wie\191y Demon\243w[ENTER]s\185 nie do pokonania. Pono\230 za ka\191dym razem gdy[ENTER]zostan\185 zabici, po prostu od\191ywaj\185 gotowi do[ENTER]dalszej walki. Je\156li to si\234 zgadza, czekaj\185 nas[ENTER]mroczne czasy. Prosz\234, dowiedz si\234 nieco wi\234cej[ENTER]na ten temat! "
gameforge.locale.questscroll5.mission_49_hunt = "W\179adca Wie\191y Demon\243w "
gameforge.locale.questscroll5.mission_49_mis = "Zabij 60 Brutalnych Demon Szaman\243w. "
gameforge.locale.questscroll5.mission_49_text = "Po wa\191nych badaniach, odnale\159li\156my \159r\243d\179o[ENTER]ci\185g\179ego wskrzeszania duch\243w wojownik\243w. Musimy[ENTER]wyeliminowa\230 Brutalnych Demon Szaman\243w, aby[ENTER]unikn\185\230 powrotu k\179opot\243w. "
gameforge.locale.questscroll5.mission_4_hunt = "Atak Szarych Wilk\243w 1 "
gameforge.locale.questscroll5.mission_4_mis = "Zabij 35 Szarych Wilk\243w. "
gameforge.locale.questscroll5.mission_4_text = "S\179ysza\179e\156 o Szarych Wilkach? Przewa\191nie podr\243\191uj\185[ENTER]gdzie\156 same, ale wp\179yw z\179ej mocy Chi w ostatnich[ENTER]tygodniach sprawi\179, \191e zacz\234\179y polowa\230 na[ENTER]podr\243\191nych. Czy m\243g\179by\156 wyeliminowa\230 te Szare[ENTER]Wilki? Bardzo Ci\234 o to prosz\234. Oczywi\156cie[ENTER]otrzymasz nagrod\234. "
gameforge.locale.questscroll5.mission_50_hunt = "Zbadaj Doyyumhwan "
gameforge.locale.questscroll5.mission_50_mis = "Zabij 45 S\179ug Walcz\185cego Tygrysa. "
gameforge.locale.questscroll5.mission_50_text = "Doyyumhwan jest obszarem lawowym, kt\243ry jest[ENTER]zasiedlony przez nieznane bestie. Musimy zbada\230[ENTER]ten teren. Czy mo\191esz nam w tym pom\243c? "
gameforge.locale.questscroll5.mission_51_hunt = "Ogniste Duchy! Ich to\191samo\156\230 "
gameforge.locale.questscroll5.mission_51_mis = "Zabij 45 Ognistych Duch\243w. "
gameforge.locale.questscroll5.mission_51_text = "Grupa, kt\243ra powinna unicestwi\230 Walcz\185ce Tygrysy,[ENTER]zosta\179a wyeliminowana w nieznanych[ENTER]okoliczno\156ciach. M\243wi si\234, \191e pokona\179y ich[ENTER]postacie wygl\185daj\185ce jak p\179on\185ce dziewczyny.[ENTER]Odkryj jaka jest prawda. "
gameforge.locale.questscroll5.mission_52_hunt = "Zredukuj liczb\234 Walcz\185cych Tygrys\243w "
gameforge.locale.questscroll5.mission_52_mis = "Zabij 60 S\179ug Walcz\185cego Tygrysa i 40 Walcz\185cych[ENTER]Tygrys\243w. "
gameforge.locale.questscroll5.mission_52_text = "Skoro mo\191emy ju\191 walczy\230 z Ognistymi Duchami,[ENTER]musimy kompletnie je wyeliminowa\230 w otwartej[ENTER]walce. Niekt\243re zadania wykonywane przez wojsko[ENTER]zosta\179y zaniedbane. Pom\243\191 nam zredukowa\230 liczb\234[ENTER]Walcz\185cych Tygrys\243w. "
gameforge.locale.questscroll5.mission_53_hunt = "Zbadaj Ogniste Potwory "
gameforge.locale.questscroll5.mission_53_mis = "Zabij 40 P\179omieni. "
gameforge.locale.questscroll5.mission_53_text = "P\179omienie s\185 niewiarygodnie brutalne. Bawi\185 si\234[ENTER]jedz\185c zabitych ludzi. Nie mam poj\234cia jak je[ENTER]zabi\230. Mo\191esz si\234 tego dowiedzie\230? "
gameforge.locale.questscroll5.mission_54_hunt = "Ogni\156ci Wojownicy "
gameforge.locale.questscroll5.mission_54_mis = "Zabij 60 Ognistych Wojownik\243w. "
gameforge.locale.questscroll5.mission_54_text = "Niedawno, dziecko arystokraty, kt\243re zapu\156ci\179o[ENTER]si\234 w Ognist\185 Ziemi\234, zosta\179o zabite przez[ENTER]jednego z Ognistych Wojownik\243w. Je\156li ich[ENTER]zabijesz, otrzymasz nagrod\234. Wyzwij ich na[ENTER]pojedynek. "
gameforge.locale.questscroll5.mission_55_hunt = "Zabij Duchy Drzewa "
gameforge.locale.questscroll5.mission_55_mis = "Zabij 30 Duch\243w Drzewa. "
gameforge.locale.questscroll5.mission_55_text = "Wygl\185daj\185 jak zwyczajne drzewa - pod takim[ENTER]kamufla\191em atakuj\185 zwierz\234ta i ludzi. Ich liczba[ENTER]wzrasta. Dowiedz si\234, jak mo\191emy je zniszczy\230. "
gameforge.locale.questscroll5.mission_56_hunt = "Tajemnica Lasu Duch\243w "
gameforge.locale.questscroll5.mission_56_mis = "Zabij 40 Pniak\243w Drzewa Duch\243w i 30 Driad. "
gameforge.locale.questscroll5.mission_56_text = "Badania pokaza\179y, \191e Las Duch\243w zamieszkiwany[ENTER]jest przez Pniaki Drzewa Duch\243w i Driady. Je\156li[ENTER]je wyeliminujesz, mo\191e zapobiegniemy ich[ENTER]rozpowszechnieniu si\234. "
gameforge.locale.questscroll5.mission_5_hunt = "O posiad\179o\156ciach wiejskich "
gameforge.locale.questscroll5.mission_5_mis = "Zabij 40 Dzik\243w. "
gameforge.locale.questscroll5.mission_5_text = "Cierpienia mieszka\241c\243w wioski ostatnio bardzo si\234[ENTER]zwi\234kszy\179y. Dziki kt\243re kiedy\156 atakowa\179y tylko[ENTER]ma\179e zwierz\234ta w g\243rach, sta\179y si\234 agresywne.[ENTER]Niszcz\185 pola, zjadaj\185 ziarno i atakuj\185 farmer\243w.[ENTER]Czy mo\191esz si\234 ich pozby\230? "
gameforge.locale.questscroll5.mission_6_hunt = "Tygrysy i Nied\159wiedzie "
gameforge.locale.questscroll5.mission_6_mis = "Zabij 25 Tygrys\243w i 30 Nied\159wiedzi. "
gameforge.locale.questscroll5.mission_6_text = "Dotar\179y do Ciebie pog\179oski o tym? Je\156li Tygrysy i[ENTER]Nied\159wiedzie jedz\185 przez 100 dni tylko czosnek i[ENTER]m\179ode cebule, mog\185 przemieni\230 si\234 w Wielkie[ENTER]Nied\159wiedzie i Ogniste Tygrysy. To pewnie[ENTER]nieprawda, ale je\156li to okaza\179o by si\234 prawdziwe,[ENTER]ucierpia\179o by wielu ludzi. Czy mo\191esz zabi\230[ENTER]troch\234 Nied\159wiedzi i Tygrys\243w? Po wykonaniu[ENTER]zadania nagroda Ci\234 nie ominie. "
gameforge.locale.questscroll5.mission_7_hunt = "Zniszcz Metin Chciwo\156ci "
gameforge.locale.questscroll5.mission_7_mis = "Zniszcz 2 Metiny Chciwo\156ci. "
gameforge.locale.questscroll5.mission_7_text = "Od niedawna kamienie ze z\179ym Chi zacz\234\179y spada\230[ENTER]blisko g\179\243wnego miasta. Badania dowiod\179y, \191e Chi[ENTER]w tych kamieniach doprowadza zwierz\234ta do[ENTER]szale\241stwa. Zniszcz te kamienie. Prosz\234 Ci\234,[ENTER]otrzymasz nagrod\234. "
gameforge.locale.questscroll5.mission_8_hunt = "Zniszcz Metin Bitwy "
gameforge.locale.questscroll5.mission_8_mis = "Zniszcz 2 Metiny Bitwy. "
gameforge.locale.questscroll5.mission_8_text = "Od niedawna kamienie ze z\179ym Chi zacz\234\179y spada\230[ENTER]blisko g\179\243wnego miasta. Badania dowiod\179y, \191e Chi[ENTER]w tych kamieniach doprowadza zwierz\234ta do[ENTER]szale\241stwa. Zniszcz te kamienie. Prosz\234 Ci\234,[ENTER]otrzymasz nagrod\234. "
gameforge.locale.questscroll5.mission_9_hunt = "O posiad\179o\156ciach wiejskich 2 "
gameforge.locale.questscroll5.mission_9_mis = "Zabij 30 Czerwonych Dzik\243w. "
gameforge.locale.questscroll5.mission_9_text = "Od niedawna Dziki i ich przyw\243dcy, Czerwone[ENTER]Dziki, atakuj\185 posiad\179o\156ci wiejskie w okolicach[ENTER]G\179\243wnego Miasta. Zarz\185dcy wioski nakazali[ENTER]wyeliminowa\230 Czerwone Dziki. Ka\191dy wojownik[ENTER]proszony jest o zabicie 30 Czerwonych Dzik\243w.[ENTER]Prosz\234, pom\243\191. "
gameforge.locale.questscroll_10_hunt = "W\234\191owi \175o\179nierze "
gameforge.locale.questscroll_10_mis = "Zabij \191o\179nierzy b\234d\185cych p\243\179 lud\159mi i p\243\179 w\234\191ami. "
gameforge.locale.questscroll_10_text = "Nie mo\191na nazwa\230 ich lud\159mi. Ale te\191 nie mo\191na[ENTER]powiedzie\230, \191e nimi nie s\185. Wygl\185daj\185 jak ludzie,[ENTER]ale ich g\179owa, sk\243ra i usposobienie bardziej[ENTER]przypominaj\185 w\234\191a. Mo\191na ich spotka\230 na pustyni,[ENTER]cz\234sto atakuj\185 handlarzy.[ENTER]Zabij 20 W\234\191owych Ludzi a nie ominie Ci\234 nagroda: "
gameforge.locale.questscroll_11_hunt = "W\234\191owi \163ucznicy "
gameforge.locale.questscroll_11_mis = "Zabij \163ucznik\243w, kt\243rzy s\185 p\243\179 lud\159mi i p\243\179[ENTER]w\234\191ami. "
gameforge.locale.questscroll_11_text = "S\185 tak inteligentni jak ludzie. S\185 chytrzy i[ENTER]wiedz\185 jak u\191ywa\230 broni. \163ucznicy, p\243\179 ludzie,[ENTER]p\243\179 w\234\191e, atakuj\185 z daleka niewinnych handlarzy.[ENTER]Wielu ju\191 poleg\179o.[ENTER]Zabij 20 W\234\191owych \163ucznik\243w a nie ominie Ci\234[ENTER]nagroda: "
gameforge.locale.questscroll_12_hunt = "Pustynni Zawadiacy "
gameforge.locale.questscroll_12_mis = "Zabij Pustynnych Zawadiak\243w. "
gameforge.locale.questscroll_12_text = "Z\179e istoty \191yj\185 na Pustyni Yongbi. Potocznie[ENTER]zwani s\185 Pustynnymi W\179\243cz\234gami i nawet niebo[ENTER]p\179acze nad ich z\179ymi uczynkami. Rabuj\185 i zabijaj\185[ENTER]handlarzy tylko dla zabawy. Niszcz\185 wioski na[ENTER]Pustyni.[ENTER]Zabij 12 Pustynnych W\179\243cz\234g\243w, je\156li Ci si\234[ENTER]powiedzie, otrzymasz nagrod\234: "
gameforge.locale.questscroll_13_hunt = "Walcz\185ce Tygrysy "
gameforge.locale.questscroll_13_mis = "Zabij Walcz\185ce Tygrysy. "
gameforge.locale.questscroll_13_text = "S\185 tutaj gdzie\156 zwierz\234ta zwane Walcz\185cymi[ENTER]Tygrysami. Ich krew stworzona zosta\179a z ognia a[ENTER]ich cia\179a z wulkanicznych ska\179. S\185 niewiarygodnie[ENTER]mocnymi potworami. Te monstra karmi\185 si\234 law\185 i[ENTER]ogniem wulkanicznym. Czasami opuszczaj\185 wulkan,[ENTER]atakuj\185 i zjadaj\185 ludzi.[ENTER]Zabij 20 Walcz\185cych Tygrys\243w, je\156li Ci si\234[ENTER]powiedzie, nagroda Ci\234 nie ominie: "
gameforge.locale.questscroll_14_hunt = "Ludzie Wojny "
gameforge.locale.questscroll_14_mis = "Zabij Ludzi Wojny "
gameforge.locale.questscroll_14_text = "Doyyumhwan to du\191y i gor\185cy obszar, kt\243ry jest[ENTER]pe\179en dzikich zwierz\185t. Spotykaj\185 si\234 tam[ENTER]wojownicy z Chunjo, Jinno i Shinsoo. Czekaj\185 tam[ENTER]na nich przera\191aj\185ce i pot\234\191ne potwory. Ludzie[ENTER]Wojny s\185 jednymi z tych, kt\243rzy kontroluj\185[ENTER]Doyyumhwan.[ENTER]Chcesz si\234 z nimi zmierzy\230? Je\156li zabijesz 20 z[ENTER]nich, otrzymasz nast\234puj\185c\185 nagrod\234: "
gameforge.locale.questscroll_15_hunt = "Wojownicy Taehwa "
gameforge.locale.questscroll_15_mis = "Pokonaj Wojownik\243w Taehwa "
gameforge.locale.questscroll_15_text = "S\179uchajcie wy, kt\243rzy uwa\191acie si\234 za[ENTER]nieustraszonych i mocnych wojownik\243w! To[ENTER]P\179omienne Pole Bitewne pe\179ne \179ez, bitew, b\243lu i[ENTER]\156mierci! \175yje tutaj z wieloma potworami i[ENTER]z\179oczy\241cami! Kto jest na tyle odwa\191ny by mnie[ENTER]wyzwa\230? Czy znajdzie si\234 kto\156, kto stanie[ENTER]naprzeciw mnie z mieczem w d\179oni?[ENTER]Je\156li w siebie wierzysz, wyzwij mnie! Je\156li[ENTER]pokonasz mnie i 12 moich kamrat\243w, otrzymasz[ENTER]nagrod\234: "
gameforge.locale.questscroll_16_hunt = "Czarne Nied\159wiedzie "
gameforge.locale.questscroll_16_mis = "Zabij Czarne Nied\159wiedzie "
gameforge.locale.questscroll_16_text = "Obawiam si\234, \191e to m\243j koniec. Ale pozw\243l mi[ENTER]powiedzie\230 Ci o powa\191nym wydarzeniu... W momencie[ENTER]gdy czytasz ten list, ja ju\191 pewnie nie \191yj\234 b\185d\159[ENTER]zgin\234 za chwil\234. \175y\179em w Dolinie Seungryong,[ENTER]gdzie zajmowa\179em si\234 zbieraniem zi\243\179 medycznych.[ENTER]Ale potwory cz\234sto nazywane Mrocznymi[ENTER]Nied\159wiedziami zacz\234\179y wyrz\185dza\230 tutaj wiele[ENTER]szk\243d. Zabi\179y moj\185 rodzin\234. Prosz\234, pom\156cij mnie[ENTER]i moj\185 rodzin\234.[ENTER]Je\156li zabijesz 25 Mrocznych Nied\159wiedzi otrzymasz[ENTER]nagrod\234: "
gameforge.locale.questscroll_17_hunt = "Gigantyczne Nied\159wiedzie "
gameforge.locale.questscroll_17_mis = "Zabij Gigantyczne Nied\159wiedzie "
gameforge.locale.questscroll_17_text = "B\243g Nied\159wiedzi swtorzy\179 nowego potwora: zwyk\179e[ENTER]nied\159wiedzie po\179\185czy\179 z jeszcze gorszymi[ENTER]potworami. Powsta\179y Gigantyczne Nied\159wiedzie,[ENTER]jeszcze wi\234ksze, silniejsze od zwyk\179ych. S\185[ENTER]niesamowicie z\179e. Tak d\179ugo, jak zostan\185 w[ENTER]Dolinie Seungryong, ludzie b\234d\185 cierpie\230.[ENTER]Zabij 20 Gigantycznych Nied\159wiedzi. Je\156li Ci si\234[ENTER]uda, otrzymasz nagrod\234: "
gameforge.locale.questscroll_18_hunt = "\175o\179nierze cierpi\185cy na tajemnicz\185 chorob\234... "
gameforge.locale.questscroll_18_mis = "Zabij \175o\179nierzy cierpi\185cych na tajemnicz\185 zaraz\234. "
gameforge.locale.questscroll_18_text = "Wie\156 wygl\185da na start\185 w proch. Mieszka\241cy,[ENTER]kt\243rzy prze\191yli tajemnicz\185 zaraz\234, atakuj\185[ENTER]handlarzy i jedz\185 niewinnych ludzi. S\185[ENTER]ekstremalnie niebezpieczni.[ENTER]Zabij 35 \175o\179nierzy cierpi\185cych na tajemnicz\185[ENTER]zaraz\234. Je\156li Ci si\234 uda, otrzymasz nagrod\234: "
gameforge.locale.questscroll_19_hunt = "\163ucznicy cierpi\185cy na tajemnicz\185 zaraz\234... "
gameforge.locale.questscroll_19_mis = "Zabij \163ucznik\243w cierpi\185cych na tajemnicz\185 chorob\234. "
gameforge.locale.questscroll_19_text = "Tajemnicza zaraza jest powodem cierpienia wielu[ENTER]zara\191onych ni\185 ludzi. Najgro\159niejsi s\185 \179ucznicy,[ENTER]kt\243rzy siej\185 zaraz\234. \163ucznicy strzelaj\185[ENTER]toksycznymi strza\179ami, parali\191uj\185 podr\243\191nych i[ENTER]porywaj\185 ich.[ENTER]Zabij 25 \163ucznik\243w cierpi\185cych na tajemnicz\185[ENTER]zaraz\234. Je\156li Ci si\234 powiedzie, otrzymasz[ENTER]nagrod\234: "
gameforge.locale.questscroll_1_hunt = "Ogniste Nied\159wiedzie "
gameforge.locale.questscroll_1_mis = "Zabij 25 Ognistych Nied\159wiedzi "
gameforge.locale.questscroll_1_text = "Ogniste Nied\159wiedzie cz\234sto wyst\234puj\185 blisko[ENTER]miast. Przechadzaj\185 si\234 po preriach, ale tak\191e po[ENTER]w\185skich ludzkich ulicach. Coraz wi\234cej ludzi[ENTER]staje si\234 ich ofiarami. Wielu ludzi ju\191 zgin\234\179o.[ENTER]Poluj na te Ogniste Nied\159wiedzie. Kiedy zabijesz[ENTER]ich 25, otrzymasz nagrod\234: "
gameforge.locale.questscroll_20_hunt = {}
gameforge.locale.questscroll_20_mis = "Zabij 4 wrog\243w "
gameforge.locale.questscroll_20_text = "Obawiam si\234, \191e to ju\191 m\243j koniec! M\243j wzrok jest[ENTER]ju\191 zamglony... Kiedy czytasz ten list, pewnie[ENTER]jestem ju\191 w kawa\179kach. Te dranie porwa\179y mnie.[ENTER]Mog\179em uciec, ale rany by\179y zbyt g\179\234bokie i[ENTER]upad\179em. Nie znam Ci\234. Ale prosz\234, pom\156cij mnie![ENTER]Zabij 4 wrog\243w na polu bitwy. Je\156li Ci si\234 uda,[ENTER]otrzymasz nagrod\234: "
gameforge.locale.questscroll_2_hunt = "Wielki Tygrys "
gameforge.locale.questscroll_2_mis = "Zabij 20 Wielkich Tygrys\243w "
gameforge.locale.questscroll_2_text = "Ich nazwa z\179owieszczo wisi w powietrzu: Wielkie[ENTER]Tygrysy. Mieszkaj\185 blisko miasta. Atakuj\185 ludzi i[ENTER]zjadaj\185 wielu dostawc\243w. Ci\234\191ko ju\191 zliczy\230 ich[ENTER]ofiary.[ENTER]Poluj na Wielkie Tygrysy. Kiedy zabijesz ich 20,[ENTER]otrzymasz nagrod\234: "
gameforge.locale.questscroll_3_hunt = "B\243g Ps\243w z g\243r "
gameforge.locale.questscroll_3_mis = "Zabij psiego przyw\243dc\234 z g\243r "
gameforge.locale.questscroll_3_text = "B\243g Ps\243w z G\243r prowadzi rekrutacj\234 wojownik\243w.[ENTER]Jest silny i dziki. Nie tak dawno temu pojawi\179[ENTER]si\234 blisko wioski i zacz\185\179 atakowa\230 handlarzy.[ENTER]Ju\191 teraz spowodowa\179 wiele \156mierci. Nie mo\191na[ENTER]d\179u\191ej ignorowa\230 jego zachowania.[ENTER]Zabij psiego przyw\243dc\234. Je\156li Ci si\234 powiedzie,[ENTER]otrzymasz nagrod\234: "
gameforge.locale.questscroll_4_hunt = "Zabij przyw\243dc\234 \156wi\241 "
gameforge.locale.questscroll_4_mis = "Zabij przyw\243dc\234 \156wi\241. "
gameforge.locale.questscroll_4_text = "Nasta\179 czas koszenia zb\243\191 na okolicznych polach.[ENTER]Czas \191niw. Czas, aby rolnicy zebrali swoje ci\234\191ko[ENTER]wypracowane zbiory. Ale przyw\243dca \156wi\241 i jego[ENTER]kompani zjadaj\185 ca\179e ziarno. Ich chciwo\156\230 zagra\191a[ENTER]farmerom, musisz go zabi\230.[ENTER]Zabij przyw\243dc\234 \156wi\241. Przewa\191nie bywa w okolicach[ENTER]G\179\243wnego Miasta. Je\156li Ci si\234 powiedzie,[ENTER]otrzymasz nagrod\234: "
gameforge.locale.questscroll_5_hunt = "B\243g Nied\159wiedzi "
gameforge.locale.questscroll_5_mis = "Zabij przyw\243dc\234 Nied\159wiedzi "
gameforge.locale.questscroll_5_text = "W swoim naturalnym \156rodowisku, przyw\243dca[ENTER]Nied\159wiedzi zawsze by\179 dobry. Ale teraz pojawi\179[ENTER]si\234 blisko G\179\243wnego Miasta gdzie atakuje ludzi.[ENTER]Powoduje coraz wi\234cej ofiar. Ju\191 nikt nie mo\191e[ENTER]zliczy\230 ile os\243b zabi\179. Musi st\185d znikn\185\230.[ENTER]Zabij przyw\243dc\234 Nied\159wiedzi. Je\156li uda Ci si\234 go[ENTER]st\185d pozby\230, otrzymasz nagrod\234: "
gameforge.locale.questscroll_6_hunt = "B\243g Tygrys\243w "
gameforge.locale.questscroll_6_mis = "Zabij przyw\243dc\234 Tygrys\243w. "
gameforge.locale.questscroll_6_text = "Naprawd\234 nie mog\234 uwierzy\230, \191e przyw\243dca Tygrys\243w[ENTER]spowodowa\179 takie okropie\241stwa... Jestem tylko[ENTER]prost\185 kobiet\185 kt\243ra zawsze go chwali\179a. Czasami[ENTER]pojawia\179 si\234 na skalnych p\243\179kach. Jednak pewnego[ENTER]dnia, przyw\243dca Tygrys\243w i jego s\179udzy[ENTER]zaatakowali moj\185 rodzin\234 i zabili ich wszystkich![ENTER]Ja sama straci\179am r\234k\234.[ENTER]Prosz\234, pom\156cij moj\185 rodzin\234. Je\156li go zabijesz,[ENTER]nie ominie Ci\234 nagroda: "
gameforge.locale.questscroll_7_hunt = "Lider Zaprzysi\234\191onych "
gameforge.locale.questscroll_7_mis = "Zabij Lidera Zaprzysi\234\191onych. "
gameforge.locale.questscroll_7_text = "Klan Zaprzysi\234\191onych to grup\185 kobiet porzuconych[ENTER]przez swoich m\234\191\243w i \159le traktowanych przez[ENTER]\156wiat. Mo\191e i s\185 pokrzywdzone, ale spos\243b w jaki[ENTER]pl\185druj\185 wioski jest po prostu okrutny. Jedna z[ENTER]moich znajomych zosta\179a ukamieniowana kiedy[ENTER]zbli\191y\179a si\234 do wioski. Nie mo\191emy pozwoli\230 im[ENTER]wej\156\230 do wioski i atakowa\230 ludzi.[ENTER]Zabij 20 Lider\243w Zaprzysi\234\191onych. Je\156li Ci si\234[ENTER]uda, otrzymasz nagrod\234: "
gameforge.locale.questscroll_8_hunt = "Lider Gangu Czarnego Wiatru "
gameforge.locale.questscroll_8_mis = "Zabij Lidera Gangu Czarnego Wiatru. "
gameforge.locale.questscroll_8_text = "Z\179odzieje z Gangu Czarnego Wiatru od d\179u\191szego[ENTER]ju\191 czasu poluj\185 na handlarzy. S\185 tak[ENTER]przera\191aj\185cy, \191e nikt nie jest tak odwa\191ny, \191eby[ENTER]si\234 im przeciwstawi\230. Ale to nie mo\191e ju\191 d\179u\191ej[ENTER]trwa\230, za du\191o ju\191 krwi napsuli.[ENTER]Zabij 20 Lider\243w Gangu Czarnego Wiatru. Je\156li Ci[ENTER]si\234 uda, otrzymasz nagrod\234: "
gameforge.locale.questscroll_9_hunt = "Lider Dzikus\243w "
gameforge.locale.questscroll_9_mis = "Zabij Lidera Dzikus\243w. "
gameforge.locale.questscroll_9_text = "Ju\191 troch\234 czasu min\234\179o od kiedy Dzicy[ENTER]przekroczyli granic\234 i zaatakowali wiosk\234. Liczb\234[ENTER]zabitych liczy si\234 ju\191 w setkach, a ich ilo\156\230[ENTER]ci\185gle ro\156nie. Dzicy s\185 tak brutalni, \191e nikt nie[ENTER]odwa\191y\179 si\234 im przeciwstawi\230. Nie mo\191emy jednak[ENTER]d\179u\191ej tolerowa\230 takiej sytuacji.[ENTER]Zabij 25 Lider\243w Dzikus\243w. Je\156li Ci si\234[ENTER]powiedzie, otrzymasz nagrod\234: "
gameforge.locale.quest_temp_reward_1 = "Nagroda "
gameforge.locale.quest_temp_reward_2 = "Podczas okres\243w pr\243bnych dla zada\241, nie ma[ENTER]nagr\243d. Po otrzymaniu nagrody, bie\191\185ce zadanie[ENTER]mo\191e zosta\230 wykonany ponownie. "
