gameforge.locale.skeleton_gem.order_refuse = "To zbyt niebezpieczne "
gameforge.locale.skeleton_gem.order_refuse_answer = "Domokr\185\191ca:[ENTER]Rozumiem twoje zw\185tpienie. Oczywi\156cie, \191e to[ENTER]trudne i niebezpieczne zadanie! Je\191eli nic si\234[ENTER]nie zmieni to marnie sko\241cz\234! "
gameforge.locale.skeleton_gem.order_say = "Domokr\185\191ca:[ENTER]Teraz wszystko si\234 sko\241czy\179o. Nie ma nic do[ENTER]roboty, poza czekaniem na w\179asn\185 \156mier\230. Gdyby ci[ENTER]z\179odzieje mnie wtedy nie zaatakowali, nadal[ENTER]mia\179bym swoje skarby. Dlaczego to przydarzy\179o si\234[ENTER]w\179a\156nie mi?! "
gameforge.locale.skeleton_gem.order_say2 = "Domokr\185\191ca:[ENTER]Prosz\234, pom\243\191 mi. Znajd\159 dla mnie Klejnot[ENTER]Demona+. Ma go Magiczny Demon. Oczywi\156cie je\156li[ENTER]wykonasz zadanie to hojnie Ci\234 wynagrodz\234. "
gameforge.locale.skeleton_gem.order_too_late = "Domokr\185\191ca:[ENTER]Ju\191 kto\156 inny to dla mnie zdoby\179. Nie musisz ju\191[ENTER]si\234 martwi\230. "
