gameforge.locale.skeleton_gem.start_say = "List Domokr\185\191cy:[ENTER]Nie wiem co robi\230... Klejnot Demona+ zosta\179[ENTER]skradziony, a to dla mnie wielka tragedia.[ENTER]Zap\179aci\179em za niego ca\179ym swoim maj\185tkiem. Czy[ENTER]mo\191esz mi pom\243c? Bardzo potrzebuj\234 twojej pomocy.[ENTER]Jestem zdesperowany! "
gameforge.locale.skeleton_gem.success_say = "Domokr\185\191ca:[ENTER]Naprawd\234 Ci si\234 uda\179o? Dobra robota! Jestem[ENTER]uratowany! To naprawd\234 dobra nowina! "
