gameforge.locale.skill_group = {}
gameforge.locale.skill_group.board = "Tekst na broszurze:[ENTER]Rekrutujemy dzielnych m\234\191czyzn i kobiety ch\234tnych[ENTER]do walki za pok\243j w Kr\243lestwie.[ENTER][ENTER]Aby do nas do\179\185czy\230 musisz mie\230 5 poziom. "
gameforge.locale.skill_group.dialog_assassin_1 = "Tutaj trenujemy Ninja potrafi\185cych si\234 chowa\230 i[ENTER]atakowa\230 z ukrycia swoich wrog\243w. Najwi\234ksz\185[ENTER]uwag\234 przywi\185zuje si\234 tu do treningu z u\191yciem[ENTER]sztylet\243w i trucizn. Do\179\185czy\230 mog\185 tylko Ninja z[ENTER]co najmniej 5 poziomem. Je\191eli osi\185gniesz ten[ENTER]poziom, dostaniesz propozycj\234 przy\179\185czenia si\234.[ENTER]Wr\243\230 do mnie gdy b\234dziesz gotowy na ukrywanie si\234[ENTER]w ciemno\156ciach jako Ninja. Wtedy porozmawiamy. "
gameforge.locale.skill_group.dialog_assassin_2 = "Tutaj trenujemy Ninja potrafi\185cych si\234 ukrywa\230 i[ENTER]atakowa\230 z ukrycia swoich wrog\243w. Najwi\234ksz\185[ENTER]uwag\234 przywi\185zuje si\234 tu do treningu z u\191yciem[ENTER]sztylet\243w i trucizn. Wr\243\230 do mnie gdy b\234dziesz[ENTER]gotowy na ukrywanie si\234 w ciemno\156ciach jako[ENTER]Ninja. Przywitam ka\191dego, kto b\234dzie gotowy by do[ENTER]nas do\179\185czy\230. "
gameforge.locale.skill_group.dialog_assassin_3 = "Tutaj trenujemy Ninja potrafi\185cych walczy\230 na[ENTER]odleg\179o\156\230 przy pomocy \179uku. Podczas treningu[ENTER]najwi\234ksz\185 uwag\234 przywi\185zuje si\234 do umiej\234tno\156ci[ENTER]\179uczniczych. Trenerzy naucz\185 Ci\234 jak strzela\230 ze[ENTER]znacznej odleg\179o\156ci dobrze wycelowan\185 Ognist\185[ENTER]Strza\179\185 w swoich wrog\243w. Do\179\185czy\230 mog\185 tylko[ENTER]Ninja z co najmniej 5 poziomem. Je\191eli osi\185gniesz[ENTER]ten poziom, dostaniesz propozycj\234 przy\179\185czenia[ENTER]si\234. Wr\243\230 porozmawia\230 ze mn\185 je\156li interesuje Ci\234[ENTER]taka droga rozwoju. "
gameforge.locale.skill_group.dialog_assassin_4 = "Tutaj trenujemy Ninja potrafi\185cych walczy\230 na[ENTER]odleg\179o\156\230 przy pomocy \179uku. Podczas treningu[ENTER]najwi\234ksz\185 uwag\234 przywi\185zuje si\234 do umiej\234tno\156ci[ENTER]\179uczniczych. Trenerzy naucz\185 Ci\234 jak strzela\230 ze[ENTER]znacznej odleg\179o\156ci dobrze wycelowan\185 Ognist\185[ENTER]Strza\179\185 w swoich wrog\243w. Wr\243\230 porozmawia\230 ze mn\185[ENTER]je\156li interesuje Ci\234 taka droga rozwoju. Dzi\234ki[ENTER]mnie staniesz si\234 najlepszym \179ucznikiem w[ENTER]Kr\243lestwie. "
gameforge.locale.skill_group.dialog_assassin_5 = "Wybierz pomi\234dzy Walk\185 Sztyletami a Walk\185 na[ENTER]Odleg\179o\156\230. Otrzymasz umiej\234tno\156ci, kt\243re[ENTER]wybierzesz. "
gameforge.locale.skill_group.dialog_shaman_1 = "To miejsce, w kt\243rym trenowani s\185 Szamani[ENTER]pod\185\191aj\185cy drog\185 Boga Smoka. Uczy si\234 ich jak[ENTER]u\191ywa\230 talizman\243w i mocy magicznej. S\185 w stanie[ENTER]podnosi\230 swoj\185 odporno\156\230 dzi\234ki sile Boga Smoka.[ENTER]Mog\185 wspomaga\230 zaprzyja\159nione osoby. Do\179\185czy\230[ENTER]mog\185 tylko Szamani z co najmniej 5 poziomem.[ENTER]Je\191eli osi\185gniesz ten poziom, dostaniesz[ENTER]propozycj\234 przy\179\185czenia si\234. Wr\243\230 do mnie gdy[ENTER]b\234dziesz gotowy na pod\185\191anie \156cie\191k\185 Boga Smoka. "
gameforge.locale.skill_group.dialog_shaman_2 = "To miejsce, w kt\243rym trenowani s\185 Szamani[ENTER]pod\185\191aj\185cy drog\185 Boga Smoka. Uczy si\234 ich jak[ENTER]u\191ywa\230 talizman\243w i mocy magicznej.[ENTER]S\185 w stanie podnosi\230 swoj\185 odporno\156\230 dzi\234ki sile[ENTER]Boga Smoka. Mog\185 wspomaga\230 zaprzyja\159nione osoby.[ENTER]Wr\243\230 do mnie gdy b\234dziesz gotowy na pod\185\191anie[ENTER]\156cie\191k\185 Boga Smoka. "
gameforge.locale.skill_group.dialog_shaman_3 = "Tutaj Szamani czcz\185 Si\179\234 Natury i \140wiat\179a. Ucz\185[ENTER]si\234 umiej\234tno\156ci w\179adania B\179yskawicami, Burz\185 i[ENTER]Leczeniem. Cz\234sto dzia\179aj\185 w grupach aby[ENTER]wzajemnie si\234 wspiera\230. Do\179\185czy\230 mog\185 tylko[ENTER]Szamani z co najmniej 5 poziomem. Je\191eli[ENTER]osi\185gniesz ten poziom, dostaniesz propozycj\234[ENTER]przy\179\185czenia si\234. B\234d\234 na Ciebie czeka\230. "
gameforge.locale.skill_group.dialog_shaman_4 = "Tutaj Szamani czcz\185 si\179\234 Natury i \140wiat\179a. Ucz\185[ENTER]si\234 umiej\234tno\156ci w\179adania B\179yskawicami, Burz\185 i[ENTER]Leczeniem. Cz\234sto dzia\179aj\185 w grupach aby[ENTER]wzajemnie si\234 wspiera\230. Chcesz pomaga\230 innym[ENTER]ludziom razem ze mn\185? Twoje wsparcie pomo\191e[ENTER]wszystkim, kt\243rzy cierpi\185. Prosz\234, przy\179\185cz si\234. "
gameforge.locale.skill_group.dialog_shaman_5 = "Wybierz pomi\234dzy Si\179\185 Smoka a Leczeniem.[ENTER]Otrzymasz umiej\234tno\156ci, kt\243re wybierzesz. "
gameforge.locale.skill_group.dialog_sura_1 = "Ucz\234 ludzi, jak u\191ywa\230 takiej magii, kt\243ra[ENTER]zosta\179a zasiana przez Nasienie Diab\179\243w w moim[ENTER]lewym ramieniu. Czaruj\234 Miecze i Zbroje, co[ENTER]pomaga mi zwi\234kszy\230 warto\156\230 ataku, ponadto mog\234[ENTER]przywo\179a\230 z\179ego ducha z piek\179a obni\191aj\185c \191ycie[ENTER]wroga. Tylko Sura, kt\243rzy osi\185gn\234li co najmniej 5[ENTER]poziom mog\185 do nas do\179\185czy\230. Je\156li osi\185gn\185\179e\156[ENTER]wymagany poziom poprzez trening dostaniesz ofert\234[ENTER]rekrutacji. Je\156li jeste\156 gotowy na pos\179ugiwanie[ENTER]si\234 Mieczami Nocy lub wypowiadanie wiecznych[ENTER]Zakl\234\230 Nocy, przyjd\159 tu. "
gameforge.locale.skill_group.dialog_sura_2 = "Ucz\234 ludzi jak u\191ywa\230 takiej magii, kt\243ra zosta\179a[ENTER]zasiana przez Nasienie Diab\179\243w w moim lewym[ENTER]ramieniu. Czaruj\234 Miecze i Zbroje, co pomaga mi[ENTER]zwi\234kszy\230 warto\156\230 ataku, ponadto mog\234 przywo\179a\230[ENTER]z\179ego ducha z piek\179a obni\191aj\185c \191ycie wroga. Je\156li[ENTER]jeste\156 gotowy na pos\179ugiwanie si\234 Mieczami Nocy[ENTER]lub wypowiadanie wiecznych Zakl\234\230 Nocy, sprawi\234,[ENTER]\191e staniesz si\234 pot\234\191ny. "
gameforge.locale.skill_group.dialog_sura_3 = "Je\156li jeste\156 zainteresowany: tutaj s\185 tylko ci,[ENTER]kt\243rzy po\156wi\234caj\185 siebie ciemno\156ci. Ucz\185 si\234[ENTER]umiej\234tno\156ci u\191ywania P\179omienia Diab\179a i[ENTER]Umiej\234tno\156ci z\179ych duch\243w i demon\243w. Tylko Sura,[ENTER]kt\243rzy osi\185gn\234li co najmniej 5 poziom mog\185[ENTER]do\179\185czy\230. Je\156li osi\185gn\185\179e\156 wymagany Poziom[ENTER]poprzez trening dostaniesz ofert\234 rekrutacji.[ENTER]Je\156li chcesz \191y\230 w ciemno\156ci to jest prawdziwie[ENTER]miejsce by dowiedzie\230 si\234 co oferuje ten \156wiat. "
gameforge.locale.skill_group.dialog_sura_4 = "Je\156li jeste\156 zainteresowany: tutaj s\185 tylko ci,[ENTER]kt\243rzy po\156wi\234caj\185 siebie ciemno\156ci. Ucz\185 si\234[ENTER]umiej\234tno\156ci u\191ywania P\179omienia Diab\179a i[ENTER]Umiej\234tno\156ci z\179ych duch\243w i demon\243w. Je\156li jeste\156[ENTER]zainteresowany staniem si\234 przyjacielem z\179ych[ENTER]duch\243w trawi\185cych Ci\234 bardziej i bardziej,[ENTER]przyjd\159. Je\156li przyjdziesz - zostaw za sob\185[ENTER]cz\179owiecze\241stwo. "
gameforge.locale.skill_group.dialog_sura_5 = "Wybierz pomi\234dzy Treningiem Czarnej Magii a[ENTER]Treningiem Broni. Dostaniesz umiej\234tno\156ci, kt\243re[ENTER]wybierzesz. "
gameforge.locale.skill_group.dialog_warrior_1 = "Wiesz gdzie jeste\156? Tutaj s\185 trenowani wojownicy,[ENTER]kt\243rzy b\234d\185 najszybsi i najdzielniejsi w ca\179ym[ENTER]Kr\243lestwie. Nauczamy tutaj technik szybkiego[ENTER]powtarzania cios\243w i walki za pomoc\185 mieczy lub[ENTER]w\179\243czni. Tylko wojownicy z nauk\185 zawodu i z[ENTER]Poziomem 5 wzwy\191 mog\185 przyst\185pi\230. Je\156li[ENTER]osi\185gn\185\179e\156 ustalony Poziom wojsko powie Ci, \191e[ENTER]zosta\179e\156 zaakceptowany. Je\156li chcesz odnale\159\230[ENTER]prawdziw\185 si\179\234 swojego cia\179a, chod\159 ze mn\185! "
gameforge.locale.skill_group.dialog_warrior_2 = "Wiesz gdzie jeste\156? Tutaj s\185 trenowani wojownicy,[ENTER]kt\243rzy s\185 najszybsi i najdzielniejsi. Ucz\185[ENTER]atak\243w, kt\243re mog\185 by\230 szybko powtarzalne i[ENTER]zgodne. Trenuj\185 g\179ownie u\191ycie Miecza i W\179\243czni.[ENTER]Wi\234c, jak b\234dzie? Chcesz do nas do\179\185czy\230? "
gameforge.locale.skill_group.dialog_warrior_3 = "Tutaj wojownicy uczeni s\185 u\191ywania Chi. Ucz\185 si\234[ENTER]atak\243w Zamkni\234tego Boju, kt\243re s\185 troszk\234[ENTER]wolniejsze do powtarzania i m\234cz\185 umys\179owo.[ENTER]Jednocze\156nie takie ataki s\185 bardzo mocne i[ENTER]efektywne. Tylko wojownicy z nauk\185 zawodu i[ENTER]poziomu 5 wzwy\191 mog\185 uczestniczy\230. Je\156li[ENTER]osi\185gn\185\179e\156 wymagany poziom, dostaniesz ofert\234[ENTER]rekrutacji do wojska. Je\156li jeste\156[ENTER]zainteresowany, chod\159 ze mn\185. "
gameforge.locale.skill_group.dialog_warrior_4 = "Tutaj wojownicy uczeni s\185 u\191ycia Chi. Ucz\185 si\234[ENTER]walki w zwarciu, kt\243re s\185 troszk\234 wolniejsze do[ENTER]powtarzania i m\234cz\185 umys\179owo. Jednocze\156nie takie[ENTER]ataki s\185 bardzo mocne i efektywne. Zgodnie z[ENTER]twoim po\156wi\234ceniem Umiej\234tno\156ci Walki Duchowej[ENTER]ujawniaj\185 si\234 w walce. Jeste\156 zainteresowany[ENTER]Walk\185 Duchow\185? "
gameforge.locale.skill_group.dialog_warrior_5 = "Wybierz pomi\234dzy walk\185 Cia\179a a walk\185 Duchow\185, a[ENTER]otrzymasz wybrane umiej\234tno\156ci. "
gameforge.locale.skill_group.invite = "Zawiadomienie o rekrutacji: "
gameforge.locale.skill_group.lets_join_skill_group_1 = "[COLOR r;1|g;0.6|b;0.6]Zawiadomienie o Rekrutacji[ENTER]Wojownik\243w[/COLOR][ENTER]Je\156li podziwiasz Wojownika za jego szybko\156\230 i[ENTER]powtarzaln\185 wiedz\234 atakowania, powiniene\156 uczy\230[ENTER]si\234 Walki Cia\179a. Je\156li chcesz zabi\230 ca\179\185 grup\234[ENTER]potwor\243w jednym uderzeniem powiniene\156 uczy\230 si\234[ENTER]Walki Duchowej.[ENTER][ENTER]Czekamy na Ciebie na placu w mie\156cie. "
gameforge.locale.skill_group.lets_join_skill_group_2 = "[COLOR r;1|g;0.6|b;0.6]Zawiadomienie o Rekrutacji[ENTER]Ninja[/COLOR][ENTER]Je\156li chcesz m\243c nazywa\230 si\234 najlepszym[ENTER]\179ucznikiem, powiniene\156 wybra\230 Trening \163uku. Je\156li[ENTER]jeste\156 gotowy na tajemne misje, Trening Ostrza[ENTER]b\234dzie dla Ciebie odpowiedni.[ENTER][ENTER]Czekamy na Ciebie na placu w mie\156cie. "
gameforge.locale.skill_group.lets_join_skill_group_3 = "[COLOR r;1|g;0.6|b;0.6]Zawiadomienie o Rekrutacji[ENTER]Sura[/COLOR][ENTER]Czy chcesz by\230 prawdziwym Dyplomat\185 i Kawalerem,[ENTER]kim\156 kto mo\191e sta\230 si\234 super cz\179owiekiem? Ucz si\234[ENTER]sztuki Broni. Je\156li chcesz sia\230 strach jak[ENTER]Czarodziej Ciemno\156ci i m\243c Przeklina\230, ucz si\234[ENTER]sztuki Czarnej Magii.[ENTER][ENTER]Czekamy na Ciebie na placu w mie\156cie. "
gameforge.locale.skill_group.lets_join_skill_group_4 = "[COLOR r;1|g;0.6|b;0.6]Zawiadomienie o Rekrutacji[ENTER]Szaman\243w[/COLOR][ENTER]Je\156li chcesz by\230 Magiem, wiedzie\230 jak u\191ywa\230[ENTER]Amulet\243w tak dobrze jak legendarni mistycy i[ENTER]b\179ogos\179awieni, powiniene\156 pod\185\191a\230 drog\185 Mocy[ENTER]Smoka. Je\156li chcesz \179agodzi\230 b\243le ran przez[ENTER]regeneracj\234 i uzdrawianie, powiniene\156 uczy\230 si\234[ENTER]Mocy Leczenia.[ENTER][ENTER]Czekamy na Ciebie na placu w mie\156cie. "
