gameforge.locale.stamina_food.butcher.start_say = "Staruszek w restauracji Suhpyung:[ENTER]Moje cia\179o nie jest ju\191 w takiej formie jak[ENTER]kiedy\156. Kiedy by\179em m\179ody, mog\179em pracowa\230 r\243wno[ENTER]tydzie\241 i nadal mie\230 si\179\234 na picie ka\191dej nocy![ENTER]Teraz nawet stanie jest ci\234\191kie.[ENTER]W takich momentach przyda\179aby si\234 butelka \175abiej[ENTER]zupy do zregenerowania energii. "
gameforge.locale.stamina_food.butcher.start_say2 = "Staruszek w restauracji Suhpyung:[ENTER]Chcesz wiedzie\230 co to jest \175abia zupa? Je\156li[ENTER]zjesz jedn\185 butelk\234 tego, nigdy si\234 nie zm\234czysz![ENTER]Nawet je\156li b\234dziesz pracowa\230 na polach r\243wno[ENTER]tydzie\241, nadal b\234dziesz mia\179 energi\234 wieczorami![ENTER]M\243j przyjaciel Oakgu jest najlepszy w gotowaniu[ENTER]zielonej \175abiej zupy. Z jakiego\156 powodu ju\191 jej[ENTER]wi\234cej nie robi... "
