gameforge.locale.stamina_food.food_manager.order_say = "Oakgu:[ENTER]Zielona \175abia zupa? Tak! Gotowa\179em j\185 w dawnych[ENTER]czasach. Ale mog\179em j\185 zrobi\230 tylko kiedy by\179em[ENTER]m\179ody. Wtedy nie obawia\179em si\234 gro\159nych potwor\243w[ENTER]i mog\179em spokojnie polowa\230 na zielone \191aby. "
gameforge.locale.stamina_food.food_manager.order_say2 = "Oakgu:[ENTER]A teraz? Jestem stary i nie mam tyle si\179y na to.[ENTER]Chcia\179bym zn\243w zje\156\230 zielon\185 \175abi\185 zup\234. Ale[ENTER]zielone \191aby nie jest \179atwo zabi\230! Je\156li[ENTER]zdob\234dziesz dla mnie jaki\156 zielony \175abi posi\179ek,[ENTER]b\234d\234 m\243g\179 zrobi\230 najlepsz\185 na \156wiecie zup\234! "
