gameforge.main_quest_flame_lv100._010_sendLetter = "Czarna Materia "
gameforge.main_quest_flame_lv100._020_say = "Szuka ci\234 Yak-Hwan. Prosz\234, id\159 do niego. "
gameforge.main_quest_flame_lv100._030_say = "Witaj. Yon-I-Walker zako\241czy\179 badania. Ten[ENTER]fenomen, kt\243ry uda\179o ci si\234 zaobserwowa\230 na[ENTER]Ognistej Ziemi, okre\156lany jest mianem Czarnej[ENTER]Materii. "
gameforge.main_quest_flame_lv100._040_say = "Wydobywa si\234 ona z twierdzy i przemienia demony w[ENTER]okolicy. Im du\191ej s\185 one pod jej wp\179ywem, tym[ENTER]staj\185 si\234 silniejsze i agresywniejsze. Musimy[ENTER]zapobiec rozszerzaniu si\234 Czarnej Materii. "
gameforge.main_quest_flame_lv100._050_say = {}
gameforge.main_quest_flame_lv100._060_say = "Nie mo\191emy przecie\191 siedzie\230 z za\179o\191onymi r\234kami,[ENTER]podczas gdy nasz alchemik szuka jakiego\156[ENTER]rozwi\185zania. Wr\243\230 do Ognistej Ziemi i zabij 300[ENTER]demon\243w grasuj\185cych w pobli\191u twierdzy. "
