gameforge.main_quest_flame_lv100._120_say = "Obawiam si\234, \191e nie uda\179o ci si\234 jeszcze zabi\230[ENTER]wystarczaj\185cej ilo\156ci demon\243w. Wr\243\230 do Ognistej[ENTER]Ziemi i walcz dalej. "
