gameforge.main_quest_flame_lv100._160_sendLetter = "Deszczowy Olejek "
gameforge.main_quest_flame_lv100._170_say = "Szuka ci\234 alchemik. Wydaje mi si\234, \191e ma do[ENTER]ciebie piln\185 spraw\234! "
gameforge.main_quest_flame_lv100._180_say = "Katastrofa! Zleci\179em przecie\191 Yak-Hwan, aby[ENTER]dzia\179a\179 z rozwag\185. I co on robi? Rzuca si\234 z[ENTER]mieczem i wci\185ga nas w niesamowity chaos! Nie[ENTER]wiedzia\179 o tym, \191e Czarna Materia ro\156nie i[ENTER]rozprzestrzenia si\234 znacznie szybciej, je\156li jego[ENTER]\191ywiciel zginie. A teraz dowiaduj\234 si\234, \191e ju\191[ENTER]300 zara\191onych demon\243w zosta\179o zabitych! To nie[ENTER]dobrze... "
gameforge.main_quest_flame_lv100._190_say = "W tych warunkach nie wystarczy nawet m\243j[ENTER]Deszczowy Olejek, aby zakl\185\230 Czarn\185 Materi\234.[ENTER]Potrzebuj\234 koniecznie sk\179adnik\243w, aby[ENTER]wyprodukowa\230 wi\234ksz\185 ilo\156\230. "
gameforge.main_quest_flame_lv100._200_say = {}
