gameforge.main_quest_flame_lv100._220_say = "Natychmiast wyruszam. "
gameforge.main_quest_flame_lv100._230_say = "Wspaniale. Po\156piesz si\234, poniewa\191 Czarna Materia[ENTER]rozprzestrzenia si\234 z minuty na minut\234 coraz[ENTER]bardziej. "
gameforge.main_quest_flame_lv100._240_notice = "Besorge die Zutaten mit denen der Alchemist die Nimbustinktur herstellen kann "
gameforge.main_quest_flame_lv100._250_say = "Verbleibende Zutaten "
gameforge.main_quest_flame_lv100._260_sayTitle = "Deszczowy Olejek "
gameforge.main_quest_flame_lv100._270_say = "Za\179atw 10 Kamieni W\234gielny, 50 \175\243\179ci[ENTER]Nied\159wiedzia, 10 Work\243w z Paj\234cz\185 Trucizn\185 oraz[ENTER]200 Od\179amk\243w Energii. Zanie\156 wszystkie te[ENTER]sk\179adniki do alchemika. "
gameforge.main_quest_flame_lv100._280_say = "Uda\179 ci si\234 znale\159\230 wszystkie sk\179adniki.[ENTER]Znakomicie! To zabieram si\234 do pracy. Dam ci[ENTER]zna\230, gdy Deszczowy Olejek b\234dzie gotowy. "
gameforge.main_quest_flame_lv100._290_say = "Je\156li nie powstrzymamy wkr\243tce Czarnej Materii,[ENTER]krucho b\234dzie z nami. Jazda! Przynie\156 mi[ENTER]wszystkie sk\179adniki potrzebne to zrobienia[ENTER]Deszczowego Olejku. "
gameforge.main_quest_flame_lv100._300_notice = "Uda\179o ci si\234 zgromadzi\230 wszystkie sk\179adniki.[ENTER]Teraz wr\243\230 do alchemika. "
gameforge.main_quest_flame_lv100._310_say = "Pogadaj z Alchemikiem. "
gameforge.main_quest_flame_lv100._320_sendLetter = "Powstrzymaj Czarn\185 Materi\234 "
gameforge.main_quest_flame_lv100._330_say = "Co za stary uparciuch... e, szkoda gada\230.[ENTER]Poskar\191y\179em si\234 u kowala, bo Kamienie W\234gielne[ENTER]by\179y za grubo zmielone. Teraz obrazi\179 si\234 i nie[ENTER]chce przerobi\230 pozosta\179ych kamieni na proszek.[ENTER]Porozmawiaj z nim, mo\191e ciebie us\179ucha? "
gameforge.main_quest_flame_lv100._340_say = "Jasne. "
gameforge.main_quest_flame_lv100._350_say = "Danke Hier sind die Fundamentsteine Und bringe ihm diesen Korb mit Leckereien als Entschuldigung "
