gameforge.main_quest_flame_lv100._400_say = "Nie, dzisiaj nie. Jestem tutaj, poniewa\191 alchemik[ENTER]chcia\179 ci\234 przeprosi\230 za swoje ostre s\179owa i[ENTER]przekaza\230 w jego imieniu ten oto koszyk ze[ENTER]smako\179ykami. "
