gameforge.main_quest_flame_lv101._040_say = "Wyposa\191\234 twoj\185 bro\241 w Deszczowy Olejek. Teraz[ENTER]podczas zabijania zara\191onych demon\243w, ukryta w[ENTER]nich Czarna Materia zostanie wyp\234dzona i w ten[ENTER]spos\243b nie b\234dzie mog\179a si\234 dalej[ENTER]rozprzestrzenia\230. "
gameforge.main_quest_flame_lv101._050_say = "Teraz mo\191esz odwa\191y\230 si\234 wej\156\230 do \156rodka[ENTER]tajemniczej twierdzy. Przepustk\234 posiadasz. Mo\191e[ENTER]uda ci si\234 odkry\230 tam jak\185\156 wskaz\243wk\234 \156wiadcz\185c\185[ENTER]o machinacjach Wasali Mroku i dowiedzie\230 si\234[ENTER]czego\156 o moim zaginionym zwiadowcy. "
