gameforge.main_quest_flame_lv101._070_say = "Natychmiast wyruszam w drog\234. "
gameforge.main_quest_flame_lv101._080_say = "Danke Ich w\252nsche dir das Beste "
gameforge.main_quest_flame_lv101._090_notice = "Przedosta\241 si\234 do twierdzy i pokonaj w \156rodku[ENTER]demony. Miej oczy szeroko otwarte. Pami\234taj,[ENTER]potrzebujemy informacji o zaginionym zwiadowcy i[ENTER]inne wa\191ne wskaz\243wki dotycz\185ce Wasali Mroku. "
gameforge.main_quest_flame_lv101._100_sayTitle = "Festung erkunden "
gameforge.main_quest_flame_lv101._110_say = "Przedosta\241 si\234 do twierdzy i pokonaj w \156rodku[ENTER]demony. Szukaj wskaz\243wek dotycz\185cych machinacji[ENTER]Wasali Mroku i zaginionego zwiadowcy. "
gameforge.main_quest_flame_lv101._120_sayReward = "Du kannst diesen Dungeon nicht alleine betreten Bilde eine Gruppe um passieren zu d\252rfen Du erh\228ltst keinen weiteren Passierschein "
gameforge.main_quest_flame_lv101._130_say = "Czy uda\179o ci si\234 przedosta\230 do \156rodka twierdzy?[ENTER]Tam musz\185 znajdowa\230 si\234 jakie\156 wskaz\243wki[ENTER]dotycz\185ce machinacji Wasali Mroku oraz \156lady[ENTER]\156wiadcz\185ce o pobycie mojego zwiadowcy! Udaj si\234[ENTER]ponownie do Ognistej Ziemi i przeszukaj twierdz\234. "
gameforge.main_quest_flame_lv101._140_say = "Der Sp\228her ist schon eine Weile tot In seiner Tasche findest du einen Brief \220berbringe ihn Yak Hwan "
gameforge.main_quest_flame_lv101._150_notice = "Uda\179o ci si\234 odnale\159\230 zwiadowc\234 Yak-Hwan "
gameforge.main_quest_flame_lv101._160_say = "Hast du Neuigkeiten "
gameforge.main_quest_flame_lv101._170_say = {}
gameforge.main_quest_flame_lv101._180_say = "Po twojej minie wida\230, \191e nie przynosisz dobrych[ENTER]wie\156ci. Tego si\234 obawia\179em. Mia\179 przy sobie list?[ENTER]Poka\191. W tej twierdzy musi znajdowa\230 si\234 jaka\156[ENTER]wskaz\243wka \156wiadcz\185ca o machinacjach Wasali Mroku.[ENTER]Wr\243\230 tam i poszukaj jej. A ten list przeczytamy[ENTER]p\243\159niej. "
gameforge.main_quest_flame_lv101._190_notice = "Co? Znalaz\179e\156 Wysadzany Naszyjnik nale\191\185cy do[ENTER]Wasali Mroku? Poka\191 go Yak-Hwan. "
gameforge.main_quest_flame_lv101._200_say = "To jest bardzo interesuj\185ce. A wi\234c ten Wysadzany[ENTER]Naszyjnik nale\191y naprawd\234 do Wasali Mroku. Mo\191e[ENTER]zawiera jak\185\156 wskaz\243wk\234 o ich machinacjach! Co,[ENTER]nie ma \156ladu po moim zwiadowcy? Nie poddawaj si\234,[ENTER]szukaj go dalej. On musi by\230 w tej twierdzy. "
gameforge.main_quest_flame_lv101._210_notice = "Uda\179o ci si\234 odnale\159\230 zar\243wno Wysadzany[ENTER]Naszyjnik, jak i zwiadowc\234. To teraz zdaj raport[ENTER]Yak-Hwan. "
gameforge.main_quest_flame_lv101._220_say = "Zdaj raport Yak-Hwan. "
gameforge.main_quest_flame_lv101._230_say = "A wi\234c uda\179o ci si\234! Ten Wysadzany Naszyjnik[ENTER]nale\191y do Wasali Mroku. Daj\234 g\179ow\234, \191e zawiera on[ENTER]ukryt\185 wskaz\243wk\234 dotycz\185c\185 ich plan\243w. A co to[ENTER]jest? List napisany przez mojego zwiadowc\234?[ENTER]Poka\191. "
gameforge.main_quest_flame_lv101._240_say = {}
gameforge.main_quest_flame_lv101._250_say = "Ein Brief den mir mein Sp\228her hinterlassen hat Ich bin ersch\252ttert Lass uns gemeinsam seine letzten Worte lesen "
gameforge.main_quest_flame_lv101._260_sayTitle = "Po\156piesznie napisane s\179owa: "
gameforge.main_quest_flame_lv101._270_say = "Drogi Yak-Hwan, nie powr\243c\234 do domu \191ywy, ale mam[ENTER]nadziej\234, \191e do twoich r\185k dotrze przynajmniej[ENTER]ten list. Odkry\179em w Ognistej Ziemi twierdz\234,[ENTER]kt\243ra nie jest oznaczona na \191adnej z map. Panem i[ENTER]w\179adc\185 twierdzy jest pot\234\191ny demon Ognistej[ENTER]Ziemi, kt\243rego otacza niezwyk\179a aura. Jego ryk[ENTER]jest og\179uszaj\185cy i wydaje mi si\234, \191e musi co\156[ENTER]bardzo wa\191nego strzec. Ale co, niestety nie[ENTER]dowiedzia\179em si\234. Przebacz, zawiod\179em ci\234... "
gameforge.main_quest_flame_lv101._280_say = "Koniecznie musimy si\234 dowiedzie\230, co ukrywa si\234 w[ENTER]tej twierdzy.[ENTER]Popatrz, wewn\185trz Wysadzanego Naszyjnika jest[ENTER]jaki\156 grawerunek. Poprosz\234 o rad\234 Yon-I-Walker.[ENTER]On da ci zna\230, gdy b\234dzie potrzebowa\179 twojej[ENTER]pomocy. "
gameforge.main_quest_flame_lv101._290_sendLetter = "Gravur entschl\252sseln "
gameforge.main_quest_flame_lv101._300_say = "Szuka ci\234 Yon-I-Walker. Id\159 do niego. "
gameforge.main_quest_flame_lv101._310_say = "Willkommen ich habe dich bereits erwartet Ich brauche etwas Hilfe dabei die Gravur in diesem Nietenhalsband zu entschl\252sseln "
gameforge.main_quest_flame_lv101._320_say = {}
gameforge.main_quest_flame_lv101._330_say = "Wygrawerowane litery na Wysadzanym Naszyjniku[ENTER]pochodz\185 z pradawnej kultury, kt\243ra ju\191 dawno[ENTER]wymar\179a. Aby je odszyfrowa\230, potrzebuj\234 Krwi[ENTER]Ognistego Kr\243la. Krew ta jest gor\234tsza od lawy. "
gameforge.main_quest_flame_lv101._340_say = "Dostarcz\234 ci jej. "
gameforge.main_quest_flame_lv101._350_say = "Wenn du das Blut erhalten hast musst du so schnell wie m\246glich zu mir zur\252ckkehren Denn selbst dieses Gef\228\223 kann seine Hitze nur f\252r eine begrenzte Zeit ohne Schaden \252berstehen "
gameforge.main_quest_flame_lv101._360_notice = "Zdob\185d\159 Krew Ognistego Kr\243la. "
gameforge.main_quest_flame_lv101._370_say = "Bez Krwi Ognistego Kr\243la nie damy rady odczyta\230[ENTER]grawerunku! "
gameforge.main_quest_flame_lv101._380_notice = "Uda\179o ci si\234 zdoby\230 Krew Ognistego Kr\243la. Wr\243\230[ENTER]teraz do Yon-I-Walker. "
gameforge.main_quest_flame_lv101._390_say = "Porozmawiaj z Yon-I-Walker. "
gameforge.main_quest_flame_lv101._400_say = "Znakomicie! Z pomoc\185 tej krwi b\234d\234 m\243g\179 odczyta\230[ENTER]grawerunek. Ale wymaga to troch\234 czasu. A wi\234c[ENTER]przyjd\159 jutro. "
gameforge.main_quest_flame_lv101._410_say = "Gedulde dich noch Stunde n und Minute n "
