gameforge.main_quest_flame_lv101._490_say = "\220berbringe Yak Hwan den Brief von Yon I Walker "
gameforge.main_quest_flame_lv101._500_say = "Konnte Yon I Walker die Gravur lesen Oh ein Brief mit allen Informationen von ihm Sehr gut zeig her "
gameforge.main_quest_flame_lv101._510_say = "Aha... Piecz\234\230 Wielkich Smok\243w. Wydaje mi si\234, \191e[ENTER]twierdza, kt\243r\185 odkryli\156my jest legendarn\185[ENTER]Twierdz\185 Czerwonego Smoka! Podobno uwi\234ziony jest[ENTER]tam jeden ze smok\243w, kt\243rego musz\185 zabi\230 Wasale[ENTER]Mroku, aby zdoby\230 Per\179y Nocy. Prosz\234, we\159 t\234[ENTER]Przepustk\234, ale dobrze j\185 schowaj. Wkr\243tce na[ENTER]pewno b\234dziesz j\185 potrzebowa\230... "
