gameforge.main_quest_flame_lv102._160_say = {}
gameforge.main_quest_flame_lv102._170_say = "M\243wisz, \191e to by\179 pot\234\191ny ognisty demon? To by\179[ENTER]Razador, w\179adca ognia! Je\156li wys\179ali go Wasale[ENTER]Mroku, to w twierdzy musi znajdowa\230 si\234 co\156[ENTER]bardzo wa\191nego. Ca\179kiem mo\191liwe, \191e legendarny[ENTER]Czerwony Smok! Musz\234 teraz porozmawia\230 z moimi[ENTER]doradcami.[ENTER]Prosz\234, we\159 t\234 Przepustk\234 i strze\191 j\185 jak oka w[ENTER]g\179owie. Z pewno\156ci\185 b\234dzie ci ona potrzebna. "
gameforge.main_quest_flame_lv102._180_sendLetter = "Razador "
