gameforge.main_quest_flame_lv102._200_say = "Uda\179o ci si\234 prze\191y\230 spotkanie ze straszliwym[ENTER]Razadorem. Schylam czo\179o przed tob\185. "
gameforge.main_quest_flame_lv102._210_say = {}
gameforge.main_quest_flame_lv102._220_say = "W\179adca Ognia nale\191y wraz z Kr\243lem Mrozu Alastorem[ENTER]do najgro\159niejszych i \156mierciono\156nych stworze\241[ENTER]podziemnych jakich zna ludzko\156\230. Ca\179kiem mo\191liwe,[ENTER]\191e sam Razador jest \159r\243d\179em Czarnej Materii. "
gameforge.main_quest_flame_lv102._230_say = {}
gameforge.main_quest_flame_lv102._240_say = {}
gameforge.main_quest_flame_lv102._250_say = "I to w\179a\156nie sprawia, \191e jest nadzwyczajnie[ENTER]silnym przeciwnikiem. Najpierw zg\179ad\159 w Twierdzy[ENTER]Czerwonego Smoka pomniejsze demony i wydob\185d\159 z[ENTER]ich cia\179 Czarn\185 Materi\234. 10 sztuk powinno[ENTER]wystarczy\230. Mo\191e w ten spos\243b znajdziemy jakie\156[ENTER]rozwi\185zanie, aby zneutralizowa\230 ich si\179y, zanim[ENTER]spotkamy na swojej drodze Razadora. "
gameforge.main_quest_flame_lv102._260_say = "W takim razie do dzie\179a! "
