gameforge.main_quest_flame_lv102._320_notice = "Uda\179o ci si\234 zdoby\230 10 jednostek Czarnej Materii.[ENTER]Znie\156 je do Yon-I-Walker. "
gameforge.main_quest_flame_lv102._330_say = "Na sam widok Czarnej Materii dostaj\234 g\234siej[ENTER]sk\243rki! No dobra, zabieram si\234 teraz do pracy...[ENTER]Dam ci zna\230, gdy b\234d\234 gotowy. "
