gameforge.main_quest_flame_lv102._360_say = "Mam dobre nowiny! Dowiedzia\179em si\234, w jaki spos\243b[ENTER]mo\191emy zneutralizowa\230 si\179\234 Czarnej Materii. "
gameforge.main_quest_flame_lv102._370_say = {}
gameforge.main_quest_flame_lv102._380_say = "Wszystkie si\179y w przyrodzie posiadaj\185 swoj\185[ENTER]przeciwwag\234 \150 \156wiat\179o i ciemno\156\230, ogie\241 i woda,[ENTER]dobro i z\179o. Czarna Materia r\243wnie\191 posiada swoje[ENTER]przeciwie\241stwo, kt\243re jest w stanie j\185[ENTER]zneutralizowa\230 - to Czysty Lumen. "
