gameforge.main_quest_flame_lv102._400_say = "Z przyjemno\156ci\185! "
gameforge.main_quest_flame_lv102._410_notice = "Zbierz 50 butelek Wody Mong i 100 Od\179amk\243w[ENTER]Energii. Nast\234pnie zanie\156 to wszystko do Yu-Hwan. "
