gameforge.main_quest_flame_lv102._440_say = "Yon-I-Walker ostrzeg\179 mnie, \191e do mnie wpadniesz.[ENTER]Dobra, teraz nie czas na pogaduszki, pora zakasa\230[ENTER]r\234kawy i zabra\230 si\234 do pracy. Ty w tym czasie[ENTER]mo\191esz sobie troch\234 odpocz\185\230. "
gameforge.main_quest_flame_lv102._450_say = "Yon-I-Walker ostrzeg\179 mnie, \191e wpadniesz do mnie.[ENTER]Zabra\179bym, si\234 do roboty, ale nie mam jeszcze[ENTER]wszystkich materia\179\243w, aby wyprodukowa\230 Czysty[ENTER]Lumen. Id\159 i zdob\185d\159 ich wi\234cej. "
