gameforge.main_quest_flame_lv103._030_say = "Nadesz\179a pora. Walka rozpocz\234ta. Wys\179a\179em do[ENTER]Twierdzy Czerwonego Smoka jeden z oddzia\179\243w.[ENTER]Wszyscy \191o\179nierze zaopatrzeni zostali w Czysty[ENTER]Lumen. Ich zmys\179y s\185 niesamowicie wyostrzone.[ENTER]Efekt jest niesamowity! "
