gameforge.main_quest_flame_lv99._260_sayTitle = "\163owy na Demony "
gameforge.main_quest_flame_lv99._270_say = "Pokonaj demony Ognistej Ziemi, kt\243re w\179\243cz\185 si\234 w[ENTER]pobli\191u twierdzy i sprawd\159, czy zafarbuje si\234[ENTER]twoja bro\241. "
gameforge.main_quest_flame_lv99._280_say = "Hm, jestem pewien, \191e w Ognistej Ziemi mo\191na[ENTER]znale\159\230 wskaz\243wki dotycz\185ce tej aury. Musisz wi\234c[ENTER]jeszcze raz wr\243ci\230 do Ognistej Ziemi i pokona\230[ENTER]demony, znajduj\185ce si\234 tu\191 obok twierdzy. "
