gameforge.main_quest_flame_lv99._300_say = "Ah so wie ich es erwartet hatte Das ist h\246chst bemerkenswert Ich werde dieses Papier etwas n\228her untersuchen Ruhe dich solange aus "
gameforge.main_quest_flame_lv99._310_sendLetter = "Aura erforschen "
gameforge.main_quest_flame_lv99._320_say = "Szuka ci\234 Yon-I-Walker. Id\159 do niego, aby[ENTER]dowiedzie\230 si\234 szczeg\243\179\243w. "
gameforge.main_quest_flame_lv99._330_say = "Ach, jeste\156! Aura jest zdradliwa i m\185ci m\243j rozum.Potrzebuj\234 S\179onecznych Zi\243\179, aby znowu m\243c jasno[ENTER]my\156le\230 i prowadzi\230 badania. Czy mo\191esz za\179atwi\230[ENTER]mi kilka? "
gameforge.main_quest_flame_lv99._340_say = "Oczywi\156cie. "
gameforge.main_quest_flame_lv99._350_say = "S\179oneczne Zio\179a rosn\185 w gor\185cych i suchych[ENTER]miejscach np. mo\191esz je znale\159\230 przez ca\179y rok w[ENTER]Ognistej Ziemi . Zaznacz\234 ci na mapie ostatnie[ENTER]miejsce, gdzie znalaz\179em te zio\179a. Chocia\191... nie[ENTER]jestem teraz pewny, czy rzeczywi\156cie one tam[ENTER]w\179a\156nie ros\179y. "
gameforge.main_quest_flame_lv99._360_say = "W takim razie do dzie\179a! "
gameforge.main_quest_flame_lv99._370_notice = "Id\159 do oznaczonego miejsca w Ognistej Ziemi i[ENTER]poszukaj S\179onecznych Zi\243\179. "
gameforge.main_quest_flame_lv99._380_sayTitle = "Sonnenkr\228uter besorgen "
