gameforge.main_quest_flame_lv99._400_say = "Przychodzisz z pustymi r\234kami? To niedobrze.[ENTER]Czuj\234, jak m\243j umys\179 staje si\234 coraz bardziej[ENTER]zamglony - to wina tej aury. Prosz\234, przynie\156 mi[ENTER]te S\179oneczne Zio\179a. "
