gameforge.main_quest_lv1._20_say = "Ekscytuj\185ce przygody w Metin2 to dopiero[ENTER]pocz\185tek. Na rozpocz\234cie dostaniesz kilka[ENTER]podstawowych informacji i r\243\191nych zada\241 od[ENTER]Stra\191nika Miejskiego. Prosz\234, udaj si\234 do niego,[ENTER]ju\191 na Ciebie czeka.[ENTER][ENTER]Je\156li b\234dziesz chcia\179 zapolowa\230, znajdziesz kilka[ENTER]dzikich zwierz\185t na zewn\185trz wioski, kt\243re s\185[ENTER]oznaczone na czerwono Mini-Mapie. Na pocz\185tek[ENTER]powiniene\156 polowa\230 na naj\179atwiejsze zwierz\234ta,[ENTER]np. Dzikie Psy.[ENTER]Powodzenia! "
gameforge.main_quest_lv1._30_targetVid = "Znajd\159 Stra\191nika Miejskiego "
gameforge.main_quest_lv1._40_sayTitle = "Znajd\159 Stra\191nika Miejskiego "
gameforge.main_quest_lv1._50_sayReward = "Porozmawiaj ze Stra\191nikiem Miejskim. Znajd\159 NPC,[ENTER]na kt\243rego wskazuj\234 strza\179ka i na niego kliknij.[ENTER]Je\156li nie widzisz \191adnego NPC, pod\185\191aj za[ENTER]czerwonym znaczkiem na Mini-Mapie. "
gameforge.main_quest_lv1._60_sayTitle = "Stra\191nik Miejski: "
gameforge.main_quest_lv1._70_say = "Jeste\156 nowy? Widz\234, \191e nie zrobili jeszcze z[ENTER]Ciebie \191o\179nierza. Mia\179e\156 w og\243le ju\191 jaki\156[ENTER]trening? Sp\243jrz na siebie! Wiesz w og\243le jak u\191y\230[ENTER]broni? S\179uchaj! Musimy by\230 czujni, je\156li chcemy[ENTER]przetrwa\230 na tej wojnie. Dop\243ki nie osi\185gniesz 10[ENTER]poziomu b\234d\234 Ci pomaga\179. Nie b\234dzie \179atwo![ENTER]Ruszaj! "
gameforge.main_quest_lv1._80_say = "Teraz id\159 i naucz si\234 podstaw polowania! Kiedy[ENTER]osi\185gniesz wy\191szy poziom, przyjd\159 do wioski i ze[ENTER]mn\185 porozmawiaj. Czemu jeszcze tu stoisz?[ENTER]Za samo stanie w miejscu nie dostaje si\234 Punkt\243w[ENTER]Do\156wiadczenia! "
