gameforge.main_quest_lv10._110_sayTitle = "Trening Kapitana "
gameforge.main_quest_lv10._120_sayReward = "Pierwsze zlecenie Kapitana prowadzi Ciebie do[ENTER]s\185siedniej wioski. Masz tam odnale\159\230 muzyka[ENTER]Yu-Hwan i spyta\230 si\234 go tajemne dokumenty dla[ENTER]Kapitana. "
gameforge.main_quest_lv10._130_sayTitle = "Muzyk Yu-Hwan: "
gameforge.main_quest_lv10._140_say = "\175ycie jest tylko snem, jak wszystko inne. Sk\185d[ENTER]przybywamy i dok\185d zmierzamy? \140wiat jest pe\179en[ENTER]konfilikt\243w. Uczciwa praca nigdy nie pop\179aca.[ENTER]Jeste\156 tu, aby wys\179ucha\230 pie\156ni? "
gameforge.main_quest_lv10._150_say = "Och, przys\179a\179 Ci\234 Kapitan! Ciii, nie m\243w tak[ENTER]g\179o\156no... Nikt z wioski nie mo\191ne dowiedzie\230 si\234[ENTER]o mojej prawdziwej to\191samo\156ci. Musisz by\230 godny[ENTER]zaufania, skoro Kapitan wys\179a\179 w\179a\156nie Ciebie![ENTER]Masz, trzymaj. Dokument zawiera wszystkie[ENTER]informacje jakie mog\179em zebra\230. Dostarcz go do[ENTER]Kapitana. "
gameforge.main_quest_lv10._160_sayTitle = "Muzyk Yu-Hwan: "
gameforge.main_quest_lv10._170_say = "Po\156piesz si\234! Je\156li b\234dziesz tu tak d\179u\191ej sta\179[ENTER]co\156 z\179ego mo\191e si\234 wydarzy\230. Czym jest \191ycie?[ENTER]\175ycie jest bardzo kr\243tkie... Ciesz si\234 nim tak[ENTER]d\179ugo jak tylko mo\191esz. "
gameforge.main_quest_lv10._180_targetVid = "Wr\243\230 do Kapitana. "
gameforge.main_quest_lv10._190_sayReward = "Muzyk Yu-Hwan pracuj\185cy potajemnie jako szpieg[ENTER]przekaza\179 Ci wa\191ne dokumenty. Zanie\156 je[ENTER]Kapitanowi w pierwszej wiosce. "
gameforge.main_quest_lv10._200_say = "To jest dokument od Muzyka? Nie\159le jak na nowego[ENTER]poszukiwacza przyg\243d! Wi\185\191\234 z Tob\185 wielkie[ENTER]nadzieje. We\159 to jako potwierdzenie Twojej[ENTER]ci\234\191kiej pracy. Pracuj tak dalej dla swojego[ENTER]Kr\243lestwa! "
gameforge.main_quest_lv10._20_sayReward = "Uzbiera\179e\156 wystarczaj\185co du\191o do\156wiadczenia, aby[ENTER]m\243c s\179u\191y\230 twojemu kr\243lestwu jako[ENTER]pe\179nowarto\156ciowy wojownik. Od tej chwili Kapitan[ENTER]b\234dzie twoim zleceniodawcom. Znajdziesz go w[ENTER]pierwszej wiosce. Nie zwlekaj zbyt d\179ugo. "
gameforge.main_quest_lv10._30_sayTitle = "Kapitan "
gameforge.main_quest_lv10._40_say = "Wygl\185dasz znajomo... Och tak, my\156l\234, \191e s\179ysza\179em[ENTER]ju\191 o Tobie. Jeste\156 tym nowym poszukiwaczem[ENTER]przyg\243d, kt\243ry udowodni\179 ju\191 swoje umiej\234tno\156ci.[ENTER]Nie wiem jak bardzo jeste\156 uzdolniony, ale w[ENTER]przysz\179o\156ci otrzymasz wiele zada\241. "
gameforge.main_quest_lv10._50_say = "Zostanie przygotowanych dla Ciebie kilka wyzwa\241.[ENTER]Znasz mo\191e histori\234 o trzech Kr\243lestwach[ENTER]kontynentu cz\234sto nazywanego Niebem? Znasz j\185?[ENTER]Czego Ci\234 tam instruktorzy nauczyli? Czy musz\234[ENTER]uczy\230 Ci\234 tak podstawowych rzeczy? "
gameforge.main_quest_lv10._60_say = "To s\185 wa\191ne sprawy i podsumuj\234 je dla Ciebie.[ENTER]Dawno temu by\179o jedno Zjednoczone Kr\243lestwo.[ENTER]Kiedy pojawi\179y si\234 Kamienie Metin, Kr\243lestwo[ENTER]zosta\179o podzielone na 3 mniejsze Kr\243lestwa:[ENTER]Shinsoo - Kr\243lestwo Handlu, Chunjo - Kr\243lestwo[ENTER]Religii, i Jinno, kt\243re by\179o Kr\243lestwem Armii. "
gameforge.main_quest_lv10._70_say = "Ka\191de z Kr\243lestw do tej pory stara si\234 otrz\185sn\185\230[ENTER]po zamieszaniu, jakie wytworzy\179y Kamienie Metin.[ENTER]Wszyscy pr\243buj\185 zjednoczy\230 Kr\243lestwa na nowo.[ENTER]Ty tak\191e musisz pracowa\230 nad Zjednoczeniem Trzech[ENTER]Kr\243lestw! To jest bardzo wa\191ne, nie mo\191esz o tym[ENTER]zapomnie\230! "
gameforge.main_quest_lv10._80_say = "Przydziel\234 Ci pierwsze zadanie.[ENTER]Spokojnie, to jest raczej prosta robota.[ENTER]W nast\234pnej wiosce znajdziesz Muzyka o imieniu[ENTER]Yu-Hwan. Ludzie my\156l\185, \191e opu\156ci\179 armi\234, aby[ENTER]zosta\230 muzykiem. Tak naprawd\234 jest szpiegiem.[ENTER]Yu-Hwan ma dokument, kt\243rego potrzebuj\234 Dostarcz[ENTER]mi go. Nie zapomnaj, \191e to tajna misja. "
gameforge.main_quest_lv10._90_say = "Kliknij klawisz M, aby si\234 dowiedzie\230 jak dotrze\230[ENTER]do nast\234pnej wioski. Skorzystaj z Portalu[ENTER]oznaczonego niebiesk\185 kropk\185. Pospiesz si\234! Muzyk[ENTER]Yu-Hwan jest wysokim m\234\191czyzn\185 z instrumentem. "
