gameforge.main_quest_lv15._100_say = "Jinno: Nasze Kr\243lestwo zawsze mia\179o siln\185[ENTER]wojskow\185 tradycj\234. Kr\243l zjednoczy\179 kontynent[ENTER]dzi\234ki pot\234\191nej kawalerii.[ENTER]Nawet teraz, gdy jeste\156my podzieleni z powodu[ENTER]problem\243w jakie stworzy\179y Kamienie Metin, nasze[ENTER]Kr\243lestwo nadal ma prawdziw\185 moc Iryung. "
gameforge.main_quest_lv15._10_qSetTitle = "Aktualna sytuacja "
gameforge.main_quest_lv15._110_say = "Nadal mamy najpot\234\191niejsz\185 armi\234 ze wszystkich[ENTER]Trzech Kr\243lestw, jednak mimo tego nie jeste\156my w[ENTER]stanie przeciwdzia\179a\230 Kamieniom Metin. Je\156li[ENTER]naprawd\234 by\156my chcieli, mogliby\156my z \179atwo\156ci\185[ENTER]podbi\230 inne Kr\243lestwa.[ENTER]Powiniene\156 mocno trenowa\230, aby\156 m\243g\179 sta\230 si\234[ENTER]dobrym \191o\179nierzem. "
gameforge.main_quest_lv15._120_say = "Dam Ci teraz nowe zadanie.[ENTER]Dostarcz amunicj\234 do Yu-Hwan w drugiej wiosce.[ENTER]Nasze kr\243lestwo ma pot\234\191n\185 armi\234, ale musimy by\230[ENTER]pewni, \191e mamy wystarczaj\185c\185 ilo\156\230 amunicji.[ENTER]Je\156li dostarczysz j\185 do Yu-Hwan, pomo\191esz im w[ENTER]dozbrojeniu wioski. "
gameforge.main_quest_lv15._130_sayReward = "Otrzyma\179e\156 36.000 Punkt\243w Do\156wiadczenia.[ENTER]Otrzyma\179e\156 10.000 Yang.[ENTER]Otrzyma\179e\156 Ornament. "
gameforge.main_quest_lv15._140_sayTitle = "Aktualna sytuacja "
gameforge.main_quest_lv15._150_sayReward = "Kapitan powierzy\179 Ci przesy\179k\234 dla Yu-Hwan. Udaj[ENTER]si\234 do drugiej wioski i dostarcz mu j\185. "
gameforge.main_quest_lv15._160_say = "Pewnego razu odby\179a si\234 krwawa bitwa pomi\234dzy[ENTER]Sung Mahi i Bogiem Smoka. Teraz trwaj\185 wojny[ENTER]pomi\234dzy lud\159mi. Och, to znowu Ty![ENTER]Czego potrzebujesz tym razem? Kapitan ma co\156[ENTER]wa\191nego dla mnie? Dzi\234kuj\234. Nie chc\234, aby kto\156[ENTER]zobaczy\179 nas razem, dlatego prosz\234, id\159 ju\191! "
gameforge.main_quest_lv15._170_makequestbutton = "Porozmawiaj z Kapitanem. "
gameforge.main_quest_lv15._175_say = "Przekaza\179e\156 Yu-Hwan przesy\179k\234 od Kapitana. Powr\243\230[ENTER]teraz do Kapitana i odbierz swoj\185 nagrod\234. "
gameforge.main_quest_lv15._180_say = "Dobra robota! Je\191eli nadal b\234dziesz si\234 tak[ENTER]stara\230, staniesz si\234 wa\191nym pomocnikiem w naszej[ENTER]wiosce. Oto Twoja nagroda. "
gameforge.main_quest_lv15._20_say = "Je\156li p\243jdziesz do Kapitana, dowiesz si\234 o[ENTER]aktualnie panuj\185cej sytuacji dotycz\185cej Trzech[ENTER]Kr\243lestw. Id\159 do niego. "
gameforge.main_quest_lv15._30_say = "Widz\234, \191e jeste\156 gotowy aby dowiedzie\230 si\234 wi\234cej[ENTER]o aktualnej sytuacji. Rozpoczn\234 od naszego[ENTER]Kr\243lestwa. Aby wygra\230 wojn\234, musisz pozna\230[ENTER]najpierw siebie, zanim naprawd\234 poznasz swojego[ENTER]wroga. "
gameforge.main_quest_lv15._40_say = "Shinsoo: Nasze Kr\243lestwo by\179o zawsze Kr\243lestwem[ENTER]handlu. Mieli\156my bardzo rozbudowan\185 sie\230[ENTER]handlow\185, dlatego wymiana kwit\179a w najlepsze.[ENTER]Od czasu pojawienia si\234 Kamieni Metin, handel[ENTER]pogorszy\179 si\234 i interesy sz\179y bardzo \159le.[ENTER]Jako kr\243lestwo handlowe nigdy nie mieli\156my du\191ej[ENTER]armii.[ENTER][ENTER]Dzi\234ki naszemu dobrobytowi, byli\156my w stanie[ENTER]zatrudnia\230 mn\243stwo najemnik\243w. Najemnicy s\185 godni[ENTER]zaufania i lojalni, dop\243ki s\185 op\179acani. "
gameforge.main_quest_lv15._50_say = "Dzi\234ki Najemnikom, nasze Kr\243lestwo odzyska\179o[ENTER]stabilno\156\230.[ENTER]Ale \191eby by\230 przygotowanym na przysz\179e wojny,[ENTER]potrzeba nam wi\234cej najemnik\243w i silniejszej[ENTER]ekonomii. To wymaga od nas du\191o pracy. "
gameforge.main_quest_lv15._60_say = "Dam Ci teraz nowe zadanie.[ENTER]Zanie\156 t\185 specjalno\156\230 do Yu-Hwan w s\185siedniej[ENTER]wiosce. Nasze Kr\243lestwo opiera si\234 na handlu,[ENTER]handlujemy wieloma r\243\191nymi specjalno\156ciami[ENTER]regionu. Bardzo wspomo\191esz wiosk\234, je\156li[ENTER]dostarczysz to do Yu-Hwan. "
gameforge.main_quest_lv15._70_say = "Chunjo: jeste\156my pod panowaniem Gubernatora Yoon[ENTER]Young. Nasze Kr\243lestwo swoj\185 si\179\234 czerpie z[ENTER]wiary. Dzi\234ki wierze wiedzieli\156my o istnieniu[ENTER]Sung Mahi przed innymi. Nasi Szamani przygotowali[ENTER]nas na przybycie Kamieni Metin. W tej chwili[ENTER]szamani ci\234\191ko pracuj\185 nad zapewnieniem[ENTER]bezpiecze\241stwa naszemu Kr\243lestwu.[ENTER]S\185 bardzo utalentowani, ich si\179a le\191y w wierze.[ENTER]Bez nich, kwesti\185 czasu by\179oby podbicie nas przez[ENTER]inne Kr\243lestwa. "
gameforge.main_quest_lv15._80_say = "Mieszka\241cy naszego kraju to ludzie g\179\234bokiej[ENTER]wiary, modl\185cy si\234 codziennie do Boga Smoka.[ENTER]Hojny B\243g Smoka chroni nas przed[ENTER]zmartwychwstaniem Sung Mahis. Powinni\156my broni\230[ENTER]si\234 przed barbarzy\241skimi atakami i zjednoczy\230[ENTER]kontynent na korzystnych dla nas warunkach. "
gameforge.main_quest_lv15._90_say = "Dam Ci teraz nowe zadanie.[ENTER]Dostarcz ten kamienny pos\185\191ek od Boga Smoka do[ENTER]Yu-Hwan w s\185siedniej wiosce. Nasze Kr\243lestwo jest[ENTER]bardzo religijne i g\179\234boka wiara w Boga Smoka[ENTER]jest bardzo wa\191na. Je\156li dostarczysz to do[ENTER]Yu-Hwan, wy\156wiadczysz mieszka\241com du\191\185 przys\179ug\234. "
