gameforge.main_quest_lv3._80_sendLetter = "Pom\243\191 Handlarce R\243\191no\156ci "
gameforge.main_quest_lv3._90_sayReward = "Id\159 do Handlarki R\243\191no\156ci, potrzebuje twojej[ENTER]pomocy. "
gameforge.main_quest_lv30 = {}
gameforge.main_quest_lv30._100_say = "Na Kamiennym Pomniku s\185 wyryte napisy. Szybko je[ENTER]spisujesz. "
gameforge.main_quest_lv30._10_targetVid = "Znajd\159 Uriela "
gameforge.main_quest_lv30._110_say = "Uriel mia\179 racj\234: Na Kamiennym Pomniku[ENTER]rzeczywi\156cie znajdowa\179 si\234 napis. Nie potrafi\179e\156[ENTER]go co prawda przeczyta\230 ale przynajmniej zrobi\230[ENTER]kopi\234. Zanie\156 j\185 Uriel. "
gameforge.main_quest_lv30._120_say = "Znalaz\179e\156 Kamienny Pomnik Hasuna? Och, masz nawet[ENTER]kopi\234 napisu, wspaniale! Jest to odkrycie na[ENTER]skal\234 historyczn\185! Poka\191 no.[ENTER]Hmm... Wygl\185da na to, \191e jest to rzeczywi\156cie[ENTER]informacja na temat Kamieni Metin. Niestety nie[ENTER]potrafi\234 rozszyfrowa\230 wszystkiego. To pismo jest[ENTER]bardzo staro\191ytne, niekt\243re litery wydaj\185 si\234[ENTER]prawie antyczne. Co teraz zrobimy? "
gameforge.main_quest_lv30._130_say = "Ach, mam pomys\179! Znasz Dolin\234 Seungryong?[ENTER]Znajduj\234 si\234 tam tajemnicza machina z czas\243w[ENTER]staro\191ytnych. Gdyby\156 znalaz\179 tam stare napisy,[ENTER]m\243g\179bym by\230 mo\191e za ich pomoc\185 odgadn\185\230 znaczenie[ENTER]brakuj\185cych liter. Udaj si\234 do Doliny Seungryong[ENTER]i znajd\159 Kamienny Pomnik Seul Ronga! "
gameforge.main_quest_lv30._140_targetVid = "Tablica w Dolinie Seungryong "
gameforge.main_quest_lv30._150_say = "M\234drzec Uriel potrzebuje wi\234cej staro\191ytnych[ENTER]tekst\243w, aby odgadn\185\230 znaczenie niekt\243rych[ENTER]nieznanych mu liter.[ENTER]Id\159 do Doliny Seungryong i poszukaj tam napis\243w[ENTER]na Kamiennym Pomniku Seul Ronga. "
gameforge.main_quest_lv30._160_say = "Znalaz\179e\156 wi\234cej napis\243w? Och! Dzi\234ki Tobie b\234d\234[ENTER]nied\179ugo w stanie, rozwia\230 tajemnice wok\243\179[ENTER]Kamieni Metin. Stanie si\234 to by\230 mo\191e znaczniej[ENTER]szybciej ni\191 my\156la\179em. Dzi\234ki, tak bardzo Ci[ENTER]dzi\234kuj\234! Je\156li w przysz\179o\156ci znowu b\234d\234[ENTER]potrzebowa\179 twej pomocy, dam Ci zna\230. Aha, prosz\234[ENTER]przyjmij to jako wynagrodzenie za twoje trudy! "
gameforge.main_quest_lv30._20_sendLetter = "Sekret Kamieni Metin "
gameforge.main_quest_lv30._30_say = "Uriel w ko\241cu zdoby\179 kilka informacji o[ENTER]tajemniczych kamieniach Metin. Id\159 i z nim[ENTER]porozmawiaj. "
gameforge.main_quest_lv30._40_sayTitle = "Uriel: "
gameforge.main_quest_lv30._50_say = "Kapitan ju\191 raz Ci\234 do mnie wys\179a\179. Wygl\185dasz na[ENTER]bardzo utalentowanego.[ENTER]Musz\234 prosi\230 Ci\234 o przys\179ug\234.[ENTER]Zdajesz sobie spraw\234 z istnienia Kamieni Metin,[ENTER]prawda? Przyby\179y one z niebios. Posiadaj\185[ENTER]diabelsk\185 energie i rozprzestrzeniaj\185 plag\234,[ENTER]zwierz\234ta dziczej\185 z ich powodu. Nie wiemy jak[ENTER]dosta\179y si\234 do naszego \156wiata lub co maj\185 w[ENTER]\156rodku. To czyni dochodzenie jeszcze[ENTER]trudniejszym.[ENTER]Ostatnio znalaz\179em klucz do sekretu Kamieni Metin. "
gameforge.main_quest_lv30._60_say = "Jest pewna tablica pochodz\185ca ze staro\191ytnego[ENTER]kr\243lestwa, znajduj\185ca si\234 w \163atwym Lochu Ma\179p.[ENTER]My\156l\234, \191e informacje na tej tablicy zawieraj\185[ENTER]sekret Kamieni Metin. Je\156li dostarczysz mi te[ENTER]informacje, by\230 mo\191e b\234d\234 w stanie odkry\230 sekret[ENTER]Kamienie Metin. Prosz\234 dostarcz mi te informacje[ENTER]z tablicy w \163atwym Lochu Ma\179p! "
gameforge.main_quest_lv30._70_sayReward = "Otrzyma\179e\156 122.000 Punkt\243w Do\156wiadczenia.[ENTER]Otrzyma\179e\156 20.000 Yang.[ENTER]Otrzyma\179e\156 Srebrn\185 Bransoletk\234. "
gameforge.main_quest_lv30._80_targetVid = "Kamienny Pomnik w \163atwym Lochu Ma\179p "
gameforge.main_quest_lv30._90_say = "Wydaje si\234, \191e M\234drzec Uriel wpad\179 na trop, kt\243ry[ENTER]pomo\191e mu w rozwi\185zaniu tajemnicy Kamieni Metin.[ENTER]Udaj si\234 do \163atwego Lochu Ma\179p i znajd\159 tam[ENTER]Kamienny Pomnik Hasuna. "
gameforge.main_quest_lv32 = {}
gameforge.main_quest_lv32._100_sayReward = "Wskaz\243wka: Je\156li b\234dziesz podr\243\191owa\179 konno,[ENTER]dotrzesz tam o wiele szybciej i wygodniej. "
gameforge.main_quest_lv32._10_sendLetter = "Tajemnicza Ksi\185\191ka "
gameforge.main_quest_lv32._110_npcChat = "Strony Tajemniczej Ksi\185\191ki "
gameforge.main_quest_lv32._120_sayTitle = "Domokr\185\191ca: "
gameforge.main_quest_lv32._130_say = "Od czas\243w gdy \156wiat sta\179 si\234 burzliwy, handel[ENTER]sta\179 si\234 jeszcze trudniejszy. Co chcesz kupi\230?[ENTER]Ach, przys\179a\179 Ci\234 M\234drzec Uriel? Jest sta\179ym[ENTER]klientem. Poszukuje starych ksi\185\191ek z r\243\191nych[ENTER]miejsc. Uwa\191am to za raczej zabawne.[ENTER]Hahaha. Chcesz si\234 czego\156 dowiedzie\230 o starych[ENTER]ksi\185\191kach?[ENTER]Hmmm... O starych ksi\185\191kach... "
gameforge.main_quest_lv32._140_say = "S\179ysza\179em co\156 kilka dni temu, ale nie powiem Ci o[ENTER]tym za darmo! Je\156li spe\179nisz moje \191yczenie, dam[ENTER]Ci t\185 informacj\234. Ostatnio kwitnie handel broni\185.[ENTER]Ale nie mog\234 zapewni\230 takiej ilo\156ci na w\179asn\185[ENTER]r\234k\234. Wszyscy ludzie chc\185 kupi\230 bro\241! Zamiast tak[ENTER]bezczynnie sta\230, zdob\185d\159 dla mnie 20 Srebrnych[ENTER]Mieczy+0. Jak tylko mi je dostarczysz, podziel\234[ENTER]si\234 z tob\185 informacj\185 o pewnej Starej Ksi\234dze. "
gameforge.main_quest_lv32._150_targetVid = "Id\159 do Domokr\185\191cy "
gameforge.main_quest_lv32._160_sayTitle = "Masz 20 Srebrnych Mieczy+0 "
gameforge.main_quest_lv32._170_say = "Domokr\185\191ca wie co\156 na temat Starej Ksi\234gi.[ENTER]Przynie\156 mu 20 Srebrnych Mieczy +0, a powie Ci,[ENTER]co wie. "
gameforge.main_quest_lv32._180_sayTitle = "Zdob\185d\159 20 Srebrnych Mieczy+0 "
gameforge.main_quest_lv32._190_say = "Domokr\185\191ca, kt\243ry wie co\156 o Starej Ksi\234dze, nie[ENTER]chce si\234 podzieli\230 t\185 informacj\185 za darmo. W[ENTER]zamian chce otrzyma\230 20 Srebrnych Mieczy+0.[ENTER]Zdob\185d\159 20 Srebrnych Mieczy+0 i mu je dostarcz. "
gameforge.main_quest_lv32._200_npcChat = "Mam Miecze "
gameforge.main_quest_lv32._20_targetVid = "Poszukaj M\234drca Uriel "
gameforge.main_quest_lv32._210_say = "Dobrze. Jeste\156 bardziej utalentowany ni\191[ENTER]my\156la\179em. Dzi\234ki Twojej pomocy m\243j interes b\234dzie[ENTER]nied\179ugo przynosi\179 wi\234cej zysku.[ENTER]Co do tej Strony... par\234 dni temu przechodzi\179em[ENTER]obok pawilonu, obok kt\243rego sta\179 pomnik.[ENTER]Zatrzyma\179em si\234 tam, aby odpocz\185\230 i dostrzeg\179em[ENTER]potargany kawa\179ek papieru u coko\179u pomnika. "
gameforge.main_quest_lv32._220_say = "Nic wtedy sobie nie pomy\156la\179em. Ale teraz wydaje[ENTER]mi si\234, \191e mog\179a by\230 to jedna z tych stron,[ENTER]kt\243rych szukasz. Nazwa pomnika? Hmm... czy nie[ENTER]by\179 to przypadkiem Pomnik Woela? Tak, tak w\179a\156nie[ENTER]si\234 nazywa\179. Pomnik Woela w pobli\191u s\185siedniej[ENTER]wioski. Tam powiniene\156 szuka\230! "
gameforge.main_quest_lv32._230_sayTitle = "Domokr\185\191ca: "
gameforge.main_quest_lv32._240_say = "Przynie\156 mi 20 Srebrnych Mieczy+0, a podziel\234 si\234[ENTER]z tob\185 informacj\185 o pewnej starej Stronie. "
gameforge.main_quest_lv32._250_sendLetter = "Poszukiwania 1. Strony "
gameforge.main_quest_lv32._260_targetVid = "Pomnik ko\179o pawilonu "
gameforge.main_quest_lv32._270_say = "Domokr\185\191ca widzia\179 u coko\179u Pomnika Woela star\185[ENTER]Stron\234 ksi\234gi, gdy odpoczywa\179 w pawilonie[ENTER]nieopodal pomnika.[ENTER]Udaj si\234 do Pomnika Woela w pobli\191u pierwszej[ENTER]wioski i sprawd\159, czy jest to mo\191e jedna z tych[ENTER]stron, kt\243rych szukasz. "
gameforge.main_quest_lv32._280_npcChat = "Pomnik Woela "
gameforge.main_quest_lv32._290_say = "TAK! To Pomnik Woela! W ko\241cu![ENTER]Oto ona! Znalaz\179em Pierwsz\185 Stron\234! "
gameforge.main_quest_lv32._300_sendLetter = "Pierwsza Strona "
gameforge.main_quest_lv32._30_say = "M\234drzec Uriel potrzebuje twojej pomocy. Bada on[ENTER]obecnie bardzo star\185, tajemnicz\185 ksi\234g\234. Udaj si\234[ENTER]do niego i spytaj si\234, w jaki spos\243b mo\191esz[ENTER]pom\243c. "
gameforge.main_quest_lv32._310_targetVid = "Poszukaj M\234drca Uriel "
gameforge.main_quest_lv32._320_sayTitle = "Znalaz\179e\156 Pierwsz\185 Stron\234. "
gameforge.main_quest_lv32._330_say = "Post\185pi\179e\156 zgodnie z rad\185 Domokr\185\191cy i znalaz\179e\156[ENTER]pierwsz\185 z brakuj\185cych stron. Zanie\156 j\185 M\234drcowi[ENTER]Uriel. "
gameforge.main_quest_lv32._340_say = "Wi\234c, znalaz\179e\156 jak\185\156 Star\185 Stron\234?[ENTER]Och, masz jedn\185, wspaniale! Zobaczmy, co tam jest[ENTER]napisane. Hmmm...[ENTER]Wygl\185da to jak pami\234tnik. Pos\179uchaj! "
gameforge.main_quest_lv32._350_sayTitle = "Pierwsza Strona Ksi\185\191ki: "
gameforge.main_quest_lv32._360_sayReward = "Lee Seop z Kr\243lestwa Taejo poszerza swoje[ENTER]terytorium, dzi\234ki licznym podbojom. Chce podbi\230[ENTER]wszystkie terytoria si\179\185, przy pomocy swoich[ENTER]\191o\179nierzy. Musimy mu w tym przeszkodzi\230 za[ENTER]wszelk\185 cen\234 i upewni\230 si\234, \191e nie zaatakuje[ENTER]naszego Kr\243lestwa. Nasze mo\191liwo\156ci s\185[ENTER]ograniczone. Dlatego zdecydowali\156my si\234[ENTER]skorzysta\230 z zabronionej magii! "
gameforge.main_quest_lv32._370_sayTitle = "Pierwsza Strona Ksi\185\191ki: "
gameforge.main_quest_lv32._380_sayReward = "To jest nasza jedyna szansa na przetrwanie.[ENTER]Nie wiemy czy nam si\234 uda, ale definitywnie[ENTER]powinni\156my spr\243bowa\230. Zanim nas zaatakuj\185, musimy[ENTER]zdoby\230 informacje o zakazanej magii.[ENTER]Prawdopodobnie w starych legendach odnajdziemy[ENTER]informacje o pradawnej magii. Zgodnie z[ENTER]legendami, informacje te mo\191emy odnale\159\230 w[ENTER]Smoczej Dolinie, to tam powinni\156my zacz\185\230. "
gameforge.main_quest_lv32._390_say = "Z tekst\243w wynika, \191e w tym kraju w staro\191ytno\156ci[ENTER]istnia\179a jaka\156 dziwna religia. Zanim Lee Seop z[ENTER]Kr\243lestwa Taejo zjednoczy\179 ca\179y kontynent, ka\191dy[ENTER]kraj charakteryzowa\179 si\234 inn\185 religi\185 i innymi[ENTER]wyznawcami. Autor tego tekstu bez w\185tpienia by\179[ENTER]jakim\156 uczonym. Zapewne nale\191a\179 do jednej z[ENTER]gildii, a mo\191e by\179 nawet jakim\156 przyw\243dc\185. Gildie[ENTER]by\179y tworzone wy\179\185cznie przez osoby z g\243rnych[ENTER]warstw spo\179ecze\241stwa. "
gameforge.main_quest_lv32._400_say = "Wok\243\179 starych historii ze Smoczej Doliny toczy[ENTER]si\234 wiele rozm\243w. Nawet ja znam kilka takich[ENTER]opowie\156ci. Prawdopodobnie nadal mamy szanse na[ENTER]zdobycie ciekawych informacji lub nawet na[ENTER]znalezienie kolejnych Stron Pami\234tnika. Niestety[ENTER]nie wiem jak dotrze\230 do Doliny Smoka, nigdy tam[ENTER]nie by\179em. Id\159 do \163owcy Yang-Shin w s\185siedniej[ENTER]wiosce, on na pewno wie jak tam dotrze\230. Mo\191liwe,[ENTER]\191e b\234dzie wiedzia\179 gdzie powinni\156my zacz\185\230[ENTER]szuka\230. "
gameforge.main_quest_lv32._40_say = "Pozdrawiam.[ENTER]To co mi da\179e\156 ostatnim razem by\179o bardzo[ENTER]pomocne. Z twoj\185 pomoc\185 by\179em w stanie poczyni\230[ENTER]du\191y post\234p w moim dochodzeniu. Ale teraz mam[ENTER]problem... Podczas poszukiwania informacji o[ENTER]tajemniczych kamieniach i tajemniczej kobiecie,[ENTER]uda\179o mi si\234 odnale\159\230 pewn\185 Star\185 Ksi\234g\234.[ENTER]Poniewa\191 ksi\185\191ka jest napisana w pradawnym[ENTER]j\234zyku, nie jest \179atwo j\185 odczyta\230. My\156l\234, \191e s\185[ENTER]tam wa\191ne informacje, kt\243re opisuj\185 pow\243d zmian. "
gameforge.main_quest_lv32._410_say = "To takie ekscytuj\185ce! Oh, zanim zapomn\234: oto[ENTER]twoja nagroda za Pierwsz\185 Stron\234! "
gameforge.main_quest_lv32._420_sayReward = "Otrzyma\179e\156 1.000.000 Punkt\243w Do\156wiadczenia. "
gameforge.main_quest_lv32._430_sayReward = "Otrzyma\179e\156 50.000 Yang. "
gameforge.main_quest_lv32._440_sayReward = "Otrzyma\179e\156 \163z\234 Bogini. "
gameforge.main_quest_lv32._450_sendLetter = "Id\159 do \163owcy "
gameforge.main_quest_lv32._460_targetVid = "Znajd\159 \163owc\234 Yang-Shin. "
gameforge.main_quest_lv32._470_sayTitle = "Spytaj Yang-Shin o Smocz\185 Dolin\234 "
gameforge.main_quest_lv32._480_say = "Na pierwszej stronie Tajemniczej Ksi\234gi jest mowa[ENTER]o Smoczej Dolinie. Uriel zna o niej legendy, nie[ENTER]wie jednak, gdzie jej szuka\230. Udaj si\234 do[ENTER]s\185siedniej wioski i spytaj si\234 \163owcy Yang-Shin,[ENTER]czy wie co\156 wi\234cej na ten temat. "
gameforge.main_quest_lv32._490_sayReward = "Wskaz\243wka: \163owca jest w s\185siedniej wiosce. "
gameforge.main_quest_lv32._500_npcChat = "Informacje o Smoczej Dolinie "
gameforge.main_quest_lv32._50_say = "Problem w tym, \191e strony s\185 mocno podarte.[ENTER]Dlatego tak ci\234\191ko je odczyta\230. Prawdopodobnie,[ENTER]Ksi\185\191ka przechodzi\179a z r\185k do r\185k, dlatego jest[ENTER]tak bardzo zniszczona. Kto\156 wyrwa\179 z niej a\191 13[ENTER]Stron. Mo\191esz je dla mnie zdoby\230? Prawdopodobnie[ENTER]znajduj\185 si\234 na nich informacje, kt\243re powiedz\185[ENTER]nam jak mo\191na zako\241czy\230 wojn\234. "
gameforge.main_quest_lv32._510_sayTitle = "Yang-Shin: "
gameforge.main_quest_lv32._520_say = "Chcesz si\234 czego\156 dowiedzie\230 o Dolinie Smoka?[ENTER]Hmmm. Dlaczego chcesz uda\230 si\234 w tak[ENTER]niebezpieczne miejsce? Dolina jest pe\179na Ork\243w i[ENTER]cz\179onk\243w Tajemniczej Sekty. Nawet ja, wielki[ENTER]\179owca, nie lubi\234 tam chodzi\230. By\179oby lepiej,[ENTER]je\156li trzyma\179by\156 si\234 od Doliny z daleka. "
gameforge.main_quest_lv32._530_say = "Co? Szukasz starych Stron?[ENTER]Hm! S\179ysza\179em raz od innego \179owcy, \191e Elitarny[ENTER]Ork Czarodziej ma jakie\156 dziwne papiery. Ale czy[ENTER]to prawda? Je\156li jeste\156 taki ciekawy, id\159 i[ENTER]sprawd\159 sam. Powiedzia\179em ju\191, \191e to jest[ENTER]niebezpieczne miejsce. Trzymaj si\234! "
gameforge.main_quest_lv32._540_sendLetter = "Poszukiwania Drugiej Strony "
gameforge.main_quest_lv32._550_say = "Jak ju\191 wspomnia\179 \163owca, powiniene\156 odnale\159\230[ENTER]Elitarnego Orka Czarodzieja w Smoczej Dolinie.[ENTER]Prawdopodobnie to w\179a\156nie on ma drug\185 Stron\234.[ENTER]Zabij tego Orka i odbierz mu drug\185 Stron\234.[ENTER]Gdy ju\191 j\185 zdob\234dziesz, udaj si\234 do Uriela. "
gameforge.main_quest_lv32._560_sendLetter = "Druga Strona "
gameforge.main_quest_lv32._570_sayTitle = "Znalaz\179e\156 Drug\185 Stron\234 "
gameforge.main_quest_lv32._580_say = "Polowanie na Elitarnych Ork\243w Czarodziei[ENTER]zako\241czy\179o si\234 sukcesem. Znalaz\179e\156 Drug\185 Stron\234[ENTER]Tajemniczej Ksi\234gi.[ENTER]Zanie\156 j\185 M\234drcowi Uriel. "
gameforge.main_quest_lv32._590_say = "Czy to jest Druga Strona? Zobaczmy. Hmm.[ENTER]Nie jest \179atwo j\185 odczyta\230. Z tre\156ci wynika, \191e... "
gameforge.main_quest_lv32._600_sayTitle = "Druga Strona: "
gameforge.main_quest_lv32._60_say = "Jak tylko znajdziesz te brakuj\185ce Strony,[ENTER]dostarcz je do mnie jak najszybciej. Spr\243buj\234 je[ENTER]odszyfrowa\230. Hmmm... Gdzie powiniene\156 rozpocz\185\230[ENTER]poszukiwania? Jaki\156 czas temu s\179ysza\179em o pewnym[ENTER]Domokr\185\191cy w s\185siedniej wiosce, kt\243ry znalaz\179[ENTER]jak\185\156 Stron\234. Id\159 do niego i sprawd\159 czy mo\191esz[ENTER]si\234 czego\156 dowiedzie\230. "
gameforge.main_quest_lv32._610_sayReward = "Odnale\159li\156my mag\243w pos\179uguj\185cych si\234 czarn\185[ENTER]magi\185. Ukrywali si\234 w Dolinie Smoka. Dobrze znali[ENTER]zakazan\185 magi\234, kt\243ra by\179a przekazywana przez[ENTER]wieki z pokolenia na pokolenie. Po przeczytaniu i[ENTER]przestudiowaniu stron, sta\179o si\234 jasne, \191e[ENTER]potrzebne jest odprawienia rytua\179u. To miejsce[ENTER]koniecznie musi by\230 wype\179nione z\179\185 energi\185.[ENTER]Czy takie miejsce istnieje? Nie ma czasu. Musz\234[ENTER]jak najszybciej odnale\159\230 odpowiednie miejsce. "
gameforge.main_quest_lv32._620_say = "Hmmm, zakazany rytua\179 wymaga miejsca, kt\243re jest[ENTER]przepe\179nione z\179\185 energi\185! Miejsce, gdzie wszystko[ENTER]jest konwertowane na z\179\185 energi\234? Gdzie mo\191e by\230[ENTER]takie miejsce? Hmm... To z pewno\156ci\185 \140wi\185tynia[ENTER]Ciemno\156ci. To jest miejsce, w kt\243re nie tylko[ENTER]ludzie, ale tak\191e zwierz\234ta nie chc\185 si\234[ENTER]wybiera\230. Jest to miejsce, gdzie tajemna moc[ENTER]zaw\179adn\234\179a potworami. "
gameforge.main_quest_lv32._630_say = "Ponadto, wytworzy\179a si\234 pewna wi\234\159 mi\234dzy[ENTER]zakazanym rytua\179em a tajemnicz\185 moc\185. Musisz[ENTER]znale\159\230 wskaz\243wk\234 w \140wi\185tyni Hwang. Zbadaj co si\234[ENTER]tam dzieje i spr\243buj znale\159\230 jakie\156 inne Strony[ENTER]Pami\234tnika! Oto twoja nagroda za drug\185 Stron\234... "
gameforge.main_quest_lv32._640_sayReward = "Otrzyma\179e\156 1.000.000 Punkt\243w Do\156wiadczenia. "
gameforge.main_quest_lv32._650_sayReward = "Otrzyma\179e\156 50.000 Yang. "
gameforge.main_quest_lv32._660_sayReward = "Otrzyma\179e\156 10 Bia\179ych Flag. "
gameforge.main_quest_lv32._670_sendLetter = "Trzecia Strona "
gameforge.main_quest_lv32._680_say = "Dwie Strony zosta\179y ju\191 odnalezione.[ENTER]Kolejna Strona znajduje si\234 w \140wi\185tyni Hwang. "
gameforge.main_quest_lv32._690_sayReward = "Wskaz\243wka: Dalsze zadania z tej serii b\234d\185[ENTER]dost\234pne dopiero po osi\185gni\234ciu poziomu 40. "
