gameforge.main_quest_lv40._280_sayTitle = "Czwarta Strona: "
gameforge.main_quest_lv40._290_sayReward = "Jestem w du\191ej jaskini gdzie \191yj\185 ma\179py, ale[ENTER]nawet tu ilo\156\230 z\179ej energii jest[ENTER]niewystarczaj\185ca. Czas ucieka... Nie ma[ENTER]specjalnych metod. Ka\191dy jest wstrz\185\156ni\234ty z[ENTER]powodu strachu. Nie chc\234 my\156le\230 co si\234 mo\191e sta\230[ENTER]gdy zawiod\234. Czy uda nam si\234 znale\159\230 miejsce[ENTER]zanim nadci\185gnie kawaleria Lee Seop? "
