gameforge.main_quest_lv40._30_sayTitle = "Znalaz\179e\156 3. Stron\234 "
gameforge.main_quest_lv40._310_sayReward = "Musz\234 jak najszybciej znale\159\230 nowe, lepsze[ENTER]miejsce. Jeszcze nic nie jest stracone. Spr\243buj\234[ENTER]w Lochu Paj\185k\243w. Tym razem nasze \191yczenie mo\191e[ENTER]si\234 spe\179ni\230... "
gameforge.main_quest_lv40._320_say = "Hm. Lochy Ma\179p nie s\185 miejscem, kt\243rego szukamy.[ENTER]Musimy spr\243bowa\230 jeszcze raz! Zgodnie z tym co[ENTER]jest tutaj napisane, musimy uda\230 si\234 do Lochu[ENTER]Paj\185k\243w. Jednak najpierw musimy zaj\185\230 si\234[ENTER]wa\191niejsz\185 spraw\185: Kapitan jest zaniepokojony,[ENTER]poniewa\191 do wioski regularnie przybywaj\185[ENTER]nieznajomi i zadaj\185 dziwne pytania. Udaj si\234 do[ENTER]Kapitana i zbadaj t\185 spraw\234. "
gameforge.main_quest_lv40._330_say = "Nie wiem czemu, ale nie czuj\234 si\234 zbyt dobrze.[ENTER]Zobaczmy co powie nam Kapitan.[ENTER]Oh, zanim zapomn\234: Oto nagroda za czwart\185 Stron\234. "
