gameforge.main_quest_lv40._40_say = "Uriel mia\179 racj\234 co do Elitarnych Ezoterycznych[ENTER]Fanatyk\243w. Znalaz\179e\156 u nich trzeci\185 Stron\234[ENTER]Pami\234tnika. Zanie\156 j\185 M\234drcowi Uriel. "
gameforge.main_quest_lv40._410_say = "Ostatnio wzros\179a liczba przybysz\243w w naszej[ENTER]wiosce. Nieznajomi nios\185 ze sob\185 ogromne[ENTER]problemy. Pytaj\185 o mieszka\241c\243w, pomniki i stare[ENTER]ksi\185\191ki. S\185 to ludzie dobrze poinformowani,[ENTER]jednak oficjalnie nic nie wiedz\185. Wszyscy s\185 w[ENTER]niebezpiecze\241stwie. Mamy trudne czasy zdominowane[ENTER]przez wojn\234. "
gameforge.main_quest_lv40._420_say = "Dochodzenie odkry\179o, \191e Nakajima z s\185siedniej[ENTER]wioski mo\191e mie\230 z tym co\156 wsp\243lnego. Postaraj[ENTER]dowiedzie\230 si\234 czego\156 o dziwnych przybyszach. "
