gameforge.main_quest_lv40._460_sayTitle = "Nakajima: "
gameforge.main_quest_lv40._470_say = "Przepraszam? Co to za pytanie? Przykro mi. Nie[ENTER]mog\234 Ci pom\243c. Nie mam poj\234cia o czym m\243wisz.[ENTER]Nie, nie. Ci\234\191ko jest znale\159\230 dla siebie prac\234 w[ENTER]czasie wojny. Za co mam \191y\230, hm? "
gameforge.main_quest_lv40._480_say = "No dobra, przyznaje si\234. Zgodzi\179em si\234 tylko[ENTER]dlatego, bo obiecali mi mn\243stwo Yang.[ENTER]Co ci nieznajomi tutaj chc\185, tego nie wiem.[ENTER]Powierzyli mi jednak zadanie: Mam zabi\230 Best.[ENTER]Kapitan\243w. "
gameforge.main_quest_lv40._490_say = "Wi\234cej informacji mo\191esz uzyska\230 od Best.[ENTER]Kapitan\243w. Nieznajomi bardzo chcieli, abym ich[ENTER]zabi\179. O, mam pomys\179! Lepiej b\234dzie je\156li Ty tam[ENTER]p\243jdziesz i zabijesz ich za mnie, co? Prosz\234! "
