gameforge.main_quest_lv40._510_say = "Nakajima przyzna\179 si\234, \191e nieznajomi przybysze[ENTER]chcieli, aby zabi\179 Best. Kapitana. Jako, \191e[ENTER]pytali o Strony Pami\234tnika, kt\243ry\156 z Best.[ENTER]Kapitan\243w musi je posiada\230. Aby dowiedzie\230 si\234[ENTER]wi\234cej, musz\234 zabi\230 kilka Best. Kapitan\243w. Mo\191na[ENTER]ich znale\159\230 na zewn\185trz drugiej wioski. "
gameforge.main_quest_lv40._520_sendLetter = "Znalaz\179e\156 Pi\185t\185 Stron\234. "
gameforge.main_quest_lv40._530_say = "Dotar\179em tutaj wcze\156niej ni\191 nieznajomi i[ENTER]odebra\179em pi\185t\185 Stron\234 Pami\234tnika od jednego z[ENTER]Bestialskich Kapitan\243w. Jestem pewnym, \191e teraz[ENTER]nieznajomi znikn\185 z tej okolicy. Zanios\234 Stron\234[ENTER]do Uriela, aby m\243g\179 j\185 odszyfrowa\230. "
gameforge.main_quest_lv40._540_sayTitle = "Pi\185ta Strona Ksi\185\191ki "
gameforge.main_quest_lv40._550_sayReward = "Wskaz\243wka: Mo\191esz zanie\156\230 Pi\185t\185 Stron\234 do Uriela,[ENTER]dopiero po osi\185gni\234ciu 47. poziomu postaci.[ENTER]Do tego czasu, zaopiekuj si\234 Stron\185. "
gameforge.main_quest_lv40._60_sayTitle = "Trzecia Strona: "
gameforge.main_quest_lv40._70_sayReward = "Dotarli\156my na miejsce gdzie powstaje z\179a energia.[ENTER]Ale to za ma\179o... Gdzie mo\191na odprawi\230 zakazany[ENTER]rytua\179?[ENTER]Nowe informacje m\243wi\185 nam, \191e sekretne miejsce na[ENTER]Pustyni Yongbi mo\191e si\234 do tego nadawa\230.[ENTER]Pe\179ni nadziei przenosimy si\234 na Pustyni\234 Yongbi. "
gameforge.main_quest_lv40._80_say = "A wi\234c, nie byli w stanie osi\185gn\185\230 celu w Smoczej[ENTER]Dolinie. Hm... Pustynia Yongbi? Zazwyczaj trudno[ENTER]spotka\230 tam jaki\156 ludzi, a wiele obszar\243w w[ENTER]tamtej okolicy nie zosta\179o jeszcze przebadanych.[ENTER]Jednak to bardzo skomplikowane. Gdzie dok\179adnie[ENTER]jest obszar, o kt\243rym oni m\243wi\185? Zgaduj\234, \191e[ENTER]chodzi o Loch Ma\179p Junsun Dong. To g\179\234boka[ENTER]jaskinia, w kt\243rej na pewno mo\191na zgromadzi\230[ENTER]bardzo du\191o negatywnej energii. "
gameforge.main_quest_lv40._90_say = "Udaj si\234 do Jungsun Dong i poszukaj tam dalszych[ENTER]pomnik\243w. Przy odrobinie szcz\234\156cia znajdziesz[ENTER]przy tych pomnikach dalsze Strony Ksi\185\191ki. Och,[ENTER]oczywi\156cie nie mo\191emy zapomnie\230 o twojej[ENTER]nagrodzie za dostarczenie mi trzeciej Strony. "
