gameforge.main_quest_lv47._160_npcChat = "Sz\243sta Strona "
gameforge.main_quest_lv47._170_say = "Jak by\179o w Lochu Paj\185k\243w? Uda\179o Ci si\234 znale\159\230[ENTER]sz\243st\185 Stron\234? To \156wietnie! Zobaczmy jakie[ENTER]informacje zdob\234dziemy z sz\243stej Strony. Bardzo[ENTER]si\234 ciesz\234, \191e uda\179o Ci si\234 j\185 zdoby\230. Ca\179y czas[ENTER]s\179ysz\234, \191e jacy\156 nieznajomi ludzie tak\191e pr\243buj\185[ENTER]j\185 odnale\159\230. Strona ta musi zawiera\230 bardzo wa\191ne[ENTER]informacje, skoro tak wielu ludzi jej poszukuje. "
