gameforge.main_quest_lv47._270_npcChat = "Jakie\156 nowiny? "
gameforge.main_quest_lv47._280_say = "Ciesz si\234 \191yciem, poniewa\191 jest ulotne![ENTER]Trallalaaa...[ENTER]Ach, to znowu ty. Pewnie przys\179a\179 Ci\234 Uriel. Par\234[ENTER]dni temu spyta\179 mnie, czy m\243g\179bym pozbiera\230 dla[ENTER]niego informacje. Dowiedzia\179em si\234, \191e we[ENTER]wszystkich kr\243lestwach pojawili si\234 podr\243\191nicy[ENTER]szukaj\185cy wa\191nych dokument\243w. Niestety nikt nie[ENTER]m\243g\179 mi powiedzie\230, o co dok\179adnie chodzi. "
gameforge.main_quest_lv47._290_say = "To dziwne, \191e te przera\191aj\185ce postacie przebywaj\185[ENTER]w naszej okolicy podczas wojny. Pozby\230 si\234 ich,[ENTER]oczywi\156cie! Ponadto, s\179ysza\179em, \191e Pustynni[ENTER]Zawadiacy mog\185 posiada\230 pewne rzeczy, kt\243re mog\185[ENTER]by\230 dla nas bardzo przydatne.[ENTER]Powiniene\156 zobaczy\230 co mo\191esz od nich zdoby\230. "
