gameforge.main_quest_lv47._330_say = "Uriel s\185dzi, \191e szczeg\243\179y zwi\185zane z rytua\179em[ENTER]mog\185 by\230 bardzo wa\191ne. Muzyk powiedzia\179 nam, \191e[ENTER]dalsze informacje mo\191esz odnale\159\230 u Pustynnych[ENTER]Zawadiak\243w. Powinni\156my wybra\230 si\234 na pustyni\234 i[ENTER]zabi\230 kilku Pustynnych Zawadiak\243w. "
