gameforge.main_quest_lv47._360_say = "Dzi\234ki informacjom dostarczonym Tobie przez[ENTER]muzyka Yu-Hwan uda\179o Ci si\234 znale\159\230 si\243dm\185 Stron\234[ENTER]Ksi\185\191ki u Pustynnych Zawadiak\243w.[ENTER]Udaj si\234 do Yu-Hwan i powiadom go, \191e jego[ENTER]informacja by\179a poprawna. "
gameforge.main_quest_lv47._370_say = "Twoje oczy s\185 tak pi\234kne jak g\243rskie jezioro[ENTER]lalalala.... Hej, to znowu ty... Czy Pustynna[ENTER]Banda mia\179a jakie\156 ciekawe informacje? Co?! To[ENTER]tylko jaka\156 Strona papieru... Na nic mi si\234 to[ENTER]nie przyda. Ale je\156li chcesz, to zabierz Stron\234[ENTER]do Uriela. Koniecznie pozdr\243w go ode mnie! "
