gameforge.main_quest_lv47._440_say = "Ah, tak: zanim skupimy si\234 na kolejnych stronach,[ENTER]prawdopodobnie powinienem Ci powiedzie\230 co jest[ENTER]na sz\243stej Stronie. Hrm-hrm... "
gameforge.main_quest_lv47._450_sayTitle = "Sz\243sta Strona: "
gameforge.main_quest_lv47._460_sayReward = "Czas na ucieka. Pr\243bowali\156my zastosowa\230 sekretn\185[ENTER]magi\234 nawet w Lochu Paj\185k\243w, bezskutecznie. Czego[ENTER]nam jeszcze brakuje? Niekt\243rzy z naszych mistyk\243w[ENTER]uwa\191aj\185, \191e sekretna magia wymaga wy\191szych ofiar.[ENTER]Je\156li to prawda, to musi by\230 rzeczywi\156cie pot\234\191na. "
gameforge.main_quest_lv47._470_sayReward = "Zgodnie z legendami ten typ magii wymaga ofiary z[ENTER]cz\179owieka. Jednak je\156li zabij\234 cz\179owieka na[ENTER]o\179tarzu, moja reputacja drastycznie spadnie.[ENTER]Musimy poszuka\230 odpowiedniego zamiennika.[ENTER]Spr\243bujmy z W\234\191owymi Miecznikami z pustyni. "
gameforge.main_quest_lv47._480_say = "Ach tak. Skoro nie mog\185 z\179o\191y\230 w ofierze ludzi,[ENTER]zdecydowali si\234 u\191y\230 W\234\191owych Wojownik\243w. Nie[ENTER]mog\234 powiedzie\230, \191eby podoba\179 mi si\234 ten nowy[ENTER]spos\243b my\156lenia. \143le to si\234 mo\191e sko\241czy\230...[ENTER]Mimo to musimy pod\185\191a\230 za ich \156ladem. Udaj si\234 do[ENTER]Pustyni i zabij tam par\234 W\234\191owych Miecznik\243w oraz[ENTER]W\234\191owych \163ucznik\243w. Kto wie, co jeszcze tam[ENTER]znajdziemy. A propos znalezienia: w tej sakiewce[ENTER]znajdziesz swoje wynagrodzenie! "
gameforge.main_quest_lv47._490_sendLetter = "Zabij W\234\191owych Wojownik\243w "
gameforge.main_quest_lv47._500_sayTitle = "\243sma Strona "
gameforge.main_quest_lv47._50_sayTitle = "Pi\185ta Strona: "
gameforge.main_quest_lv47._510_say = "Pami\234tnik opisuje pr\243b\234 ofiarowania W\234\191owych[ENTER]Miecznik\243w oraz W\234\191owych \163ucznik\243w w celu[ENTER]uzyskania sekretnej magii. Udaj si\234 do Pustyni[ENTER]Yongbi i zabij W\234\191owych Wojownik\243w. Spr\243buj[ENTER]uzyska\230 r\243wnie\191 wi\234cej informacji. "
gameforge.main_quest_lv47._520_sendLetter = "Znalaz\179e\156 \243sm\185 Stron\234 "
gameforge.main_quest_lv47._530_targetVid = "Udaj si\234 do Uriela "
gameforge.main_quest_lv47._540_say = "Znalaz\179e\156 \243sm\185 Stron\234 Pami\234tnika u W\234\191owych[ENTER]Wojownik\243w w Pustyni.[ENTER]Zanie\156 j\185 M\234drcowi Uriel. "
gameforge.main_quest_lv47._550_say = "To jest \211sma Strona. Jako, \191e jest bardzo kr\243tka,[ENTER]zaraz j\185 odszyfruj\234. "
gameforge.main_quest_lv47._560_sayTitle = "\211sma Strona: "
gameforge.main_quest_lv47._570_sayReward = "Odpowiednie ofiary s\185 znalezione. Mamy szcz\234\156cie.[ENTER]Czy\191by to by\179 znak? Nast\234pnie potrzebujemy[ENTER]ceremonialny dzwonek. Je\156li mnie pami\234\230 nie myli,[ENTER]widzia\179em co\156 takiego u Paj\185k\243w. W drog\234! "
gameforge.main_quest_lv47._580_say = "Znowu Loch Paj\185k\243w, dziwne. Musisz koniecznie tam[ENTER]si\234 uda\230 i poszuka\230 tego Dzwonu. B\234dzie to jednak[ENTER]m\234cz\185ca podr\243\191, odpocznij wi\234c najpierw i przyjd\159[ENTER]p\243\159nej z powrotem. Ja jeszcze pomy\156l\234 i[ENTER]przet\179umacz\234 dalsze fragmenty. Jak wr\243cisz,[ENTER]powierz\234 Ci nast\234pne zlecenie. Nie martw si\234,[ENTER]wynagrodzenie za \243sm\185 Stron\234 otrzymasz oczywi\156cie[ENTER]ju\191 teraz. "
gameforge.main_quest_lv47._590_sayReward = "Punkty Do\156wiadczenia: 3.000.000[ENTER]Yang: 70.000[ENTER]Dodatkowo: otrzyma\179e\156 Peleryny M\234stwa.[ENTER]Informacja: do nast\234pnego zadania musisz mie\230 co[ENTER]najmniej 50 poziom postaci. "
gameforge.main_quest_lv47._60_sayReward = "Leo Sepp dotar\179 wraz ze sw\185 kawaleri\185 do[ENTER]kr\243lestwa Taejo i wygl\185da na to, \191e p\243ki co nie[ENTER]b\234dzie rusza\179 dalej. W mi\234dzyczasie na ziemi\234[ENTER]spadaj\185 meteoryty. Przynosz\185 chaos, zniszczenie i[ENTER]niezgod\234. Wielkie kr\243lestwo podzieli\179o si\234 na[ENTER]trzy mniejsze kr\243lestwa, kt\243re wzajemnie si\234[ENTER]atakuj\185, zamiast o wsp\243lnych si\179ach stawi\230 czo\179o[ENTER]prawdziwemu z\179u. Smoczy B\243g ju\191 do nas nie[ENTER]przemawia. Jego \179aska sp\179ywa raz na jednego, raz[ENTER]na drugiego. I tak wszyscy walcz\185 o jego[ENTER]przychylno\156\230 gdy zaraza szerzy si\234[ENTER]niepohamowanie... "
gameforge.main_quest_lv47._70_sayTitle = "Uriel: "
gameforge.main_quest_lv47._80_say = "Relacja naocznego \156wiadka z pierwszych dni naszej[ENTER]ery. Absolutnie bezcenna! Ach w\179a\156nie, zap\179ata.[ENTER]Oto twoja nagroda za znakomit\185 robot\234! I jeszcze[ENTER]jedno: Kto\156 wpad\179 najwidoczniej na ten sam trop,[ENTER]co my. Nie mam zatem czasu do stracenia. Pod[ENTER]koniec tej strony napisane jest, \191e Lee Seop[ENTER]nast\234pnie szuka\179 z\179ej energii w Lochu Paj\185k\243w.[ENTER]Je\156li tam co\156 znajdziesz, przyjd\159 natychmiast do[ENTER]mnie! Spalam si\234 z niecierpliwo\156ci! "
gameforge.main_quest_lv47._90_sendLetter = "Sz\243sta Strona "
gameforge.main_quest_lv50 = {}
