gameforge.main_quest_lv50._110_sayReward = "Otrzymujesz 5.000.000 Punkt\243w Do\156wiadczenia. "
gameforge.main_quest_lv50._120_sayReward = "Otrzyma\179e\156 125.000 Yang. "
gameforge.main_quest_lv50._130_sayReward = "Otrzyma\179e\156 Symbol Kr\243la Przepowiedni. "
