gameforge.main_quest_lv50._170_say = "Niegdy\156 na G\243rze Sohan odby\179a si\234 straszliwa[ENTER]bitwa. Szukaj tam kolejnych Stron z Pami\234tnika[ENTER]lub innych pisemnych dowod\243w na przebieg bitwy. "
gameforge.main_quest_lv50._180_npcChat = "Stare Pud\179o Z Papierami! "
gameforge.main_quest_lv50._190_say = "To s\185 wojskowe plany i zapiski oraz kolejna[ENTER]Strona z Pami\234tnika! Powinienem dostarczy\230 to[ENTER]wszystko do Uriela. "
gameforge.main_quest_lv50._200_sendLetter = "Dziesi\185ta Strona "
gameforge.main_quest_lv50._20_say = "Z poprzedniego dochodzenia wynika, \191e \156lady[ENTER]prowadz\185 do Loch\243w Paj\185k\243w. Udaj si\234 tam i zabij[ENTER]Elitarnego Truj\185cego Paj\185k \175o\179nierza w Lochu[ENTER]Paj\185k\243w i je\156li znajdziesz kolejn\185 Stron\234 ze[ENTER]starej Ksi\234gi, dostarcz j\185 do Uriela. "
gameforge.main_quest_lv50._210_sayTitle = "Znalaz\179e\156 dziesi\185t\185 stron\234 "
gameforge.main_quest_lv50._220_say = "Znalaz\179e\156 dziesi\185t\185 Stron\234 tajemniczego[ENTER]Pami\234tnika na Lodowej Pustyni. Strona by\179a w[ENTER]Starym Pudle z Papierami. Zanie\156 j\185 do Uriela. "
gameforge.main_quest_lv50._230_say = "Ach, \156wietnie! Znalaz\179e\156 dziesi\185t\185 Stron\234 z[ENTER]Pami\234tnika.[ENTER]Zbli\191amy si\234 do ko\241ca opowie\156ci. Mi\179o, \191e[ENTER]wszystko zosta\179o zapisane, w przeciwnym razie nie[ENTER]dowiedzieliby\156my si\234 niczego. Zobaczmy, czego si\234[ENTER]dowiemy. "
gameforge.main_quest_lv50._235_sayTitle = "Dziesi\185ta Strona Ksi\185\191ki: "
gameforge.main_quest_lv50._240_sayReward = "Uda\179o nam si\234 odeprze\230 pierwszy atak. Ale kolejna[ENTER]fala nied\179ugo nadci\185gnie. Wprawdzie teren[ENTER]utrudnia poruszanie si\234 uzbrojonej kawalerii Lee[ENTER]Seopa, ale przybywa ich coraz wi\234cej. Nie[ENTER]wygramy. Pozostaje nam ostatnia szansa, czyli[ENTER]zako\241czenie badania nad mrocznym rytua\179em. Pod[ENTER]ochron\185 nocy prze\179amiemy lini\234 oporu wrog\243w i[ENTER]powr\243cimy do Jaski\241 Paj\185k\243w. Modl\234 si\234... nie o[ENTER]zwyci\234stwo, a o odrobin\234 nadziei... "
gameforge.main_quest_lv50._250_say = "Oooch. My\156l\234, \191e jeste\156my ju\191 blisko celu! W[ENTER]ko\241cu dowiemy si\234 czego\156 wi\234cej o tym zakazanym[ENTER]rytuale. Nie mog\234 si\234 doczeka\230![ENTER]Wr\243\230 do Lochu Paj\185k\243w. Gdzie\156 tam musi by\230[ENTER]jedenasta Strona. "
gameforge.main_quest_lv50._260_say = "Oto zas\179u\191ona nagroda! "
gameforge.main_quest_lv50._270_sayReward = "Otrzyma\179e\156 5.500.000 Punkt\243w Do\156wiadczenia. "
gameforge.main_quest_lv50._280_sayReward = "Otrzyma\179e\156 137.500 Yang. "
gameforge.main_quest_lv50._290_sayReward = "Otrzyma\179e\156 R\234kawic\234 Kr\243la Przepowiedni. "
gameforge.main_quest_lv50._300_sayTitle = "Zabij Szponiastego Truj\185cego Paj\185ka "
gameforge.main_quest_lv50._30_sendLetter = "Dziewi\185ta Strona "
gameforge.main_quest_lv50._310_say = "Badania zwi\185zane z zakazanym rytua\179em s\185[ENTER]kontynuowane w Lochu Paj\185k\243w. Udaj si\234 tam, zabij[ENTER]kilka Szponiastych Truj\185cych Paj\185k\243w i zdob\185d\159[ENTER]potrzebne informacje. "
gameforge.main_quest_lv50._320_sendLetter = "Jedenasta Strona "
gameforge.main_quest_lv50._330_targetVid = "Wr\243\230 do Uriela. "
gameforge.main_quest_lv50._335_sayTitle = "Odnalaz\179a si\234 Jedenasta Strona "
gameforge.main_quest_lv50._340_say = "W Lochu Paj\185k\243w znalaz\179e\156 jedenast\185 Stron\234[ENTER]tajemniczego Pami\234tnika. Zanie\156 j\185 do Uriela. "
gameforge.main_quest_lv50._350_say = "Masz jakie\156 nowiny dotycz\185ce zakazanego rytua\179u?[ENTER]Aha, jedenasta strona! Zobaczmy. Ah tak, to[ENTER]ca\179kiem proste. Teraz bardzo dobrze radz\234 sobie z[ENTER]pismem tego typu. A teraz s\179uchaj! "
gameforge.main_quest_lv50._355_sayTitle = "Jedenasta Strona Ksi\185\191ki: "
gameforge.main_quest_lv50._360_sayReward = "Magia zawiod\179a. Pomimo wszystkich naszych[ENTER]przygotowa\241, zgubi\179 nas po\156piech. Teraz wielu z[ENTER]nas jest rannych, a niekt\243rzy nawet postradali[ENTER]zmys\179y. Czarna magia jest naprawd\234 z\179a. Kawaleria[ENTER]Lee Seop ma nas w gar\156ci, ale teraz to ma\179o[ENTER]istotne. Mamy za ma\179o ludzi aby m\243c si\234[ENTER]skutecznie broni\230. I tak umrzemy. "
gameforge.main_quest_lv50._365_sayTitle = "Kontynuacja jedenastej Strony Ksi\185\191ki: "
gameforge.main_quest_lv50._370_sayReward = "Jeden ostatni cel trzyma reszt\234 oddzia\179u razem i[ENTER]daje nam si\179\234: Nasi informatorzy z Doliny Smoka[ENTER]nas ok\179amali. Celowo nie ostrzegli nas o[ENTER]strasznych efektach ubocznych zakazanego rytua\179u.[ENTER]Nawet je\156li b\234dzie to ostatnia rzecz jak\185[ENTER]zrobimy, zap\179ac\185 nam za to. "
gameforge.main_quest_lv50._380_say = "Heh, na ko\241cu wszystko potoczy\179o si\234 nieco[ENTER]inaczej ni\191 tego chcieli. To smutna historia.[ENTER]Jednak nie mo\191na ufa\230 komukolwiek, kto jest w[ENTER]jakim\156 stopniu powi\185zany z czarn\185 magi\185. Powinni[ENTER]o tym pomy\156le\230. Dziwnym wydaje si\234 fakt, \191e autor[ENTER]tego tekstu zdo\179a\179 dotrze\230 do takiego zakazanego[ENTER]rytua\179u. Kto wie jaki cel mieli jego[ENTER]informatorzy. Powinni\156my doko\241czy\230 dochodzenie,[ENTER]nawet, je\156li jest bardzo niebezpieczne. Wiemy ju\191[ENTER]tak wiele, \191e szkoda by\179oby si\234 podda\230. "
gameforge.main_quest_lv50._390_say = "By\179e\156 ju\191 w Dolinie Seungryong. My\156l\234, \191e nie[ENTER]znajdziemy ju\191 tam informacji. Hmm... zastanawiam[ENTER]si\234, gdzie jeszcze mogliby\156my poszuka\230... wiem! W[ENTER]naszym dochodzeniu znacz\185c\185 rol\234 odgrywa\179y[ENTER]Pomniki. W okolicy s\185 Pomniki, kt\243rych jeszcze[ENTER]nie zbadali\156my. Te, z innych Kr\243lestw! Jest tam[ENTER]bardzo niebezpiecznie. Prawdopodobnie b\234dziesz[ENTER]ci\185gle atakowany. Wi\234c dobrze si\234 przygotuj i[ENTER]wr\243\230 gdy b\234dziesz gotowy. "
gameforge.main_quest_lv50._400_say = "Oto twoja nagroda za jedenast\185 Stron\234. "
gameforge.main_quest_lv50._40_targetVid = "Udaj si\234 do Uriela "
gameforge.main_quest_lv50._410_sayReward = "Otrzyma\179e\156 6,000,000 Punkt\243w Do\156wiadczenia.[ENTER]Otrzyma\179e\156 150,000 Yang.[ENTER]Dodatkowo, otrzyma\179e\156 Medal Smoka.[ENTER]Wskaz\243wka: do nast\234pnego zadania musisz mie\230 co[ENTER]najmniej 55 poziom. "
gameforge.main_quest_lv50._50_sayTitle = "Znalaz\179e\156 dziewi\185t\185 Stron\234. "
gameforge.main_quest_lv50._60_say = "Znalaz\179e\156 dziewi\185t\185 Stron\234 w Lochu Paj\185k\243w.[ENTER]Zanie\156 j\185 do Uriela. "
gameforge.main_quest_lv50._70_say = "Znalaz\179e\156 \156lad starej magii? Wow, to dziewi\185ta[ENTER]Strona! Co tam jest napisane? Jestem bardzo[ENTER]ciekawy, czy ta magia zadzia\179a\179a, \156pieszmy si\234... "
gameforge.main_quest_lv50._75_sayTitle = "Dziewi\185ta Strona Ksi\185\191ki: "
gameforge.main_quest_lv50._80_sayReward = "Atak Lee Seop si\234 rozpocz\185\179. Nadal nie wiemy jak[ENTER]u\191y\230 zakazanego rytua\179u. Jestem bardzo[ENTER]zdenerwowany. Jeste\156my na froncie pr\243buj\185c[ENTER]chroni\230 nasze Kr\243lestwo, jednak nasza si\179a jest[ENTER]niewystarczaj\185ca. Si\179a \191o\179nierzy naszych wrog\243w[ENTER]jest bardzo pot\234\191na, mo\191emy przegra\230 bitw\234.[ENTER]Musimy znale\159\230 lepsze miejsce! Mo\191e powinni\156my[ENTER]uda\230 si\234 na Lodow\185 Pustyni\234 i zaatakowa\230 naszych[ENTER]wrog\243w stamt\185d? Je\156li b\234dziemy mieli troszk\234[ENTER]szcz\234\156cia to do tego czasu uda nam si\234 lepiej[ENTER]pozna\230 rytua\179. Bo\191e, pom\243\191 nam... "
gameforge.main_quest_lv50._90_say = "Hmm... Zanim zd\185\191yli sprawdzi\230 czym jest ta magia[ENTER]zostali zaatakowani. Ludzie zabarykadowali si\234 na[ENTER]Lodowej Ziemi, aby mogli dalej bada\230 star\185 magi\234.[ENTER]Mogliby\156my poszuka\230 dalszych \156lad\243w.[ENTER]Udaj si\234 na G\243r\234 Sohan i poszukaj jakichkolwiek[ENTER]wskaz\243wek. "
gameforge.main_quest_lv55 = {}
gameforge.main_quest_lv55._100_say = "Znalaz\179e\156 dwunast\185 Stron\234 w centrum Joan.[ENTER]Zanie\156 Stron\234 do Uriela w Yongan. "
gameforge.main_quest_lv55._10_sendLetter = "Poszukiwania pomnik\243w "
gameforge.main_quest_lv55._110_say = "Znalaz\179e\156 dwunast\185 Stron\234 w centrum Yongan.[ENTER]Zanie\156 Stron\234 do Uriela w Pyungmo. "
gameforge.main_quest_lv55._120_say = "Ciesz\234 si\234, ze zn\243w Ci\234 widz\234! Przykro mi, \191e[ENTER]musia\179em Ci\234 wys\179a\230 w tak wiele r\243\191nych miejsc,[ENTER]ale nasz sukces potwierdzi\179 nasze domys\179y.[ENTER]Zobaczmy co tam masz. Mam nadziej\234, \191e by\179o[ENTER]warto. "
gameforge.main_quest_lv55._130_sayTitle = "Dwunasta Strona Pami\234tnika: "
gameforge.main_quest_lv55._140_sayReward = "Znale\159li\156my informator\243w, zap\179acili \191yciem za ich[ENTER]k\179amstwo. Jednak co wa\191niejsze, uda\179o nam si\234 od[ENTER]nich uzyska\230 dodatkowe informacje: nie[ENTER]potrzebujemy Lochu Paj\185k\243w, a \140wi\185tyni Ciemno\156ci.[ENTER]To tam staro\191ytni wyznawcy odprawiali zakazane[ENTER]rytua\179y. Jest to miejsce, kt\243re po\179\185czone jest[ENTER]bezpo\156rednio ze \159r\243d\179em ogromnej mocy. "
gameforge.main_quest_lv55._145_sayTitle = "Kontynuacja dwunastej Strony Ksi\185\191ki: "
gameforge.main_quest_lv55._150_sayReward = "Tak niewiele dzieli nas od powstrzymania Lee[ENTER]Seop. Musimy uda\230 si\234 do \140wi\185tyni Ciemno\156ci, aby[ENTER]odprawi\230 zakazany rytua\179. Nie zosta\179o nas wielu,[ENTER]a ostatnie miesi\185ce da\179y si\234 we znaki.[ENTER]Jednak nawet garstka zm\234czonych ludzi mo\191e[ENTER]zmieni\230 los ca\179ego \156wiata. Ju\191 nied\179ugo wszyscy[ENTER]zobacz\185 efekt naszej ci\234\191kiej pracy. Ruszajmy[ENTER]dalej. "
gameforge.main_quest_lv55._160_say = "Ah, w ko\241cu odnale\159li odpowiednie miejsce. Moje[ENTER]przeczucie si\234 sprawdzi\179o! To naprawd\234 \140wi\185tynia[ENTER]Hwang. Na pewno pami\234tasz to mroczne miejsce, w[ENTER]kt\243rym by\179o du\191o z\179ej energii. To tutaj[ENTER]odprawiane by\179y tajne rytua\179y. Obrz\185dki te[ENTER]najcz\234\156ciej mia\179y pod\179o\191\234 wojenne. Ca\179e to[ENTER]miejsce przepe\179nione jest energi\185 niewinnych[ENTER]ofiar. "
gameforge.main_quest_lv55._170_say = "Teraz, w \156rodku \140wi\185tyni \191yj\185 same potwory. Przez[ENTER]bardzo d\179ugi okres nikt nie widzia\179 tam \191ywego[ENTER]cz\179owieka. Jest to niezwykle niebezpieczne[ENTER]miejsce. To w\179a\156nie tam wiedzie ostatnia[ENTER]pozostawiona wskaz\243wka. Poszukaj najnowszych[ENTER]informacji w \140wi\185tyni. Powodzenia! Oh, poczekaj[ENTER]chwilk\234, oto nagroda za dwunast\185 Stron\234. "
gameforge.main_quest_lv55._180_sayReward = "Otrzyma\179e\156 26.000 Punkt\243w Do\156wiadczenia.[ENTER]Otrzyma\179e\156 15.000 Yang.[ENTER]Otrzyma\179e\156 Nos \140wini. "
gameforge.main_quest_lv55._190_sayReward = "Otrzyma\179e\156 162.500 Yang. "
gameforge.main_quest_lv55._200_sendLetter = "Ostatnia Strona "
gameforge.main_quest_lv55._20_say = "Uriel s\185dzi, \191e potrzebne nam informacje mog\185[ENTER]znajdowa\230 si\234 w pobli\191u pomnik\243w, kt\243re nie[ENTER]zosta\179y jeszcze przez nas zbadane. Udaj si\234 do[ENTER]Kr\243lestwa Chunjo i zbadaj pomniki znajduj\185ce si\234[ENTER]na obszarze Joan. "
gameforge.main_quest_lv55._210_sayTitle = "Zabij Straszyd\179o w \140wi\185tyni "
gameforge.main_quest_lv55._220_say = "Do tej pory znalaz\179e\156 dwana\156cie z trzynastu[ENTER]Stron. Pozosta\179 tylko jeden krok. Uriel m\243wi, \191e[ENTER]czarna magia by\179a odprawiana w \140wi\185tyni Hwang.[ENTER]Powiniene\156 si\234 tam uda\230 i rozpocz\185\230 badania.[ENTER]Wskaz\243wek szukaj u potwor\243w zwanych Straszyd\179ami. "
gameforge.main_quest_lv55._230_say = "Musz\234 uda\230 si\234 w g\179\185b \140wi\185tyni! "
gameforge.main_quest_lv55._240_sendLetter = "\140wi\185tynia Ciemno\156ci "
gameforge.main_quest_lv55._250_sayTitle = "Z\179a energia \140wi\185tyni "
gameforge.main_quest_lv55._260_sayReward = "Po tym jak sp\234dzi\179e\156 troch\234 czasu w \140wi\185tyni,[ENTER]masz wra\191enie, \191e w ka\191dym k\185cie czyhaj\185 na[ENTER]Ciebie jakie\156 przera\191aj\185ce istoty skrywaj\185ce si\234[ENTER]w cieniu. Im bli\191ej wn\234trza, tym energia jest[ENTER]silniejsza. To \140wi\185tynia jest \159r\243d\179em.[ENTER]To tutaj wszystko si\234 rozpocznie... "
gameforge.main_quest_lv55._270_say = "Zda\179e\156 sobie spraw\234 z faktu, \191e im jeste\156 bli\191ej[ENTER]centrum \140wi\185tyni, tym z\179a energia wisz\185ca w[ENTER]powietrzu jest silniejsza. Powiniene\156 szuka\230[ENTER]wskaz\243wki w centrum \140wi\185tyni. To tam musi by\230[ENTER]\159r\243d\179o z\179a. "
gameforge.main_quest_lv55._280_npcChat = "Memoria\179 Gum "
gameforge.main_quest_lv55._290_say = "Pomnik Gum jest w centrum \140wi\185tyni. Powoli[ENTER]zbli\191asz si\234 i znajdujesz ostatni\185 Stron\234[ENTER]Pami\234tnika. "
gameforge.main_quest_lv55._300_say = "W \140wi\185tyni odnalaz\179e\156 ostatni\185 Stron\234[ENTER]tajemniczego Pami\234tnika. Udaj si\234 do Uriela i[ENTER]poinformuj go o swoim znalezisku. "
gameforge.main_quest_lv55._30_say = "Uriel s\185dzi, \191e potrzebne nam informacje mog\185[ENTER]znajdowa\230 si\234 w pobli\191u pomnik\243w, kt\243re nie[ENTER]zosta\179y jeszcze przez nas zbadane. Udaj si\234 do[ENTER]Kr\243lestwa Jinno i zbadaj pomniki znajduj\185ce si\234[ENTER]na obszarze Pyungmo. "
gameforge.main_quest_lv55._310_say = "Oto i ona, ostatnia, trzynasta Strona! Nie wiem[ENTER]jak m\243g\179bym Ci podzi\234kowa\230. Sp\243jrz na moje r\234ce,[ENTER]dr\191\185. Jestem tak podekscytowany, \191e nawet nie[ENTER]mog\234 spojrze\230 na Stron\234. Nie czekajmy d\179u\191ej,[ENTER]zobaczmy jak ko\241czy si\234 ta dziwna historia. "
gameforge.main_quest_lv55._320_sayTitle = "Trzynasta Strona Pami\234tnika: "
gameforge.main_quest_lv55._330_sayReward = "W ko\241cu dotarli\156my.[ENTER]Dali\156my sobie rad\234 ze wszystkimi przeciwno\156ciami[ENTER]losu, nasza misja jest nast\234puj\185ca: musimy[ENTER]przerwa\230 panowanie Lee Seop i uaktywni\230 zakazan\185[ENTER]magi\234. Mam nadziej\234, \191e wystarczy nam si\179.[ENTER]Jeste\156my wyczerpani, podr\243\191 by\179a bardzo d\179uga, a[ENTER]ca\179y czas mieli\156my za sob\185 \191o\179nierzy wroga.[ENTER]Musimy spr\243bowa\230, albo nasze Kr\243lestwo zostanie[ENTER]zniszczone. "
gameforge.main_quest_lv55._335_sayTitle = "Kontynuacja trzynastej Strony Ksi\185\191ki: "
gameforge.main_quest_lv55._340_sayReward = "Pozosta\179o tylko siedem os\243b. Za\179o\191yli\156my nasze[ENTER]najlepsze ubrania, mimo tego, \191e teraz wygl\185daj\185[ENTER]jak \179achmany. Zbierzemy si\234 w kole i z\179apiemy za[ENTER]r\234ce, aby przywo\179a\230 zakazan\185 si\179\234. Wtedy[ENTER]zaczniemy recytowa\230 zakl\234cie w nadziei, \191e rytua\179[ENTER]nie b\234dzie potrzebowa\179 wi\234kszej ilo\156ci ofiar.[ENTER][ENTER]... "
gameforge.main_quest_lv55._350_sayReward = "... Koniec...[ENTER]Zapowiada\179o si\234 bardzo obiecuj\185co. Pomieszczenie[ENTER]wype\179ni\179o si\234 energi\185 i s\179owami zakl\234cia, to by\179o[ENTER]naprawd\234 dziwne. Moich sze\156ciu kompan\243w pad\179o na[ENTER]kolana. \140wi\185tynia zacz\234\179a si\234 trz\185\156\230. Potem[ENTER]uderzy\179 piorun i zostali\156my odrzuceni do ty\179u.[ENTER]Linia si\179 p\234k\179a...[ENTER]Teraz nasta\179a niesamowita cisza. Moi przyjaciele[ENTER]le\191\185 zabici na ziemi. Magia nie zadzia\179a\179a.[ENTER]Zawiedli\156my. "
gameforge.main_quest_lv55._360_say = "Co? To wszystko?!?[ENTER]To szale\241stwo! Ca\179a nasza praca na marne? Nie[ENTER]mog\234 w to uwierzy\230. Podr\243\191owali\156my, walczyli\156my,[ENTER]t\179umaczyli\156my dziwne teksty, sp\234dzili\156my nad tym[ENTER]wszystkim ogromn\185 ilo\156\230 czasu. I to na nic![ENTER]Jeste\156my tak samo m\185drzy jak byli\156my wcze\156niej.[ENTER]Jedyne czego si\234 nauczyli\156my to to, \191e lepiej[ENTER]trzyma\230 si\234 z daleka od czarnej magii. Zawsze tak[ENTER]my\156la\179em. To wielka szkoda, ze historia ko\241czy[ENTER]si\234 w taki spos\243b. Nikt nie spodziewa\179 si\234[ENTER]takiego zako\241czenia, prawda? "
gameforge.main_quest_lv55._370_say = "Najpierw zrobimy sobie przerw\234. Boli mnie g\179owa,[ENTER]a ty pewnie jeste\156 nie\159le zm\234czony. Musz\234 si\234[ENTER]zastanowi\230 nad tym wszystkim. Kiedy sko\241cz\234,[ENTER]porozmawiamy. Mimo wszystko, wy\156wiadczy\179e\156 mi[ENTER]ogromn\185 przys\179ug\234. To nie zostanie zapomniane! "
gameforge.main_quest_lv55._380_sayReward = "Otrzyma\179e\156 7.000.000 Punkt\243w Do\156wiadczenia. "
gameforge.main_quest_lv55._390_sayReward = "Otrzyma\179e\156 175.000 Yang. "
gameforge.main_quest_lv55._400_sayReward = "Otrzyma\179e\156 Ksi\185\191k\234 Lidera. "
gameforge.main_quest_lv55._40_say = "Uriel s\185dzi, \191e potrzebne nam informacje mog\185[ENTER]znajdowa\230 si\234 w pobli\191u pomnik\243w, kt\243re nie[ENTER]zosta\179y jeszcze przez nas zbadane. Udaj si\234 do[ENTER]Kr\243lestwa Shinsoo i zbadaj pomniki znajduj\185ce si\234[ENTER]na obszarze Yongan. "
gameforge.main_quest_lv55._50_npcChat = "Oto ona! "
gameforge.main_quest_lv55._60_say = "To ten pomnik, kt\243rego szuka\179 Uriel! Z\179o\191ona[ENTER]Strona z Pami\234tnika le\191y pod pomnikiem.[ENTER]Powinienem j\185 natychmiast dostarczy\230 do Uriela. "
