gameforge.main_quest_lv6._100_sayReward = "Id\159 do Kowala. Potrzebuje Twojej pomocy. "
gameforge.main_quest_lv6._10_targetVid = "Id\159 do Stra\191nika Miejskiego. "
gameforge.main_quest_lv6._110_say = "Kim jeste\156? Jestem bardzo zaj\234ty, wi\234c prosz\234 mi[ENTER]nie przeszkadza\230. Stra\191nik Miejski Ci\234 przys\179a\179?[ENTER]My\156la\179em, \191e nikt ju\191 nie przyjdzie. To nie jest[ENTER]zbyt trudne zadanie i nie zajmie Ci du\191o czasu. W[ENTER]sam raz dla m\179odego poszukiwacza przyg\243d. "
gameforge.main_quest_lv6._120_say = "Powinienem dosta\230 ju\191 pewn\185 przesy\179k\234 od Dozorcy,[ENTER]jednak do tej pory jej nie ma. Prosz\234, id\159 do[ENTER]Dozorcy i zapytaj go o ni\185. Pospiesz si\234. Bez tej[ENTER]przesy\179ki nie mog\234 kontynuowa\230 swojej pracy. "
gameforge.main_quest_lv6._130_targetVid = "Znajd\159 Dozorc\234. "
gameforge.main_quest_lv6._140_sendLetter = "Id\159 do Dozorcy "
gameforge.main_quest_lv6._150_sayReward = "Kowal czeka na piln\185 przesy\179k\234. Udaj si\234 wi\234c do[ENTER]Dozorcy i zapytaj si\234 o Nos \140wini dla Kowala. "
gameforge.main_quest_lv6._160_sayTitle = "Dozorca: "
gameforge.main_quest_lv6._170_say = "Witaj. Jestem Dozorc\185 Magazynu w tej wiosce.[ENTER]Je\156li masz przy sobie za du\191o przedmiot\243w, mog\234[ENTER]je przechowa\230 w moim magazynie.[ENTER]Jest to bardzo praktyczne. "
gameforge.main_quest_lv6._180_say = "Witaj! Czy chcesz co\156 przechow...?[ENTER]Ach, przys\179a\179 Ci\234 Kowal po Nos \140wini! "
gameforge.main_quest_lv6._190_say = "Obawiam si\234, \191e powoli starzej\234 si\234 i miewam[ENTER]skleroz\234. Prosz\234 oto Nos \140wini. Zanie\156 go[ENTER]natychmiast do Kowala. Do zobaczenia! "
gameforge.main_quest_lv6._200_sendLetter = "Z powrotem do Kowala "
gameforge.main_quest_lv6._20_sayReward = "Stra\191nik ma nowe zadanie dla Ciebie. Udaj si\234 do[ENTER]niego i dowiedz si\234 o co chodzi. "
gameforge.main_quest_lv6._210_sayReward = "Dozorca ca\179kiem zapomnia\179 o przesy\179ce. Teraz w[ENTER]ko\241cu wr\234czy\179 Ci Nos \140wini. Zanie\156 go natychmiast[ENTER]do Kowala, by nie musia\179 d\179u\191ej czeka\230. "
gameforge.main_quest_lv6._220_say = "Wr\243ci\179e\156 szybciej ni\191 my\156la\179em! Tak trzymaj, taka[ENTER]szybko\156\230 na pewno przyda Ci si\234 w przysz\179o\156ci. A[ENTER]teraz s\179uchaj mnie uwa\191nie, poniewa\191 mam bardzo[ENTER]wa\191n\185 informacj\234. "
gameforge.main_quest_lv6._230_say = "Wiesz co\156 o uszlachetnieniu? Oczywi\156cie, \191e nie![ENTER]Jeste\156 jeszcze m\179odym poszukiwaczem przyg\243d![ENTER]Wyja\156ni\234 Ci spraw\234: Je\156li dasz mi cz\234\156\230 swojej[ENTER]zbroi, mog\234 j\185 uszlachetni\230 za niewielk\185 ilo\156\230[ENTER]Yang. "
gameforge.main_quest_lv6._240_say = "Aby ulepszy\230 przedmioty, a\191 do +3 musisz zap\179aci\230[ENTER]troch\234 Yang. Ale od poziomu +4 i wy\191ej, mo\191e by\230[ENTER]wymagany dodatkowy przedmiot je\156li b\234dziesz[ENTER]chcia\179 co\156 ulepszy\230. W przesy\179ce by\179 Nos \140wini,[ENTER]by\179 mi potrzebny do ulepszenia przedmiotu. Musisz[ENTER]by\230 ostro\191ny i przygotowany na strat\234 przedmiotu,[ENTER]kt\243ry pr\243bujesz ulepszy\230. Mog\234 by\230 dobry, ale[ENTER]zawsze mo\191e zdarzy\230 si\234 wpadka. Je\156li masz czas,[ENTER]wpadnij. Mog\234 wyku\230 Ci kilka dobrych broni! "
gameforge.main_quest_lv6._250_sayReward = "Otrzyma\179e\156 %s Punkt\243w Do\156wiadczenia. "
gameforge.main_quest_lv6._260_sayReward = "Otrzyma\179e\156 %s Yang. "
gameforge.main_quest_lv6._270_sayReward = "Otrzyma\179e\156 Futro Wilka+. "
gameforge.main_quest_lv6._30_say = "Hej, nie obijaj si\234 po mie\156cie i nie m\243w, \191e nie[ENTER]ma nic do roboty! Musisz dalej trenowa\230! W[ENTER]dzisiejszych trudnych czasach trening jest[ENTER]jedynym sposobem na przetrwanie! "
gameforge.main_quest_lv6._40_say = "Je\156li ju\191 tutaj jeste\156, to mam dla Ciebie[ENTER]zadanie: Kowal by\179 w\179a\156nie u mnie i \191ali\179 si\234, \191e[ENTER]ma problemy z dostaw\185 Nosa \140wini. Chyba[ENTER]potrzebuje pomocy.[ENTER]Udaj si\234 do Kowala i powiedz mu, \191e ja Ci\234[ENTER]przys\179a\179em. Ruszaj! "
gameforge.main_quest_lv6._50_sayReward = "Je\156li pomo\191esz Kowalowi, otrzymasz nagrod\234 "
