gameforge.main_quest_lv60._120_say = "Wed\179ug przeprowadzony bada\241 przez Uriela siedem[ENTER]Smoczych Kap\179anek nale\191a\179o do Mrocznego Narodu.[ENTER]Zbadaj Stary Nagrobek na G\243rze Sohan. Tam mia\179a[ENTER]znajdowa\230 si\234 wieki temu stolica Mrocznego[ENTER]Narodu. "
gameforge.main_quest_lv60._130_say = "Nie przypominasz sobie przypadkiem, jaka by\179a[ENTER]inskrypcja nagrobka?![ENTER]Widocznie nie. Ten nagrobek mo\191e nam dostarczy\230[ENTER]wa\191nych informacji o Mrocznym Narodzie. Czy[ENTER]m\243g\179by\156 uda\230 si\234 na G\243r\234 Sohan i zrobi\230 dla mnie[ENTER]Kopi\234 Inskrypcji? "
gameforge.main_quest_lv60._140_sayReward = "Znalaz\179e\156 Stary Nagrobek z czas\243w Mrocznego[ENTER]Narodu i zrobi\179e\156 Kopi\234 Inskrypcji. A teraz[ENTER]zanie\156 j\185 do Uriela. "
gameforge.main_quest_lv60._150_say = "Wed\179ug przeprowadzony bada\241 przez Uriela siedem[ENTER]Smoczych Kap\179anek nale\191a\179o do Mrocznego Narodu.[ENTER]Zbadaj Stary Nagrobek na G\243rze Sohan. Tam mia\179a[ENTER]znajdowa\230 si\234 wieki temu stolica Mrocznego[ENTER]Narodu. "
gameforge.main_quest_lv60._160_say = "Wreszcie! Teraz mog\234 zanalizowa\230 Inskrypcj\234...[ENTER]G\179osi ona: Mroczny Nar\243d odda\179 si\234 czarnej magii[ENTER]i s\179u\191y Sung Mahi, demonicznemu B\243gu. "
gameforge.main_quest_lv60._170_say = "Wielkie nieba... Sung Mahi! Mo\191e tych siedem[ENTER]Smoczych Kap\179anek pr\243bowa\179o przywo\179a\230 Sung Mahi z[ENTER]pomoc\185 zakazanej magii? "
