gameforge.main_quest_lv60._220_sendLetter = "Mroczny Nar\243d II "
gameforge.main_quest_lv60._230_say = "Zdaniem Uriela Las Duch\243w nale\191a\179 wcze\156niej do[ENTER]kr\243lestwa Mrocznego Narodu. Mo\191e odkryjemy tam[ENTER]kolejne wskaz\243wki. W lesie tym czyha wiele[ENTER]niebezpiecze\241stw a w dodatku kamienie Metin[ENTER]sprawiaj\185, \191e wszystkie kreatury znajduj\185ce si\234 w[ENTER]lesie s\185 nadzwyczaj agresywne. Znajd\159 Z\179e Drzewo,[ENTER]aby otrzyma\230 dalsze wskaz\243wki. Porozmawiaj o tym[ENTER]z Urielem. "
gameforge.main_quest_lv60._240_say = "O Mrocznym Narodzie kr\185\191\185 niezliczone tajemnice.[ENTER]Dzi\234ki Tobie wyja\156nili\156my ju\191 kilka z nich, ale w[ENTER]dalszym ci\185gu brakuje nam wa\191nych informacji.[ENTER]Prosz\234, wyrusz teraz na poszukiwanie Starego[ENTER]Dokumentu. Prawdopodobnie znajdziesz go w Lesie[ENTER]Duch\243w, w pobli\191u G\243ry Sohan. "
gameforge.main_quest_lv60._250_counter = "Pozosta\179y czas: "
gameforge.main_quest_lv60._260_say = "O Mrocznym Narodzie kr\185\191\185 niezliczone tajemnice.[ENTER]Dzi\234ki Tobie wyja\156nili\156my ju\191 kilka z nich, ale w[ENTER]dalszym ci\185gu brakuje nam wa\191nych informacji.[ENTER]Prosz\234, wyrusz teraz na poszukiwanie Starego[ENTER]Dokumentu. Prawdopodobnie znajdziesz go w Lesie[ENTER]Duch\243w, w pobli\191u G\243ry Sohan. "
gameforge.main_quest_lv60._270_sayReward = "Pokona\179e\156 Z\179e Drzewo i zabra\179e\156 Dokument.[ENTER]Niestety, nie mo\191esz odczyta\230 tre\156ci, poniewa\191[ENTER]jest napisany w obcym j\234zyku. Daj Urielowi do[ENTER]przet\179umaczenia. "
gameforge.main_quest_lv60._280_say = "Wreszcie! Odnalaz\179e\156 Stary Dokument. Miejmy[ENTER]nadziej\234, \191e uchyli on r\185bek tajemnicy! "
gameforge.main_quest_lv60._290_say = "Ale co to ...?! Tutaj prawie nic nie ma![ENTER]W\179a\156ciwie ten dokument powinien zawiera\230 dziesi\234\230[ENTER]stron. Prosz\234, wr\243\230 do Lasu Duch\243w i znajd\159[ENTER]pozosta\179e dziewi\234\230 stron. "
gameforge.main_quest_lv60._300_say = "Ilo\156\230 stron do znalezienia: %d "
gameforge.main_quest_lv60._30_say = "Cze\156\230, jak leci? Przypominasz sobie mo\191e ten[ENTER]stary pami\234tnik z t\185 dziwn\185 histori\185, kt\243ra nagle[ENTER]si\234 ko\241czy na 13 stronie? "
gameforge.main_quest_lv60._310_say = "A teraz zobaczmy...[ENTER]Widocznie Mroczny Nar\243d zwabi\179 arcykap\179ank\234[ENTER]smoczego kultu u\191ywaj\185c do tego tajemniczego[ENTER]zakl\234cia i wykorzysta\179 \156wi\234te si\179y siedmiu[ENTER]kap\179anek do przeprowadzenia rytua\179u kultu czarnej[ENTER]magii. "
gameforge.main_quest_lv60._320_say = "Aby przywo\179a\230 Sung Mahi, trzeba by\179o[ENTER]przeprowadzi\230 rytua\179 czarnej magii r\243wnocze\156nie w[ENTER]siedmiu r\243\191nych miejscach.[ENTER]Jednak Lee Seop wraz ze swoj\185 armi\185 w sam\185 por\234[ENTER]zak\179\243cili przeprowadzenie rytua\179u i tym samym[ENTER]udaremnili zgubny plan Mrocznego Narodu. "
gameforge.main_quest_lv60._330_say = "Rzeczywi\156cie nar\243d ten wzbudza\179 strach. By\179 on w[ENTER]stanie przy u\191yciu czarnej magii kontrolowa\230[ENTER]ludzk\185 \156wiadomo\156\230! "
gameforge.main_quest_lv60._340_sendLetter = "Wskaz\243wka "
gameforge.main_quest_lv60._350_say = "Uriel odkry\179 w staro\191ytnych skryptach wskaz\243wk\234[ENTER]dotycz\185c\185 Pomnika Gum. Id\159 do niego i dowied\159 si\234[ENTER]czego\156 wi\234cej. "
gameforge.main_quest_lv60._360_say = "Podsumujmy teraz, co dowiedzieli\156my si\234 do tej[ENTER]pory: Niegdy\156 istnia\179 lud, kt\243ry zwa\179 si\234[ENTER]Mrocznym Narodem i s\179u\191y\179 demonicznemu Bogu, Sung[ENTER]Mahi. Aby go przywo\179a\230, zwabi\179 siedem Smoczych[ENTER]Kap\179anek i wykorzysta\179 ich \156wi\234te si\179y w celu[ENTER]przeprowadzenia zakazanego rytua\179u czarnej magii.[ENTER]Jednak trzeba by\179o go koniecznie przeprowadzi\230[ENTER]r\243wnocze\156nie w siedmiu r\243\191nych miejscach. "
gameforge.main_quest_lv60._370_say = "Smocze Kap\179anki przeprowadza\179y rytua\179y czarnej[ENTER]magii tylko w tej wie\191y a nie w siedmiu r\243\191nych[ENTER]miejscach...[ENTER]Dlatego nie powiod\179o si\234 przywo\179anie Sung Mahi! "
gameforge.main_quest_lv60._380_say = "Mroczny Nar\243d musia\179 poda\230 Smoczym Kap\179ankom z\179e[ENTER]informacje. "
gameforge.main_quest_lv60._390_say = "Mo\191e nie wiedzia\179y o tym ...[ENTER]By\230 mo\191e to tylko przypadek, ale staro\191ytne[ENTER]skrypty wspominaj\185 o wie\191y opisuj\185c Pomnik Gum.[ENTER]Wydaje si\234, \191e chodzi tutaj o Wie\191\234 Demon\243w przy[ENTER]\140wi\185tyni Hwang. "
gameforge.main_quest_lv60._400_say = "W ko\241cu odnale\159li\156my decyduj\185cy \156lady prowadz\185ce[ENTER]do siedmiu Smoczych Kap\179anek![ENTER]Odpocznij chwilk\234 a potem porozmawiamy, jaki[ENTER]b\234dzie nasz nast\234pny krok. Obawiam si\234, \191e masz[ENTER]przed sob\185 d\179ug\185 drog\234 do Wie\191y Demon\243w ... "
gameforge.main_quest_lv60._40_say = "Tak, oczywi\156cie. Siedem os\243b uciek\179o przed Lee[ENTER]Seop i jego kawaleri\185 do \140wi\185tyni Hwang, gdzie[ENTER]podj\234li desperackie kroki, korzystaj\185c z[ENTER]zabronionej czarnej magii... tylko jednemu z nich[ENTER]uda\179o si\234 to prze\191y\230. "
gameforge.main_quest_lv60._410_sayReward = "Dalsza cz\234\156\230 przygody czeka na Ciebie po[ENTER]osi\185gni\234ciu poziomu 66. "
gameforge.main_quest_lv60._50_say = "Zgadza si\234. Przeprowadzi\179em dalsze badania i[ENTER]dowiedzia\179em si\234, \191e te siedem os\243b nale\191a\179o do[ENTER]\156wi\234tego kultu Smoczych Kap\179anek. W staro\191ytnych[ENTER]skryptach wspominane one by\179y w zwi\185zku z[ENTER]teokratycznym ludem, zwanym Mrocznym Narodem.[ENTER]Ale czy one nale\191a\179y do tego tajemniczego narodu?[ENTER]Prosz\234, przeczytaj uwa\191nie ten oto zw\243j i wr\243\230,[ENTER]aby porozmawia\230 ze mn\185 jeszcze raz. "
gameforge.main_quest_lv60._60_sendLetter = "Mroczny Nar\243d I "
gameforge.main_quest_lv60._70_say = "Wed\179ug przeprowadzonych bada\241 przez Uriela siedem[ENTER]Smoczych Kap\179anek wywodzi si\234 z Mrocznego Narodu.[ENTER]Zbadaj ten Stary Nagrobek na G\243rze Sohan.[ENTER]Tam w\179a\156nie mia\179a by\230 stolica Mrocznego Narodu.[ENTER]Ale najpierw porozmawiaj jeszcze raz z Urielem. "
gameforge.main_quest_lv60._80_say = "Ich nadzwyczaj wysokorozwini\234ta sztuka[ENTER]czarnoksi\234stwa i fakt, \191e zosta\179y zg\179adzone przez[ENTER]Lee Seop, o czym mo\191na si\234 dowiedzie\230 z[ENTER]Pami\234tnika, jest dowodem na to, \191e tych siedem[ENTER]Smoczych Kap\179anek nale\191a\179o do Mrocznego Narodu. "
gameforge.main_quest_lv60._90_say = "Przygl\185daj\185c si\234 uwa\191nie mapie ze staro\191ytnych[ENTER]skrypt\243w mo\191na stwierdzi\230 ca\179\185 pewno\156ci\185, \191e[ENTER]stolica Mrocznego Narodu faktycznie musia\179a[ENTER]znajdowa\230 si\234 na G\243rze Sohan. "
gameforge.main_quest_lv66 = {}
gameforge.main_quest_lv66._100_say = "Niesamowite! Rozumiesz co to oznacza? Pocz\185tkowo[ENTER]w Wie\191y Demon\243w nie by\179o \191adnych demon\243w ani[ENTER]duch\243w. To dziedzictwo pozostawione przez Smocz\185[ENTER]Kap\179ank\234. Poprzez jej mroczny rytua\179, kt\243ry by\179[ENTER]jej ostatni\185 desperack\185 pr\243b\185 zniszczenia[ENTER]kawalerii Lee Seopa, otworzy\179a bramy do naszego[ENTER]\156wiata demonom i przyp\179aci\179a za to swoim \191yciem. "
gameforge.main_quest_lv66._10_sendLetter = "Pami\234tnik "
gameforge.main_quest_lv66._110_say = "I w taki oto spos\243b przyby\179 do nas Umar\179y[ENTER]Rozpruwacz ze swoim demonicznym orszakiem.[ENTER]Jednak\191e wielka misja Mrocznego Narodu oraz[ENTER]Smoczych Kap\179anek spe\179z\179a na niczym: Nie powiod\179o[ENTER]si\234 przywo\179anie Sung Mahis, natomiast Lee Seop[ENTER]ur\243s\179 w si\179\234 i wreszcie stworzy\179 zjednoczone[ENTER]imperium.[ENTER]Dzi\234ki twojej pomocy uda\179o mi si\234 w ko\241cu[ENTER]rozwik\179a\230 najwi\234ksz\185 tajemnic\234 mojego \191ycia! "
gameforge.main_quest_lv66._120_say = "W nagrod\234 chcia\179bym podarowa\230 ci Zw\243j[ENTER]B\179ogos\179awie\241stwa. Prosz\234 we\159 ten prezent,[ENTER]nalegam! "
gameforge.main_quest_lv66._130_sendLetter = "Otrzyma\179e\156 wiadomo\156\230. "
gameforge.main_quest_lv66._140_say = "Stra\191nik Wsi ma list dla ciebie. Przeczytaj go[ENTER]uwa\191nie i dowiedz si\234, kto jest tajemniczym[ENTER]anonimowym nadawc\185. "
gameforge.main_quest_lv66._150_say = "Ostatnio nie pokazywa\179e\156 si\234 tutaj zbyt cz\234sto,[ENTER]co? Mam ci przekaza\230 ten list - nie mam zielonego[ENTER]poj\234cia, od kogo on jest, nie przedstawi\179 mi si\234. "
gameforge.main_quest_lv66._160_say = "Papier, na kt\243ry zasta\179 napisany list, wygl\185da na[ENTER]bardzo stary. Kto\156 w po\156piesznie nagryzmoli\179:[ENTER]Mam bardzo wa\191ne informacje dotycz\185ce siedmiu[ENTER]Smoczych Kap\179anek oraz Sung Mahi. Czekam na[ENTER]ciebie z ty\179u Wie\191y Demon\243w w \140wi\185tyni Hwang.[ENTER]Znajdziesz mnie w cieniu drzewa. Po\156piesz si\234,[ENTER]czas nagli! "
gameforge.main_quest_lv66._170_sendLetter = "Anonimowy List "
gameforge.main_quest_lv66._180 = "Id\159 do \140wi\185tyni Hwang i spotkaj si\234 tam z[ENTER]tajemniczym autorem listu. Czeka on na ciebie z[ENTER]ty\179u Wie\191y Demon\243w. "
gameforge.main_quest_lv66._190_sayTitle = "Lee Chung "
gameforge.main_quest_lv66._200_say = "Witaj! Pozw\243l, \191e si\234 najpierw przedstawi\234: mam[ENTER]na imi\234 Lee Chung. Wykaza\179e\156 si\234 spor\185 odwag\185,[ENTER]przychodz\185c tutaj na \191yczenie nieznajomego. Nie[ENTER]myli\179em si\234 co do ciebie - ty te\191 nie b\234dziesz[ENTER]tego \191a\179owa\179. Pos\179uchaj uwa\191nie, co ci powiem! "
gameforge.main_quest_lv66._20_say = "Uriel dowiedzia\179 si\234 czego\156 o ostatniej Smoczej[ENTER]Kap\179ance, kt\243ra ocala\179a. Jej Pami\234tnik musi by\230 w[ENTER]Wie\191y Demon\243w. Udaj si\234 do Uriela i dowiedz si\234[ENTER]czego\156 wi\234cej. "
gameforge.main_quest_lv66._210_sendLetter = "Nowe Z\179o "
gameforge.main_quest_lv66._220_say = "Pos\179uchaj, co ma dopowiedzenia Lee Chung. "
gameforge.main_quest_lv66._230_say = "Istnieje pow\243d, dlaczego wezwa\179em ci\234 w\179a\156nie do[ENTER]\140wi\185tyni Hwang: Ostatnio zdarzaj\185 si\234 tutaj[ENTER]dziwne rzeczy. W dodatku niedawno odkryli\156my z[ENTER]ty\179u Wie\191y Demon\243w wej\156cie do olbrzymiej jaskini! "
gameforge.main_quest_lv66._240_say = "Olbrzymiej jaskini? A co jest w \156rodku? "
gameforge.main_quest_lv66._250_say = "W jaskini rozgo\156ci\179o si\234 i czeka na nas nowe[ENTER]niewyobra\191alne Z\179o: Nasi zwiadowcy donie\156li o[ENTER]przera\191aj\185cym stworzeniu, kt\243re jest gorsze od[ENTER]setki demon\243w.[ENTER]Jego straszliwy wygl\185d i niezaspokojona \191\185dza[ENTER]\191ycia wskazuje na to, \191e chodzi tutaj o[ENTER]legendarnego Agwi - jednego z dziesi\234ciu wielkich[ENTER]diab\179\243w \156wiata demon\243w.[ENTER]Je\156li nasze przypuszczenia potwierdz\185 si\234, to[ENTER]ludzko\156ci znajduje si\234 w wielkim[ENTER]niebezpiecze\241stwie. "
gameforge.main_quest_lv66._260_say = "Straszliwszy od demon\243w... doprawdy ta kreatura[ENTER]musi by\230 pot\234\191na i gro\159na. "
gameforge.main_quest_lv66._270_say = "To prawda. Pr\243bowa\179em z moimi lud\159mi kilka razy[ENTER]szturmowa\230 Diabelskie Katakumby. Niestety, za[ENTER]ka\191dym razem ponosili\156my straszliw\185 kl\234sk\234 i[ENTER]ogromne straty.[ENTER]Potrzebujemy wsparcia znakomitego wojownika -[ENTER]dlatego te\191 wezwali\156my ciebie. Pomo\191esz nam? "
gameforge.main_quest_lv66._280_say = "Mo\191ecie liczy\230 na moj\185 pomoc. "
gameforge.main_quest_lv66._290_say = "Doprawdy? To na nowo rozpala w nas iskr\234 nadziei![ENTER]Teraz, kiedy ju\191 wiem, \191e jeste\156 po naszej[ENTER]stronie, zdradz\234 ci ca\179\185 prawd\234: Ja, Lee Chung,[ENTER]jestem komendantem Wojownik\243w Cieni. Jeste\156my[ENTER]tajn\185 elitarn\185 jednostk\185 armii Lee Seopa. "
gameforge.main_quest_lv66._300_sayTitle = "Lee Chung "
gameforge.main_quest_lv66._30_say = "Och, jak to dobrze ci\234 znowu spotka\230. Jak widz\234[ENTER]jeste\156 ca\179y i zdrowy. Czy jeste\156 got\243w podj\185\230[ENTER]kolejn\185 przygod\234? Ci\185gle brakuje nam wa\191nych[ENTER]informacji o Mrocznym Narodzie oraz o siedmiu[ENTER]Smoczych Kap\179ankach. Ostatnia ocala\179a Smocza[ENTER]Kap\179anka musia\179a ukry\230 sw\243j Pami\234tnik w Wie\191y[ENTER]Demon\243w, zanim jeszcze wykona\179a rytua\179 czarnej[ENTER]magii. Wyrusz w drog\234 i przynie\156 mi ten[ENTER]Pami\234tnik. Kr\243l Demon\243w mo\191e mie\230 go w swoich[ENTER]szponach. "
gameforge.main_quest_lv66._310_say = "Ju\191 od niepami\234tnych czas\243w staraj\185 si\234 Wojownicy[ENTER]Cieni w wielkiej tajemnicy zapobiec[ENTER]zmartwychwstaniu Sung Mahis. To jest nasza misja.[ENTER]Spr\243bujmy wsp\243lnie zmusi\230 Agwi do powrotu do[ENTER]jaskini. Musimy si\234 te\191 dowiedzie\230, w jaki spos\243b[ENTER]dotar\179 on do naszego \156wiata! "
gameforge.main_quest_lv66._320_sendLetter = "Nie ma czasu "
gameforge.main_quest_lv66._330_say = "Szuka Ci\234 Lee Chung, komendant Wojownik\243w Cieni.[ENTER]To bardzo pilna sprawa! "
gameforge.main_quest_lv66._340_say = "Mam bardzo piln\185 pro\156b\234. Widzisz tam tego rannego[ENTER]\191o\179nierza? To jeden z moich zwiadowc\243w, kt\243ry z[ENTER]mojego rozkazu mia\179 zbada\230 Diabelskie Katakumby,[ENTER]ale zosta\179 zaatakowany przez Agwi i zatruty.[ENTER]Trucizna zacz\234\179a ju\191 rozprzestrzenia\230 si\234 w jego[ENTER]ciele, nie zosta\179o mu zbyt wiele czasu. "
gameforge.main_quest_lv66._350_say = "Potrzebuje on Antidotum - i to jak najszybciej![ENTER]Czy m\243g\179by\156 je dostarczy\230? Znajdziesz je w[ENTER]Czerwonym Lesie przy Czerwonej Driadzie. Jest on[ENTER]jednym z najwa\191niejszych moich wojownik\243w -[ENTER]uratuj go, a otrzymasz ode mnie %s "
gameforge.main_quest_lv66._360_say = "Przynios\234 Antidotum! "
gameforge.main_quest_lv66._370_say = "Jestem ci niesamowicie wdzi\234czny! Wprawdzie jest[ENTER]jeszcze przy \191yciu, ale z minuty na minut\234[ENTER]s\179abnie. Nie mamy czasu do stracenia! "
gameforge.main_quest_lv66._380_notice = "Pozosta\179o ci jeszcze %d min. "
gameforge.main_quest_lv66._390_sendLetter = "Antidotum "
gameforge.main_quest_lv66._400_say = "Od Lee Chung dowiedzia\179e\156 si\234, \191e Antidotum[ENTER]znajduje si\234 w Czerwonym Lesie. Schwytaj w tym[ENTER]celu %d Czerwone Driady.[ENTER][ENTER]Czerwony Las jest niebezpieczniejszym miejscem[ENTER]ni\191 Las Duch\243w, a wi\234c uwa\191aj na siebie. "
gameforge.main_quest_lv66._40_say = "Pokona\179e\156 Kr\243la Demon\243w i zdoby\179e\156 Pami\234tnik[ENTER]Smoczej Kap\179anki. Zanie\156 go teraz do m\234drca[ENTER]Uriela. On go dok\179adnie zanalizuje. "
gameforge.main_quest_lv66._410_say = "Czas ju\191 min\185\179. \175o\179nierz powoli umiera, a wi\234c[ENTER]zanie\156 mu jak najszybciej Antidotum. "
gameforge.main_quest_lv66._420_say = "Pozosta\179o ci jeszcze %d min. "
gameforge.main_quest_lv66._430_say = "W ko\241cu znalaz\179e\156 Antidotum! Zanie\156 je pr\234dko do[ENTER]Lee Chung. "
gameforge.main_quest_lv66._440_say = "Tutaj, szybko! Wydaje mi si\234, \191e jeszcze[ENTER]zd\185\191y\179e\156. Kamie\241 spad\179 mi z serca. Ja i moi[ENTER]ludzie jeste\156my ci niesko\241czenie wdzi\234czni. "
gameforge.main_quest_lv66._450_say = "Dzi\234ki twojej pomocy prze\191y\179 m\243j \191o\179nierz. Oto[ENTER]twoja nagroda za wy\156wiadczon\185 mi pomoc. "
gameforge.main_quest_lv66._460_say = "Nie \156pieszy\179e\156 si\234 zbytnio, ale na szcz\234\156cie[ENTER]przyszed\179e\156 w ostatniej chwili. W nim tli si\234[ENTER]jeszcze ostatnia iskierka \191ycia. "
gameforge.main_quest_lv66._470_say = "Wydaje si\234, \191e prze\191yje. Jednak musz\234 przyzna\230,[ENTER]\191e prawie by umar\179, poniewa\191 tak d\179ugo szuka\179e\156[ENTER]tego Antidotum.[ENTER]Przykro mi, to wszystko co mog\234 da\230 ci w nagrod\234. "
gameforge.main_quest_lv66._480_sendLetter = "Raport "
gameforge.main_quest_lv66._490_say = "Zwiadowca odzyska\179 przytomno\156\230. Pos\179ucha, co on[ENTER]zaobserwowa\179 w Diabelskich Katakumbach. "
gameforge.main_quest_lv66._500_say = "Dzi\234kuj\234, \191e mnie uratowa\179e\156. W Diabelskich[ENTER]Katakumbach zobaczy\179em co\156 niewiarygodnego, ale[ENTER]niestety potem zosta\179em dostrze\191ony i... "
gameforge.main_quest_lv66._50_say = "Znalaz\179e\156 go! Pami\234tnik ostatniej Smoczej[ENTER]Kap\179anki. Moje r\234ce a\191 dr\191\185 ze wzruszenia.[ENTER]Na pewno b\234d\234 potrzebowa\179 troch\234 czasu na[ENTER]przeanalizowanie jej zapisk\243w. Mi\234dzyczasie[ENTER]mo\191esz odpocz\185\230. Zawo\179am ci\234 do siebie, gdy b\234d\234[ENTER]ci m\243g\179 co\156 wi\234cej powiedzie\230. "
gameforge.main_quest_lv66._510_say = "Co zobaczy\179e\156? "
gameforge.main_quest_lv66._520_say = "By\179y tam osoby w czarnych pelerynach z kapturami[ENTER]opuszczonymi g\179\234boko na twarz. Niestety, do moich[ENTER]uszu dochodzi\179y tylko strz\234pki rozm\243w, z kt\243rych[ENTER]mog\179em wywnioskowa\230, \191e chodzi tutaj o Wasali[ENTER]Mroku. Poczekaj, to jeszcze nie wszystko: okropny[ENTER]duch, przypominaj\185cy kszta\179tem kobiet\234, unosi\179[ENTER]si\234 nad ich g\179owami. Wasale Mroku zwali j\185[ENTER]Banshee. "
gameforge.main_quest_lv66._530_say = "Niedobrze. Co takiego zamierzaj\185 Wasale Mroku i[ENTER]ta Banshee? "
gameforge.main_quest_lv66._540_say = "Banshee przywo\179a\179a za pomoc\185 czarnej magii Agwi,[ENTER]diabelsk\185 istot\234, kt\243ra przysz\179a prosto z[ENTER]piekielnej otch\179ani. To ona nazwa\179a kr\243la Agwi[ENTER]Azrael. "
gameforge.main_quest_lv66._550_say = "Natychmiast wyrusza\179em, aby opowiedzie\230 o tym Lee[ENTER]Chung. Niestety potkn\185\179em si\234 i zosta\179em[ENTER]dostrze\191ony.[ENTER][ENTER]Ach, przypomnia\179em sobie, \191e komendant Lee Chung[ENTER]chce Ci jeszcze co\156 wa\191nego przekaza\230. Najlepiej,[ENTER]gdy p\243jdziesz do niego od razu. "
gameforge.main_quest_lv66._560_sendLetter = "Mroczne Zagro\191enie "
gameforge.main_quest_lv66._570_say = "Id\159 do Lee Chung i porozmawiaj z nim o nowym[ENTER]zagro\191eniu, kt\243re czai si\234 w Diabelskich[ENTER]Katakumbach. "
gameforge.main_quest_lv66._580_say = "To straszne o czym opowiada\179 m\243j zwiadowca,[ENTER]przyznasz mi racj\234? Wasale Mroku, to rodzaj sekt,[ENTER]kt\243ra jest odpowiedzialna za pojawienie si\234 Agwi.[ENTER]Oni te\191 obudzili ostatniego ducha Smoczych[ENTER]Kap\179anek. Powr\243ci\179a do tego \156wiata jako Banshee,[ENTER]manifestacja Z\179a i dzi\234ki jej magicznym si\179\185 chc\185[ENTER]przywo\179a\230 Demonicznego Boga, Sung Mahi. "
gameforge.main_quest_lv66._590_say = "Co? Banshee to duch ostatniej Smoczej Kap\179anki? "
gameforge.main_quest_lv66._600_say = "Bez w\185tpienia. W\156r\243d si\243str smoczego kultu[ENTER]obdarzona by\179a ona wyj\185tkow\185 si\179\185, dzi\234ki kt\243rej[ENTER]mog\179a przywo\179a\230 czterech \156wi\234tych Stra\191nik\243w[ENTER]Niebios i przeprowadzi\230 rytua\179 czarnej magii.[ENTER]Teraz wiemy ju\191, kto kryje si\234 za nowym[ENTER]zagro\191eniem: Wasale Mroku i Banshee planuj\185[ENTER]zako\241czy\230 to straszliwe dzie\179o Mrocznego Narodu i[ENTER]obudzi\230 Sung Mahi! "
gameforge.main_quest_lv66._60_sendLetter = "Rozwi\185zanie Zagadki "
gameforge.main_quest_lv66._610_say = "Du\191o Ci zawdzi\234czamy: Uratowa\179e\156 od \156mierci[ENTER]mojego najlepszego \191o\179nierza i tylko dzi\234ki temu[ENTER]dowiedzieli\156my si\234 o nag\179ym pojawieniu si\234 Agwi[ENTER]oraz o nowym zagro\191eniu w Diabelskich[ENTER]Katakumbach.[ENTER]Teraz mo\191esz odpocz\185\230 - potem pomy\156limy o[ENTER]odpowiedniej taktyce. "
gameforge.main_quest_lv66._620_say = "Mo\191esz kontynuowa\230 przygod\234, gdy tylko osi\185gniesz[ENTER]poziom 72. "
gameforge.main_quest_lv66._70_say = "Uriel ci\234 szuka. Przeczyta\179 Pami\234tnik. "
gameforge.main_quest_lv66._80_say = "Ach, doskonale! Jeste\156 tutaj.[ENTER]Rzeczywi\156cie, zapiski zrobione przez ostatni\185[ENTER]Smocz\185 Kap\179ank\234 s\185 zdumiewaj\185ce. Pos\179uchaj tylko: "
gameforge.main_quest_lv66._90_say = "M\243j los jest przes\185dzony! Zabarykadowa\179am si\234 na[ENTER]najwy\191szym pi\234trze wie\191y. Ludzie Lee Seopa zaraz[ENTER]wywa\191\185 drzwi do mojego ostatniego wi\234zienia. Nie[ENTER]mam \191adnego wyj\156cia... Jestem zgubiona.[ENTER][ENTER]Nie, tak nie mo\191e si\234 to sko\241czy\230! Przecie\191 to[ENTER]wszystko nie mo\191e p\243j\156\230 na marne. Sama musz\234[ENTER]wezwa\230 czarn\185 magi\234, pradawn\185 si\179\234 Z\179a i[ENTER]przywo\179a\230 mroczne si\179y.[ENTER][ENTER]Wprawdzie to oznacza dla mnie pewn\185 \156mier\230, ale[ENTER]poci\185gn\234 te\191 za sob\185 w otch\179a\241 zguby moich wrog\243w[ENTER]- nawet, je\156li to b\234dzie moja ostatnia rzecz,[ENTER]kt\243r\185 zrobi\234! "
gameforge.main_quest_lv7 = {}
gameforge.main_quest_lv7._100_say = "Jeszcze jej nie dostarczy\179e\156? Ta w\234dka jest dla[ENTER]Rybaka na dole przy rzece. Po\156piesz si\234, pilnie[ENTER]jej potrzebuje! "
gameforge.main_quest_lv7._10_targetVid = "Kolejna przys\179uga "
gameforge.main_quest_lv7._110_npcChat = "Kowal posy\179a t\185 now\185 w\234dke! "
gameforge.main_quest_lv7._120_say = "Dzi\234kuj\234 Ci bardzo. Nareszcie mog\234 pogrzeba\230 sw\185[ENTER]wiern\185, lecz ju\191 bardzo zu\191yt\185 star\185 w\234dk\234.[ENTER]\163owienie ryb to dla mnie nie tylko zarobek, ale[ENTER]r\243wnie\191 najwi\234ksza przyjemno\156\230 dnia![ENTER]Wiesz jak \179owi\230 ryby na w\234dk\234? "
gameforge.main_quest_lv7._130_say = "Najpierw we\159 w r\234k\234 W\234dk\234, potem u\191yj robaka[ENTER]poprzez klikni\234cie na niego. Potem zarzu\230 W\234dk\185,[ENTER]korzystaj\185c ze swoich \179ownych umiej\234tno\156ci. Je\156li[ENTER]poczu\179e\156, \191e masz branie (chmurka), skorzystaj z[ENTER]umiej\234tno\156ci ponownie. Albo si\234 uda, albo[ENTER]b\234dziesz musia\179 spr\243bowa\230 ponownie. Jest wiele[ENTER]ryb, kt\243re mo\191esz z\179apa\230. Ryba jest dobra dla[ENTER]Twojego zdrowia, czasem te\191 mo\191esz z\179owi\230 co\156 o[ENTER]du\191ej warto\156ci. Wi\234c, je\156li b\234dziesz mie\230 czas,[ENTER]spr\243buj! "
gameforge.main_quest_lv7._140_say = "Tak, masz dow\243d, \191e dostarczy\179e\156 mi W\234dk\234.[ENTER]Powiniene\156 dostarczy\230 go do Kowala. "
gameforge.main_quest_lv7._150_sayItem = "Dostarcz potwierdzenie odbioru W\234dki. "
gameforge.main_quest_lv7._160_sayReward = "Dostarczy\179e\156 W\234dk\234 Rybakowi, kt\243r\185 zrobi\179 Kowal.[ENTER]Wr\243\230 do Kowala wraz z dowodem, \191e to zrobi\179e\156,[ENTER]wtedy otrzymasz nagrod\234. "
gameforge.main_quest_lv7._170_say = "Uda\179o ci si\234 znale\159\230 rybaka?[ENTER]Wspaniale. Dzi\234ki twojej eskapadzie zaoszcz\234dz\234[ENTER]sporo czasu. W nagrod\234 dostaniesz ode mnie troch\234[ENTER]Yang i 1500 punkt\243w do\156wiadczenia. "
gameforge.main_quest_lv7._180_sendLetter = "Kredyt "
gameforge.main_quest_lv7._190_sayReward = "Dzi\234ki temu Kredytowi, Kowal ulepszy twoj\185 zbroj\234[ENTER]za darmo. Przesu\241 zbroj\234 nad Kowala i upu\156\230 aby[ENTER]otworzy\230 okienko ulepszania. "
gameforge.main_quest_lv7._200_sayItem = "Kredyt na darmowe uszlachetnienie "
gameforge.main_quest_lv7._20_sayReward = "Prosz\234, id\159 do Kowala. Potrzebuje pomocy kogo\156,[ENTER]kto mo\191e dostarczy\230 co\156 do Rybaka. "
gameforge.main_quest_lv7._210_sayTitle = "Wskaz\243wka: "
gameforge.main_quest_lv7._220_sayReward = "1. Kredyt nie jest widoczny w ekwipunku.[ENTER]2. Pomy\156lne uszlachetnienie (tak jak w przypadku[ENTER]ka\191dego uszlachetnienia) nie jest gwarantowane. "
gameforge.main_quest_lv7._230_sayTitle = "Kredyt zosta\179 ju\191 wykorzystany. "
gameforge.main_quest_lv7._240_sayReward = "Kredyt zosta\179 ju\191 wykorzystany na jedno darmowe[ENTER]uszlachetnienie. Wa\191ny jest on tylko na jedno[ENTER]uszlachetnienie. "
gameforge.main_quest_lv7._30_say = "Witaj poszukiwaczu przyg\243d! Czy m\243g\179by\156 wykona\230[ENTER]dla mnie kolejn\185 rzecz? Zwykle nie prosz\234 innych[ENTER]ludzi o przys\179ugi, ale ty wydajesz si\234 by\230 godny[ENTER]zaufania. Wybra\179em do tego w\179a\156nie Ciebie, to[ENTER]du\191e wyr\243\191nienie! "
gameforge.main_quest_lv7._40_say = "Zrobi\179em W\234dk\234 dla Rybaka, ale niestety jestem[ENTER]bardzo zaj\234ty i dlatego nie mog\234 jej mu[ENTER]dostarczy\230 osobi\156cie.[ENTER]Czy m\243g\179by\156 to za mnie zrobi\230? "
gameforge.main_quest_lv7._50_sayItem = "Bardzo Elastyczna W\234dka "
gameforge.main_quest_lv7._60_say = "Rybaka powiniene\156 znale\159\230 gdzie\156 przy rzece.[ENTER]Je\156li dostarczysz W\234dk\234 do Rybaka, dam Ci troch\234[ENTER]Yang. My\156l\234, \191e to uczciwy uk\179ad, nieprawdwa\191? "
gameforge.main_quest_lv7._70_sendLetter = "Znajd\159 Rybaka "
gameforge.main_quest_lv7._80_sayReward = "Kowal przygotowa\179 W\234dk\234 dla Rybaka. Znajd\159[ENTER]Rybaka, kt\243ry jest gdzie\156 przy rzece i daj mu[ENTER]W\234dk\234. "
gameforge.main_quest_lv7._90_npcChat = "Dla kogo jest ta w\234dka? "
gameforge.main_quest_lv72 = {}
gameforge.main_quest_lv72._100_say = "\163za Niebios uzyskuje jej doskona\179\185 czysto\156\230[ENTER]poprzez jej magiczne po\179\185czenie z \140wi\234con\185[ENTER]\175ywic\185, Niebiesk\185 Esencj\185 Kryszta\179u oraz[ENTER]Czerwonym Kwarcem Piekie\179.[ENTER]Niebieska Esencja Kryszta\179u musi by\230 zdobyta od[ENTER]w\179adcy Lodowej Ziemi. "
gameforge.main_quest_lv72._10_sendLetter = "Zwietrza\179a P\179yta "
gameforge.main_quest_lv72._110_say = "Zanotowa\179e\156 sobie t\234 godn\185 uwagi inskrypcj\234.[ENTER]Opowiedz teraz Lee Chung, o tym, co przed chwil\185[ENTER]przeczyta\179e\156. "
gameforge.main_quest_lv72._120_say = "Wr\243ci\179e\156 ca\179y i zdrowy! Widz\234 po twojej minie, \191e[ENTER]odnios\179e\156 sukces, prawda? "
gameforge.main_quest_lv72._130_say = "Masz racj\234! Dzi\234ki inskrypcji na Zwietrza\179ej[ENTER]P\179ycie dowiedzia\179em si\234, \191e \156wi\234te si\179y mo\191na[ENTER]przywo\179a\230 za pomoc\185 magicznego kamienia, zwanego[ENTER]\163z\185 Niebios. "
gameforge.main_quest_lv72._140_say = "\163za Niebios... A wi\234c ona naprawd\234 istnieje. Czy[ENTER]uda\179o ci si\234 znale\159\230 wskaz\243wki, jak mo\191na j\185[ENTER]zdoby\230? "
gameforge.main_quest_lv72._150_say = "Aby wyprodukowa\230 \163z\234 Niebios, potrzeba do tego[ENTER]\140wi\234con\185 \175ywic\234, Niebiesk\185 Esencj\234 Kryszta\179u oraz[ENTER]Czerwony Kwarc Piekie\179. Napisane by\179o, \191e[ENTER]Niebiesk\185 Esencj\234 Kryszta\179u mo\191na otrzyma\230 od[ENTER]w\179adcy Lodowej Ziemi. "
gameforge.main_quest_lv72._160_say = "W\179adcy Lodowej Ziemi? Hmm... To chodzi chyba o[ENTER]G\243r\234 Sohan. Natychmiast poka\191\234 Twoje notatki[ENTER]magom Wojownik\243w Mroku i przeanalizuje je z nimi.[ENTER]Dam ci natychmiast zna\230, gdy dowiem si\234 czego\156[ENTER]wi\234cej! "
gameforge.main_quest_lv72._170_say = "Zabierz to, prosz\234, w nagrod\234 za Twoje czyny.[ENTER]Nadal b\234d\234 liczy\179 na Twoj\185 pomoc! "
gameforge.main_quest_lv72._180_sendLetter = "Lodowy Skarb "
gameforge.main_quest_lv72._190_say = "Komendant Lee Chung kaza\179 ci przekaza\230, \191e je\156li[ENTER]chodzi o pierwszy sk\179adnik do \163zy Niebios,[ENTER]Niebiesk\185 Esencj\234 Kryszta\179u, to jest to[ENTER]legendarny skarb Dziewi\234ciu Ogon\243w na G\243rze[ENTER]Sohan. Strzeg\185 go Lodowe Golemy, Yeti oraz Mro\159ni[ENTER]Lodowi Ludzie. Musisz pokona\230 te potwory, aby[ENTER]zdoby\230 Niebiesk\185 Esencj\234 Kryszta\179u.[ENTER]Porozmawiaj jeszcze raz z Lee Chung, zanim[ENTER]rzucisz si\234 wir walki. "
gameforge.main_quest_lv72._200_say = "Magowie Wojownik\243w Cieni dowiedzieli si\234, \191e[ENTER]Niebieskiej Esencji Kryszta\179u z G\243ry Sohan[ENTER]strze\191e jak oka w g\179owie straszliwy potw\243r o[ENTER]imieniu Dziewi\234\230 Ogon\243w. "
gameforge.main_quest_lv72._20_say = "Lee Chung, komendant Wojownik\243w Cieni, chce z[ENTER]tob\185 porozmawia\230. Dowiedzia\179 si\234 on, jak mo\191na[ENTER]pokona\230 Agwi w Diabelskich Katakumbach. "
gameforge.main_quest_lv72._210_say = "Skarb Dziewi\234ciu Ogon\243w jest strze\191ony przez[ENTER]Lodowe Golemy, Yeti oraz Mro\159nych Lodowy Ludzi.[ENTER][ENTER]Do produkcji \163zy Niebios potrzeba 50 Niebieskich[ENTER]Esencji Kryszta\179u. "
gameforge.main_quest_lv72._220_say = "Przypuszczamy, \191e Czerwony Kwarc Piekie\179 mo\191na[ENTER]zdoby\230 albo w \140wi\185tyni Hwang albo w Ognistej[ENTER]Ziemi. Wys\179a\179em zwiadowc\234, kt\243ry ma si\234[ENTER]dowiedzie\230 czego\156 wi\234cej. "
gameforge.main_quest_lv72._230 = "Komendant Lee Chung kaza\179 ci przekaza\230, \191e je\156li[ENTER]chodzi o pierwszy sk\179adnik do \163zy Niebios,[ENTER]Niebiesk\185 Esencj\234 Kryszta\179u, to jest to[ENTER]legendarny skarb Dziewi\234ciu Ogon\243w na G\243rze[ENTER]Sohan. Strzeg\185 go Lodowe Golemy, Yeti oraz Mro\159ni[ENTER]Lodowi Ludzie. Musisz pokona\230 te potwory, aby[ENTER]zdoby\230 Niebiesk\185 Esencj\234 Kryszta\179u. "
gameforge.main_quest_lv72._240_notice = "Przeszukuj\185c zw\179oki zabitych potwor\243w natrafiasz[ENTER]na niebiesko-po\179yskuj\185cy kamie\241. To musi by\230[ENTER]Niebieska Esencja Kryszta\179u. "
gameforge.main_quest_lv72._250_notice = "Pozosta\179a ilo\156\230 Niebieskiej Esencji Kryszta\179u do[ENTER]odnalezienia: %d "
gameforge.main_quest_lv72._260_say = "Na dzisiaj otrzyma\179e\156 ju\191 wystarczaj\185co porad.[ENTER]Przyjd\159 jutro. "
gameforge.main_quest_lv72._270_say = "Te kryszta\179y s\185 do wyrzucenia. Popatrz sam: maj\185[ENTER]zadrapania. Ja potrzebuj\234 idealnych, bez \191adnej[ENTER]skazy. Szukaj dalej! "
gameforge.main_quest_lv72._280_say = "Te s\185 idealne, bez skazy. Znakomicie! Przynie\156 mi[ENTER]jeszcze %d szt. "
gameforge.main_quest_lv72._290_say = "Zebra\179e\156 wszystkie Niebieskie Esencje Kryszta\179u.[ENTER]Czuj\234 w nich moc Dziewi\234ciu Ogon\243w. To[ENTER]niesamowite... Pulsuj\185 przepe\179nione energi\185.[ENTER]Dobra robota! "
gameforge.main_quest_lv72._300_say = "Mo\191esz kontynuowa\230 przygod\234, gdy tylko osi\185gniesz[ENTER]poziom 78. "
gameforge.main_quest_lv72._30_say = "Agwi nie mo\191na tak po prostu zg\179adzi\230 jak[ENTER]zwyk\179ych demon\243w. My, Wojownicy Mroku,[ENTER]wypr\243bowali\156my ju\191 wszystkiego, ale bez[ENTER]powodzenia. "
gameforge.main_quest_lv72._40_say = "Teraz jednak dowiedzia\179em si\234, \191e Smocze Kap\179anki[ENTER]posiadaj\185 zdolno\156ci przywo\179ania \156wi\234tych si\179,[ENTER]kt\243re s\185 w stanie przep\234dzi\230 z\179e duchy. "
gameforge.main_quest_lv72._50_say = "W Czerwonym Lesie znajdowa\179a si\234 niegdy\156[ENTER]po\156wi\234cona \156wi\185tynia Smoczych Kap\179anek. Poszukaj[ENTER]tam ruin i dowod\243w \156wiadczonych o istnieniu ich[ENTER]kultury. Zwiadowcy donie\156li mi o Zwietrza\179ej[ENTER]P\179ycie, kt\243r\185 teraz porasta trawa... Mo\191e[ENTER]znajdziemy na niej dalsze wskaz\243wki. "
gameforge.main_quest_lv72._60_sendLetter = "Odkrycie "
gameforge.main_quest_lv72._70_say = "Od Lee Chung dowiedzia\179e\156 si\234, \191e Smocze Kap\179anki[ENTER]potrafi\185 przywo\179a\230 \156wi\234te si\179y, to pradawne[ENTER]zakl\234cie bia\179ej magii, kt\243ry odp\234dza z\179e duchy.[ENTER]Poszukaj w Czerwonym Lesie Zwietrza\179ej P\179yty, o[ENTER]kt\243rej opowiada\179 Lee Chung a otrzymasz dalsze[ENTER]wskaz\243wki. "
gameforge.main_quest_lv72._80_say = "Po d\179ugich poszukiwaniach dostrzegasz w trawie[ENTER]p\179yt\234. Wydaje si\234, \191e le\191y ona tutaj ju\191 od[ENTER]wiek\243w. To musi by\230 ta p\179yta, o kt\243rej m\243wi\179 Lee[ENTER]Chung! Z trudem odczytujesz zwietrza\179y napis. "
gameforge.main_quest_lv72._90_say = "\163za Niebios to najcenniejsza tajemnica Smoczych[ENTER]Kap\179anek. Sztuka jej robienia to dobrze strze\191ony[ENTER]sekret, przekazywany z generacji na generacj\234.[ENTER]Wiele razu ju\191 przelewano za ni\185 krew. Do[ENTER]w\179a\156ciciela tego magicznego kamienia nie mo\191e si\234[ENTER]zbli\191a\230 si\234 nawet Agwi lub demony. Je\156li \163za[ENTER]Niebios zostanie nape\179niona moc\185 \156wi\234tej si\179y, to[ENTER]jej dzia\179anie jest druzgocz\185ce. B\179yszczy tak[ENTER]jasno jak gwiazda polarna na firmamencie nieba[ENTER]przez siedem tarcz s\179onecznych. "
gameforge.main_quest_lv78 = {}
gameforge.main_quest_lv78._100_say = "Och, fantastycznie! Uda\179o si\234. Oto Czerwony Kwarc[ENTER]Piekie\179. "
gameforge.main_quest_lv78._10_sendLetter = "Czerwony Kwarc Piekie\179 "
gameforge.main_quest_lv78._110_sendLetter = "Ostatni Element "
gameforge.main_quest_lv78._120_say = "Lee Chung wraz z Rad\185 Mag\243w odkryli, \191e ostatni[ENTER]element, \140wi\234con\185 \175ywic\234, mo\191na uzyska\230 z[ENTER]Czerwonego Z\179ego Drzewa. Udaj si\234 na polowanie[ENTER]Czerwonych Z\179ych Drzew w Czerwonym Lesie i zbierz[ENTER]100 porcji \140wi\234conej \175ywicy. Wcze\156niej jednak[ENTER]porozmawiaj z Lee Chung. "
gameforge.main_quest_lv78._130_say = "Lee Chung wraz z Rad\185 Mag\243w odkryli, \191e ostatni[ENTER]element, \140wi\234con\185 \175ywic\234, mo\191na uzyska\230 z[ENTER]Czerwonego Z\179ego Drzewa. Udaj si\234 na polowanie[ENTER]Czerwonych Z\179ych Drzew w Czerwonym Lesie i zbierz[ENTER]100 porcji \140wi\234conej \175ywicy. "
gameforge.main_quest_lv78._140_say = "To ju\191 ostatni krok w produkcji \163zy Niebios.[ENTER]Uwa\191aj na siebie, w Czerwonym Lesie roi si\234 od[ENTER]zab\243jczych kreatur! "
gameforge.main_quest_lv78._150_say = "Pozosta\179a ilo\156\230 \140wi\234conej \175ywicy do zebrania: %d "
gameforge.main_quest_lv78._160_notice = "Znalaz\179e\156 wystarczaj\185c\185 ilo\156\230 \140wi\234conej \175ywicy![ENTER]Zanie\156 j\185 do komendanta Lee Chung. "
gameforge.main_quest_lv78._170_say = "Czy to jest \140wi\234cona \175ywica? Ju\191 wyczuwam jej[ENTER]nadzwyczajn\185 si\179\234. Niesamowite! Niestety musia\179em[ENTER]wys\179a\230 wszystkich mag\243w na misj\234. Nie b\234dzie ich[ENTER]przez jaki\156 czas. Czy przypadkiem nie ma w Twojej[ENTER]wiosce aptekarza o imieniu Baek-Go? "
gameforge.main_quest_lv78._180_say = "Tak, rzeczywi\156cie mamy. "
gameforge.main_quest_lv78._190_say = "Ach, to dobrze si\234 sk\179ada! We\159 ze sob\185 trzy[ENTER]elementy i zanie\156 je do Baek-Go. On na pewno[ENTER]b\234dzie potrafi\179 wyprodukowa\230 z tego \163z\234 Niebios. "
gameforge.main_quest_lv78._200_say = "Masz za sob\185 m\234cz\185c\185 podr\243\191. Prosz\234, we\159 t\234[ENTER]nagrod\234 za sw\243j trud i po\156wi\234cenie. "
gameforge.main_quest_lv78._20_say = "Lee Chung, komendant Wojownik\243w Cieni, dowiedzia\179[ENTER]si\234 czego\156 wi\234cej o Czerwonym Kwarcu Piekie\179. Aby[ENTER]go wyprodukowa\230 potrzeba trzech r\243\191nych[ENTER]substancji: Ziemi\234 Wulkaniczn\185 Doyyumhwan,[ENTER]P\179on\185c\185 Grzyw\234 oraz Kamie\241 W\234gielny. Poluj na[ENTER]P\179omienie, Ognistych Wojownik\243w oraz Walcz\185ce[ENTER]Tygrysy w Ognistej Ziemi, aby zdoby\230 substancje.[ENTER]Nast\234pnie daj do uformowania 20 szt. Czerwonego[ENTER]Kwarcu Piekie\179. Zanim jednak wyruszysz do walki,[ENTER]odszukaj Lee Chung. "
gameforge.main_quest_lv78._210_sendLetter = "\163za Niebios "
gameforge.main_quest_lv78._220_say = "Wr\243\230 do rodzinnej wioski, odszukaj Baek-Go i[ENTER]popro\156 go w imieniu Lee Chung o wykonanie \163zy[ENTER]Niebios. "
gameforge.main_quest_lv78._230_say = "D\179ugo ciebie nie by\179o. Zastanawia\179em si\234 ju\191, czy[ENTER]co\156 ci si\234 nie sta\179o. Co sprowadza ci\234 do mnie? "
gameforge.main_quest_lv78._240_say = "Lee Chung zleci\179 mi, abym poprosi\179 ci\234 o[ENTER]przys\179ug\234. "
gameforge.main_quest_lv78._250_say = "Lee Chung?! Komendant Wojowni... och, psss![ENTER]Cicho! Przed Tob\185 stoi mag Wojownik\243w Cieni. Jego[ENTER]misja jest \156ci\156le tajna i nikt nie mo\191e si\234 o[ENTER]niej dowiedzie\230. A, o jak\185 przys\179ug\234 chce[ENTER]poprosi\230 mnie Lee Chung? "
gameforge.main_quest_lv78._260_say = "Chce, aby\156 z tych trzech element\243w zrobi\179 \163z\234[ENTER]Niebios. "
gameforge.main_quest_lv78._270_say = "\163z\234 Niebios, nooo... Ale przecie\191 ma tyle mag\243w[ENTER]wok\243\179 siebie. Dlaczego zostawia mi do wykonania[ENTER]jedno z najtrudniejszych zada\241?[ENTER]...[ENTER]No, gotowe. Mamy \163z\234 Niebios. Cudowna! Wy\156l\234 j\185[ENTER]zaufanym pos\179a\241cem bezpo\156rednio do Lee Chung i on[ENTER]ju\191 poprosi ci\234, aby\156 przyszed\179, gdy wszystko[ENTER]b\234dzie gotowe. Zdradzisz mi, do czego ona s\179u\191y? "
gameforge.main_quest_lv78._280_say = "Nie mog\234 ci nic wi\234cej powiedzie\230. Tylko tyle, \191e[ENTER]kamie\241 ten ma moc przywo\179ywania \156wi\234tej si\179y,[ENTER]kt\243ra przep\234dza wszelkie demony i inne z\179e[ENTER]istoty. "
gameforge.main_quest_lv78._290_say = "Interesuj\185ce. \175ycz\234 ci powodzenia podczas twojej[ENTER]misji. W nagrod\234 za twoje czyny otrzymasz dwie[ENTER]Zasuszone G\179owy. A teraz kiedy ju\191 wiem, jak to[ENTER]wszystko dzia\179a, ch\234tnie ci pomog\234, gdy b\234dziesz[ENTER]potrzebowa\179 kolejnej \163zy Niebios. Ach, przeka\191esz[ENTER]ode mnie serdeczne pozdrowienia Lee Chung? "
gameforge.main_quest_lv78._300_say = "Mo\191esz kontynuowa\230 przygod\234, gdy tylko osi\185gniesz[ENTER]poziom 84. "
gameforge.main_quest_lv78._30_say = "Nasi magowie wykryli, \191e Czerwony Kwarc Piekie\179,[ENTER]u\191ywany do produkcji \163zy Niebios, zawiera w sobie[ENTER]si\179\234 ognia. W\179a\156nie dzi\234ki temu kwarcowi[ENTER]posiadaj\185 kreatury Ognistej Ziemi nadzwyczajn\185[ENTER]si\179\234. "
gameforge.main_quest_lv78._40_say = "Czerwony Kwarc Piekie\179 jest produkowany z trzech[ENTER]substancji: Ziemi Wulkanicznej, P\179on\185cej Grzywy[ENTER]oraz Kamienia W\234gielnego. Wszystkie substancje[ENTER]znajdziesz w Ognistej Ziemi. "
gameforge.main_quest_lv78._50_say = "Dokona\179e\156 tego! Nareszcie posiadamy potrzebne %d[ENTER]szt. Czerwonego Kwarcu Piekie\179. Za ka\191dym razem[ENTER]od nowa podziwiam twoj\185 odwag\234 i ducha walki! "
gameforge.main_quest_lv78._60_say = "Brakuje jeszcze jednej substancji. Potrzebujemy[ENTER]Ziemi Wulkanicznej, P\179on\185cej Grzywy oraz Kamienia[ENTER]W\234gielnego. "
gameforge.main_quest_lv78._70_say = "Przykro mi, ale w jednym dniu mog\234 wyprodukowa\230[ENTER]tylko siedem sztuk Czerwonego Kwarcu Piekie\179. Ta[ENTER]produkcja to wyzwanie dla moich magicznych[ENTER]zdolno\156ci. W ko\241cu nie jestem magiem! "
gameforge.main_quest_lv78._80_say = "Do dzie\179a! Wymieszam teraz te trzy substancje ze[ENTER]sob\185 i spr\243buj\234 wyprodukowa\230 Czerwony Kwarc[ENTER]Piekie\179. "
gameforge.main_quest_lv78._90_say = "Grrrrr! Czar si\234 nie powi\243d\179. Widocznie[ENTER]przeceni\179em moje magiczne zdolno\156ci. Nast\234pnym[ENTER]razem na pewno si\234 powiedzie. "
gameforge.main_quest_lv84 = {}
gameforge.main_quest_lv84._100_say = "Gdy pokonasz genera\179a Tartar, otworz\185 si\234 wrota[ENTER]do ukrytego poziomu w Diabelskich Katakumbach.[ENTER]Tam znajdziesz ksi\234cia Charon! Teleportuj si\234 do[ENTER]sz\243stego poziomu i sta\241 do walki z ksi\234ciem Agwi.[ENTER]Pami\234taj jednak, \191e jest on nadzwyczajnie silny a[ENTER]w dodatku cwany jak diabe\179. "
gameforge.main_quest_lv84._10_sendLetter = "Rozpoczyna si\234 walka "
gameforge.main_quest_lv84._110_say = "Niesamowite, poruszasz si\234 po Diabelskich[ENTER]Katakumbach swobodnie i bez cienia strachu - ty[ENTER]na pewno nie jeste\156 zwyk\179ym \156miertelnikiem![ENTER]Bazaltowy Obelisk, kt\243ry znajduje si\234 na pi\185tym[ENTER]poziomie pos\179u\191y ci jako portal do ukrytego[ENTER]sz\243stego poziomu. "
gameforge.main_quest_lv84._120_say = "Stamt\185d w\179a\156nie ksi\185\191\234 Charon wydaje wszystkie[ENTER]swoje rozkazy genera\179owi Agwi o imieniu Tartar.[ENTER]Na co jeszcze czekasz? Zg\179ad\159 ksi\234cia Charon i[ENTER]udaremnij mroczne plany Wasali Mroku oraz[ENTER]Banshee! "
gameforge.main_quest_lv84._130_sayReward = "Znakomicie si\234 spisa\179e\156! Pokona\179e\156 Charon,[ENTER]ksi\234cia Agwi. "
gameforge.main_quest_lv84._140_say = "Do cna zm\234czony, ale odczuwaj\185c ulg\234, ocierasz[ENTER]pot z czo\179a. Nagle rozbrzmiewa dono\156ny i[ENTER]przera\159liwy chichot dochodz\185cy z Diabelskich[ENTER]Katakumb, a\191 przechodz\185 ci\234 ciarki:[ENTER]Hahaha! Za p\243\159no, wy n\234dzne ludzkie kreatury![ENTER]Nasz mistrz, Sung Mahi, ju\191 zmartwychwsta\179 i wy[ENTER]nic na to nie mo\191ecie poradzi\230! Ju\191 go nie[ENTER]powstrzymacie.[ENTER]Zbli\191a si\234 dzie\241, kiedy to Sung Mahi przejmie[ENTER]ca\179kowit\185 w\179adz\234 na wyspie, gdzie \156pi\185 z\179e smoki.[ENTER]Wasz \156wiat jest skazany na zag\179ad\234! "
gameforge.main_quest_lv84._150_sendLetter = "Niedoko\241czona Historia "
gameforge.main_quest_lv84._160_say = "Id\159 do Lee Chung i opowiedz mu o niebezpiecznym[ENTER]przes\179aniu Banshee. "
gameforge.main_quest_lv84._170_say = "Po zdaniu raportu komendantowi o swoich[ENTER]chwalebnych zwyci\234stwach nad Tartar oraz Charon,[ENTER]przekazujesz mu te\191 przygn\234biaj\185c\185 wiadomo\156\230 od[ENTER]Banshee. Z powag\185 w g\179osie zaczyna on do ciebie[ENTER]przemawia\230: "
gameforge.main_quest_lv84._180_say = "My\156la\179em, \191e je\156li obalimy ksi\234cia Agwi, to tym[ENTER]samym udaremnimy mroczne plany Wasali Mroku oraz[ENTER]Banshee. Przeliczy\179em si\234... "
gameforge.main_quest_lv84._190_say = "Banshee musia\179a razem z Azrael, mrocznym kr\243lem[ENTER]Agwi, dokona\230 ju\191 rytua\179u zmartwychwstania[ENTER]Demonicznego Boga, Sung Mahi. Dr\191\234 na sam\185 my\156l o[ENTER]tym... "
gameforge.main_quest_lv84._200_say = "Wyspa, na kt\243rej \156pi\185 z\179e smoki... Hm, chyba mia\179[ENTER]na my\156li Ska\179\234 Mrocznego Smoka, niezbadan\185 wysp\234,[ENTER]le\191\185c\185 daleko st\185d. Nie martw si\234, nawet je\156li[ENTER]nie osi\185gn\234li\156my tego, co zamierzali\156my, jeste\156my[ENTER]ci bardzo wdzi\234czni. Bez ciebie nigdy nie[ENTER]odkryliby\156my przyczyny tego ca\179ego Z\179a, kt\243re[ENTER]czai\179o si\234 w Diabelskich Katakumbach. "
gameforge.main_quest_lv84._20_say = "Lee Chung otrzyma\179 \163z\234 Niebios i wszystko ju\191[ENTER]przygotowa\179 do twojej misji w Diabelskich[ENTER]Katakumbach. Udaj si\234 do niego, aby si\234 wi\234cej[ENTER]dowiedzie\230. "
gameforge.main_quest_lv84._210_say = "Dokona\179e\156 chwalebnych czyn\243w! Wierz mi, nikt nie[ENTER]by\179yby w stanie zrobi\230 tego, co ty osi\185gn\185\179e\156[ENTER]swoj\185 odwag\185 i po\156wi\234ceniem. Przyrzekam, \191e[ENTER]zawsze b\234d\234 ci\234 wspiera\179 w potrzebie. \175egnaj! "
gameforge.main_quest_lv84._30_say = "Teraz, gdy mamy w naszych r\234kach ju\191 \163z\234 Niebios,[ENTER]to tylko kwestia czasu, aby w ko\241cu pokona\230[ENTER]Wasali Mroku i przep\234dzi\230 raz na zawsze Agwi z[ENTER]naszego \156wiata! Jednak jej ca\179a moc dzia\179a[ENTER]dopiero wtedy, gdy zostanie ona umieszczona w[ENTER]szczeg\243lnym miejscu w Diabelskich Katakumbach. "
gameforge.main_quest_lv84._40_say = "Wiemy o ju\191 o pi\234ciu poziomach w Diabelskich[ENTER]Katakumbach. Na pi\185tym i ostatnim nam znanym[ENTER]poziomie spotkasz Tartar, to okrutny genera\179[ENTER]Agwi, kt\243ry jest trzeci w hierarchii po kr\243lu[ENTER]Azrael, oraz ksi\234ciu o imieniu Charon. Zniszcz[ENTER]go, u\191ywaj\185c do tego \163zy Niebios! "
gameforge.main_quest_lv84._50_say = "Gdzie ukrywa si\234 ksi\185\191\234 Charon? "
gameforge.main_quest_lv84._60_sendLetter = "Genera\179 Tartar "
gameforge.main_quest_lv84._70_say = "U\191yj \163zy Niebios dopiero po przej\156ciu na pi\185ty[ENTER]poziom w Diabelskich Katakumbach. Wej\156cie do[ENTER]Diabelskich Katakumb znajduje si\234 z ty\179u za Wie\191\185[ENTER]Demon\243w. "
gameforge.main_quest_lv84._80_say = "\140wi\234te si\179y zaczynaj\185 dzia\179a\230 w \163zie Niebios.[ENTER]Czujesz powoli jak przez Twoje cia\179o przep\179ywa[ENTER]niesamowita energia. Si\179a tego kamienia jest[ENTER]nadzwyczajna![ENTER][ENTER]Zg\179ad\159 genera\179a Tartar. "
gameforge.main_quest_lv84._90_sendLetter = "Ksi\185\191\234 Charon "
gameforge.main_quest_lv9 = {}
gameforge.main_quest_lv9._10_targetVid = "Znajd\159 Stra\191nika Miejskiego "
gameforge.main_quest_lv9._20_sendLetter = "Porozmawiaj ze Stra\191nikiem Miejskim "
gameforge.main_quest_lv9._30_sayReward = "Pierwsze kroki w drodze do prawdziwego[ENTER]bohaterstwa ju\191 masz za sob\185. Nadszed\179 teraz czas[ENTER]na \156wietniejsze czyny. Udaj si\234 do Stra\191nika[ENTER]Miejskiego i odbierz swoje ostatnie zadanie dla[ENTER]pocz\185tkuj\185cych. "
gameforge.main_quest_lv9._40_say = "My\156l\234, \191e jeste\156 ju\191 gotowy na trudniejsze[ENTER]zadania. Nie b\234dzie tak \179atwo jak do tej pory.[ENTER]B\234dziesz musia\179 pracowa\230 znacznie ci\234\191ej dla[ENTER]swojego Kr\243lestwa. We\159miesz udzia\179 w wielu[ENTER]walkach i pokonasz wielu przeciwnik\243w. Czasami[ENTER]zadanie mo\191e wydawa\230 si\234 za trudne, jednak nigdy[ENTER]si\234 nie poddawaj! Do tej pory wykona\179e\156 zaledwie[ENTER]kilka misji, jednak doceniam tw\243j wysi\179ek. Oto[ENTER]twoja nagroda. Mam nadziej\234, \191e Ci si\234 przyda. "
gameforge.main_quest_lv9._50_say = "Od teraz Kapitan b\234dzie sta\179 po Twojej stronie.[ENTER]B\234dzie Ci\234 nadzorowa\179 w przysz\179o\156ci i przydziela\179[ENTER]nowe zadania.[ENTER]Zdob\185d\159 troch\234 wi\234cej Punkt\243w Do\156wiadczenia i[ENTER]udaj si\234 do Kapitana.[ENTER]Powodzenia! "
gameforge.main_quest_lv90 = {}
gameforge.main_quest_lv90._010_sendLetter = "Ska\179a Mrocznego Smoka "
gameforge.main_quest_lv90._020_say = "Wprawdzie podr\243\191 by\179a d\179uga i uci\185\191liwa, ale w[ENTER]ko\241cu dotar\179e\156 do celu: Ska\179y Mrocznego Smoka.[ENTER]Odszukaj Admira\179a Angmura. Znajdziesz go na[ENTER]Przyl\185dku Smoczego Ognia. "
gameforge.main_quest_lv90._030_say = "Witaj przybyszu w Skale Mrocznego Smoka![ENTER]Przyby\179e\156, aby nas wesprze\230 w walce z Sung Mahi? "
gameforge.main_quest_lv90._040_say = "Tak jest. Przysy\179a mnie Lee Chung, komendant[ENTER]Wojownik\243w Cieni. "
gameforge.main_quest_lv90._050_say = "Lee Chung! Znam go dosy\230 dobrze, to m\243j drogi[ENTER]towarzysz broni. A wi\234c przybywasz tutaj z jego[ENTER]rozkazu? Ach, to teraz wiem, \191e mog\234 ci zaufa\230. "
gameforge.main_quest_lv90._060_say = "Dzi\234kuj\234. A jak wygl\185da tutaj sytuacja? "
gameforge.main_quest_lv90._070_say = "Demony opanowa\179y kolejne cz\234\156ci wyspy. Nikt i nic[ENTER]nie jest tutaj ju\191 bezpieczny. Dochodzi nawet do[ENTER]tego, \191e po\191eraj\185 si\234 nawzajem. Mroczny wp\179yw[ENTER]Sung Mahi pozbawia wszystkich rozumu. "
gameforge.main_quest_lv90._080_say = "Prawd\234 m\243wi\185c, przyda\179aby mi si\234 twoja pomoc. Czy[ENTER]m\243g\179by\156 zbada\230 wysp\234 i przynie\156 mi raport o[ENTER]aktualnej sytuacji na wyspie? "
gameforge.main_quest_lv90._090_say = "Oczywi\156cie. "
gameforge.main_quest_lv90._1000_say = "Zgoda. "
gameforge.main_quest_lv90._100_say = "Dzi\234kuj\234 ci. Poczekaj, poka\191\234 ci drog\234. "
gameforge.main_quest_lv90._1010_say = "Wprawdzie rzetelnie wype\179niasz swoje obowi\185zki,[ENTER]ale to jeszcze nie wystarczy. Zbieraj dalej! "
gameforge.main_quest_lv90._1020_sayTitle = "Zbieraj ceg\179y "
gameforge.main_quest_lv90._1030_say = "Aby zdoby\230 ceg\179y, musisz stan\185\230 do walki przeciw[ENTER]Mantykorom. "
gameforge.main_quest_lv90._1040_1_notice = "Uda\179o ci si\234 zebra\230 wystarczaj\185c\185 ilo\156\230 cegie\179. "
gameforge.main_quest_lv90._1040_2_notice = "Dostarcz je Admira\179owi Angmurowi. "
gameforge.main_quest_lv90._1050_say = "Porozmawiaj z Admira\179em Angmurem. "
gameforge.main_quest_lv90._1060_say = "Znakomicie! Dzi\234ki tobie mamy wystarczaj\185c\185 ilo\156\230[ENTER]materia\179u, aby wzmocni\230 wa\179 ochronny. Gdy tylko[ENTER]zako\241czymy prace, po\156l\234 po ciebie. "
gameforge.main_quest_lv90._1070_sendLetter = "Zadanie od Lee Chunga "
gameforge.main_quest_lv90._1080_say = "Lee Chung ma dla ciebie zadanie. "
gameforge.main_quest_lv90._1090_say = "Niestety, znowu spotykamy si\234 w niezbyt[ENTER]przyjemnych okoliczno\156ciach. Wasale Mroku s\185 o[ENTER]krok od ich celu. Wkr\243tce Sung Mahi b\234dzie[ENTER]niezwyci\234\191ony.[ENTER]Nie mamy czasu do stracenia! Id\159 do teleportera.[ENTER]Stamt\185d odbierze ci\234 statek i zawiezie do Ska\179y[ENTER]Mrocznego Smoka. Odszukaj tam Admira\179a Angmura.[ENTER]Wys\179a\179em list do niego, kt\243ry zapowiada twoje[ENTER]przybycie. "
