gameforge.main_quest_lv90._270_say = "Podczas gdy opowiadasz, co widzia\179e\156 i prze\191y\179e\156[ENTER]w Skale Mrocznego Smoka, twarz admira\179a robi si\234[ENTER]coraz bardziej smutna. "
