gameforge.main_quest_lv90._290_say = "Demony na wyspie rosn\185 w si\179\234.[ENTER]Je\156li nie zdo\179amy powstrzyma\230 Sung Mahi i Wasali[ENTER]Mroku... to niech B\243g Smok\243w ma nas w swojej[ENTER]opiece. "
gameforge.main_quest_lv90._300_say = "Zgadzam si\234, to nie wygl\185da zbyt dobrze. "
gameforge.main_quest_lv90._310_say = "O tak, ca\179kowicie si\234 zgadzam...[ENTER]Lee Chung musia\179 odkry\230 co\156 bardzo niepokoj\185cego.[ENTER]Wys\179a\179 mi list z wa\191nymi informacjami. Niestety,[ENTER]nie otrzyma\179em go... gnolle napad\179y na pos\179a\241ca z[ENTER]listem. "
