gameforge.main_quest_lv90._390_say = "Porozmawiaj z Admira\179em Angmurem. "
gameforge.main_quest_lv90._400_say = "Jeste\156 ju\191 z powrotem. Masz list? Ej, wiedzia\179em,[ENTER]\191e mog\185 na ciebie liczy\230. Poka\191 go. "
gameforge.main_quest_lv90._410_say = "Witaj Angmur, m\243j drogi przyjacielu, chcia\179em ci[ENTER]donie\156\230, \191e w opuszczonych obozach Sung Mahis[ENTER]natrafili\156my na wa\191ne informacje dotycz\185ce[ENTER]demon\243w. Wasale Mroku wys\179ali swoim[ENTER]sprzymierze\241com na wyspie tajemn\185 wiadomo\156\230.[ENTER]Jeden list by\179 skierowany do plemienia Gnolli.[ENTER]Je\156li zdo\179aliby\156cie go przej\185\230, poznamy zamiary[ENTER]demon\243w i b\234dziemy im o krok do przodu![ENTER]Wysy\179am Wam do pomocy %s. \175ycz\234 Wam odwagi i si\179y[ENTER]w tych mrocznych czasach. L.C. "
