gameforge.main_quest_lv90._650_say = "Znakomicie, teraz mo\191emy w ko\241cu odszyfrowa\230[ENTER]wiadomo\156\230: Hm, w li\156cie jest mowa o smokach,[ENTER]kt\243re \156pi\185 w sercu \156wiata.... o metodzie ich[ENTER]przebudzenia i w jaki spos\243b mo\191na je[ENTER]rozw\156cieczy.[ENTER]Ojej, nie dobrze... "
