gameforge.main_quest_lv91._490_say = "Zmierz si\234 z Genera\179em Lobsterem oraz Kr\243lem[ENTER]Krabbsem z plemienia Skorupiak\243w i zdob\185d\159 trzy[ENTER]dawki Proszku Karapaks. "
