gameforge.main_quest_lv91._590_say = "Po prostu \156pieszy\179 si\234 i by\179 nieostro\191ny. A do[ENTER]tego na nasze nieszcz\234\156cie sko\241czy\179y si\234 zapasy[ENTER]zi\243\179 leczniczych. Poszukaj Skalnych Kwiat\243w - ich[ENTER]korzonki mog\234 znaturalizowa\230 trucizn\234. Popatrz,[ENTER]na tej mapie zaznaczy\179em, gdzie one rosn\185. "
gameforge.main_quest_lv91._600_say = "Oczywi\156cie. "
gameforge.main_quest_lv91._610_say = "Wiedzia\179em, \191e na ciebie mo\191na liczy\230. Prosz\234,[ENTER]po\156piesz si\234, nie pozosta\179o nam zbyt wiele czasu. "
