gameforge.main_quest_lv91._630_say = "Odnajd\159 Korzonek Skalnego Kwiatu, aby uzdrowi\230[ENTER]zatrutego Yon-I-Walker! "
gameforge.main_quest_lv91._640_1_notice = "Zanie\156 do Yon-I-Walker Korzonek Skalnego Kwiatu. "
