gameforge.main_quest_lv92._020_say = "Ostatni list Wasali Mroku znajduje si\234 u Bandy[ENTER]Czerwonych. Admira\179 Angmur ma wi\234cej informacji[ENTER]dla ciebie. "
gameforge.main_quest_lv92._030_say = "Zbli\191amy si\234 do rozwik\179ania zagadki spisku Wasali[ENTER]Mroku. Ostatni list znajduje si\234 w r\234kach Bandy[ENTER]Czerwonych. "
