gameforge.main_quest_lv92._050_say = "To grupa przest\234pc\243w wygnana do Ska\179y Mrocznego[ENTER]Smoka. Ale najbardziej dziwne w tej bandzie jest[ENTER]to, \191e zjednoczyli si\234 z demonami. "
gameforge.main_quest_lv92._060_say = "Demony, kt\243re jednocz\185 si\234 z lud\159mi, zamiast ich[ENTER]po\191re\230? Faktycznie, to bardzo dziwne. "
