gameforge.main_quest_lv92._160_say = "Wspaniale. We\159 to jako dow\243d mojej wdzi\234czno\156ci. "
gameforge.main_quest_lv92._170_sendLetter = "List do Bandy Czerwonych "
gameforge.main_quest_lv92._180_say = "Admira\179 Angmur potrzebuje twojej pomocy. "
gameforge.main_quest_lv92._190_say = "Dobrze, \191e jeste\156. Mamy problem. "
gameforge.main_quest_lv92._200_say = "O co chodzi? "
gameforge.main_quest_lv92._210_say = "Istnieje jeszcze pi\185ta cz\234\156\230 Listu do Bandy[ENTER]Czerwonych. Bez niej pozosta\179e cz\234\156ci s\185[ENTER]bezu\191yteczne. Wys\179a\179em ju\191 Bae-Yong, mojego[ENTER]najdzielniejszego wojownika - ale musia\179o mu si\234[ENTER]co\156 przydarzy\230. Powinien przecie\191 ju\191 dawno[ENTER]wr\243ci\230. Odszukaj go, dobrze? "
gameforge.main_quest_lv92._220_say = "Odszukam go. A wiesz przypadkiem, gdzie on teraz[ENTER]mo\191e by\230? "
gameforge.main_quest_lv92._230_say = "Wydaje mi si\234, \191e mia\179 zamiar p\243j\156\230 do Nefrytowej[ENTER]Zatoki. Ale czy tam dotar\179, tego nie wiem. "
gameforge.main_quest_lv92._240_say = "W takim razie do dzie\179a! "
gameforge.main_quest_lv92._250_sayTitle = "Zaginiony \191o\179nierz "
gameforge.main_quest_lv92._260_say = "Odnajd\159 pi\185t\185 cz\234\156\230 listu. Najpierw jednak musisz[ENTER]odszuka\230 Bae-Yong w Nefrytowej Zatoce. "
gameforge.main_quest_lv92._270_say = "Jeszcze nie uda\179o ci si\234 odszuka\230 Bae-Yong? To[ENTER]sprawa \191ycia i \156mierci! Prosz\234, nie rezygnuj,[ENTER]szukaj dalej. "
gameforge.main_quest_lv92._280_say = "*ci\234\191ko dyszy*[ENTER]Dzi\234kuj\185, \191e mnie odnalaz\179e\156. Zosta\179em ci\234\191ko[ENTER]zraniony i obawiam si\234, \191e nie pozosta\179o mi zbyt[ENTER]wiele czasu...[ENTER]Ten skrawek papieru wydar\179em z r\185k jednego z[ENTER]Bandy Czerwonych.[ENTER]Zanie\156 go do Admira\179a Angmura. Jazda! Po\156piesz[ENTER]si\234! Ja sobie poradz\234...[ENTER](Umiera na twoich r\234kach). "
gameforge.main_quest_lv92._290_1_notice = "Zanim jednak Bae-Yong wyzion\185\179 ducha, przekaza\179[ENTER]ci brakuj\185c\185 cz\234\156\230 listu. "
gameforge.main_quest_lv92._290_2_notice = "A teraz wr\243\230 do Admira\179a Angmura. "
gameforge.main_quest_lv92._300_say = "Jeste\156 ju\191! Uda\179o ci si\234 odnale\159\230 Bae-Yong? "
gameforge.main_quest_lv92._310_say = "Tak, ale... "
gameforge.main_quest_lv92._320_say = "Ale?[ENTER]O nie! Nie \191yje? "
gameforge.main_quest_lv92._330_say = "Nic nie mo\191na by\179o ju\191 dla niego zrobi\230. Przyjmij[ENTER]moje wyrazy wsp\243\179czucia. By\179 on odwa\191nym[ENTER]wojownikiem - odda\179 swoje \191ycie za ostatni\185 cz\234\156\230[ENTER]listu. Oto ona. "
gameforge.main_quest_lv92._340_say = "Wszyscy bardzo cierpimy z powodu straty Bae-Yong.[ENTER]Jednak jeste\156my dumni z niego. Wykona\179 swoj\185[ENTER]misj\234 do ko\241ca - mamy teraz wszystkie cz\234\156ci[ENTER]listu. "
gameforge.main_quest_lv92._350_say = "Dzi\234kuj\234 ci za wszystko. Prosz\234, oto twoja[ENTER]nagroda.[ENTER]Teraz zapal\234 \156wieczk\234 za Bae-Yong.[ENTER]P\243\159niej zg\179osz\234 si\234 do ciebie. "
gameforge.main_quest_lv92._360_say = "Udaj si\234 do Admira\179a Angmura. "
gameforge.main_quest_lv92._370_sendLetter = "Odszyfruj List do Bandy Czerwonych "
gameforge.main_quest_lv92._380_say = "Admira\179 Angmur ma wa\191ne informacje dotycz\185ce[ENTER]Listu do Bandy Czerwonych.[ENTER]Pos\179uchaj, co ma on do powiedzenia. "
gameforge.main_quest_lv92._390_say = "Ach, jeste\156. Wasale Mroku przyprawiaj\185 mnie o b\243l[ENTER]g\179owy. List jest zaszyfrowany. Zanie\156 go do[ENTER]Yon-I-Walker. "
gameforge.main_quest_lv92._400_say = "W porz\185dku. "
gameforge.main_quest_lv92._410_say = "Zanie\156 zaszyfrowany list do Yon-I-Walker. "
gameforge.main_quest_lv92._420_say = "Ej, musisz si\234 zawsze tak skrada\230?[ENTER]W czym mog\234 ci s\179u\191y\230? "
gameforge.main_quest_lv92._430_say = "Mam List do Bandy Czerwonych. Niestety, tak jak[ENTER]inne jest on zaszyfrowany. "
gameforge.main_quest_lv92._440_say = "Niech spojrz\234 na niego. Hm, wydaje mi si\234, \191e to[ENTER]s\185 litery j\234zyka Tryton\243w. \163atwo je odszyfrowa\230. "
gameforge.main_quest_lv92._450_say = "Wspaniale. Ile ci zejdzie? "
gameforge.main_quest_lv92._460_say = "Nie tak szybko. Wprawdzie szyfr nie jest[ENTER]szczeg\243lnie skomplikowany, ale do tego potrzebuj\234[ENTER]jednak \156rodk\243w pomocniczych. "
gameforge.main_quest_lv92._470_say = "Oczywi\156cie. To by\179oby zbyt proste. "
gameforge.main_quest_lv92._480_say = "Jak widz\234, nie straci\179e\156 swojego poczucia humoru,[ENTER]hihi.[ENTER]Aby odszyfrowa\230 list, potrzebuj\234 \163usek Oin.[ENTER]Niestety, te rzadkie \179uski maj\185 na sobie tylko[ENTER]Genera\179 Kappa i sam Tryton, kr\243l plemienia[ENTER]Tryton\243w.[ENTER]Przynie\156 10 sztuk. "
gameforge.main_quest_lv92._490_say = "Natychmiast wyruszam. "
gameforge.main_quest_lv92._500_sayTitle = "Znajd\159 \163uski Oin! "
gameforge.main_quest_lv92._510_say = "\163usk\185 pokryci s\185 tylko Tryton, kr\243l plemienia[ENTER]Tryton\243w oraz Genera\179 Kappa. "
gameforge.main_quest_lv92._520_say = "Nie odszyfruj\234 listu bez \179usek. Musz\234 je mie\230. "
gameforge.main_quest_lv92._530_1_notice = "Uda\179o ci si\234 znale\159\230 tryto\241skie \179uski Oin. "
gameforge.main_quest_lv92._530_2_notice = "Zanie\156 je szybko do Yon-I-Walker. "
gameforge.main_quest_lv92._540_say = "Wykona\179e\156 dobr\185 robot\234. Gdy tylko odszyfruj\234[ENTER]list, poinformuj\234 o tym Admira\179a Angmura.[ENTER]Wypocznij tymczasem. Prosz\234, we\159 to jako dow\243d[ENTER]mojej wdzi\234czno\156ci. "
gameforge.main_quest_lv92._550_say = "Yon-I-Walker chce z tob\185 porozmawia\230. "
gameforge.main_quest_lv92._560_sendLetter = "Mroczne plany "
gameforge.main_quest_lv92._570_say = "List Wasali Mroku zosta\179 odszyfrowany. Admira\179[ENTER]Angmur wtajemniczy ci\234 w ich mroczne plany. "
gameforge.main_quest_lv92._580_say = "Uda\179o nam si\234 ca\179kowicie odszyfrowa\230 tajemn\185[ENTER]wiadomo\156\230. Przypominasz sobie List do Gnolli. W[ENTER]nim by\179a mowa o smokach, kt\243re \156pi\185 g\179\234boko sercu[ENTER]wyspy oraz w jaki spos\243b mo\191na je przebudzi\230 i je[ENTER]rozw\156cieczy\230. Teraz dowiadujemy si\234, jak chc\185 to[ENTER]wykorzysta\230 Wasale Mroku. "
gameforge.main_quest_lv92._590_say = "Trzeba zabi\230 smoka wtedy, gdy jego umys\179 jest[ENTER]czarny jak piekielna otch\179a\241, a wypluje Per\179y[ENTER]Nocy. Za pomoc\185 tych pere\179 zostan\185 przywo\179ane do[ENTER]naszego \156wiata niewyobra\191alne moce Sung Mahi.[ENTER]A wi\234c to jest ich mroczny plan! "
gameforge.main_quest_lv92._600_say = "Musimy dok\179adnie przemy\156le\230 nast\234pny krok. Je\156li[ENTER]b\234d\234 mia\179 dla ciebie nowe informacje, przywo\179am[ENTER]ci\234. Dzi\234kuj\234 ci za wszystko. "
gameforge.main_quest_lv92._610_say = "Mo\191esz kontynuowa\230 przygod\234, gdy tylko osi\185gniesz[ENTER]poziom 93. "
gameforge.main_quest_lv93 = {}
gameforge.main_quest_lv93._010_sendLetter = "Wzmocnij si\179y I "
gameforge.main_quest_lv93._020_say = "Admira\179 Angmur chce z tob\185 porozmawia\230. "
gameforge.main_quest_lv93._030_say = "Depczemy ju\191 po pi\234tach Wasalom Mroku. "
gameforge.main_quest_lv93._040_say = "Aby ich pokona\230, musimy wzmocni\230 twoje si\179y.[ENTER]Wiesz co to jest Wewn\234trzne \140wiat\179o? To[ENTER]skoncentrowana energia. Maj\185 j\185 w sobie niekt\243re[ENTER]mistyczne stworzenia lub ro\156liny. Yon-I-Walker[ENTER]mo\191e z niej przyrz\185dzi\230 \156rodek wzmacniaj\185cy. Id\159[ENTER]do niego. "
gameforge.main_quest_lv93._050_say = "Zgoda. "
gameforge.main_quest_lv93._060_say = "Ach, to jest m\243j wybawiciel![ENTER]Wewn\234trzne \140wiat\179o, och tak... Dzi\234ki mojemu[ENTER]\156rodkowi wzmacniaj\185cemu dor\243wnasz si\179\185 Wasalom[ENTER]Mroku. "
gameforge.main_quest_lv93._070_say = "Potrzebuj\234 do tego Wewn\234trzne \140wiat\179o Cyklop\243w[ENTER]oraz Gigant\243w. Ale pami\234taj, nosz\185 je w sobie[ENTER]tylko sami przyw\243dcy tych plemion. Zajmij si\234[ENTER]najpierw Cyklopami. "
gameforge.main_quest_lv93._080_say = "Zgoda. "
gameforge.main_quest_lv93._090_sayTitle = "Wewn\234trzne \140wiat\179o I "
gameforge.main_quest_lv93._100_say = "Pokonaj Polifema, Kr\243la Cyklop\243w i odbierz mu[ENTER]jego Wewn\234trzne \140wiat\179o. "
gameforge.main_quest_lv93._110_say = "Przychodzisz z pustymi r\234kami? W ten spos\243b nie[ENTER]b\234d\234 w stanie ci pom\243c. Przynie\156 mi Wewn\234trzne[ENTER]\140wiat\179o! "
gameforge.main_quest_lv93._120_1_notice = "Uda\179o ci si\234 znale\159\230 Wewn\234trzne \140wiat\179o. Zanie\156[ENTER]je do Yon-I-Walker. "
gameforge.main_quest_lv93._130_say = "Porozmawiaj z Yon-I-Walker. "
gameforge.main_quest_lv93._140_say = "A wi\234c to jest Wewn\234trzne \140wiat\179o... Zanim b\234d\234[ENTER]m\243g\179 podda\230 przer\243bce, musz\234 go oczy\156ci\230. To z[ENTER]pewno\156ci\185 potrwa jaki\156 czas. Dam ci zna\230, gdy[ENTER]b\234d\234 got\243w. "
gameforge.main_quest_lv93._150_sendLetter = "Wzmocnij si\179y II "
gameforge.main_quest_lv93._160_say = "Yon-I-Walker szuka ciebie. "
gameforge.main_quest_lv93._170_say = "Wewn\234trzne \140wiat\179o Polifema jest oczyszczone.[ENTER]Potrzebujemy te\191 \156wiat\179a Gigant\243w.[ENTER]Aby je zdoby\230, musisz pokona\230 Kr\243la Wobba. "
gameforge.main_quest_lv93._180_say = "Natychmiast wyruszam. "
gameforge.main_quest_lv93._190_sayTitle = "Wewn\234trzne \140wiat\179o II "
gameforge.main_quest_lv93._200_say = "Pokonaj Kr\243l Gigant\243w Wobba i odbierz mu jego[ENTER]Wewn\234trzne \140wiat\179o. "
gameforge.main_quest_lv93._210_say = "Przychodzisz z pustymi r\234kami? Zdziwi\179bym si\234[ENTER]okropnie, je\156li nie podo\179a\179by\156 temu zadaniu.[ENTER]Spr\243buj ponownie! "
gameforge.main_quest_lv93._220_1_notice = "Trzymasz w swoich r\234kach Wewn\234trzne \140wiat\179o[ENTER]Gigant\243w. "
gameforge.main_quest_lv93._220_2_notice = "Zanie\156 je do Yon-I-Walker. "
gameforge.main_quest_lv93._230_say = "Porozmawiaj z Yon-I-Walker. "
gameforge.main_quest_lv93._240_say = "Wewn\234trzne \140wiat\179o Kr\243la Wobba posiada olbrzymi\185[ENTER]moc. Wydaje mi si\234, \191e to z powodu tej masy.[ENTER]Teraz musz\234 go tylko oczy\156ci\230. A to mo\191e potrwa\230[ENTER]chwilk\234. "
gameforge.main_quest_lv93._250_sendLetter = "Wzmocnij si\179y III "
gameforge.main_quest_lv93._260_say = "Yon-I-Walker szuka ciebie. "
gameforge.main_quest_lv93._270_say = "Bardzo dobrze. Potrzebuj\234 twojej pomocy. Aby[ENTER]ca\179kowicie zadzia\179a\179 m\243j Eliksir Wzmocnienia[ENTER]potrzebuje jeszcze jednego sk\179adnika: Esencji[ENTER]Milenium. "
gameforge.main_quest_lv93._280_say = "Esencja Milenium? Nie s\179ysza\179em nigdy o niej. "
gameforge.main_quest_lv93._290_say = "To silna mikstura sporz\185dzona z r\243\191nych esencji[ENTER]zio\179owych. Znasz Octavio? Mieszka na kontynencie[ENTER]i jest jedynym, kt\243ry jest w stanie przyrz\185dzi\230[ENTER]Esencj\234 Milenium. Id\159 do niego. Mam nadziej\234, \191e[ENTER]nam pomo\191e. Czasem jest uparty... "
gameforge.main_quest_lv93._300_say = "Zgoda. "
gameforge.main_quest_lv93._310_sayTitle = "Porozmawiaj z Octavio! "
gameforge.main_quest_lv93._320_say = "Odszukaj Octavio. Mieszka on na kontynencie i[ENTER]jest jedynym, kt\243ry mo\191e przyrz\185dzi\230 Esencj\234[ENTER]Milenium. "
gameforge.main_quest_lv93._330_say = "Hej! Co mog\234 ci przynie\156\230? Mo\191e zupk\234 samgyetang?[ENTER]Specjalno\156\230 domu z... "
gameforge.main_quest_lv93._340_say = "Octavio, nie jestem tutaj z powodu twojej[ENTER]wyborowej kuchni! Potrzebuj\234 co\156 innego: Esencj\234[ENTER]Milenium. "
gameforge.main_quest_lv93._350_say = "Oj, psss, nie tak g\179o\156no! Esencja Milenium...[ENTER]Nie, to nie wchodzi w rachub\234. Od kogo si\234 o niej[ENTER]dowiedzia\179e\156? Tylko nieliczni radz\185 sobie z jej[ENTER]gigantyczn\185 moc\185, kt\243r\185 mo\191e ich obdarzy\230. To[ENTER]jest zbyt ryzykowne. A teraz sio, zanim jeszcze[ENTER]kto\156 to us\179yszy... "
gameforge.main_quest_lv93._360_say = "Octavio, zaczekaj i wys\179uchaj mnie! Przysy\179a mnie[ENTER]Yon-I-Walker ze Ska\179y Mrocznego Smoka. Koniecznie[ENTER]potrzebujemy tej esencji. Bez niej nie damy rady[ENTER]pokona\230 Wasali Mroku. I \156wiat, kt\243ry teraz znamy,[ENTER]przestanie istnie\230. Tylko ty mo\191esz j\185[ENTER]sporz\185dzi\230.[ENTER]Prosz\234! "
gameforge.main_quest_lv93._370_say = "Powiadasz Yon-I-Walker? Hm, to m\243j stary dobry[ENTER]przyjaciel. Nie jedn\185 butelk\234 wyborowego wina[ENTER]wypili\156my razem podczas naszych nocnych rozm\243w.[ENTER]Musz\234 si\234 zastanowi\230. Przyjd\159 do mnie jutro, to[ENTER]powiem ci, czy si\234 zgadzam. "
gameforge.main_quest_lv93._380_say = {}
gameforge.main_quest_lv93._390_say = "Jeszcze nie zdecydowa\179em. Przyjd\159 p\243\159niej. "
gameforge.main_quest_lv93._400_npcChat = "Esencja Milenium "
gameforge.main_quest_lv93._410_say = "Octavio chcia\179by z tob\185 porozmawia\230. "
gameforge.main_quest_lv93._420_say = "Rozmy\156la\179em przez ca\179\185 noc nad twoj\185 pro\156b\234. I[ENTER]postanowi\179em, \191e zaryzykuj\234. Wiem o tym, \191e to[ENTER]jest prawid\179owa decyzja. Tak, pomog\234 ci. "
gameforge.main_quest_lv93._430_say = "Wspaniale! "
gameforge.main_quest_lv93._440_say = "Jednak nie mam jest w zapasie. Czy przyniesiesz[ENTER]mi kilka sk\179adnik\243w? To przyrz\185dz\234 j\185 dla ciebie. "
gameforge.main_quest_lv93._450_say = "Oczywi\156cie. Co potrzebujesz? "
gameforge.main_quest_lv93._460_say = "Potrzebuj\234 Korzeni Gango, Grzyb\243w Tue oraz R\243\191[ENTER]Alpejskich. Z ka\191dego sk\179adnika po 200 sztuk. "
gameforge.main_quest_lv93._470_say = "Natychmiast wyruszam. Gdzie mog\234 znale\159\230 te[ENTER]sk\179adniki? "
gameforge.main_quest_lv93._480_say = "Ro\156liny te znajdziesz w r\243\191nych miejscach na[ENTER]kontynencie.[ENTER]Podczas gdy ty b\234dziesz szuka\179 sk\179adnik\243w, ja[ENTER]rozpoczn\234 przygotowania. "
gameforge.main_quest_lv93._490_sayTitle = "Receptura Milenium "
gameforge.main_quest_lv93._500_say = "Poszukaj Korzenia Gango, Grzyba Tue oraz R\243\191y[ENTER]Alpejskiej.[ENTER]Potrzebujesz po 200 sztuk. "
gameforge.main_quest_lv93._510 = "Ro\156liny te znajdziesz w r\243\191nych miejscach na[ENTER]kontynencie.[ENTER]Podczas gdy ty b\234dziesz szuka\179 sk\179adnik\243w, ja[ENTER]rozpoczn\234 przygotowania. "
gameforge.main_quest_lv93._520_say = "Ach, wspaniale, jeste\156 z powrotem. I masz[ENTER]wszystko co potrzeba. No to zabieram si\234 do[ENTER]roboty. Teraz potrzebuj\234 spokoju. Przyjd\159 jutro o[ENTER]tej samej porze. Mam nadziej\234, \191e do tego czasu[ENTER]esencja b\234dzie gotowa. "
gameforge.main_quest_lv93._530_say = "W porz\185dku. Do jutra. "
gameforge.main_quest_lv93._540_say = "Rozumiem, \191e ci \156pieszno, ale musisz jeszcze[ENTER]troch\234 poczeka\230. Przyjd\159 p\243\159niej. "
gameforge.main_quest_lv93._550_say = "Szuka ci\234 Octavio. "
gameforge.main_quest_lv93._560_say = "No prosz\234, przychodzisz w sam\185 por\234. W\179a\156nie[ENTER]zako\241czy\179em przyrz\185dzanie Esencji Milenium![ENTER]Mo\191esz j\185 teraz zanie\156 do Yon-I-Walker. "
gameforge.main_quest_lv93._570_say = "Dzi\234kuj\234! "
gameforge.main_quest_lv93._580_sendLetter = "Esencja Milenium "
gameforge.main_quest_lv93._590_say = "Yon-I-Walker szuka ciebie. "
gameforge.main_quest_lv93._600_say = "Masz Esencj\234 Milenium! Teraz mam wszystkie[ENTER]sk\179adniki potrzebne do mojego Eliksiru[ENTER]Wzmocnienia. Zawo\179am ci\234, jak tylko go[ENTER]przyrz\185dz\234. "
gameforge.main_quest_lv93._610_say = "Dobra. "
gameforge.main_quest_lv93._620_say = "Mo\191esz kontynuowa\230 przygod\234, gdy tylko osi\185gniesz[ENTER]poziom 94. "
gameforge.main_quest_lv93._630_say = "%s: %d szt., %s: %d szt.,[ENTER]%s: %d szt. "
gameforge.main_quest_lv93._640_say = "Ja mam co do roboty, musz\234 zajmowa\230 si\234 moj\185[ENTER]gospod\185 i nie mog\234 marnowa\230 czasu. Przynie\156 mi[ENTER]brakuj\185ce sk\179adniki - i po\156piesz si\234! "
gameforge.main_quest_lv93._650_1_notice = "Uda\179o ci si\234 znale\159\230 wszystkie sk\179adniki[ENTER]potrzebne do przyrz\185dzenia Esencji Milenium. "
gameforge.main_quest_lv93._650_2_notice = "Wr\243\230 do Octavio. "
gameforge.main_quest_lv94 = {}
gameforge.main_quest_lv94._010_sendLetter = "Per\179y Syriusza "
gameforge.main_quest_lv94._020_say = "Yon-I-Walker szuka ciebie. "
gameforge.main_quest_lv94._030_say = "Uda\179o mi si\234. Po\179\185czy\179em najskuteczniejsze[ENTER]esencje, kt\243re s\185 nam znane. Prezentuj\234: Per\179y[ENTER]Syriusza! "
gameforge.main_quest_lv94._040_say = "Dzi\234kuj\234! "
gameforge.main_quest_lv94._050_say = "Gdy po\179kniesz te kapsu\179ki, by\230 mo\191e nawet nie[ENTER]poczujesz \191adnej zmiany. Ale wprawne oko, np.[ENTER]moje lub Angmura, dostrze\191e r\243\191nic\234.[ENTER]Angmur chce z tob\185 pogada\230. Udaj si\234 do niego,[ENTER]natychmiast! "
gameforge.main_quest_lv94._060_sayTitle = "Pokrzep si\234! "
gameforge.main_quest_lv94._070_say = "We\159 Per\179y Syriusza i udaj si\234 do Admira\179a Angmura. "
gameforge.main_quest_lv94._080_sendLetter = "Wezwanie G\243r Gromistych "
gameforge.main_quest_lv94._090_say = "Admira\179 Angmur ma dla ciebie nowe wie\156ci. "
gameforge.main_quest_lv94._1000_say = "Potrzebuj\234 nieco czasu do dog\179\234bnej analizy[ENTER]pr\243bek. Przyjd\159 ponownie jutro, do tej pory b\234d\234[ENTER]mie\230 wyniki. "
gameforge.main_quest_lv94._100_say = "Ach, Per\179y Syriusza zacz\234\179y ju\191 dzia\179a\230. Otacza[ENTER]ciebie pot\234\191na aura mocy.[ENTER]Moi zwiadowcy maj\185 pewne podejrzenia, co do[ENTER]siedziby g\179\243wnej Wasali Mroku. Miejsce to jest[ENTER]jednak dobrze strze\191one. Przeprowadzisz tam[ENTER]rozpoznanie? "
gameforge.main_quest_lv94._1010_say = "Przeka\191\234 swoje wyniki Angmurowi.[ENTER]W razie czego da ci zna\230. "
gameforge.main_quest_lv94._1020_say = "Admira\179 Angmur posiada pewne informacje na temat[ENTER]Czarnego Z\179ota. Udaj si\234 do niego. "
gameforge.main_quest_lv94._1030_say = "Aj, jeste\156 wreszcie. Niestety nie uko\241czy\179em[ENTER]jeszcze analizy Czarnego Z\179ota. Mam nadziej\234, \191e[ENTER]nied\179ugo b\234d\234 mia\179 dla ciebie wi\234cej informacji.[ENTER]Prosz\234, przyjmij to jako wynagrodzenie za sw\243j[ENTER]wysi\179ek. "
gameforge.main_quest_lv94._1040_say = "Nie wolno nam traci\230 czasu. Szybko, przynie\156 mi[ENTER]pr\243bki Czarnego Z\179ota! "
gameforge.main_quest_lv94._1050_say = "Ci\185g dalszy przygody po osi\185gni\234ciu poziomu 95 "
gameforge.main_quest_lv94._1060_say = "Pozosta\179o "
gameforge.main_quest_lv94._1070_say = {}
gameforge.main_quest_lv94._1080_say = "Brakuj\185ca ilo\156\230: "
gameforge.main_quest_lv94._1090_say = {}
gameforge.main_quest_lv94._110_say = "Oczywi\156cie. "
gameforge.main_quest_lv94._120_say = "Dzi\234kuj\234. Chod\159, poka\191\234 ci, jakie tereny musisz[ENTER]wysondowa\230. Gdy ju\191 to zrobisz, zdaj mi[ENTER]sprawozdanie. "
gameforge.main_quest_lv94._130_say = {}
gameforge.main_quest_lv94._140_say = "Na zlecenie Admira\179a Angmura sondujesz Gromiste[ENTER]G\243ry. Tw\243j pierwszy cel to: (%d, %d) "
