gameforge.main_quest_lv94._160_say = "Wysonduj Gromiste G\243ry i zdaj raport Admira\179owi[ENTER]Angmurowi. "
gameforge.main_quest_lv94._170_say = "Jeszcze nie uda\179o ci si\234 wysondowa\230 wszystkich[ENTER]lokacji, prawda? Te informacje s\185 dla nas[ENTER]naprawd\234 wa\191ne. Prosz\234, wype\179nij moje zlecenie. "
gameforge.main_quest_lv94._180_say = "Tw\243j pierwszy cel to: %d, %d "
gameforge.main_quest_lv94._190_say = "Tw\243j drugi cel to: %d, %d "
gameforge.main_quest_lv94._200 = {}
gameforge.main_quest_lv94._210_say = "Tw\243j trzeci cel to: %d, %d "
