gameforge.main_quest_lv94._230_say = "Drugi cel zaliczony. Nast\234pna lokacja to: (%d, %d)  "
gameforge.main_quest_lv94._240 = "Trzeci cel zaliczony. "
gameforge.main_quest_lv94._250_say = "Posiadasz teraz pewne poj\234cie o sytuacji w[ENTER]Gromistych G\243rach.[ENTER]Zdaj raport Admira\179owie Angmurowi. "
gameforge.main_quest_lv94._260_say = "Wr\243\230 do Admira\179a Angmura. "
gameforge.main_quest_lv94._270_say = "Ach, jeste\156 wreszcie! \140wietnie, teraz[ENTER]przeanalizujemy dostarczone przez ciebie[ENTER]informacje i opracujemy jak\185\156 strategi\234. "
gameforge.main_quest_lv94._280_say = "Oto twoja nagroda. "
gameforge.main_quest_lv94._290_sendLetter = "Os\179ab band\234 Czerwonych "
gameforge.main_quest_lv94._300_say = "Szuka ci\234 Admira\179 Angmur. "
gameforge.main_quest_lv94._310_say = "Bezpo\156redni atak wydaje mi si\234 na razie zbyt[ENTER]ryzykowny. Zanim przejdziemy do dzia\179a\241[ENTER]ofensywnych, powinni\156my os\179abi\230 si\179y wroga. "
gameforge.main_quest_lv94._320_say = "W Gromistych G\243rach napotkasz nast\234puj\185ce grupy:[ENTER]Giganci, Cyklopy i Czerwoni.[ENTER]Na pocz\185tku namierzamy band\234 Czerwonych! "
gameforge.main_quest_lv94._330_say = "Jakie s\185 s\179abe punkty bandy Czerwonych? "
gameforge.main_quest_lv94._340_say = "Czerwony W\243dz nosi specjaln\185 peleryn\234, symbol[ENTER]si\179y i zwyci\234stwa. Odbierz mu t\234 peleryn\234, aby[ENTER]os\179abi\230 morale Czerwonych! "
gameforge.main_quest_lv94._350_say = "Czerwony W\243dz? Nie b\234dzie to prosta sprawa... "
gameforge.main_quest_lv94._360_say = "Masz racj\234. Ale je\156li kto\156 jest w stanie stawi\230[ENTER]mu czo\179o, to jeste\156 to niechybnie ty. Powodzenia! "
gameforge.main_quest_lv94._370_sayTitle = "Czerwony W\243dz "
gameforge.main_quest_lv94._380_say = "Pokonaj Czerwonego Wodza i odbierz mu jego[ENTER]peleryn\234. "
gameforge.main_quest_lv94._390_say = "... pora\191ka? Nie, wie wierz\234. Nie poddawaj si\234[ENTER]tak szybko. Spr\243buj ponownie, a tym razem na[ENTER]pewno sobie z nim poradzisz! "
gameforge.main_quest_lv94._400_1_notice = "Czerwony W\243dz poleg\179. "
gameforge.main_quest_lv94._400_2_notice = "We\159 jego peleryn\234 i zanie\156 j\185 Admira\179owi[ENTER]Angmurowi. "
gameforge.main_quest_lv94._410_say = "Admira\179 Angmur oczekuje ci\234. "
gameforge.main_quest_lv94._420_say = "Peleryna! Wiedzia\179em, \191e ci si\234 uda. Teraz[ENTER]powiesimy j\185 na widoku gdzie\156 w pobli\191u ich[ENTER]obozu.[ENTER]Taka akcja powinna ich nie\159le zdezorientowa\230.[ENTER]Moi ludzie ju\191 tym si\234 zajm\185, a ty mo\191esz nieco[ENTER]odpocz\185\230. "
gameforge.main_quest_lv94._430_sendLetter = "Os\179ab Cyklopy "
gameforge.main_quest_lv94._440_say = "Admira\179 Angmur chce z tob\185 porozmawia\230. "
gameforge.main_quest_lv94._450_say = "Nasz plan okaza\179 si\234 strza\179em w dziesi\185tk\234. Gdy[ENTER]Czerwoni zobaczyli peleryn\234, popadli w niema\179\185[ENTER]panik\234. Demony i ludzie zacz\234li walczy\230 mi\234dzy[ENTER]sob\185, a ca\179a banda jest obecnie w proszku.[ENTER]Nadszed\179 czas, aby zaj\185\230 si\234 Cyklopami. "
gameforge.main_quest_lv94._460_say = "Mam jaki\156 plan? "
gameforge.main_quest_lv94._470_say = "Cyklopy czcz\185 swoich przyw\243dc\243w. Je\156li usuniemy[ENTER]tych ich bo\191yszczy, wpadn\185 w panik\234 i pouciekaj\185.[ENTER]Za\179atw zatem %d razy Genera\179a Outisa, %d razy[ENTER]Argesa oraz %d razy Polifema. "
gameforge.main_quest_lv94._480_say = "Z przyjemno\156ci\185... "
gameforge.main_quest_lv94._490_say = "Uwa\191aj na siebie. "
gameforge.main_quest_lv94._500_sayTitle = "Na pohybel Cyklopom! "
gameforge.main_quest_lv94._510_say = "Za\179atw %d x Genera\179a Outisa, %d x Aregsa i %d x[ENTER]Polifema. "
gameforge.main_quest_lv94._520 = "Jako\156 nie chce mi si\234 wierzy\230, \191e nie potrafisz[ENTER]poradzi\230 sobie z Cyklopami. Dawaj, wiem przecie\191[ENTER]na co ci\234 sta\230! "
gameforge.main_quest_lv94._530_1_notice = "Przyw\243dcy Cyklop\243w polegli. "
gameforge.main_quest_lv94._530_2_notice = "Zdaj raport Admira\179owi Angmurowi. "
gameforge.main_quest_lv94._540_say = "Udaj si\234 do Admira\179a Angmura. "
gameforge.main_quest_lv94._550_say = "Wie\156ci o twoich bohaterskich czynach szybko si\234[ENTER]roznosz\185! Cyklopy wzi\234\179y nogi za pas.[ENTER]Pozostali jeszcze Giganci. Zasi\234gn\234 informacji na[ENTER]temat ich s\179abych punkt\243w i dam ci zna\230. "
