gameforge.main_quest_lv94._630_say = "Zgoda. "
gameforge.main_quest_lv94._640_sayTitle = "Totem Gigant\243w "
gameforge.main_quest_lv94._650_say = "Zdob\185d\159 wszystkie cz\234\156ci totemu. "
gameforge.main_quest_lv94._660_say = "Giganci s\185 bardzo pot\234\191nymi przeciwnikami.[ENTER]Ale nie mamy innego wyj\156cia! Musisz ich pokona\230 i[ENTER]przynie\156\230 mi ich totem. "
gameforge.main_quest_lv94._670_say_1_notice = "Zebrano wszystkie cz\234\156ci totemu. "
gameforge.main_quest_lv94._670_say_2_notice = "Wr\243\230 do Admira\179a Angmura. "
gameforge.main_quest_lv94._680_say = "Aj, zacz\185\179em ju\191 si\234 martwi\230! Ale widz\234, \191e ci[ENTER]si\234 uda\179o. Teraz posiadamy \156wi\234tym Totem[ENTER]Gigant\243w.[ENTER]Czeka na ciebie hojne wynagrodzenie. "
