gameforge.main_quest_lv94._720_say = "Dowiedz si\234, co takiego knuj\185 Cyklopy. Zapewne[ENTER]nie b\234dzie to nic dobrego... i raczej nie zdradz\185[ENTER]swej tajemnicy dobrowolnie. "
