gameforge.main_quest_lv94._800_say = "Cyklopy nie by\179y wprawdzie zbyt komunikatywne,[ENTER]ale dzi\234ki mojemu niezr\243wnanemu darze perswazji[ENTER]uda\179o mi si\234 wyci\185gn\185\230 z nich to tutaj... czarny[ENTER]po\179yskuj\185cy kamie\241 oraz kartk\234. "
gameforge.main_quest_lv94._810_say = "Zlokalizowali\156my z\179o\191a Czarnego Z\179ota w[ENTER]Gromistych G\243rach i wydobywamy je dla was. W[ENTER]celach wymiany spotkamy si\234, tak jak ustalili\156my,[ENTER]we wn\234trzu Gromistych G\243r. "
gameforge.main_quest_lv94._820_say = "Czarne Z\179oto... jest to ruda wyst\234puj\185ca jedynie[ENTER]w Gromistych G\243rach. Ale na co ona Wasalom Mroku? "
