gameforge.main_quest_lv94._870_say = "Alchemik nie potrafi\179 dokona\230 analizy Czarnego[ENTER]Z\179ota. Potrzebuje wi\234kszej pr\243bki. Musimy[ENTER]koniecznie pozna\230 jego w\179a\156ciwo\156ci, aby przejrze\230[ENTER]zamiary Wasali Mroku! Udaj si\234 prosz\234 ponownie do[ENTER]Gromistych G\243r i przynie\156 nam wi\234cej pr\243bek[ENTER]Czarnego Z\179ota. "
