gameforge.main_quest_lv94._920_say = "Hmmm, niech no pomy\156l\234... my\156l\234, \191e tak z %d[ENTER]powinno starczy\230. "
gameforge.main_quest_lv94._930_say = "Zgoda. "
gameforge.main_quest_lv94._940_sayTitle = "Z\179oto Gromistych G\243r "
gameforge.main_quest_lv94._950_sayTitle = "Udaj si\234 do Alchemika. "
gameforge.main_quest_lv94._960_say = "Poszukaj w Gromistych G\243rach pr\243bek Czarnego[ENTER]Z\179ota. "
gameforge.main_quest_lv94._970_1_notice = "Uda\179o ci si\234 odkry\230 z\179o\191\234 Czarnego Z\179ota i pobra\230[ENTER]pr\243bk\234 rudy. "
gameforge.main_quest_lv94._970_2_notice = "Zanie\156 j\185 do Alchemika. "
gameforge.main_quest_lv94._980_say = "Ach, Czarne Z\179oto... poka\191 no! Hmm, \191adnej skazy,[ENTER]wystarczaj\185co du\191e... tak, nadaje si\234 do[ENTER]przeprowadzenia analizy. Potrzebuj\234 jeszcze %d. "
