gameforge.main_quest_lv95._130_say = {}
gameforge.main_quest_lv95._140_say = "Cholera! Kapitan Haak przekaza\179 Czarne Z\179oto[ENTER]Banshee. Nie rozumiem jednak ostatniego zdania:[ENTER]Kl\185twa \191ycia przywo\179a armi\234 ciemno\156ci z mglistych[ENTER]otch\179ani czasu. "
gameforge.main_quest_lv95._150_say = "Musimy zatrzyma\230 t\234 dostaw\234! Kryj\243wka Banshee[ENTER]znajduje si\234 gdzie\156 na zachodzie, przy Klifie[ENTER]Gautama. Jest to straszne odludzie spowite[ENTER]wieczn\185 mg\179\185. Zamieszkuj\185 je Ogry i Lemury. "
