gameforge.main_quest_lv95._310_say = "Nie jest zatem jeszcze za p\243\159no. Dowiem si\234, kto[ENTER]obecnie jest w posiadaniu Czarnego Z\179ota, i czy[ENTER]zosta\179o ju\191 przetworzone. Gdy tylko b\234d\234 mia\179 te[ENTER]informacje, po\156l\234 po ciebie. Prosz\234, przyjmij to[ENTER]za swoje trudy. Na razie! "
