gameforge.main_quest_lv95._340_say = "Uzyskali\156my informacje, \191e proces przetwarzania[ENTER]Czarnego Z\179ota jest nadzorowany przez Ogra[ENTER]Maximusa, kt\243ry po sko\241czonej robocie ma je[ENTER]dostarczy\230 do Banshee. "
gameforge.main_quest_lv95._350_say = "Obecnie znajduje si\234 w okolicach Klifu Gautama.[ENTER]Nie dopu\156\230, aby Czarnego Z\179oto dotar\179o do celu.[ENTER]Szybko, dop\243ki jeszcze nie jest za p\243\159no! "
