gameforge.main_quest_lv95._460_say = "Niech B\243g Smok\243w oka\191e si\234 nam \179askawy! Ale tak[ENTER]\179atwo to si\234 nie poddamy. Wy\156l\234 swoich[ENTER]zwiadowc\243w, aby odnale\159li kryj\243wk\234 Banshee. Gdy[ENTER]tylko dowiem si\234 wi\234cej, po\156l\234 po ciebie. W[ENTER]mi\234dzyczasie nabierz nowych si\179 i przyjmij t\234 oto[ENTER]nagrod\234. "
gameforge.main_quest_lv95._470_sendLetter = "Kl\185twa \175ycia "
