gameforge.main_quest_lv95._500_say = {}
gameforge.main_quest_lv95._510_say = "Wskrzeszanie zmar\179ych... sama my\156l o tym[ENTER]przyprawia mnie palpitacje serca. Wasale Mroku[ENTER]wykorzystuj\185 Czarne Z\179oto w celach zestawienia[ENTER]ca\179ej armii nieumar\179ych. Musimy ich powstrzyma\230! "
gameforge.main_quest_lv95._520_say = "Udaj si\234 do starych ruin w okolicy Klifu Gautama[ENTER]i odnajd\159 tam Lemura Maga. On wie co\156 na temat[ENTER]tej kl\185twy. Je\156li go \179adnie poprosisz, to[ENTER]powinien ci pom\243c. "
gameforge.main_quest_lv95._530_say = "Aha, poprosz\234 go zatem po swojemu. "
