gameforge.main_quest_lv95._560_say = "Nie mamy czasu do stracenia. Pokonaj Lemura Maga[ENTER]i wyci\156nij z niego informacje na temat Kl\185twy[ENTER]\175ycia. "
gameforge.main_quest_lv95._570_1_notice = "Mag Lemur poleg\179, pozostawiaj\185c po sobie kamienn\185[ENTER]tablic\234 z wyrytym napisem. "
