gameforge.main_quest_lv95._590_say = "Aj, Mag Lemur mia\179 przy sobie t\234 oto tablic\234?[ENTER]Poka\191, poka\191... "
gameforge.main_quest_lv95._600_sayReward = "Do wskrzeszenia umar\179ych nieodzowne s\185 trzy[ENTER]rzeczy:[ENTER]1. ludzkie cia\179o[ENTER]2. ...[ENTER]Tablica Lemur\243w jest w tym miejscu z\179amana.[ENTER]Brakuje reszty inskrypcji. "
gameforge.main_quest_lv95._610_say = "Obawiam si\234, \191e przyjdzie ci ponownie wyruszy\230 w[ENTER]drog\234. Potrzebujemy dw\243ch pozosta\179ych cz\234\156ci tej[ENTER]oto tablicy. Koniecznie! "
gameforge.main_quest_lv95._620_say = "Oto nagroda za wszystkie twoje dotychczasowe[ENTER]starania. A teraz udaj si\234 na poszukiwania[ENTER]pozosta\179ych cz\234\156ci Tablicy Lemur\243w! "
