gameforge.main_quest_lv95._670_say = "Zanie\156 pozosta\179e dwie cz\234\156ci Tablicy Lemur\243w do[ENTER]Admira\179a Angmura. "
gameforge.main_quest_lv95._680_say = "Aj, dobrze ci\234 widzie\230! A teraz chod\159, z\179o\191ymy[ENTER]Tablic\234 Lemur\243w do kupy i odczytamy inskrypcj\234. "
gameforge.main_quest_lv95._690_sayReward = "Do wskrzeszenia umar\179ych nieodzowne s\185 trzy[ENTER]rzeczy:[ENTER]1. ludzkie cia\179o[ENTER]2. Czarne Z\179oto[ENTER]3. Kora Drzewnych Demon\243w[ENTER]Tylko mag o nadzwyczajnych umiej\234tno\156ciach jest w[ENTER]stanie rzuci\230 zakl\234cie Kl\185twy \175ycia. Gdy jednak[ENTER]polegnie, polegnie wraz z nim ca\179a jego nieumar\179a[ENTER]armia. "
gameforge.main_quest_lv95._700_say = "To dlatego ostatnimi czasy dochodzi\179o tak cz\234sto[ENTER]do pl\185drowania naszych cmentarzy i wykopywania[ENTER]trup\243w. To w\179a\156nie te zw\179oki zostan\185 wskrzeszone[ENTER]i wcielone do armii ciemno\156ci. Co za paskudna[ENTER]my\156l! "
