gameforge.main_quest_lv95._720_say = "Aj, niestety czas dzia\179a na nasz\185 niekorzy\156\230.[ENTER]Tylko Banshee jest na tyle pot\234\191na, aby rzuci\230 to[ENTER]zakl\234cie, ale nie mamy poj\234cia, gdzie si\234 obecnie[ENTER]ukrywa. Wy\156l\234 wszystkich moich ludzi, aby[ENTER]wytropili kryj\243wk\234 tej mrocznej arcykap\179anki. Gdy[ENTER]tylko dowiem si\234 wi\234cej, po\156l\234 po ciebie. "
