gameforge.main_quest_lv97._010_sendLetter = "Zatrzymaj Banshee "
gameforge.main_quest_lv97._020_say = "Odkryto kryj\243wk\234 Banshee! Udaj si\234 do Admira\179a[ENTER]Angmura, aby dowiedzie\230 si\234 czego\156 wi\234cej na ten[ENTER]temat. "
gameforge.main_quest_lv97._030_say = "Moi ludzie odkryli w ko\241cu kryj\243wk\234 Banshee przy[ENTER]Klifie Gautama. Zaszy\179a si\234 ona g\179\234boko w[ENTER]okolicznych lasach i dalej uprawia tam swoj\185[ENTER]czarn\185 magi\234. Poza tym obudzi\179a ponownie dawn\185[ENTER]Kap\179ank\234 \140wi\185tynn\185 smoczego kultu. I wraz z ni\185[ENTER]planuje przywo\179a\230 kl\185tw\234 \191ycia. "
gameforge.main_quest_lv97._040_say = "Bez jej pomocy nie zdo\179a ona utrzyma\230 kl\185twy.[ENTER]Pokonaj Kap\179ank\234 \140wi\185tynn\185 Mu-Shu i u\179agod\159 dusze[ENTER]naszych towarzyszy, zanim ich cia\179a powstan\185[ENTER]przeciw nam. "
gameforge.main_quest_lv97._050_say = "To prawie niemo\191liwe podej\156\230 do Kap\179anki[ENTER]\140wi\185tynnej, aby ci\234 nie zauwa\191y\179a i nie[ENTER]zaatakowa\179a. Spr\243buj wykorzysta\230 swoj\185 szans\234,[ENTER]kiedy jest pogr\185\191ona tak g\179\234boko w swojej magii,[ENTER]\191e prawie wpada w trans. "
gameforge.main_quest_lv97._060_say = "W porz\185dku. "
gameforge.main_quest_lv97._070_say = "Uwa\191aj na siebie! Za \191ycia nale\191a\179a ona do[ENTER]pierwszych stra\191niczek arcykap\179anki i to nie[ENTER]tylko w sprawach magii, lecz tak\191e doskonale[ENTER]w\179ada\179a mieczem. "
gameforge.main_quest_lv97._080_sayTitle = "Kap\179anka \140wi\185tynna "
gameforge.main_quest_lv97._090_say = "Pokonaj przy Klifie Gautama Kap\179ank\234 \140wi\185tynni[ENTER]Banshee, Mu-Shu. "
gameforge.main_quest_lv97._100_notice = "\140miertelnie trafiona Kap\179anka \140wi\185tynni upada na[ENTER]ziemi\234. "
gameforge.main_quest_lv97._110_say = "Ale z was g\179upcy! Dobrowolnie po\179kn\234li\156cie[ENTER]przyn\234t\234, kt\243r\185 zarzuci\179a wam Banshee.[ENTER]Marnowali\156cie czas tutaj ze mn\185, podczas gdy ona[ENTER]wraz z Yah-Ki, prawdziw\185 Kap\179ank\185 \140wi\185tynn\185[ENTER]rozpocz\234\179y ju\191 przygotowania do przeprowadzenia[ENTER]kl\185twy. Modl\234 si\234 o to, aby si\234 im uda\179o. "
gameforge.main_quest_lv97._120_say = "Jej sobowt\243r naprowadzi\179 was na z\179y trop! Po[ENTER]przeszukaniu go, znajdujesz naszyjnik podobny do[ENTER]tego, kt\243ry mia\179 wcze\156niej Martyaxwa. W kieszonce[ENTER]wewn\234trznej znajduje si\234 dokument. "
gameforge.main_quest_lv97._130_say = "Zdaj raport Admira\179owi Angmurowi. "
gameforge.main_quest_lv97._140_say = "Jeste\156 ju\191 z powrotem. Uda\179o ci si\234 pokona\230[ENTER]Kap\179ank\234 \140wi\185tynn\185! "
gameforge.main_quest_lv97._150_say = "Nie, zostali\156my zmyleni przez sobowt\243ra.[ENTER]Prawdziwa kap\179anka mog\179a w spokoju przygotowa\230[ENTER]wskrzeszanie zmar\179ych. Ale uda\179o mi si\234 znale\159\230[ENTER]ten dokument. "
gameforge.main_quest_lv97._160_say = "Do diab\179a! Jak mogli\156my si\234 tak da\230 nabra\230?![ENTER]Prosz\234, poka\191 mi dokument. "
gameforge.main_quest_lv97._170_say = {}
gameforge.main_quest_lv97._180_say = {}
gameforge.main_quest_lv97._190_say = "Hm, zaszyfrowany. Ale mo\191e dowiemy si\234 z niego,[ENTER]gdzie znajduje si\234 faktycznie ich baza. Takie[ENTER]litery ju\191 gdzie\156 widzia\179em... Wydaje mi si\234, \191e[ENTER]Yak-Hwan, stra\191nik pa\179acowy, pokazywa\179 mi[ENTER]niedawno co\156 podobnego. Id\159 do niego. Niech on[ENTER]rzuci okiem na ten dokument. "
gameforge.main_quest_lv97._200_sendLetter = "Odszyfruj dokument "
gameforge.main_quest_lv97._210_say = "Udaj si\234 do Yak-Hwan i poka\191 mu zaszyfrowany[ENTER]dokument. "
gameforge.main_quest_lv97._220_say = "Witaj! Nazywam si\234 Yak-Hwan. To dla mnie wielki[ENTER]zaszczyt m\243c ci\234 pozna\230. Twoje czyny s\185 ju\191[ENTER]legend\185! W czym mog\234 ci pom\243c? Ach, zaszyfrowana[ENTER]wiadomo\156\230. Poka\191 mi j\185. "
gameforge.main_quest_lv97._230_say = "Potrafi\234 odszyfrowa\230 ten dokument, ale do tego[ENTER]potrzebuj\234 Skamienia\179ej Ziemi. Alchemik powinien[ENTER]posiada\230 jeszcze jak\185\156 bry\179k\234. Prosz\234, zapytaj[ENTER]si\234 go. "
