gameforge.main_quest_lv97._290_say = "Nie zapomnia\179e\156 przypadkiem o czym\156? Prosi\179em ci\234[ENTER]przecie\191, aby\156 mi przyni\243s\179 Skamienia\179\185 Ziemi\234. "
