gameforge.main_quest_lv97._340_say = "Znamy ju\191 miejsce pobytu Kap\179anki \140wi\185tynnej[ENTER]Yah-Ki. Niestety baza to przypomina pot\234\191n\185[ENTER]twierdz\234 \150 oddzia\179y stra\191y na okr\185g\179o patroluj\185[ENTER]okolic\234. Obecnie atak frontalny by\179by dla nas[ENTER]samob\243jstwem. "
gameforge.main_quest_lv97._350_say = "Dlatego chcemy zaatakowa\230 z zasadzki. Moi ludzie[ENTER]szukaj\185 ju\191 odpowiedniego miejsca. Odci\185gnij[ENTER]stra\191, aby\156my mieli wi\234cej czasu. "
gameforge.main_quest_lv97._360_say = {}
gameforge.main_quest_lv97._370_say = "Najniebezpieczniejszy jest jeden z oddzia\179\243w[ENTER]stra\191niczych. Sami siebie nazywaj\185 Brygad\185[ENTER]Czarnej \140mierci. Brygada sk\179ada si\234 Moghu,[ENTER]Carnifex i Genera\179a Albusa. Ich przyw\243dc\185 jest[ENTER]Szkieletor.[ENTER]Zlikwiduj ich wszystkich, zanim odkryj\185 m\243j[ENTER]oddzia\179 zwiadowczy. "
gameforge.main_quest_lv97._380_say = "Dobra. "
