gameforge.main_quest_lv97._400_say = "Pokonaj Brygad\234 Czarnej \140mierci, kt\243ra sk\179ada si\234[ENTER]z Moghu, Carnifex, Genera\179a Albusa i Szkieletora. "
gameforge.main_quest_lv97._410_say = "Wyeliminuj cz\179onk\243w Brygady Czarnej \140mierci,[ENTER]zanim odkryje oddzia\179 zwiadowczy. "
gameforge.main_quest_lv97._420_say = "Zdaj raport Admira\179owi Angmurowi. "
gameforge.main_quest_lv97._430_say = "Nasz plan powi\243d\179 si\234! Uda\179o ci si\234 odci\185gn\185\230[ENTER]Brygad\234 Czarnej \140mierci, a moi ludzie w tym[ENTER]czasie znale\159li odpowiednie miejsce do ataku z[ENTER]zasadzki.[ENTER]Przywo\179am ci\234, gdy tylko ustalimy nasz\185 strategi\234[ENTER]ataku. "
gameforge.main_quest_lv97._440_sendLetter = "Kap\179anka \140wi\185tynna "
gameforge.main_quest_lv97._450_say = "Admira\179 Angmur potrzebuje twojej pomocy! "
gameforge.main_quest_lv97._460_say = "Dobrze, \191e jeste\156. Szkieletor prze\191y\179 i[ENTER]zaatakowa\179 moich ludzi, w momencie gdy chcieli[ENTER]szturmowa\230 baz\234. Nikogo nie przepu\156ci\179. "
gameforge.main_quest_lv97._470_say = {}
gameforge.main_quest_lv97._480_say = "Ju\191 raz uda\179o ci si\234 go pokona\230. A wi\234c prosz\234,[ENTER]pom\243\191 moim ludziom przy Klifie Gautama! Zmierz[ENTER]si\234 ze Szkieletorem. Potem zaatakuj baz\234 i zabij[ENTER]Kap\179ank\234 \140wi\185tynni Yah-Ki. "
