gameforge.main_quest_lv97._530_say = "Nadszed\179 dzie\241 rozstrzygni\234cia. Je\156li zginiemy,[ENTER]zginie z nami ca\179y \156wiat. Jednak, je\156li[ENTER]zwyci\234\191ymy, o naszych chwalebnych czynach b\234d\185[ENTER]\156piewane pie\156ni przez nast\234pnych tysi\185c lat.[ENTER]Powstrzymaj Wasali Mroku. Zniszcz Kap\179anka[ENTER]\140wi\185tynna Yah-Ki! "
gameforge.main_quest_lv97._540_say = "Dlaczego jeste\156 tutaj? Walka si\234 jeszcze nie[ENTER]zako\241czy\179a. Pokonaj Kap\179ank\234 \140wi\185tynni Yah-Ki.[ENTER]Pok\179adamy w tobie ca\179\185 nasz\185 nadziej\234. "
gameforge.main_quest_lv97._550_1_notice = "Rzuci\179e\156 na kolana swojego przeciwnika.[ENTER]Zwyci\234stwo nale\191y do ciebie! "
gameforge.main_quest_lv97._550_2_notice = "Nie masz czasu na odpoczynek \150 Kap\179anka \140wi\185tynna[ENTER]Yah-Ki czeka na ciebie. "
gameforge.main_quest_lv97._560_notice = "Zwyci\234\191y\179e\156! Z przera\159liwym krzykiem Yah-Ki upada[ENTER]na ziemi\234. "
gameforge.main_quest_lv97._570_say = "Oj! To niemo\191liwe! Pokonana przez cz\179owieka...[ENTER]Och, Banshee, wybacz! Zawiod\179am ci\234! Nie[ENTER]wykona\179am mojego zada... "
gameforge.main_quest_lv97._580_say = "Przeszukujesz jej zw\179oki i znajdujesz[ENTER]Zapiecz\234towany List. Zanie\156 go Admira\179owi[ENTER]Angmurowi. "
