gameforge.main_quest_lv97._600_say = "Wr\243ci\179a tam sk\185d wype\179z\179a ta okropna \191mija - do[ENTER]piek\179a! Dogorywaj\185c b\179aga\179a o przebaczenie[ENTER]Banshee za to, \191e j\185 zawiod\179a. Popatrz, to mia\179a[ENTER]przy sobie. "
gameforge.main_quest_lv97._610_say = "Zapiecz\234towany List. Poka\191! "
gameforge.main_quest_lv97._620_sayReward = "Moja Pani, w ko\241cu wpadli w nasze sid\179a. Tw\243j[ENTER]plan si\234 powi\243d\179! Wskrzeszenie armii zmar\179ych[ENTER]jest w toku i nikt ju\191 teraz nas nie powstrzyma.[ENTER]Je\156li zmartwychwstan\185 bezduszne cia\179a, wyruszymy[ENTER]natychmiast na Przyl\185dek Smoczego Ognia i[ENTER]wytniemy w pie\241 wszystkich jego mieszka\241c\243w.[ENTER]Potem przejdziemy na kontynent i spotkamy si\234 z[ENTER]wami na Ognistej Ziemi. Zniszczymy ca\179y \156wiat,[ENTER]pod naszymi stopami ziemia b\234dzie p\179on\185\230.[ENTER]Z wielkim szacunkiem, Wasza wierna kap\179anka "
gameforge.main_quest_lv97._630_say = "Wiadomo\156\230 dla Banshee! Ta szkodliwa wied\159ma[ENTER]daremnie czeka w Ognistej Ziemi na swoj\185 armi\234[ENTER]ciemno\156ci.[ENTER]Dzi\234kuj\234 ci. Bez twojej pomocy przyl\185dek i jego[ENTER]mieszka\241cy zostaliby zr\243wnani z ziemi\185 przez[ENTER]armi\234 nieumar\179ych. Nie tylko uratowa\179a\156 nas, lecz[ENTER]r\243wnie\191 przywr\243ci\179a\156 spok\243j duszom naszych[ENTER]przodk\243w. Jako reprezentant ca\179ego frontu mam[ENTER]zaszczyt przekaza\230 ci t\234 oto nagrod\234. "
gameforge.main_quest_lv97._640_sayTitle = "Mo\191esz kontynuowa\230 przygod\234, gdy tylko osi\185gniesz[ENTER]poziom 98. "
gameforge.main_quest_lv97._650_say = "D\179ugo potrzebowali\156my, aby odnale\159\230 baz\234. Teraz[ENTER]nie mamy ani chwili do stracenia! "
gameforge.main_quest_lv97._660_say = "Yak-Hwan potrzebuje Skamienia\179ej Ziemi? Co za[ENTER]szcz\234\156cie, \191e jej jeszcze nie zu\191y\179em. Prosz\234[ENTER]bardzo, zanie\156 j\185 mu i pozdr\243w go ode mnie. "
gameforge.main_quest_lv97._670_counterName = "Pozosta\179o "
