gameforge.main_quest_lv98._020_say = "Admira\179 Angmur prosi ci\234 o pomoc. Id\159 do niego. "
gameforge.main_quest_lv98._030_say = "Dzi\234kuj\234 ci za przybycie. Walka odcisn\234\179a tak\191e i[ENTER]u nas swoje \156lady. Zaatakowano fort, mury obronne[ENTER]zosta\179y zniszczone w wielu miejscach. Ten pok\243j[ENTER]d\179ugo nie potrwa. Powinni\156my wykorzysta\230 t\234chwil\234[ENTER]spokoju na odbudow\234 zniszcze\241. "
