gameforge.main_quest_lv98._050_say = "Zgoda. Ile pancerzy potrzebujecie? "
gameforge.main_quest_lv98._060_say = "100 sztuk powinno nam wystarczy\230. Plemi\234[ENTER]Skorupiak\243w wci\185\191 koczuje w Nefrytowej Zatoce. "
gameforge.main_quest_lv98._070_say = "Aye, to wci\185\191 za ma\179o pancerzy Skorupiak\243w.[ENTER]Zdob\185d\159 ich wi\234cej. "
gameforge.main_quest_lv98._080_1_notice = "Wyzbiera\179e\156 ju\191 wszystkie pancerze Skorupiak\243w. "
gameforge.main_quest_lv98._080_2_notice = "Przynie\156 je Admira\179owi Angmurowi. "
gameforge.main_quest_lv98._090_say = "Aye, bardzo dobrze. Dzi\234ki pancerzom Skorupiaka[ENTER]b\234dziemy teraz mogli wzmocni\230 nasze mury obronne.[ENTER]Prosz\234, we\159 to w nagrod\234. A ja spytam moich[ENTER]in\191ynier\243w, czy potrzebuj\185 jeszcze jakich\156[ENTER]materia\179\243w i dam ci zna\230. "
gameforge.main_quest_lv98._130_sendLetter = "Odbudowa Fortu "
gameforge.main_quest_lv98._140_say = "Admira\179 Angmur zn\243w potrzebuje twojej pomocy. Id\159[ENTER]do niego. "
gameforge.main_quest_lv98._150_say = "Aby doko\241czy\230 odbudow\234 umocnie\241 potrzebujemy[ENTER]jeszcze W\179\243czni Trytona. Jak ju\191 sama ich nazwa[ENTER]m\243wi, znajdziesz je przy Trytonach. Przynie\156 mi[ENTER]prosz\234 100 sztuk. "
gameforge.main_quest_lv98._160_say = "Zgoda. "
gameforge.main_quest_lv98._170_say = "Ach, tutaj jeste\156! Aye, to wci\185\191 niewystarczaj\185ca[ENTER]ilo\156\230 W\179\243czni Trytona. Zbieraj dalej. "
