gameforge.main_quest_lv98._180_2_notice = "Przenie\156 je Admira\179owi Angmurowi. "
gameforge.main_quest_lv98._190_say = "Wspaniale! Teraz mo\191emy zbudowa\230 rozs\185dne pozycje[ENTER]obronne. Dzi\234kuj\234 ci za pomoc. A tak w og\243le, to[ENTER]Yak- Hwan ci\234 szuka. Dowiedz si\234, czego chce. "
