gameforge.new_christmas._030_say = "S\185 to ci\234\191kie czasy, w kt\243rych przysz\179o nam \191y\230.[ENTER]Nikt nie chce kupowa\230 ksi\185\191ek ani innych rzeczy.[ENTER]A w moim wieku nie mog\234 ju\191 ca\179ymi dniami lata\230[ENTER]zaprz\234giem od domu do domu. Postanowi\179em zatem,[ENTER]\191e w tym roku \140wi\234ta b\234d\234 obchodzi\179 tutaj w[ENTER]wiosce. "
