gameforge.new_christmas._060_say = "Ho ho ho! Mniemam, \191e wiesz, co to jest, co? Nie[ENTER]ma lepszego napoju na srog\185 zim\234! Dobre wino,[ENTER]szczypta cynamonu, par\234 go\159dzik\243w... chlup! "
