gameforge.new_christmas._080_say = "Widz\234, \191e posmakowa\179o, ho ho![ENTER]Czujesz rozgrzewaj\185ce ci\234 ciep\179o? No i ten smak,[ENTER]taki s\179odki i owocowy. Weso\179ych \140wi\185t! "
