gameforge.new_christmas._100_say = "Ach, moment![ENTER]Zapomnia\179em o pewnym szczeg\243le![ENTER]Mog\234 nawarzy\230 ci tylko butl\234 grza\241ca dziennie, na[ENTER]wi\234cej niestety mnie nie sta\230. Grzaniec ten jest[ENTER]zdatny do spo\191ycia przez 20 godzin. Jedna butelka[ENTER]zawiera 6 porcji, a jeden \179yk dzia\179a przez 30[ENTER]minut. Nie wytr\185b zatem wszystkiego na raz! "
