gameforge.new_christmas_sock._070_say = "Ho ho ho, widz\234, \191e masz ju\191 wystarczaj\185c\185 ilo\156\230[ENTER]skarpetek, zaraz je sprawdz\234.[ENTER]Urrrgh, ten zapaszek... Tak, to w\179a\156nie o te[ENTER]skarpetki mi chodzi\179o![ENTER]Weso\179ych \140wi\185t! "
