gameforge.new_quest_lv17._050_say_title = "Wonda-Rim chce obdarowa\230 Chaegiraba... "
gameforge.new_quest_lv17._051_say = "Ca\179a rado\156\230 badacza to mo\191liwo\156\230 przeprowadzenia[ENTER]bada\241. Uszcz\234\156liwisz Chaegiraba, je\156li pomo\191esz[ENTER]mu w jego pracy. Wilk Mu-Rang jest rzadkim[ENTER]go\156ciem w naszym kraju, a jego futro to[ENTER]drogocenny skarb dla ka\191dego biologa. 5 Futer[ENTER]powinno wystarczy\230. Przeka\191 to Wonda-Rimowi. "
gameforge.new_quest_lv17._052_say = "Takie Futro na pewno zrobi wra\191enie na Biologu. "
gameforge.new_quest_lv17._060_select = "Tak, powiem mu. "
gameforge.new_quest_lv17._065_say_title = "Powr\243t do Wonda-Rima "
gameforge.new_quest_lv17._066_say = "Uriel wpad\179 na dobry pomys\179, co mo\191na podarowa\230[ENTER]Chaegirabowi. Wr\243\230 do Wonda-Rima i opowiedz mu o[ENTER]tym. "
gameforge.new_quest_lv17._067_say = "Wonda-Rim znajduje si\234 w %s. "
gameforge.new_quest_lv17._070_say = "Rada Uriela brzmi nie\159le. A poniewa\191 tak bardzo[ENTER]chcia\179bym zrobi\230 mojemu wujkowi niespodziank\234,[ENTER]musz\234 za wszelk\185 cen\234 zdoby\230 te futra. Czy[ENTER]m\243g\179by\156 uda\230 si\234 na \179owy i zabi\230 dla mnie 5[ENTER]Mu-Rang\243w? "
gameforge.new_quest_lv17._071_say = "Musz\234 zabi\230 Wilki Mu-Rang, aby zdoby\230 ich futra. "
gameforge.new_quest_lv17._072_say = "5 sztuk wystarczy, aby zrobi\230 dobry prezent. "
gameforge.new_quest_lv17._073_say = "Do dzie\179a! "
gameforge.new_quest_lv17._074_notice = "Zdoby\179e\156 dobrej jako\156ci Futro. "
gameforge.new_quest_lv17._075_say = "Poluj na Wilki Mu-Rang i zdob\185d\159 ich Futro. "
gameforge.new_quest_lv17._076_say_reward = "Do tej pory zdoby\179e\156 %s z 5 Futer. "
gameforge.new_quest_lv17._081_say_title = "Futra dla Wonda Rima "
gameforge.new_quest_lv17._082_say = "Zdoby\179e\156 ju\191 wystarczaj\185co ilo\156\230 Futer. Dostarcz[ENTER]je teraz Wonda-Rimowi. "
gameforge.new_quest_lv17._092_say_reward = "Zdoby\179e\156 ju\191 %s Futer Wilk\243w. "
gameforge.new_quest_lv17._110_say = "To naprawd\234 pi\234kne Futra. Bardzo ci dzi\234kuj\234.[ENTER]M\243g\179by\156 je zanie\156 mojemu wujkowi Chaegirabowi? "
gameforge.new_quest_lv17._120_target = "Wujek Chaegirab "
gameforge.new_quest_lv17._121_say = "Wonda-Rim poprosi\179 ci\234, aby\156 zani\243s\179 Futra Wilk\243w[ENTER]Chaegirabowi. "
gameforge.new_quest_lv17._122_say = "Chaegirab znajduje si\234 w %s. "
gameforge.new_quest_lv17._130_say = "Aha. A teraz to pr\243buje zrobi\230. "
gameforge.new_quest_lv17._131_say = "Od kogo s\185 Futra? Od Wonda-Rima, ale to ty[ENTER]zabi\179e\156 dla niego Wilki?[ENTER]Wstydz\234 si\234 za mojego bratanka, kt\243ry pozwala,[ENTER]aby inni za niego pracowali. Dlatego te\191 nie[ENTER]przyjm\234 Futer, przykro mi, \191e po\156wi\234ci\179e\156 tyle[ENTER]czasu i trudu. "
gameforge.new_quest_lv17._132_say_reward = "Powiedz Wonda-Rimowi, \191e go przejrza\179em! Je\156li[ENTER]chce mnie uszcz\234\156liwi\230, to niech sam uda si\234 na[ENTER]\179owy. "
gameforge.new_quest_lv17._140_say = "Chaegirab nie przyj\185\179 Futer i jest rozczarowany[ENTER]post\234powaniem Wonda-Rima. Wys\179a\179 ci\234 z powrotem[ENTER]do Wonda-Rima. "
gameforge.new_quest_lv17._141_say = "Co powiedzia\179 m\243j wujek? Mam nadziej\234, \191e podoba\179[ENTER]mu si\234 prezent? "
gameforge.new_quest_lv17._142_1_select = "Tak, by\179 zachwycony! "
gameforge.new_quest_lv17._142_2_select = "Nie, wcale. "
gameforge.new_quest_lv17._143_say = "Ciesz\234 si\234! To wspania\179e uczucie sprawi\230 innym[ENTER]rado\156\230. Oczywi\156cie zostaniesz nagrodzony. Prosz\234[ENTER]przyjmij to! "
gameforge.new_quest_lv17._144_say_reward_a = "Otrzyma\179e\156 20.000 Punkt\243w Do\156wiadczenia.[ENTER]Otrzyma\179e\156 20.000 Yang.[ENTER]Otrzyma\179e\156 Bry\179k\185 Z\179ota "
gameforge.new_quest_lv17._144_say_reward_b = "Ok\179ama\179e\156 Wonda-Rima i dlatego straci\179e\156 Punkty[ENTER]Rangi! "
gameforge.new_quest_lv17._145_say = "Nie przyj\185\179 Futer? Hmm, to nie by\179 zbyt dobry[ENTER]pomys\179, wys\179a\230 ci\234 na polowanie, mog\179em uda\230 si\234[ENTER]sam. Nast\234pnym razem post\185pi\234 inaczej. "
gameforge.new_quest_lv17._146_say_reward = "Ca\179y tw\243j trud przecie\191 nie mo\191e p\243j\156\230 na marne.[ENTER]Najlepiej b\234dzie jak udasz si\234 do Yang-Shina.[ENTER]Odkupi on od ciebie Futra za dobr\185 cen\234. "
gameforge.new_quest_lv17._147_say = "Jaki jestem rozczarowany. Przynajmniej masz[ENTER]jeszcze Futra. Udaj si\234 do my\156liwego Yang-Shina,[ENTER]kt\243ry przebywa w Yayang i sprzedaj mu futra. "
gameforge.new_quest_lv17._148_say = "Jaki jestem rozczarowany. Przynajmniej masz[ENTER]jeszcze Futra. Udaj si\234 do my\156liwego Yang-Shina,[ENTER]kt\243ry przebywa w Bokjung i sprzedaj mu futra. "
gameforge.new_quest_lv17._149_say = "Jaki jestem rozczarowany. Przynajmniej masz[ENTER]jeszcze Futra. Udaj si\234 do my\156liwego Yang-Shina,[ENTER]kt\243ry przebywa w Bakra i sprzedaj mu futra. "
gameforge.new_quest_lv17._151_say = "Futra Mu-Rang? Na pewno przydadz\185 mi si\234. Zrobi\234[ENTER]sobie z nich now\185 bielizn\234. Prosz\234, oto woreczek[ENTER]Yang za tw\243j trud. Sp\243jrz, znalaz\179em wczoraj[ENTER]Ksi\234g\234, mo\191e ci si\234 przyda. "
gameforge.new_quest_lv17._152_say_reward = "Otrzyma\179e\156 40.000 Punkt\243w Do\156wiadczenia.[ENTER]Otrzyma\179e\156 10.000 Yang.[ENTER]Otrzyma\179e\156 Ksi\234g\234 Umiej\234tno\156ci. "
