gameforge.new_quest_lv22._010_target = "Stra\191nik: "
gameforge.new_quest_lv22._011_say = "Stra\191nik Wsi ma zadanie dla ciebie. Udaj si\234 do[ENTER]niego i dowiedz si\234 o co chodzi. "
gameforge.new_quest_lv22._015_npcChat = "Chory Brat "
gameforge.new_quest_lv22._016_send_letter = "Chory Stra\191nik "
gameforge.new_quest_lv22._017_say_title = "Stra\191nik: "
gameforge.new_quest_lv22._018_say_title = "Baek-Go: "
gameforge.new_quest_lv22._019_say_title = "Stra\191nik Wie\191y Demon\243w "
gameforge.new_quest_lv22._021_say = "Martwi\234 si\234 o mojego brata, kt\243ry jest[ENTER]Stra\191nikiem Wie\191y Demon\243w. Ju\191 od pewnego czasu[ENTER]nie czu\179 si\234 najlepiej, a teraz jest powa\191nie[ENTER]chory. Boli go g\179owa, a jego sk\243ra jest[ENTER]zaczerwieniona, ale niestety nie mo\191e opu\156ci\230[ENTER]s\179u\191by. Czy mo\191esz za\179atwi\230 mu lekarstwo od[ENTER]Baek-Go? "
gameforge.new_quest_lv22._022_say = "Sam bym poszed\179, ale Wie\191a Demon\243w znajduje si\234[ENTER]na terenie \140wi\185tyni Hwang, po\156rodku Doliny[ENTER]Seungryong. Tam roi si\234 tylko od niebezpiecznych[ENTER]kreatur... "
gameforge.new_quest_lv22._023_say = "Wr\243ci\179e\156 ju\191. Zapomnia\179e\156 symptomy? Musisz[ENTER]uwa\191niej s\179ucha\230, gdy kto\156 m\243wi co\156 do ciebie.[ENTER]Mojego brata boli g\179owa i ma zaczerwienion\185[ENTER]sk\243r\234. Przeka\191 to Baek-Gowi! "
gameforge.new_quest_lv22._024_select = "Pom\243\191 bratu "
gameforge.new_quest_lv22._025_say_title = "Lekarstwo od Baek-Go "
gameforge.new_quest_lv22._026_say = "Porozmawiaj z Baek-Go o lekarstwie dla Stra\191nika[ENTER]Wie\191y Demon\243w. "
gameforge.new_quest_lv22._027_say = "Baek-Go znajduje si\234 w %s. "
gameforge.new_quest_lv22._030_target = "Baek-Go: "
gameforge.new_quest_lv22._031_say = "Potrzebujesz lekarstwo? Mo\191e zako\241czy\230 si\234[ENTER]gro\159nie, za\191ycie lekarstwa tak w ciemno. Musisz[ENTER]mi powiedzie\230 jakie s\185 symptomy choroby. "
gameforge.new_quest_lv22._032_1_select = "B\243l g\179owy i zaczerwieniona sk\243ra "
gameforge.new_quest_lv22._032_2_select = "B\243l gard\179a oraz skurcze "
gameforge.new_quest_lv22._032_3_select = "Nie wiem. "
gameforge.new_quest_lv22._035_say = "Wydaje mi si\234, \191e to \156wierzb demon\243w. Mo\191na si\234[ENTER]go nabawi\230 od zara\191onych paj\234czakami bestii. Mog\234[ENTER]ci jednak zrobi\230 lekarstwo, kt\243ry mu na pewno[ENTER]pomo\191e. Zdob\185d\159 tylko kilka sk\179adnik\243w. "
gameforge.new_quest_lv22._040_say = "Potrzebuj\234: "
gameforge.new_quest_lv22._041_say_reward = "Musisz polowa\230 na: "
gameforge.new_quest_lv22._042_say = "Potrzebuj\234 te\191: "
gameforge.new_quest_lv22._043_say = "Jeszcze nigdy nie s\179ysza\179em o takiej chorobie.[ENTER]Jeste\156 pewny, \191e Stra\191nik Wsi Demon\243w poda\179 ci[ENTER]prawid\179owe symptomy? Lepiej b\234dzie jak zapytasz[ENTER]si\234 go jeszcze raz. "
gameforge.new_quest_lv22._044_say = "Nie mog\234 postawi\230 prawid\179owej diagnozy, je\156li nie[ENTER]znam symptom\243w. Id\159 i zapytaj si\234 jeszcze raz. "
gameforge.new_quest_lv22._050_set_title = "Lekarstwo "
gameforge.new_quest_lv22._056_notice = "Dobrze, brakuje jeszcze tylko %s p\234czk\243w zi\243\179. "
gameforge.new_quest_lv22._057_notice = "To ju\191 chyba wszystkie Zio\179a. A teraz szybko z[ENTER]powrotem do Baek-Go. "
gameforge.new_quest_lv22._058_notice = "Dobrze, teraz brakuje jeszcze jedynie %s w\185tr\243b. "
gameforge.new_quest_lv22._060_notice = "Ach! W\185troba. Brakuje mi jeszcze %s. "
gameforge.new_quest_lv22._061_notice = "To ju\191 chyba wszystkie W\185troby. A teraz szybko z[ENTER]powrotem do Baek-Go. "
gameforge.new_quest_lv22._062_notice = "Niestety, ale tej W\185troby nie mog\234 u\191y\230. "
gameforge.new_quest_lv22._063_say = "Potrzebujesz jeszcze %s x Zio\179a Lecznicze. "
gameforge.new_quest_lv22._064_say = "Potrzebujesz jeszcze %s x W\185troby Tygrysa. "
gameforge.new_quest_lv22._065_say = "Posiadasz ju\191 wszystkie sk\179adniki potrzebne do[ENTER]przyrz\185dzenia Lekarstwa. Udaj si\234 do Baek-Go i[ENTER]przeka\191 mu je. "
gameforge.new_quest_lv22._066_say = "Zbierz sk\179adniki, kt\243re potrzebuje Baek-Go do[ENTER]przyrz\185dzenia Lekarstwa: "
gameforge.new_quest_lv22._070_say = "Dzi\234kuj\234, teraz mog\234 przyrz\185dzi\230 Lekarstwo na[ENTER]\156wierzb demon\243w. "
gameforge.new_quest_lv22._071_say = "Gotowe! Oto Lekarstwo. Pami\234taj jednak, \191e[ENTER]przyrz\185dzi\179em ze \156wie\191ych sk\179adnik\243w i dlatego[ENTER]musisz je dostarczy\230 choremu w ci\185gu %s minut! "
gameforge.new_quest_lv22._072_say = "Brata Stra\191nika Wie\191y Demon\243w znajdziesz po\156rodku[ENTER]\140wi\185tyni Hwang. B\185d\159 jednak ostro\191ny - Dolin\234[ENTER]Seungryong zamieszkuj\185 gro\159ne kreatury! "
gameforge.new_quest_lv22._073_say = "To nie wszystkie. Zgubi\179e\156 po drodze jakie\156[ENTER]sk\179adniki? Musz\234 mie\230 wszystkie sk\179adniki, w[ENTER]przeciwnym razie nie b\234d\234 ci m\243g\179 pom\243c. "
gameforge.new_quest_lv22._080_target = "Stra\191nik Wie\191y Demon\243w "
gameforge.new_quest_lv22._082_set_clock = "Pozosta\179y czas "
gameforge.new_quest_lv22._083_say = "Wprawdzie masz jeszcze czasu, ale musisz si\234[ENTER]troch\234 po\156pieszy\230. Ruszaj do Seungryong, do[ENTER]Stra\191nika Wie\191y Demon\243w, zanim Lekarstwo si\234[ENTER]ca\179kiem zepsuje. "
gameforge.new_quest_lv22._084_say = "By\179e\156 zbyt powolny i czas ju\191 min\185\179. Dostarcz[ENTER]jednak Lekarstwo Stra\191nikowi Wie\191y Demon\243w, mo\191e[ENTER]jeszcze zadzia\179a. "
gameforge.new_quest_lv22._085_say = "Dzi\234kuj\234 za przyniesienie mi Lekarstwa. Tak mnie[ENTER]wszystko sw\234dzi i ju\191 powoli wariuj\234. "
gameforge.new_quest_lv22._086_say = "Och, nie\159le smakuje! Czuj\234, \191e przestaje mnie[ENTER]sw\234dzi\230. "
gameforge.new_quest_lv22._087_say = "Zas\179u\191y\179e\156 na wyj\185tkow\185 nagrod\234! "
gameforge.new_quest_lv22._088_say_reward = "Otrzyma\179e\156 50.000 Punkt\243w Do\156wiadczenia.[ENTER]Otrzyma\179e\156 12.000 Yang.[ENTER]Otrzyma\179e\156 Buty Wyszywane Z\179otem+4.[ENTER]Otrzyma\179e\156 5 Fioletowych Mikstur. "
gameforge.new_quest_lv22._089_say = "Ble, co za okropie\241stwo! Lekarstwo jest zepsute -[ENTER]jak d\179ugo tutaj szed\179e\156? Smakuje jak skwa\156nia\179e[ENTER]mleko. "
gameforge.new_quest_lv22._090_say = "Hmm, czekaj... wydaje mi si\234, \191e jest lepiej.[ENTER]Tak, dzia\179a! W takim razie otrzymasz nagrod\234. "
gameforge.new_quest_lv22._091_say = "Wygl\185da na to, \191e zgubi\179e\156 Lekarstwo. Prosz\234,[ENTER]udaj si\234 jeszcze raz na polowanie i zdob\185d\159[ENTER]sk\179adniki potrzebne do przyrz\185dzenia nowego[ENTER]Lekarstwa i dostarcz je Baek-Gonowi. W przeciwnym[ENTER]razie sam stan\234 si\234 demonem, bo d\179u\191ej nie[ENTER]wytrzymam tego b\243lu. "
gameforge.new_quest_lv22._095_say_reward = "Otrzyma\179e\156 50.000 Punkt\243w Do\156wiadczenia.[ENTER]Otrzyma\179e\156 8.000 Yang. "
gameforge.new_quest_lv22._098_say = "Jak to, znowu zgubi\179e\156 lekarstwo? W \191yciu nie[ENTER]spotka\179em wi\234kszej fajt\179apy! Ale c\243\191, m\243wi si\234[ENTER]trudno i \191yje si\234 dalej. "
gameforge.new_quest_lv22._100_say_reward = "Otrzymujesz 25.000 Punkt\243w Do\156wiadczenia. "
gameforge.new_quest_lv26 = {}
gameforge.new_quest_lv26._010_target = "Yang-Shin: "
gameforge.new_quest_lv26._020_say_title = "Yang-Shin: "
gameforge.new_quest_lv26._020_set_title = "Dezerter "
gameforge.new_quest_lv26._021_say = "My\156liwy Yang-Shin ma problem ze znalezieniem[ENTER]dobrej zdobyczy. Id\159 do niego i dowiedz si\234, czy[ENTER]mo\191e mu jako\156 pom\243c. "
gameforge.new_quest_lv26._025_say = "Odk\185d pojawi\179y si\234 Kamienie Metin wszystko[ENTER]zmieni\179o si\234 woko\179o. W wielu okolicach nie mo\191na[ENTER]ju\191 polowa\230, poniewa\191 dzikie zwierz\234ta zachowuj\185[ENTER]si\234 jakby by\179y w\156ciek\179e. Gdzie\156 jednak w okolicy[ENTER]mieszka W\234drowiec Nakajima i jestem przekonany,[ENTER]\191e on wie, gdzie mo\191na jeszcze co\156 dobrego[ENTER]upolowa\230. Odszukaj go i zapytaj si\234 go. "
gameforge.new_quest_lv26._030_target = "Nakajima: "
gameforge.new_quest_lv26._031_say = "A wi\234c chcesz wiedzie\230, gdzie najlepiej polowa\230?[ENTER]Nie tak szybko. Musisz wy\156wiadczy\230 mi przys\179ug\234,[ENTER]je\156li chcesz, abym ci to powiedzia\179. "
gameforge.new_quest_lv26._032_say = "Musisz o tym wiedzie\230... nie \191yj\234 tutaj[ENTER]dobrowolnie. Ukrywam si\234, poniewa\191 uciek\179em przed[ENTER]okrucie\241stwem wojska. Tak bardzo bym chcia\179, aby[ENTER]moje ukochana \191ona Ah-Yu wiedzia\179a, \191e \191yj\234. Czy[ENTER]m\243g\179by\156 jej przekaza\230 t\185 wiadomo\156\230?[ENTER]Ale pami\234taj, powiedz o tym tylko Ah-Yu! Niech ci[ENTER]zdradzi za to miejsce, gdzie j\185 po raz pierwszy[ENTER]poca\179owa\179em - tam chcia\179bym si\234 z ni\185 spotka\230 i[ENTER]tam znajdziesz swoj\185 zdobycz. "
gameforge.new_quest_lv26._034_say_title = "Nakajima: "
gameforge.new_quest_lv26._035_say_title = "Ah-Yu: "
gameforge.new_quest_lv26._036_say_title = "Odszukaj Nakajima "
gameforge.new_quest_lv26._037_say = "Nakajima powinien wiedzie\230, gdzie mo\191na upolowa\230[ENTER]dobr\185 zdobycz. "
gameforge.new_quest_lv26._038_say = "Nakajima znajduje si\234 w %s. "
gameforge.new_quest_lv26._040_say = "To ty jeste\156 Nakajima? Przys\179a\179 mnie Yang-Shin![ENTER]Szuka on dobrego miejsca na \179owy. Mo\191e wiesz,[ENTER]gdzie jest bezpiecznie? "
gameforge.new_quest_lv26._050_target = "Ah-Yu: "
gameforge.new_quest_lv26._051_say = "Nakajima jest dezerterem i musi si\234 ukrywa\230 przed[ENTER]wojskiem. Jego \191ona Ah-Yu my\156li, \191e zgin\185\179 na[ENTER]wojnie. Przeka\191 jej radosn\185 nowin\234, \191e Nakajima[ENTER]\191yje. "
gameforge.new_quest_lv26._052_say = "Ah-Yu znajduje si\234 w %s. "
gameforge.new_quest_lv26._057_say = "Nakajima... \191yje? M\243j ukochany m\185\191 \191yje? Och,[ENTER]dzi\234kuj\234 ci za wspania\179\185 wiadomo\156\230! To miejsce, o[ENTER]kt\243rym wspomina\179, to Dolinia Yonjang. Natychmiast[ENTER]wyruszam w drog\234, aby si\234 z nim tam spotka\230. "
gameforge.new_quest_lv26._058_say = "Dzi\234kuj\234, \191e umo\191liwi\179e\156 nam spotkanie. Prosz\234,[ENTER]przejmij r\243\191\234... i mo\191e podarujesz j\185 ukochanej[ENTER]osobie? A teraz... wybacz mi, ale musz\234 si\234[ENTER]po\156pieszy\230! "
gameforge.new_quest_lv26._061_say = "Dolina Yonjang, gdzie Nakajima poca\179owa\179 po raz[ENTER]pierwszy Ah-Yu - jeszcze do tej pory jest[ENTER]znakomitym terenem \179owieckim. "
gameforge.new_quest_lv26._062_say = "Yang-Shin b\234dzie zadowolony, gdy us\179yszy[ENTER]wiadomo\156\230. Udaj si\234 do %s i przeka\191 mu zdobyte[ENTER]informacje. "
gameforge.new_quest_lv26._063_say = "Dolina Yonjang? To mo\191e by\230 prawda. Jak do tej[ENTER]pory jeszcze nie s\179ysza\179em, aby tam pojawi\179 si\234[ENTER]Kamie\241 Metin i zatru\179 tereny. Jestem pewien, \191e[ENTER]nied\179ugo upoluj\234 wspania\179\185 zdobycz! A oto[ENTER]zas\179u\191ona nagroda. "
gameforge.new_quest_lv26._064_sayReward = "Otrzyma\179e\156 35.000 Punkt\243w Do\156wiadczenia. "
gameforge.new_quest_lv26._065_sayReward = "Otrzyma\179e\156 17.500 Yang. "
gameforge.new_quest_lv28 = {}
gameforge.new_quest_lv28._010_target = "Yu-Hwan: "
gameforge.new_quest_lv28._011_say = "Muzyk Yu-Hwan potrzebuje twojej pomocy. Udaj si\234[ENTER]natychmiast w drog\234, aby sprawdzi\230 co si\234 tam[ENTER]dzieje! "
gameforge.new_quest_lv28._015_npcChat = "Zmartwienia Ah-Yu "
gameforge.new_quest_lv28._016_say = "Wygl\185da na to, \191e Ah-Yu martwi si\234 czym\156, lecz[ENTER]nie chce zwierzy\230 si\234 Yu-Hwanowi. Id\159 do niej,[ENTER]mo\191e tobie powie. "
gameforge.new_quest_lv28._017_say = "Ah-Yu znajduje si\234 w %s. "
gameforge.new_quest_lv28._018_select = "Zaraz pogadam z Ah-Yu! "
gameforge.new_quest_lv28._019_say_title = "Ah-Yu: "
gameforge.new_quest_lv28._020_say_title = "Yu-Hwan: "
gameforge.new_quest_lv28._021_say = "Znasz Ah-Yu? Zbiera zio\179a do moich mikstur. Do[ENTER]tej pory by\179a ona zawsze pogodna i weso\179a, ale od[ENTER]wczoraj wydaje mi si\234, \191e martwi si\234 czym\156[ENTER]okropnie. Niestety, nie chce rozmawia\230 ze mn\185 o[ENTER]swych k\179opotach, mo\191e dlatego, \191e pracuje dla[ENTER]mnie? Prosz\234, id\159 do niej i dowiedz si\234 jak si\234[ENTER]czuje. Mo\191e tobie si\234 zwierzy. "
gameforge.new_quest_lv28._022_say = "To mi\179o ze strony Yu-Hwan, \191e martwi si\234 o mnie.[ENTER]Tak, mam co\156 na sercu... nie chcia\179am o tym[ENTER]m\243wi\230, ale nie mog\234 ju\191 d\179u\191ej tego ukrywa\230![ENTER]Chodzi o Yang-Shin, tego my\156liwego, szanta\191uje[ENTER]mnie, odk\185d dowiedzia\179 si\234, \191e m\243j m\185\191 Nakajima[ENTER]jest dezerterem. Yang-Shin grozi, \191e go wyda! Oni[ENTER]go przecie\191 zabij\185... "
gameforge.new_quest_lv28._023_say = "Teraz \191\185da on za swoje milczenie \163ap\234[ENTER]Nied\159wiedzia. Ale ja nie mog\234 przecie\191 i\156\230 na[ENTER]polowanie. Pomo\191esz mi zdob\185d\159 to co \191\185da[ENTER]Yang-Shin? "
gameforge.new_quest_lv28._024_set_title = "Polowanie na nied\159wiedzie "
gameforge.new_quest_lv28._025_notice = "Na polowanie! Upolowanie nied\159wiedzia to[ENTER]najlepsza mo\191liwo\156\230 zdobycia \163apy Nied\159wiedzia. "
gameforge.new_quest_lv28._026_notice = "Zdoby\179em \163ap\234 Nied\159wiedzia! "
gameforge.new_quest_lv28._027_notice = "To wszystko. A teraz do Yang-Shin! "
gameforge.new_quest_lv28._028_notice = "\163apa tego Nied\159wiedzia by\179a bezu\191yteczna. "
gameforge.new_quest_lv28._029_say = "Potrzebujesz jeszcze %s x \163apy Nied\159wiedzia. "
gameforge.new_quest_lv28._031_say_reward = "Musisz polowa\230 na: "
gameforge.new_quest_lv28._032_say = "Ah-Yu poprosi\179a ci\234 o spe\179nienie \191\185dania[ENTER]Yang-Shina. "
gameforge.new_quest_lv28._032_say_reward = "Potrzebujesz jeszcze %s x \163apy Nied\159wiedzi.[ENTER]Poluj na Nied\159wiedzie, aby je zdoby\230. "
gameforge.new_quest_lv28._035_target = "Yang-Shin: "
gameforge.new_quest_lv28._036_say = "Zdoby\179e\156 \191\185dane \163apy Nied\159wiedzia. Zanie\156 je do[ENTER]Yang-Shin i sp\179a\230 d\179ug Ah-Yue. "
gameforge.new_quest_lv28._037_say = "Yang-Shin znajduje si\234 w %s. "
gameforge.new_quest_lv28._038_say_title = "Yang-Shin: "
gameforge.new_quest_lv28._040_npcChat = "Szanta\191 "
gameforge.new_quest_lv28._041_say_title = "\163apy Nied\159wiedzi "
gameforge.new_quest_lv28._042_say = "Przynios\179e\156 mi kilka \163ap Nied\159wiedzia? Prosz\234 nie[ENTER]my\156l \159le o mnie! \175yjemy w ci\234\191kich czasach i[ENTER]musz\234 przecie\191 wi\185za\230 koniec z ko\241cem.[ENTER]Szczeg\243lnie teraz, kiedy ci\234\191ko o dzik\185 zwierzyn\234[ENTER]lub poprzez Kamienie Metin przeistacza si\234 ona w[ENTER]okrutne bestie. \175ycie my\156liwego sta\179o si\234[ENTER]niebezpieczne. "
gameforge.new_quest_lv28._043_say = "Prosz\234, przeka\191 Ah-Yu, \191e nie musi si\234 ju\191[ENTER]niczego obawia\230. Mo\191e by\230 tego pewna.[ENTER]Przynajmniej do czasu, kiedy zn\243w b\234d\234 co\156[ENTER]potrzebowa\179... hahaha! "
gameforge.new_quest_lv28._044_say = "Co, chcesz mnie zby\230? A gdzie m\243j \179up? \175\185da\179em[ENTER]przecie\191 \156wie\191ych \163ap Nied\159wiedzia. "
gameforge.new_quest_lv28._045_say_reward = "Mi\179o z twojej strony, \191e pomagasz Ah-Yu. Oznacza[ENTER]to jednak dla ciebie, \191e musisz robi\230 co ci ka\191\234.[ENTER]Ruszaj na polowanie i nie pokazuj mi si\234 na oczy[ENTER]dop\243ki nie przyniesiesz mi dw\243ch \163ap[ENTER]Nied\159wiedzia! "
gameforge.new_quest_lv28._046_say = "Przeka\191 Ah-Yu dobr\185 nowin\234, \191e dzi\234ki twojej[ENTER]pomocy Yang-Shin przesta\179 j\185 szanta\191owa\230. "
gameforge.new_quest_lv28._051_say = "Jeste\156 naszym wybawc\185! Jestem ci dozgonnie[ENTER]wdzi\234czna. Prosz\234, to m\243j Yang. Zabierz,[ENTER]wprawdzie nie jest zbyt du\191o, ale w pe\179ni[ENTER]zas\179u\191y\179e\156 na niego. "
gameforge.new_quest_lv28._055_1_select = "Dzi\234kuj\234, przyda mi si\234! "
gameforge.new_quest_lv28._055_2_select = "Nie mog\234 tego przyj\185\230. "
gameforge.new_quest_lv28._056_say = "To wszystko co mam. Ale je\156li dzi\234ki temu pozb\234d\234[ENTER]si\234 raz na zawsze tego wyzyskiwacza, to jest to[ENTER]tego warte. "
gameforge.new_quest_lv28._057_say = "Och, dzi\234kuj\234! Za to co zrobi\179e\156, zapewnisz sobie[ENTER]miejsce przy boku Boga Smoka! "
gameforge.new_quest_lv28._058_say_reward = "Otrzyma\179e\156 %s Yang. "
gameforge.new_quest_lv28._059_say_reward = "Otrzyma\179e\156 %s Punkt\243w Do\156wiadczenia. "
gameforge.new_quest_lv28._070_say = "Potrzebuj\234: "
gameforge.new_quest_lv29 = {}
gameforge.new_quest_lv29._010_target = "Yonah: "
gameforge.new_quest_lv29._015_npcChat = "Rozbita Porcelana "
gameforge.new_quest_lv29._020_say_title = "Yonah: "
gameforge.new_quest_lv29._021_say = "Moja ulubiona Seledynowa Porcelana! Ju\191 od trzech[ENTER]pokole\241 znajduje si\234 w mojej rodzinie, a teraz[ENTER]zosta\179y rozbite trzy drogocenne wazy. Niedawno[ENTER]zauwa\191y\179em Taurean, tego nicponia, jak skrada\179[ENTER]si\234 do magazynu. Jestem przekonany, \191e to jego[ENTER]sprawka! "
gameforge.new_quest_lv29._022_say = "To nie pierwsza jego wybryk, ale tym razem[ENTER]przesadzi\179. Kto\156 powinien mu w ko\241cu sprawi\230[ENTER]lanie! Masz na to czas? "
gameforge.new_quest_lv29._023_1_select = "Z przyjemno\156ci\185! "
gameforge.new_quest_lv29._023_2_select = "Nie nie moja sprawa. "
gameforge.new_quest_lv29._024_say = "Nie mam czasu na wychowywanie niegrzecznych[ENTER]dzieciak\243w. Sam musisz go z\179apa\230. W\185tpi\234 jednak,[ENTER]czy dasz rad\234... "
gameforge.new_quest_lv29._030_target = "Taurean: "
gameforge.new_quest_lv29._031_say = "Drogocenne pami\185tki rodzinne Yonaha, kto\156 rozbi\179[ENTER]wspania\179e trzy Wazy z Seledynowej Porcelany.[ENTER]Yonah jest przekonany, \191e to sprawka Taureana.[ENTER]Udaj si\234 do Taureana i dowiedz si\234, czy to prawda. "
gameforge.new_quest_lv29._032_say = "Taurean znajduje si\234 w %s. "
gameforge.new_quest_lv29._033_say_title = "Taurean: "
gameforge.new_quest_lv29._034_say_reward = "Dlaczego spogl\185dasz na mnie tak ponuro? Nic[ENTER]przecie\191 z\179ego nie zrobi\179em... "
gameforge.new_quest_lv29._035_say_reward = "Co zrobi\179e\156 z Wazami Yonaha? "
gameforge.new_quest_lv29._036_say_reward = "Wazami? Yonah? Naprawd\234 nie wiem o czym m\243wisz... "
gameforge.new_quest_lv29._037_say_reward = "To wyt\179umacz mi, dlaczego trzy s\185 rozbite. "
gameforge.new_quest_lv29._038_say_reward = "Przysi\234gam, dzisiaj nie widzia\179em na oczy ani[ENTER]Wazy ani Yonah. Ca\179y dzie\241 walczy\179em z Harang.[ENTER]Nawet zamkn\234\179a mnie na kilka godzin w stogu[ENTER]siana! Id\159 do niej i zapytaj si\234! Nie k\179ami\234! "
gameforge.new_quest_lv29._040_target = "Harang: "
gameforge.new_quest_lv29._041_say = "Taurean twierdzi, \191e jest niewinny. Powiedzia\179,[ENTER]\191e bawi\179 si\234 przez ca\179y dzie\241 z Harang, dlatego[ENTER]te\191 nie mia\179 sposobno\156ci rozbi\230 tych Waz. Id\159 do[ENTER]Harang i zapytaj si\234 czy to prawda. "
gameforge.new_quest_lv29._042_say_reward = "Harang, widzia\179a\156 dzisiaj Taureana? "
gameforge.new_quest_lv29._043_say_title = "Harang: "
gameforge.new_quest_lv29._044_say_reward = "Taurean? Pewnie, bawili\156my si\234 przez ca\179y dzie\241.[ENTER]Co\156 nie tak? "
gameforge.new_quest_lv29._045_say_reward = "Yonah twierdzi, \191e Taurean zbi\179 trzy Wazy. "
gameforge.new_quest_lv29._046_say_reward = "Yonah jest pod\179y. Natychmiast przep\234dza mnie i[ENTER]Taurean jak tylko podejdziemy bli\191ej. Ci\185gle boi[ENTER]si\234 o swoj\185 porcelan\234. Jego drogocenne Wazy mo\191e[ENTER]dotkn\185\230 tylko jego przyjaciel, kt\243ry jest[ENTER]stajennym. Mo\191e on je rozbi\179?! "
gameforge.new_quest_lv29._047_say = "Harang znajduje si\234 w %s. "
gameforge.new_quest_lv29._050_target = "Stajenny: "
gameforge.new_quest_lv29._051_say = "Harang potwierdzi\179a s\179owa Taureana. Jest[ENTER]niewinny, ale mo\191e s\185 oni w zmowie. Zanim jednak[ENTER]oskar\191ysz kogo\156, zapytaj si\234 jeszcze przyjaciela[ENTER]Yonaha, kt\243ry jest stajennym. "
gameforge.new_quest_lv29._052_say = "Ach, ten poczciwy Yonah. Marti si\234 o swoj\185[ENTER]porcelan\234 i podejrzewa dzieciaki z wioski. Winne[ENTER]s\185 jednak Kamienie Metin, odk\185d zatru\179y nasz kraj[ENTER]nie s\185 nasze surowce takie jak dawniej. Nawet[ENTER]porcelana sta\179a si\234 bardziej krucha. Jednak Yonah[ENTER]nie chce o tym s\179ysze\230... "
gameforge.new_quest_lv29._053_say = "Je\156li nazbierasz dla niego troch\234 Siana, to[ENTER]wy\156cieli nim swoj\185 skrzyni\234 z porcelan\185. W ten[ENTER]spos\243b udobruchasz go znowu. "
gameforge.new_quest_lv29._054_say = "Stajenny znajduje si\234 w[ENTER]%s lub w %s. "
gameforge.new_quest_lv29._061_say = "To nie winna Taureana, \191e Porcelana Yonaha jest[ENTER]rozbita. To promieniowanie Kamieni Metin wp\179ywa[ENTER]na to, \191e wszystko staje si\234 tak bardzo kruche.[ENTER]Nazbieraj Siana dla Yonaha, aby m\243g\179 bezpieczniej[ENTER]przechowywa\230 swoj\185 porcelan\234! Kilku mieszka\241c\243w[ENTER]wioski na pewno b\234dzie w stanie ci troch\234[ENTER]odst\185pi\230. "
gameforge.new_quest_lv29._062_say = "Przy wej\156ciu do wioski znajdziesz %s oraz %s.[ENTER]Maj\185 na sobie kapelusze s\179omkowe, z kt\243rych na[ENTER]pewno uzyskasz wystarczaj\185c\185 ilo\156\230 Siana. "
gameforge.new_quest_lv29._063_notice = "To b\234dzie pi\234kna wi\185zka Siana. A teraz brakuje mi[ENTER]jeszcze tylko %s. "
gameforge.new_quest_lv29._064_notice = "Kapelusz nie jest zrobiony ze s\179omy tylko z[ENTER]w\179\243kien kokosowych. A one nie przydadz\185 mi si\234 na[ENTER]nic. "
gameforge.new_quest_lv29._065_1_say = "Jak widz\234, masz sporo Siana. Je\156li dasz troch\234[ENTER]Yonahowi, to na pewno si\234 uspokoi. "
gameforge.new_quest_lv29._065_notice = "Kapelusz nie jest zrobiony z Siana tylko z[ENTER]w\179\243kien kokosowych. A do tego jest mocno[ENTER]uszkodzony... "
gameforge.new_quest_lv29._066_say = "Mo\191esz zabi\230 Dzikich \175o\179nierzy Piechoty lub[ENTER]Silnych Dzikich Piechur\243w i z ich kapeluszy[ENTER]uzyskasz Siano. "
gameforge.new_quest_lv29._067_say_reward = "Do tej pory zebra\179e\156 %s z %s wi\185zek Siana. "
gameforge.new_quest_lv29._068_notice = "Zdoby\179e\156 troch\234 Siana. "
gameforge.new_quest_lv29._070_npcChat = "St\243g siana "
gameforge.new_quest_lv29._071_say_reward = "Taurean, wspomnia\179e\156 wcze\156niej, \191e by\179e\156 w stogu[ENTER]siana. Zabra\179e\156 ze sob\185 przypadkowo troch\234 Siana? "
gameforge.new_quest_lv29._072_say_reward = "Haha, zobaczmy... by\179o w moich w\179osach i butach.[ENTER]Widzisz? Tutaj jest jeszcze wi\234cej, we\159 je! "
gameforge.new_quest_lv29._073_notice = "To nie za wiele siana, ale powinno wystarczy\230 na[ENTER]ma\179\185 wi\185zk\234. Teraz musz\234 zdoby\230 jeszcze %s. "
gameforge.new_quest_lv29._074_say_reward = "To nie by\179em ja! Nie powiedzia\179a ci Harang, \191e[ENTER]bawili\156my si\234 w stogu siana? "
gameforge.new_quest_lv29._075_say_reward = "By\179e\156 wcze\156niej przecie\191 w stogu siana? Nie[ENTER]zabra\179e\156 troch\234 Siana ze sob\185? "
gameforge.new_quest_lv29._076_say_reward = "Sk\185d wiesz o tym stogu siana? Nadal mam siano na[ENTER]moim ubraniu? Oh tak, tutaj jest troszk\234! "
gameforge.new_quest_lv29._077_say_reward = "Czy mog\234 je wzi\185\230? "
gameforge.new_quest_lv29._078_say_reward = "Niewa\191ne... "
gameforge.new_quest_lv29._079_say_reward = "Nie mam teraz czasu. Musz\234 i\156\230 do Taureana i[ENTER]uspokoi\230 go z powodu tej ca\179ej historii z Wazami! "
gameforge.new_quest_lv29._080_npcChat = "Siano dla Yonah "
gameforge.new_quest_lv29._081_say_reward = "Jest w oborze jeszcze siano, kt\243re m\243g\179bym zanie\156[ENTER]Yonahowi? "
gameforge.new_quest_lv29._082_say_title = "Stajenny: "
gameforge.new_quest_lv29._083_say_reward = "Nie mamy zbyt du\191o Siana. Dzikie zwierz\234ta i[ENTER]bandyci z poza wioski przeszkadzaj\185 nam w \156ci\234ciu[ENTER]nowego. "
gameforge.new_quest_lv29._084_say_reward = "Ale mog\234 Ci troch\234 da\230! "
gameforge.new_quest_lv29._085_notice = "To naprawd\234 niewiele, ale chocia\191 wystarczy na[ENTER]jedn\185 wi\185zk\234. Teraz potrzebuj\234 jeszcze %s. "
gameforge.new_quest_lv29._086_say_reward = "Obawiam si\234, \191e nie mog\234 nic wi\234cej dla Ciebie[ENTER]zrobi\230. "
gameforge.new_quest_lv29._090_send_letter = "Siano zamiast lania "
gameforge.new_quest_lv29._091_say = "Zebra\179e\156 odpowiedni\185 ilo\156\230 Siana dla Yonah. Id\159 i[ENTER]zanie\156 je do %s. "
gameforge.new_quest_lv29._101_say_reward = "To nie jest wina Taurean. Promieniowanie[ENTER]wydobywaj\185ce si\234 z Kamieni Metin spowodowa\179o, \191e[ENTER]porcelana jest taka krucha. "
gameforge.new_quest_lv29._102_say_title = "Yonah: "
gameforge.new_quest_lv29._103_say_reward = "Co powiedzia\179e\156? To bzdury! Ten ma\179y nier\243b[ENTER]ok\179ama\179 ci\234. "
gameforge.new_quest_lv29._104_say_reward = "Taurean bawi\179 si\234 ca\179y dzie\241 w stogu siana razem[ENTER]z Harang. "
gameforge.new_quest_lv29._105_say_reward = "Mam ci\234 pozdrowi\230 od stajennego, twojego[ENTER]przyjaciela, a poza tym przynios\179em ci troch\234[ENTER]Siana, aby\156 m\243g\179 lepiej zabezpieczy\230 Wazy. "
gameforge.new_quest_lv29._106_say_reward = "Musz\234 przyzna\230, wstyd mi, za to jak si\234[ENTER]zachowa\179em. Ale musisz wiedzie\230, \191e Porcelana[ENTER]jest dla mnie drogocenn\185 pami\185tk\185 po mojej[ENTER]rodzinie. Je\156li jedna z Waz zostanie rozbita to[ENTER]oznacza to dla mnie wi\234cej, ni\191 stracony[ENTER]przedmiot... "
gameforge.new_quest_lv29._107_say_reward = "Musz\234 przeprosi\230 Ciebie i Taurean. Trzymaj, to[ENTER]ma\179a nagroda za Twoje wysi\179ki. "
gameforge.new_quest_lv29._108_notice = "Otrzyma\179e\156 bonus w postaci %s Punkt\243w[ENTER]Do\156wiadczenia! "
gameforge.new_quest_lv29._109_say_reward = "Mam ci\234 pozdrowi\230 od stajennego, twojego[ENTER]przyjaciela, a poza tym przynios\179em ci troch\234[ENTER]Siana, aby\156 m\243g\179 lepiej zabezpieczy\230 Wazy. "
gameforge.new_quest_lv29._110_say_reward = "To bardzo mi\179o z twojej strony, ale czy m\243g\179by\156[ENTER]mi przynie\156 jeszcze %s wi\185zek Siana? Chc\234 by\230[ENTER]pewny, \191e moje Wazy s\185 dobrze zabezpieczone. "
gameforge.new_quest_lv29._111_say_reward = "Przypuszczam, \191e b\234dzie trudno zdoby\230 jeszcze[ENTER]wi\234cej Siana. Ale moje Wazy s\185 dla mnie[ENTER]\156wi\234to\156ci\185. B\234d\234 ci za to bardzo wdzi\234czny i[ENTER]otrzymasz ode mnie troch\234 Yang. "
gameforge.new_quest_lv29._112_say_reward = "Ten dzieciak, Harang, jest na pewno w zmowie z[ENTER]Taurean. "
gameforge.new_quest_lv29._113_say_reward = "Wygl\185da na to, \191e nikt tutaj mi nie uwierzy,[ENTER]je\156li powiem, \191e widzia\179em ch\179opca w pobli\191u[ENTER]magazynu. "
gameforge.new_quest_lv29._114_say_reward = "Zapomnij ju\191. Oto rekompensowana za tw\243j trud. "
gameforge.new_quest_lv29._115_say_reward = "Tutaj, %s Yang. "
gameforge.new_quest_lv42 = {}
gameforge.new_quest_lv42._010_send_letter = "Burrrrrczy "
gameforge.new_quest_lv42._020_target = "Octavio: "
gameforge.new_quest_lv42._021_say = "Kiszki mi marsza graj\185. Mo\191e powinienem wst\185pi\230[ENTER]do Octavio. Przyrz\185dza on jak nikt na \156wiecie[ENTER]najlepsz\185 zup\234 rybn\185. "
gameforge.new_quest_lv42._022_say_title = "Octavio: "
gameforge.new_quest_lv42._023_say = "Chcia\179by\156 zup\234 rybn\185? T\185 z ca\179ymi g\179owami ryb?[ENTER]Och, przykro mi, ale ju\191 od kilku dni nie[ENTER]przyrz\185dza\179em w mojej kuchni ryb. Zwykle Rybak[ENTER]dostarcza mi do mojej zupy dobrej jako\156ci ryby. "
gameforge.new_quest_lv42._024_say = "Ale ju\191 od pewnego czasu nie widzia\179em go. Czy[ENTER]poszed\179by\156 do niego i sprawdzi\179, co si\234 z nim[ENTER]dzieje? "
gameforge.new_quest_lv42._025_say = "Octavio jest w %s. "
gameforge.new_quest_lv42._026_select = "Id\234 poszuka\230 rybaka! "
gameforge.new_quest_lv42._030_target = "Rybak: "
gameforge.new_quest_lv42._031_say = "Min\234\179y ju\191 spokojne dni na morzu! Codziennie[ENTER]znikaj\185 rybacy bez \156ladu! Okropno\156\230! Od czasu[ENTER]kiedy to Kamienie Metin wpad\179y do morza zmieni\179y[ENTER]si\234 \179agodne wieloryby w krwio\191ercze potwory[ENTER]morza. \163owienie ryb sta\179o si\234 teraz bardzo[ENTER]niebezpieczne. "
gameforge.new_quest_lv42._032_say = "Nie mo\191emy ju\191 zrani\230 wieloryb\243w naszymi[ENTER]Harpunami Ich sk\243ra sta\179a si\234 twardsza ni\191 ogra! "
gameforge.new_quest_lv42._033_say = "Mo\191e Yonah b\234dzie wiedzia\179, co zrobi\230. Kiedy\156 sam[ENTER]zwyk\179 wyp\179ywa\230 na morze i polowa\230 na wieloryby. "
gameforge.new_quest_lv42._034_say_title = "Rybak: "
gameforge.new_quest_lv42._035_say = "Octavio czeka na wyj\185tkow\185 ryb\234 z g\179\234bin. Spytaj[ENTER]Rybaka dlaczego dostawa si\234 op\243\159nia. "
gameforge.new_quest_lv42._036_say = "Rybak jest w %s. "
gameforge.new_quest_lv42._037_send_letter = "Rozgniewane potwory morza "
gameforge.new_quest_lv42._038_say = "Rybak poprosi\179 Ci\234, aby\156 spyta\179 Yonah o rad\234, jak[ENTER]polowa\230 na z\179e Wieloryby. "
gameforge.new_quest_lv42._039_say = "Yonah znajduje si\234 w %s. "
gameforge.new_quest_lv42._040_target = "Yonah: "
gameforge.new_quest_lv42._041_say = "S\179ysza\179em ju\191, co sta\179o si\234 z wielorybami. Dla[ENTER]Rybak\243w to musi by\230 straszne. Nawet, gdy odwa\191\185[ENTER]si\234 wyp\179yn\185\230 na morze, to i tak ich Harpuny s\185[ENTER]zbyt s\179abe, aby przebi\230 tward\185 sk\243r\234 wieloryb\243w.[ENTER]Kiedy jeszcze pracowa\179em na kutrach rybackich,[ENTER]u\191ywali\156my specjaln\185 bro\241 do \179owienia wieloryb\243w,[ENTER]kt\243rych sk\243ra by\179o ju\191 stara i pokryta bliznami.[ENTER]Ta bro\241 mog\179a wszystko przebi\230... "
gameforge.new_quest_lv42._042_say = "Chodzi o Harpun na Wieloryby, kt\243ry jest[ENTER]zahartowany za pomoc\185 specjalnej techniki i tylko[ENTER]Kowal mo\191e sporz\185dzi\230 taki Harpun. "
gameforge.new_quest_lv42._043_say_reward = "Id\159 do Kowala. "
gameforge.new_quest_lv42._044_say_title = "Yonah: "
gameforge.new_quest_lv42._045_say = "Na po\179\243w wieloryb\243w Yonah poleca szczeg\243lnie[ENTER]twardy i ostry Harpun. Udaj si\234 do Kowala i[ENTER]zapytaj si\234 go, czy umie zrobi\230 taki. "
gameforge.new_quest_lv42._050_target = "Kowal. "
gameforge.new_quest_lv42._051_say = "Tak, ju\191 s\179ysza\179em o takich harpunach i umiem je[ENTER]zrobi\230, ale, aby osi\185gn\185\230 tak\185 twardo\156\230[ENTER]potrzebuj\234 Diamentowego Kamienia. "
gameforge.new_quest_lv42._052_say = "Potrzebuj\234: "
gameforge.new_quest_lv42._053_say_reward = "Obr\243b: "
gameforge.new_quest_lv42._054_say_title = "Kowal. "
gameforge.new_quest_lv42._060_set_title = "Diamentowy Kamie\241 "
gameforge.new_quest_lv42._061_notice = "Zobaczymy. Potrzebuj\234 Kilofa, aby wydoby\230 kamie\241.[ENTER]Mam jeszcze gdzie\156 m\243j, czy musz\234 poprosi\230[ENTER]Deokbae o nowy? "
gameforge.new_quest_lv42._062_say = "Potrzebujesz jeszcze %s x Diamentowe Kamienie. "
gameforge.new_quest_lv42._063_say = "Masz ju\191 wszystko czego potrzebujesz.[ENTER]A teraz szybko do Kowala. "
gameforge.new_quest_lv42._064_say = "Wspaniale, to wszystko co potrzebuj\234. Przyjd\159 po[ENTER]odbi\243r Harpun\243w jutro o tej samej godzinie. Takie[ENTER]\191elazo musi by\230 dobrze wykute! "
gameforge.new_quest_lv42._065_say = "Je\156li rozbijesz Kilofem \175y\179\234 Diamentow\185 to[ENTER]znajdziesz Diamentowe Kamienie. "
gameforge.new_quest_lv42._066_say = "Kowal potrzebuje Diamentowych Kamieni, aby zrobi\230[ENTER]wyj\185tkowe Harpuny na Wieloryby. Odszukaj \175y\179\234[ENTER]Diamentu, aby wydoby\230 z niej Diamentowe Kamienie.[ENTER]Je\156li nie posiadasz Kilofa, mo\191esz go naby\230 u[ENTER]Deokbae. "
gameforge.new_quest_lv42._067_say = "Kowal znajduje si\234 w %s. "
gameforge.new_quest_lv42._068_say = "Zanim jeszcze przyst\185pimy do pracy nad Harpunem,[ENTER]musimy zdoby\230 jeszcze %s x Diamentowe Kamienie. "
gameforge.new_quest_lv42._070_set_title = "Harpuny "
gameforge.new_quest_lv42._071_set_clock = "Czas oczekiwania: %s "
gameforge.new_quest_lv42._072_say = "Kowal powinien ju\191 wykona\230 twoje zlecenie. Udaj[ENTER]si\234 do niego i odbierz specjalny Harpun na[ENTER]Wieloryby. "
gameforge.new_quest_lv42._073_say = "Niestety, Harpuny s\185 jeszcze nie gotowe. Troch\234[ENTER]cierpliwo\156ci jeszcze. "
gameforge.new_quest_lv42._074_say = "Oto Harpuny. Zanie\156 je Rybakowi. "
gameforge.new_quest_lv42._075_say = "Prosi\179em ci\234 przecie\191, aby poczeka\179 a\191 Harpuny[ENTER]b\234d\185 gotowe. Przyjd\159 p\243\159niej. "
gameforge.new_quest_lv42._079_say = "Otrzyma\179e\156 od Kowala Harpuny na Wieloryby.[ENTER]Dostarcz je Rybakowi. "
gameforge.new_quest_lv42._080_say = "Wspaniale! Harpuny s\185 na prawd\234 imponuj\185ce! W[ENTER]ko\241cu mo\191emy si\234 broni\230 przed Wielorybami.[ENTER]Przeka\191 Octavio, \191e wkr\243tce mo\191e liczy\230 na \156wie\191e[ENTER]ryby! "
gameforge.new_quest_lv42._081_say_reward = "Otrzyma\179e\156 500.000 Yang. "
gameforge.new_quest_lv42._082_say_reward = "Jako dow\243d uznania otrzyma\179e\156 3x: "
gameforge.new_quest_lv42._083_say = "Mamy za ma\179o Harpun\243w, aby przep\234dzi\230 Wieloryba.[ENTER]Tym mo\191emy go tylko po\179askota\230 po brzuchu! "
gameforge.new_quest_lv42._084_say_reward = "Prosz\234, udaj si\234 jeszcze raz do Kowala i popro\156[ENTER]go, aby sporz\185dzi\179 wi\234cej Harpun\243w. "
gameforge.new_quest_lv42._090_say = "Rybacy s\185 teraz dobrze wyposa\191eni i mog\234 uda\230 si\234[ENTER]na po\179\243w. Udaj si\234 do Octavio i uspok\243j go,[ENTER]powiedz mu, \191e wkr\243tce otrzyma \156wie\191\185 dostaw\234. "
gameforge.new_quest_lv42._095_say = "Co powiedzia\179e\156? \163agodne Wieloryby przeobrazi\179y[ENTER]si\234 w krwio\191ercze potwory morskie? Straszne...[ENTER]Dzi\234kuj\234, \191e pomog\179e\156 Rybakom. Wi\234kszo\156\230 moich[ENTER]potraw zale\191y od ich dostaw. "
gameforge.new_quest_lv42._096_say = "Wracaj\185c do twojego burcz\185cego brzucha, niestety[ENTER]nie mog\234 ci przyrz\185dzi\230 jeszcze zupy rybnej, ale[ENTER]co powiesz na sushi? "
gameforge.new_quest_lv42._098_say_reward = "Otrzyma\179e\156 750.000 Punkt\243w Do\156wiadczenia.[ENTER]Otrzyma\179e\156 2 porcje Sushi. "
gameforge.new_quest_lv43 = {}
gameforge.new_quest_lv43._005_send_letter = "Wizyta u Wonda-Rima "
gameforge.new_quest_lv43._006_send_letter = "Sierota "
gameforge.new_quest_lv43._010_target = "Wonda-Rim: "
gameforge.new_quest_lv43._011_say = "Ju\191 od dawna nic nie s\179ysza\179e\156 od Wonda-Rima.[ENTER]Mo\191e poprawi\179y si\234 ju\191 stosunki mi\234dzy nim a jego[ENTER]wujkiem i zapomnia\179 ju\191 zdarzenie z Futrami Mu[ENTER]Rang. Odwied\159 go. "
gameforge.new_quest_lv43._012_say = "Wonda-Rim znajduje si\234 w %s. "
gameforge.new_quest_lv43._020_say = "Ciesz\234 si\234, \191e wpad\179e\156 do mnie. "
gameforge.new_quest_lv43._021_say_title = "Wonda-Rim: "
gameforge.new_quest_lv43._022_say = "Dorasta\179em u mojego wujka Chaegiraba. W zasadzie[ENTER]mieli\156my zawsze dobre stosunki... ale jak pytam[ENTER]go o moich rodzic\243w, to zaraz zmienia temat.[ENTER]Powiedzia\179 mi tylko, \191e zmarli. "
gameforge.new_quest_lv43._023_say_reward = "Kiedy\156 chcia\179bym przecie\191 si\234 o\191eni\230 i za\179o\191y\230[ENTER]rodzin\234. Powinienem wi\234c wiedzie\230 sk\185d pochodz\234 i[ENTER]kim byli moi rodzice. M\243g\179by\156 porozmawia\230 z moim[ENTER]wujkiem i zapyta\230 si\234 o moich rodzic\243w? Ale[ENTER]prosz\234 nie m\243w mu, \191e to ja ci\234 przys\179a\179em. "
gameforge.new_quest_lv43._024_select = "Pogadam z nim! "
gameforge.new_quest_lv43._025_say = "Wonda-Rim nie jest rodzonym bratankiem Chaegirab,[ENTER]wychowywa\179 si\234 tylko u niego. Nadszed\179 czas, aby[ENTER]dowiedzia\179 si\234 ca\179ej prawd o swoi rodzicach.[ENTER]Zapytaj si\234 Chaegiraba o pochodzenie Wonda-Rima. "
gameforge.new_quest_lv43._026_say = "Chaegirab znajduje si\234 w %s. "
gameforge.new_quest_lv43._030_target = "Chaegirab: "
gameforge.new_quest_lv43._031_say_title = "Chaegirab: "
gameforge.new_quest_lv43._032_say = "Wonda-Rim... tak, nie jestem jego prawdziwym[ENTER]wujkiem. Nie wiem, kim byli jego rodzice. Do tej[ENTER]pory chcia\179em mu oszcz\234dzi\230 cierpienia, bo nie[ENTER]by\179 jeszcze got\243w, dowiedzie\230 si\234 ca\179ej prawdy o[ENTER]swoim pochodzeniu. Mo\191e jednak teraz przysz\179a[ENTER]pora... "
gameforge.new_quest_lv43._033_say = "Znalaz\179em go w Dolinie Seungryong u zgrai Orek[ENTER]Wojownik\243w. Je\156li chcesz si\234 czego\156 dowiedzie\230 o[ENTER]pochodzeniu Wonda-Rima to najlepiej u Ork\243w. "
gameforge.new_quest_lv43._034_say = "Mo\191e i jestem surowy dla niego, ale na zawsze[ENTER]zostan\234 jego wujkiem. Nawet je\156li dalej b\234dzie[ENTER]takim nierobem. "
gameforge.new_quest_lv43._035_say_reward = "Udaj si\234 do Doliny Seungryong i poluj na Orki[ENTER]Wojownik\243w, a\191 znajdziesz jak\185\156 wskaz\243wk\234[ENTER]dotycz\185c\185 pochodzenia Wonda-Rima. "
gameforge.new_quest_lv43._036_say = "W zabrudzonej torbie jednego z zabitych Ork[ENTER]Wojownik\243w znalaz\179e\156 stary List. Ledwo mo\191na go[ENTER]odczyta\230, ale rozpozna\179e\156 na nim imi\234 Wonda-Rima.[ENTER]W\179a\156nie znalaz\179e\156 poczebn\185 wskaz\243wk\234. Zanie\156[ENTER]natychmiast List Wonda-Rima. "
gameforge.new_quest_lv43._041_say = "Ruszaj! Najlepsz\185 mo\191liwo\156ci\185, aby dowiedzie\230 si\234[ENTER]co\156 o pochodzeniu Wonda-Rima, jest zabicie Ork[ENTER]Wojownik\243w. Mo\191e maj\185 przy sobie odpowiedni\185[ENTER]wskaz\243wk\234! "
gameforge.new_quest_lv43._043_notice = "Wskaz\243wki dotycz\185ce Wonda-Rim... "
gameforge.new_quest_lv43._045_say = "Wszystko co wiedzia\179em, to ci ju\191 powiedzia\179em.[ENTER]Jedyn\185 wskaz\243wk\185, kt\243r\185 mo\191e nam jeszcze pom\243c,[ENTER]to Orki Wojownicy. Niestety z nimi nie mo\191na[ENTER]rozs\185dnie porozmawia\230... "
gameforge.new_quest_lv43._049_say = "List? Poka\191... Litery s\185 troch\234 zamazane...[ENTER]Chodzi o napad... Orki spali\179y farm\234.. i oni[ENTER]uciekli, aby ratowa\230 swoje \191ycie... musieli[ENTER]pozostawi\230 swoje dziecko... Tutaj jest moje imi\234. "
gameforge.new_quest_lv43._050_say = "Dzi\234kuj\234, \191e przynios\179e\156 mi. W ko\241cu wiem, co si\234[ENTER]naprawd\234 wydarzy\179o. "
gameforge.new_quest_lv43._051_say = "Powinienem porozmawia\230 z Chaegirabem. Narazi\179 si\234[ENTER]na niebezpiecze\241stwo, aby mnie uratowa\230. Postaram[ENTER]si\234 poprawi\230. Do zobaczenia, przyjacielu! "
gameforge.new_quest_lv43._052_say_title = "Informacja: "
gameforge.new_quest_lv43._053_say_reward = "Otrzyma\179e\156 32.000 Yang. "
gameforge.new_quest_lv43._054_say_reward = "Otrzyma\179e\156 1.250.000 Punkt\243w Do\156wiadczenia. "
gameforge.new_quest_lv43._060_say = "Rozmawia\179e\156 z moim wujkiem Chaegirab? Wskaz\243wka?[ENTER]O co ci chodzi? Je\156li nie posiadasz \191adnych[ENTER]dowod\243w, zachowaj swoje domy\179y dla siebie![ENTER][ENTER]Prosz\234 spytaj si\234 jeszcze raz mojego wuja.[ENTER]W ko\241cu za to ci p\179ac\234. "
gameforge.new_quest_lv52 = {}
gameforge.new_quest_lv52._010_send_letter = "List od Kapitana "
gameforge.new_quest_lv52._020_say_title = "Wierny Ziomek "
gameforge.new_quest_lv52._021_say_reward = "Wy\156wiadczysz mi przys\179ug\234. Nie mog\234 spa\230, chocia\191[ENTER]bior\234 lekarstwo od Baek-Go, to i tak przewracam[ENTER]si\234 przez ca\179\185 noc z boku na bok. Czy m\243g\179by\156 go[ENTER]odszuka\230 i poprosi\230 o mocniejsze Lekarstwo na[ENTER]Sen? "
gameforge.new_quest_lv52._022_say = "Baek-Go znajduje si\234 w %s. "
gameforge.new_quest_lv52._030_set_title = "Spokojna noc "
gameforge.new_quest_lv52._035_target = "Baek-Go: "
gameforge.new_quest_lv52._040_say = "Kapitan nie mo\191e spa\230 w nocy. Udaj si\234 do Baek-Go[ENTER]i popro\156 go o mocniejsze Lekarstwo na Sen dla[ENTER]Kapitana. "
gameforge.new_quest_lv52._041_say = "Lekarstwo na Sen dla Kapitana? Przykro mi, ale[ENTER]nie mam nic mocniejszego. Tylko Yu-Hwan mo\191e[ENTER]przyrz\185dzi\230 z zi\243\179 co\156 mocniejszego. "
gameforge.new_quest_lv52._042_say = "Ach, otrzyma\179e\156 m\243j List. Naprawd\234 nie wiem, co[ENTER]mam pocz\185\230. Nie mog\234 spa\230 w nocy. Prosz\234 pom\243\191[ENTER]mi. Zasi\234gnij rady u Baek-Go. "
gameforge.new_quest_lv52._042_select = "W takim razie udam si\234 lepiej do Yu-Hwan! "
gameforge.new_quest_lv52._043_say = "Baek-Go znajduje si\234 w %s. "
gameforge.new_quest_lv52._044_say_title = "Baek-Go: "
gameforge.new_quest_lv52._045_say = "Yu-Hwan znajduje si\234 w %s. "
gameforge.new_quest_lv52._046_say = "W takim razie udaj si\234 do Kapitana i powiedz, \191e[ENTER]nie mo\191esz mu pom\243c. "
gameforge.new_quest_lv52._049_say_title = "Yu-Hwan: "
gameforge.new_quest_lv52._050_target = "Yu-Hwan: "
gameforge.new_quest_lv52._051_say = "Baek-Go nie ma w swojej apteczce mocniejszego[ENTER]Lekarstwa na Sen, ale mo\191e pom\243c Yu-Hwan, je\156li[ENTER]zna Zio\179o, kt\243re pomaga w zasypianiu. "
gameforge.new_quest_lv52._052_say = "Znam bardzo dobrze Kapitana. Jak z pewno\156ci\185[ENTER]wiesz, ju\191 od d\179u\191szego czasu wype\179niam dla niego[ENTER]tajemne misje. Dlatego mog\234 z pewno\156ci\185[ENTER]powiedzie\230, \191e Zio\179a mu nie pomog\185. "
gameforge.new_quest_lv52._053_say = "Istnieje inny pow\243d, dlaczego Kapitan ma k\179opoty[ENTER]z zasypianiem. Uwierz mi, on bardzo dobrze wie[ENTER]dlaczego, ale to sprawa, kt\243r\185 on sam musi[ENTER]wyja\156ni\230, ja nie mog\234 tego zrobi\230. Udaj si\234 do[ENTER]niego i porozmawiaj z nim o tym. "
gameforge.new_quest_lv52._054_say_title = "Kapitan "
gameforge.new_quest_lv52._055_say_reward = "Ach, otrzyma\179e\156 m\243j List. Ju\191 na prawd\234 nie wiem[ENTER]co mam robi\230. Prosz\234, id\159 do Baek-Go i popro\156 go[ENTER]o rad\234, abym m\243g\179 w ko\241cu przespa\230 ca\179\185 noc. "
gameforge.new_quest_lv52._055_select = "Tak jest! "
gameforge.new_quest_lv52._056_say = "Dzi\234kuj\234! "
gameforge.new_quest_lv52._056_say_reward = "Ju\191 zrobi\179em to, ale on nie ma mocniejszego[ENTER]Lekarstwa w swej apteczce. Obiecuj\234 jednak, \191e[ENTER]odszukam Yu-Hwan i zapytam si\234 go, czy mo\191e[ENTER]pom\243c. "
gameforge.new_quest_lv52._060_target = "Kapitan "
gameforge.new_quest_lv52._061_say = "Yu-Hwan nie chce nic powiedzie\230, prawdopodobnie[ENTER]chodzi o co\156 nieprzyjemnego. Ale nic nie pomo\191e,[ENTER]musisz porozmawia\230 o tym z Kapitanem. Musimy[ENTER]najpierw pozna\230 przyczyny bezsenno\156ci, aby[ENTER]znale\159\230 jakie\156 rozwi\185zania. A wi\234c ruszaj do %s. "
gameforge.new_quest_lv52._062_say_reward = "Nie ma skuteczniejszego Lekarstwa na Sen, ale[ENTER]mo\191e m\243g\179bym pom\243c, Kapitanie, je\156li poznam[ENTER]przyczyn\234 bezsenno\156ci. "
gameforge.new_quest_lv52._063_say_reward = "To nie jest co\156, co ch\234tnie opowiedzia\179bym[ENTER]m\179odemu m\234\191czy\159nie takiemu jak ty. "
gameforge.new_quest_lv52._064_say_reward = "To nie jest co\156, co ch\234tnie opowiedzia\179bym m\179odej[ENTER]kobiecie takiej jak ty. "
gameforge.new_quest_lv52._065_say_reward = "Ale je\156li wkr\243tce si\234 porz\185dnie nie wy\156pi\234 to[ENTER]nied\179ugo zwariuje. Wygl\185da na to, \191e musz\234...[ENTER]Ale pami\234taj , to co ci teraz powiem przeznaczone[ENTER]jest tylko dla ciebie. Ka\191dej nocy odwiedzaj\185[ENTER]mnie duchy... to nie jest jeszcze takie[ENTER]straszne... Jestem odpowiedzialny za ich \156mier\230. "
gameforge.new_quest_lv52._066_say_reward = "To czterech \191o\179nierzy. Powiedzieli, \191e byli[ENTER]torturowani przez Przyzywaczy oraz Dr\234czycieli w[ENTER]Dolinie Seungryonga, potem ich zabito. To ja[ENTER]by\179em tym, kt\243ry ich tam wezwa\179 - na \156mier\230! "
gameforge.new_quest_lv52._067_say_reward = "Co ma zrobi\230, aby si\234 pozby\230 tych duch\243w? "
gameforge.new_quest_lv52._068_say_reward = "Chc\185 zemsty! Co ma zrobi\230? Je\156li wyrusz\234, aby[ENTER]pom\156ci\230, to wioska nie b\234dzie mia\179a przyw\243dcy i[ENTER]zostanie spustoszona. Ale je\156li nie p\243jd\234 to[ENTER]wkr\243tce zwariuj\234. "
gameforge.new_quest_lv52._069_say_reward = "Je\156li nie by\179bym odpowiedzialny za bezpiecze\241stwo[ENTER]wioski, to nie namy\156la\179bym si\234 d\179ugo, tylko[ENTER]natychmiast wyruszy\179. Widz\234 tylko jedno wyj\156cie: "
gameforge.new_quest_lv52._070_say_reward = "Kto\156 musi za mnie p\243j\156\230 i pom\156ci\230! Ale przecie\191[ENTER]nie mog\234 ponownie wys\179a\230 ludzi na pewn\185 zgub\234!?[ENTER]Jak mog\234 co\156 takiego za\191\185da\230 i potem spokojnie[ENTER]spa\230 w nocy? "
gameforge.new_quest_lv52._071_say_reward = "Tak\185 decyzj\234 nie jest \179atwo podj\185\230. "
gameforge.new_quest_lv52._080_1_select = "Dobro wioski... "
gameforge.new_quest_lv52._080_2_select = "Nie b\234dzie \179atwo... "
gameforge.new_quest_lv52._080_3_select = "Tego nie mo\191na przecie\191 \191\185da\230! "
gameforge.new_quest_lv52._081_say_reward = "... jest wa\191niejsze ni\191 skrupu\179y. Pomszcz\234[ENTER]\191o\179nierzy! A je\156li nie powr\243c\234, to zobaczymy si\234[ENTER]dzisiaj w nocy... "
gameforge.new_quest_lv52._082_say_reward = "... rozprawi\230 si\234 z Przyzywaczami oraz[ENTER]Dr\234czycielami. Ale obiecuj\234 Kapitanie, dzisiaj[ENTER]b\234dziecie spokojnie spa\230! "
gameforge.new_quest_lv52._083_say_reward = "To prawie samob\243jstwo wdawa\230 si\234 w b\243jk\234 z[ENTER]Przywo\179ywaczami oraz Dr\234czycielami. Kapitanie,[ENTER]spr\243buj wyt\179umaczy\230 duchom, jak bardzo jest[ENTER]kapitan tutaj potrzebny. "
gameforge.new_quest_lv52._084_say_reward = "Masz racj\234. Jednak mia\179em nadziej\234, \191e sam[ENTER]dobrowolnie si\234 zg\179osisz i wy\156wiadczysz ogromn\185[ENTER]przys\179ug\234 mnie oraz ca\179ej wiosce. "
gameforge.new_quest_lv52._090_1_select = "No dobrze... "
gameforge.new_quest_lv52._090_2_select = "Nie dam rady! "
gameforge.new_quest_lv52._091_say_reward = "... je\156li jestem ostatni\185 desk\185 ratunku, to[ENTER]rozprawie si\234 z Przyzywaczami oraz Dr\234czycielami! "
gameforge.new_quest_lv52._092_say_reward = "Je\156li spr\243buj\234, to b\234dzie z pewno\156ci\185 nawiedza\179[ENTER]Kapitana jeszcze jeden duch. "
gameforge.new_quest_lv52._093_say_reward = "No dobrze. Pozw\243l mi jednak podarowa\230 ci troch\234[ENTER]Yang za tw\243j trud. "
gameforge.new_quest_lv52._093_say_reward_exp = "Otrzyma\179e\156 20.000 Punkt\243w Do\156wiadczenia "
gameforge.new_quest_lv52._093_say_reward_gold = "Otrzyma\179e\156 25.000 Yang. "
gameforge.new_quest_lv52._100_notice = "Rozmowa zosta\179a zako\241czona. "
gameforge.new_quest_lv52._110_say_reward = "Mia\179em nadziej\234, \191e powiesz co\156 takiego. Niestety[ENTER]nie wiem dok\179adnie, kt\243ry z Przyzywaczy lub[ENTER]Dr\234czycieli ich zabi\179. Mam nadziej\234, \191e poczuj\234,[ENTER]jak jeden z duch\243w zostanie uwolniony. "
gameforge.new_quest_lv52._111_say_reward = "Przy\156l\234 ci List. Duchy powiedzia\179y mi, \191e zemsta[ENTER]musi by\230 dokonana w Tr\243jk\185cie Boga Smoka. Tam[ENTER]znajduj\185 si\234 trzy kolumny, kt\243re tworz\185[ENTER]wierzcho\179ki tr\243jk\185ta. "
gameforge.new_quest_lv52._120_set_title = "Pom\156cij 4 Poleg\179ych "
gameforge.new_quest_lv52._125_say_title = "List od Kapitana "
gameforge.new_quest_lv52._130_say_reward = "Pom\156cij jeszcze 3 \191o\179nierzy ! "
gameforge.new_quest_lv52._131_say = "Wygl\185da na to, \191e odnios\179e\156 sukces. W\179a\156nie[ENTER]us\179ysza\179em g\179os jednego z moich zabitych[ENTER]\191o\179nierzy. Powiedzia\179, \191e mi przebacza i \191e jego[ENTER]\156mier\230 zosta\179a pomszczona. A to jest tylko twoja[ENTER]zas\179uga! "
gameforge.new_quest_lv52._132_say = "Prosz\234, pom\156cij r\243wnie\191 innych poleg\179ych[ENTER]\191o\179nierzy i zabij Ezoterycznych Dr\234czycieli,[ENTER]Ezoterycznych Przyzywaczy oraz Wysokich[ENTER]Dr\234czycieli. Pami\234taj jednak o tym, \191e mo\191esz je[ENTER]wybawi\230 tylko w Tr\243jk\185cie Trzech Kolumn Boga[ENTER]Smoka. "
gameforge.new_quest_lv52._140_say_reward = "Pom\156cij jeszcze 2 \191o\179nierzy! "
gameforge.new_quest_lv52._141_say = "Wyeliminowa\179e\156 kolejnego morderc\234 moich[ENTER]\191o\179nierzy! Wydawa\179o mi si\234, \191e w p\243\179mroku[ENTER]zobaczy\179em jednego z Poleg\179ych, kt\243ry zasalutowa\179[ENTER]mi na po\191egnanie. "
gameforge.new_quest_lv52._150_say_reward = "Pom\156cij jeszcze 1 \191o\179nierza! "
gameforge.new_quest_lv52._151_say = "Jeste\156 niesamowity! Niedawno jeszcze sta\179 obok[ENTER]mnie duch jednego z poleg\179ych \191o\179nierzy i \191egna\179[ENTER]si\234 ze mn\185. Przypuszczam, \191e b\234dzie ci\234\191ko[ENTER]odnale\159\230 ostatniego z morderc\243w. "
gameforge.new_quest_lv52._160_say = "Duchy, kt\243re nachodz\185 Kapitana, to duchy m\179odych[ENTER]\191o\179nierzy, kt\243rzy polegli podczas wype\179niania[ENTER]swojej misji. Zostali zabici przez Ezoterycznych[ENTER]Dr\234czycieli, Ezoterycznych Przyzywaczy, Wysokich[ENTER]Dr\234czycieli oraz Wysokich Przywo\179ywaczy. "
gameforge.new_quest_lv52._161_say = "Musisz wyeliminowa\230 odpowiedzialnych Dr\234czycieli[ENTER]oraz Przyzywaczy w Tr\243jk\185cie Trzech Kolumn Boga[ENTER]Smoka, aby pom\156ci\230 \191o\179nierzy. "
gameforge.new_quest_lv52._162_say = "Tr\243jk\185t Boga Smoka znajduje si\234 po\156rodku Doliny[ENTER]Seungryong. "
gameforge.new_quest_lv52._170_send_letter = "Pierwszy \191o\179nierz pomszczony "
gameforge.new_quest_lv52._171_send_letter = "Drugi \191o\179nierz pomszczony "
gameforge.new_quest_lv52._172_send_letter = "Trzeci \191o\179nierz pomszczony "
gameforge.new_quest_lv52._173_send_letter = "Wszyscy \191o\179nierze pomszczeni "
gameforge.new_quest_lv52._180_say_reward = "Pom\156ci\179e\156 wszystkich 4 \191o\179nierzy! "
gameforge.new_quest_lv52._181_say = "Odnalaz\179e\156 ostatniego z morderc\243w! W\179a\156nie ukaza\179[ENTER]mi si\234 ostatni duch z czterech poleg\179ych[ENTER]\191o\179nierzy i prosi\179, abym ci podzi\234kowa\179 za twoj\185[ENTER]odwag\234. Zostawi\179 co\156 dla ciebie: %s "
gameforge.new_quest_lv52._182_say = "Przyjd\159 do mnie, aby odebra\230 nagrod\234. Czekam na[ENTER]ciebie w %s. "
gameforge.new_quest_lv52._183_say_reward = "Wy\156wiadczy\179e\156 mi oraz mojej wiosce ogromn\185[ENTER]przys\179ug\234. Oto twoja nagroda, kt\243r\185 pozostawi\179[ENTER]dla ciebie duch: %s "
gameforge.new_quest_lv52._184_say_reward = "Oto jeszcze troch\234 Yang ode mnie. A teraz id\234 si\234[ENTER]przespa\230. "
gameforge.new_quest_lv52._185_say_reward = "Jestem ci wielce zobowi\185zany, m\243j synu. "
gameforge.new_quest_lv52._186_say_reward = "Jestem ci dozgonnie wdzi\234czny. "
gameforge.new_quest_lv52._190_say_title = "Informacja: "
gameforge.new_quest_lv52._191_say_reward = "Otrzyma\179e\156 3.300.000 Punkt\243w Do\156wiadczenia.[ENTER]Otrzyma\179e\156 270.000 Yang.[ENTER]Otrzyma\179e\156 Ksi\234g\234 Mistrza. "
gameforge.new_quest_lv52._85_say = "To mo\191e p\243\159niej? Udaj si\234 do Baek-Go, gdy[ENTER]b\234dziesz got\243w. "
gameforge.new_quest_lv54 = {}
gameforge.new_quest_lv54._010_target = "Kapitan "
gameforge.new_quest_lv54._020_say_title = "Dodatkowe zaopatrzenie "
gameforge.new_quest_lv54._030_say = "Trudno motywowa\230 nasze oddzia\179y, je\156li mamy[ENTER]k\179opoty z dodatkowym zaopatrzeniem. Handlarka[ENTER]R\243\191no\156ci, kt\243ra jest naszym wa\191nym dostawc\185, ju\191[ENTER]od paru tygodni dostarcza nam tylko znikom\185 ilo\156\230[ENTER]mikstur. "
gameforge.new_quest_lv54._031_say_reward = "Prosz\234 udaj si\234 do Handlarki R\243\191no\156ci i dowiedz[ENTER]si\234 co si\234 dzieje. "
gameforge.new_quest_lv54._032_select = "Za\179atwi\234 wam te napoje! "
gameforge.new_quest_lv54._040_say_title = "Handlarka R\243\191no\156ci: "
gameforge.new_quest_lv54._040_set_title = "Dodatkowe zaopatrzenie "
gameforge.new_quest_lv54._050_target = "Handlarka R\243\191no\156ci: "
gameforge.new_quest_lv54._051_say = "Tak, ostatnio mam sporo k\179opot\243w z dostaw\185[ENTER]dodatkowego zaopatrzenia. Szlaki handlowe sta\179y[ENTER]si\234 niebezpieczne, coraz cz\234\156ciej na nich[ENTER]pojawiaj\185 si\234 rabusie oraz dzikie bestie.[ENTER]Podr\243\191uj\185cy handlarze nie maj\185 \191adnych szans, gdy[ENTER]na drodze pojawi\185 si\234 gro\159ne Tygrysy. "
gameforge.new_quest_lv54._052_say = "Mo\191e pom\243g\179by Kapitan ze swoimi \191o\179nierzami.[ENTER]Prosz\234, udaj si\234 do niego i zapytaj si\234, czy[ENTER]m\243g\179by przys\179a\230 swoich \191o\179nierzy do ochrony[ENTER]handlarzy. "
gameforge.new_quest_lv54._054_say = "Udaj si\234 do Handlarki R\243\191no\156ci i dowiedz si\234,[ENTER]dlaczego s\185 op\243\159nienia w dostawie dodatkowego[ENTER]zaopatrzenia w mikstury. "
gameforge.new_quest_lv54._055_say = "Handlarka R\243\191no\156ci znajduje si\234 w %s. "
gameforge.new_quest_lv54._056_say_title = "Kapitan "
gameforge.new_quest_lv54._060_say = "Zabezpieczy\230 szlaki handlowe? Tak... w zasadzie[ENTER]ch\234tnie bym to zrobi\179, tylko nie posiadam[ENTER]wystarczaj\185c\185 ilo\156\230 \191o\179nierzy, aby ochroni\230[ENTER]podr\243\191uj\185cych handlarzy z innych kr\243lestw. "
gameforge.new_quest_lv54._061_say = "Poza tym \191o\179nierz nie mog\185 polowa\230 na Tygrysy i[ENTER]tylko my\156liwi z \179owieckiego bractwa posiadaj\185[ENTER]takie prawo. A naruszenie tego prawa nie[ENTER]sprzyja\179oby w utrzymaniu pokoju w wiosce. "
gameforge.new_quest_lv54._062_say_reward = "Dlatego te\191 musisz zwr\243ci\230 si\234 do Yang-Shin. Jest[ENTER]cz\179onkiem bractwa \179owieckiego. Mo\191e on ci pomo\191e[ENTER]upora\230 si\234 z Tygrysami. "
gameforge.new_quest_lv54._064_say = "Udaj si\234 do Kapitana i spr\243buj go przekona\230, aby[ENTER]zabezpieczy\179 szlaki handlowe przed Tygrysami. "
gameforge.new_quest_lv54._065_say = "Kapitan znajduje si\234 w %s. "
gameforge.new_quest_lv54._070_target = "Yang-Shin: "
gameforge.new_quest_lv54._071_say = "Wielu moich my\156liwych by\179o powo\179anych jako[ENTER]wojownicy do walki i zgin\234li. Sta\179o si\234[ENTER]niemo\191liwe zachowanie r\243wnowagi w populacje[ENTER]dzikich zwierz\185t. Szczeg\243lnie dzikie koty[ENTER]powi\234kszaj\185 sw\243j rewir i zagra\191aj\185 podr\243\191uj\185cym. "
gameforge.new_quest_lv54._072_say = "Je\156li pomo\191esz nam w tej sprawie, to otrzymasz[ENTER]drogocenn\185 Tarcz\234 Tygrysa+3, kt\243ra nale\191a\179a do[ENTER]mojego poleg\179ego towarzysza Mi-Songa. Za to[ENTER]musisz znacznie przerzedzi\230 populacj\234 Tygrys\243w. "
gameforge.new_quest_lv54._073_say = "Szczeg\243lnie rozmno\191y\179y si\234 Przekl\234te Bia\179e[ENTER]Tygrysy. "
gameforge.new_quest_lv54._074_say = "Jako dow\243d, potrzebuj\234: "
gameforge.new_quest_lv54._075_say = "Musisz polowa\230 na: "
gameforge.new_quest_lv54._076_say = "Odszukaj Yang-Shin i spr\243buj go przekona\230, aby[ENTER]zabezpieczy\179 szlaki handlowe przed Tygrysami. "
gameforge.new_quest_lv54._077_say_title = "Yang-Shin: "
gameforge.new_quest_lv54._078_say = "Yang-Shin znajduje si\234 w %s. "
gameforge.new_quest_lv54._080_set_title = "Futro Tygrysa "
gameforge.new_quest_lv54._081_notice = "Ah, doskona\179y okaz. Jeszcze tylko %s sztuk! "
gameforge.new_quest_lv54._082_notice = "Gotowe! Teraz szybko wr\243\230 do Yang-Shin. "
gameforge.new_quest_lv54._083_notice = "To Futro Tygrysa jest bezu\191yteczne. "
gameforge.new_quest_lv54._084_say = "Potrzebuj\234 jeszcze %s x L\156ni\185ce Futra Tygrysa "
gameforge.new_quest_lv54._085_say = "Zdob\185d\159 L\156ni\185ce Futra Tygrysa od Przekl\234tych[ENTER]Bia\179ych Tygrys\243w. "
gameforge.new_quest_lv54._090_npcChat = "Mam Futro Tygrysa. "
gameforge.new_quest_lv54._091_say = "W jaki spos\243b ma ustali\230, czy szalki s\185[ENTER]bezpieczne. Tych kilka Futer to nie jest \191aden[ENTER]dow\243d. "
gameforge.new_quest_lv54._092_say = "W ko\241cu Futra przynios\185 mi du\191y zysk...eh![ENTER]Jeszcze jeste\156 tutaj? Dzi\234ki tobie szlaki s\185[ENTER]znowu bezpieczne! Jestem przekonany, \191e Kapitan[ENTER]wynagrodzi ci\234 po kr\243lewsku. "
gameforge.new_quest_lv54._093_say = "A teraz znikaj st\185d! Musz\234 oczy\156ci\230 Futra. "
gameforge.new_quest_lv54._094_say = "Ach, Kapitan nie da ci nagrody? To nie moja[ENTER]sprawa. A je\156li spr\243bujesz mnie zdradzi\230, to[ENTER]mo\191esz zapomnie\230 o Futrach. Nigdy nie dostaniesz[ENTER]je w swoje r\234ce! "
gameforge.new_quest_lv54._095_say_reward = "Obieca\179em ci Tarcz\234 i oczywi\156cie otrzymasz j\185.[ENTER]Ju\191 nie potrzebuj\234 tego starego, dziwacznego,[ENTER]tr\243jk\185tnego przedmiotu. "
gameforge.new_quest_lv54._096_say = "Nagroda: "
gameforge.new_quest_lv54._097_say_reward = "Otrzyma\179e\156 Tarcz\234 Tygrysa+3. "
gameforge.new_quest_lv54._098_say = "Co, chcesz mnie przekupi\230 tymi marnymi Futrami? W[ENTER]ten spos\243b m\243j d\179ug... wydaje mi si\234, \191e drogi[ENTER]nie b\234d\185 nigdy bezpieczne. "
gameforge.new_quest_lv54._099_say_reward = "Poluj tak d\179ugo, a\191 zdob\234dziesz %s Futer! "
gameforge.new_quest_lv54._100_say = "To wszystko, a teraz szybko do Yang-Shin. "
gameforge.new_quest_lv54._101_say_reward = "Otrzyma\179e\156 3.750.000 Punkt\243w Do\156wiadczenia "
gameforge.new_quest_lv54._102_say_reward = "Otrzyma\179e\156 125.000 Yang. "
