gameforge.new_quest_lv7._020_say_title = "\140lub c\243rki "
gameforge.new_quest_lv7._021_say = "Czy macie dzieci? To zrozumiecie, \191e bardzo si\234[ENTER]martwi\234... chodzi o moj\185 c\243rk\234! Pozna\179a tego[ENTER]m\234\191czyzn\234, kt\243ry zawr\243ci\179 jej w g\179owie i uciekli[ENTER]razem do innego kr\243lestwa. "
gameforge.new_quest_lv7._022_say = "Pochodzi z Chunjo. Oczywi\156cie by\179em przeciwko![ENTER]My\156la\179em, \191e dama z Shinsoo nie mo\191e wyj\156\230 za m\185\191[ENTER]za uduchowionego marzyciela z Chunjo.[ENTER]Pok\179\243cili\156my si\234 i w ko\241cu uciek\179a z nim do[ENTER]Chunjo. "
gameforge.new_quest_lv7._023_say = "Pochodzi z Jinno. Oczywi\156cie by\179em przeciwko![ENTER]My\156la\179em, \191e dama z Chunjo nie mo\191e wyj\156\230 za m\185\191[ENTER]za p\243\179g\179\243wka z Jinno. Pok\179\243cili\156my si\234 i w ko\241cu[ENTER]uciek\179a z nim do Jinno. "
gameforge.new_quest_lv7._024_say = "Pochodzi z Shinsoo. Oczywi\156cie by\179em przeciwko![ENTER]My\156la\179em, \191e dama z Jinno nie mo\191e wyj\156\230 za m\185\191[ENTER]za zbijaj\185cego kas\234 mi\234czaka. Pok\179\243cili\156my si\234 i[ENTER]w ko\241cu uciek\179a z nim do Shinsoo. "
gameforge.new_quest_lv7._030_say = "S\179ysza\179em, \191e chce go tam po\156lubi\230. "
gameforge.new_quest_lv7._031_say = "A teraz czeka moja c\243rka na znak ode mnie. Co mam[ENTER]robi\230? To moje jedyne dziecko! Oczywi\156cie, \191e[ENTER]udziel\234 jej mojego b\179ogos\179awie\241stwa. Prosz\234, udaj[ENTER]si\234 do Starszej Pani i popro\156 j\185 o pomoc w[ENTER]przygotowaniach do \156lubu. "
gameforge.new_quest_lv7._040_target = "Starsza Pani "
gameforge.new_quest_lv7._041_say = "Odszukaj Starsz\185 Pani\185 i popro\156 j\185 o pomoc w[ENTER]przygotowaniu wesela. "
gameforge.new_quest_lv7._042_say = "Starsza Pani znajduje si\234 w %s. "
gameforge.new_quest_lv7._051_say = "\140lub, powiedzia\179e\156? To bardzo wa\191ny moment w[ENTER]\191yciu ka\191dej kobiety. Ka\191dy szczeg\243\179 musi by\230[ENTER]dopracowany, pocz\185wszy od Sukni \140lubnej czy[ENTER]Smokingu, a sko\241czywszy na Pier\156cionkach[ENTER]Zar\234czynowy, kt\243re podczas ceremonii stan\185 si\234[ENTER]Obr\185czkami \140lubnymi. Je\156li ojciec panny m\179odej[ENTER]wyrazi\179 pozwolenie i zap\179aci\179 odpowiedni\185 ilo\156\230[ENTER]Yang, wtedy dopiero mo\191na zorganizowa\230 wspania\179e[ENTER]wesele. "
gameforge.new_quest_lv7._052_say = "Szczeg\243lnie wa\191ne w tym dniu s\185 kwiaty. Wesele[ENTER]nie mo\191e odby\230 si\234 bez bukietu \156lubnego. Bukiet[ENTER]powinien by\230 zrobiony z nast\234puj\185cych Kwiat\243w: "
gameforge.new_quest_lv7._054_say = "Potrzebuj\234: "
gameforge.new_quest_lv7._055_say = "Musisz polowa\230 na: "
gameforge.new_quest_lv7._056_say = "Potrzebuj\234 jeszcze: "
gameforge.new_quest_lv7._060_say = "Wr\243\230 do mnie, gdy zdob\234dziesz trzy Kwiaty.[ENTER]Zobacz\234, czy kwiaty s\185 \156wie\191e i zrobi\234 z nich[ENTER]przepi\234kny bukiet. Potem zaniesiesz go do mojej[ENTER]siostry, to ona przeprowadzi ceremoni\234. "
gameforge.new_quest_lv7._081_say = "Zbierz po jednym Kwiatku ka\191dego rodzaju.[ENTER]Zdob\234dziesz je zabijaj\185c G\179odne Alfa Wilki,[ENTER]G\179odne Niebieskie Wilki oraz G\179odne Niebieskie[ENTER]Alfa Wilki. "
gameforge.new_quest_lv7._082_say = "Ten zwi\234dni\234ty Kwiat nie jest zbyt dekoracyjny.[ENTER]Tyle prac na nic! "
gameforge.new_quest_lv7._083_say = "Ten zwi\234dni\234ty Kwiat nie jest zbyt dekoracyjny.[ENTER]Tyle prac na nic! "
gameforge.new_quest_lv7._084_say = "Ten zwi\234dni\234ty Kwiat nie jest zbyt dekoracyjny.[ENTER]Tyle prac na nic! "
