gameforge.new_quest_lv7._085_3_say_reward = "Nadal potrzebny jest %s \175\243\179ty Kwiat.[ENTER]Mo\191esz go zdoby\230 od G\179odnych Niebieskich Alfa[ENTER]Wilk\243w. "
