gameforge.new_quest_lv7._087_say_reward = "Nadal potrzebny jest %s \175\243\179ty Kwiat. "
gameforge.new_quest_lv7._088_notice = "Ten Kwiat to wspania\179y okaz. Doskonale! "
gameforge.new_quest_lv7._089_notice = "Ten Kwiat to wspania\179y okaz. Doskonale! "
gameforge.new_quest_lv7._090_notice = "Ten Kwiat to wspania\179y okaz. Doskonale! "
gameforge.new_quest_lv7._091_say = "Gotowe! Z tych Kwiat\243w b\234dzie przepi\234kny bukiet.[ENTER]A teraz szybko do Starszej Pani, zanim nam Kwiaty[ENTER]zwi\234dn\185! "
gameforge.new_quest_lv7._092_say = "Zbierz Kwiaty potrzebne do Bukietu \140lubnego. "
