gameforge.new_quest_lv7._137_say = "Powr\243\230 do Octavia, kt\243ry znajduje si\234 w Pyungmoo[ENTER]w Kr\243lestwie Jinno. "
gameforge.new_quest_lv7._140_say = "Oto Kwiaty na zbli\191aj\185cy si\234 \156lub c\243rki Octavia.[ENTER]Maj\185 by\230 przekazane pannie m\179odej podczas[ENTER]b\179ogos\179awie\241stwa. Ona b\234dzie ju\191 wiedzia\179a, od[ENTER]kogo s\185 te Kwiaty. "
gameforge.new_quest_lv7._141_say = "To przepi\234kne Kwiaty! Panna m\179oda b\234dzie[ENTER]promienie\230 po\156r\243d nich. Przygotowania do[ENTER]ceremonii s\185 ju\191 zako\241czone. A teraz przeka\191[ENTER]Oktavio zaproszenie na \156lub. Wiem, na pewno si\234[ENTER]ucieszy. "
gameforge.new_quest_lv7._142_say = "A teraz do Octavio, na co czekasz? "
gameforge.new_quest_lv7._143_say = "Przynios\179e\156 kwiaty na \156lub c\243rki Octavio? Jak[ENTER]mi\179o z twojej strony! Ale... gdzie one s\185?[ENTER]Czy\191by\156 je zgubi\179 po drodze? "
gameforge.new_quest_lv7._144_say_reward = "Id\159 do Twojego Kr\243lestwa i zdob\185d\159 nowy Bukiet[ENTER]Kwiat\243w na \156lub. "
