gameforge.new_quest_lv75._020_set_title = "Pami\234tnik Legendy "
gameforge.new_quest_lv75._021_say = "Znalaz\179em te szcz\185tki wojownika. Nie wiem czy to[ENTER]ten Sura, kt\243rego szuka Heuk-Young, ale na pewno[ENTER]b\234dzie tym zainteresowana. "
gameforge.new_quest_lv75._022_say = "Nie tylko jeden Sura tutaj umar\179. Widzia\179em ich[ENTER]szcz\185tki. Zastanawiam si\234, czy jest w\156r\243d nich[ENTER]ten legendarny wojownik? Powinienem wr\243ci\230 i[ENTER]porozmawia\230 o tym z Heuk-Young. "
gameforge.new_quest_lv75._023_say = "Znalaz\179em kawa\179ek strony, kt\243ra jest zamro\191ona w[ENTER]Podziemnym Lodowym Golemie. Ledwo co mog\234 j\185[ENTER]odczyta\230, jednak to mo\191e by\230 wa\191na wskaz\243wka,[ENTER]kt\243ra na pewno zainteresuje Heuk-Young. "
gameforge.new_quest_lv75._024_say = "Znalaz\179em sporo rzeczy, kt\243re mog\185 zainteresowa\230[ENTER]Heuk-Young. Teraz powinienem si\234 do niej uda\230 i[ENTER]pokaza\230 ten kawa\179ek papieru. Opowiem r\243wnie\191 o[ENTER]tym ciele. "
gameforge.new_quest_lv75._025_say = "Heuk-Young poprosi\179a mnie, abym mia\179 zawsze oczy[ENTER]szeroko otwarte i szuka\179 \156lad\243w legendarnego[ENTER]Sura. Niestety, nie mam poj\234cia na co mam zwraca\230[ENTER]szczeg\243ln\185 uwag\234 i czego mam szuka\230 ... "
gameforge.new_quest_lv75._030_say = "Szukam legendarnego wojownika Akuma.[ENTER]Prawdopodobnie by\179 on najbardziej znanym Sura[ENTER]jaki kiedykolwiek st\185pa\179 po tej ziemi. Kr\185\191\185[ENTER]legendy, \191e wyzwa\179 do walki nawet samego cesarza.[ENTER]Z tego w\179a\156nie miejsca znikn\185\179 przed tysi\185cami[ENTER]laty waleczny Akuma. Dlatego te\191 miej oczy[ENTER]szeroko otwarte i szukaj \156lad\243w \156wiadcz\185cych o[ENTER]jego istnieniu. "
gameforge.new_quest_lv75._040_say = "dummy "
gameforge.new_quest_lv75._050_npcChat = "Zbadaj Upad\179ych Wojownik\243w "
gameforge.new_quest_lv75._060_say = "Chodzi o szcz\185tki wojownika. Lewa r\234ka nie[ENTER]wygl\185da na ludzk\185 ... musia\179a nale\191e\230 do Sura.[ENTER]Musz\234 koniecznie powiadomi\230 o tym odkryciu[ENTER]Heuk-Young. "
gameforge.new_quest_lv75._070_notice = "Strona... zamarzni\234ta w Podziemnym Lodowym[ENTER]Golemie... "
gameforge.new_quest_lv75._090_say = "Nie mog\234 Ci dok\179adnie powiedzie\230 czego my[ENTER]szukamy. Porozgl\185daj si\234 po prostu woko\179o, a[ENTER]je\156li zobaczysz co\156 interesuj\185cego to mi to[ENTER]poka\191. "
gameforge.new_quest_lv75._100_say = "Co tam masz? Pozw\243l, \191e spojrz\234! "
gameforge.new_quest_lv75._105_say = "O notatka... co to za pismo? Musi by\230 bardzo[ENTER]stare. Chyba znalaz\179e\156 co\156 wa\191nego. Wydaje mi[ENTER]si\234, \191e ju\191 to kiedy\156 widzia\179am. Wygl\185da na to,[ENTER]\191e to cz\234\156\230 jakie\156 ksi\185\191ki. "
gameforge.new_quest_lv75._109_say = "Gdyby uda\179o si\234 znale\159\230 jeszcze kilka Stron,[ENTER]wszystko na pewno nabra\179oby sensu.[ENTER]Poszukaj nowych wskaz\243wek! "
gameforge.new_quest_lv75._110_say = "No i znowu ty. Czy znalaz\179e\156 co\156 ciekawego?[ENTER]No powiedz! "
gameforge.new_quest_lv75._115_say = "Szkielet Sura...mo\191e to on lub jeden z jego[ENTER]wojownik\243w. Potrzebujemy wi\234cej dowod\243w, aby by\230[ENTER]ca\179kowicie pewnym. Szukaj innych wskaz\243wek...[ENTER]mo\191e bro\241, bi\191uteria, notatki lub co\156 co by nas[ENTER]ca\179kowicie przekona\179o o jego to\191samo\156ci. "
gameforge.new_quest_lv75._120_say = "Szkielet Sura i kartka z pami\234tnika? Niech rzuc\234[ENTER]okiem... Hmm, mo\191e faktycznie znalaz\179e\156 szcz\185tki[ENTER]Akuma. Potrzebujemy jednak wi\234cej dowod\243w. Dobrze[ENTER]si\234 spisa\179e\156, ale porozgl\185daj si\234 jeszcze, mo\191e[ENTER]znajdziesz co\156 wi\234cej. "
gameforge.new_quest_lv75._130_say = "Co\156 znalaz\179am, ale nie jestem zupe\179nie przekonana[ENTER]czy przebywa\179 tutaj legendarny Sura. Potrzebuj\234[ENTER]wi\234cej informacji. "
gameforge.new_quest_lv75._140_1_select = "Dobrze "
gameforge.new_quest_lv75._140_2_select = "Lodowe Stworzenie "
gameforge.new_quest_lv75._140_3_select = "Na kraw\234dzi rozpaczy "
gameforge.new_quest_lv75._140_4_select = "Mroczne Przera\191enie "
gameforge.new_quest_lv75._140_5_select = "W obliczu \156mierci "
gameforge.new_quest_lv75._140_6_select = "Losy wojownika "
gameforge.new_quest_lv75._140_7_select = "Nie, nie jestem tym zainteresowany. "
gameforge.new_quest_lv75._150_say = "Nie mog\234 nic odczyta\230 z tych strz\234pk\243w zda\241. Co\156[ENTER]o dworskim \191yciu oraz przesadnej \191\185dzy przyg\243d... "
gameforge.new_quest_lv75._160_1_say = "Pismo na po\191\243\179k\179ym pergaminie, w po\179owie ju\191[ENTER]wyblak\179e, nie mo\191na do ko\241ca odczyta\230. Wygl\185da na[ENTER]to, \191e zosta\179o napisane przez starego cz\179owieka[ENTER]lub bardzo s\179abego, bo litery s\185 bardzo[ENTER]niewyra\159ne, napisane trz\234s\185c\185 si\234 r\234k\185 \"...[ENTER]Lodowe Stworzenia. Nawet ja waleczny Sura nie[ENTER]by\179em w stanie ich doszcz\234tnie wyt\234pi\230. Kilka z[ENTER]nich w\234druje jeszcze po \156wiecie. Do tej pory[ENTER]kryj\243wka by\179a moim pewnym schronieniem, lecz[ENTER]wkr\243tce... w tym miejscu wyblak\179y litery. "
gameforge.new_quest_lv75._160_2_say = "R\243wnie\191 ta strona jest ju\191 wyblak\179a i po\191\243\179k\179a. W[ENTER]g\243rnym rogu mo\191na odcyfrowa\230 jeszcze dat\234, po[ENTER]kt\243rej jeste\156 w stanie pozna\230, \191e to bardzo stary[ENTER]pami\234tnik: 'Nie po raz pierwszy chcia\179bym cofn\185\230[ENTER]czas i post\185pi\230 inaczej podczas szukania tej[ENTER]Groty. By\179em dumny, zarozumia\179y oraz zbyt pewny[ENTER]siebie! Cechy te przywiod\179y mnie tutaj, abym[ENTER]stan\185 oko w oko ze \156mierci\185...' Ostatnie s\179owo[ENTER]jest kilka razy podkre\156lone. "
gameforge.new_quest_lv75._160_3_say = "Pergaminowa strona pami\234tnika jest bardzo[ENTER]uszkodzona, cz\234\156ciowo podarta. Mo\191esz przeczyta\230[ENTER]tylko niekt\243re cz\234\156ci wiadomo\156ci: '... dw\243r[ENTER]cesarza... uczeni pokazali mi to, czego skrycie[ENTER]pragn\185\179em... czyli jak otworzy\230 portal, jednak...[ENTER]\156mier\230 oraz zgroza w ciemno\156ci...' W tym miejscu[ENTER]strona jest niestety naderwana i ukrywa przed[ENTER]tob\185 dalsz\185 tre\156\230. "
gameforge.new_quest_lv75._160_4_say = "Na kartce znajduje si\234 rysunek u\156miechni\234tej[ENTER]kobiety. Pod rysunkiem jest co\156 napisane pismem,[ENTER]kt\243re ju\191 wcze\156niej widzia\179e\156. Wydaje si\234 jednak,[ENTER]\191e litery s\185 napisane jeszcze bardziej[ENTER]niewyra\159nie, dr\191\185c\185 r\234k\185 i jakby niepewnie:[ENTER]'\140mier\230 ma szpony - wczoraj si\234 o tym[ENTER]przekona\179em. Rzuci\179em tylko jedno spojrzenie na[ENTER]te bestialskie kreatury, zanim pogna\179em z[ENTER]powrotem ob\179\234dnie przera\191ony. Och, moja ukochana[ENTER]Sunmi, jakbym wcze\156niej wiedzia\179 co mnie czeka,[ENTER]nie zapuszcza\179bym si\234 tutaj za nic w \156wiecie!' "
gameforge.new_quest_lv75._160_5_say = "Pod panowaniem dynastii Hee-Se \191y\179 legendarny[ENTER]Sura o imieniu Akuma. By\179 bardzo dzielnym i[ENTER]utalentowanym wojownikiem, z czasem nie by\179o ju\191[ENTER]\156mia\179ka, kt\243ry odwa\191y\179by si\234 z nim walczy\230.[ENTER]Tak te\191 Akuma szuka\179 ci\185gle nowych wyzwa\241.[ENTER]Pewnego razu wpad\179y mu w r\234ce notatki opisuj\185ce[ENTER]niedost\234pne i tajemnicze miejsce. Postanowi\179 za[ENTER]wszelk\185 cen\234 je odnale\159\230. Uda\179o mu si\234 nawet[ENTER]nauczy\230 jak odnale\159\230 i uaktywni\230 staro\191ytne[ENTER]portale. Ruszaj\185c w drog\234 obieca\179 swojej[ENTER]ukochanej, \191e gdy tylko odnajdzie to miejsce,[ENTER]natychmiast do niej powr\243ci... jednak od tamtej[ENTER]pory s\179uch po nim zagin\185\179. "
gameforge.new_quest_lv75._170_say = "Pismo wygl\185da na bardzo stare... a w dodatku[ENTER]napisane dr\191\185c\185 r\234k\185 , jakby ten kt\243ry go pisa\179[ENTER]nie mia\179 wystarczaj\185cej si\179y... "
gameforge.new_quest_lv75._171_say = "To przecie\191 nie ma sensu. Potrzebujemy wi\234cej[ENTER]szczeg\243\179\243w. "
gameforge.new_quest_lv75._172_say = "Powoli zaczynam rozumie\230, co si\234 tutaj wydarzy\179o,[ENTER]ale jeszcze nie wszystko jest do ko\241ca jasne. "
gameforge.new_quest_lv75._173_say = "Czy chcesz pozna\230 szczeg\243\179y? "
gameforge.new_quest_lv75._174_say = "Jeszcze jedna strona! Kto\156 musia\179 by\230 naprawd\234[ENTER]zrozpaczony. Mam Ci stre\156ci\230 co jest tam[ENTER]napisane? "
gameforge.new_quest_lv75._175_say = "Niekt\243re strony s\185 w tak z\179ym stanie, \191e tylko[ENTER]mog\234 zgadywa\230 co jest napisane na nich. Jednak[ENTER]powoli wszystkie cz\234\156ci puzzli sk\179adaj\185 si\234 w[ENTER]ca\179o\156\230 tworz\185c interesuj\185c\185 histori\234, kt\243ra[ENTER]rozegra\179a si\234 dawno dawno temu w tej oto[ENTER]Komnacie. "
gameforge.new_quest_lv75._176_say = "Du\191o ju\191 nie brakuje. Chcesz us\179ysze\230 czego uda\179o[ENTER]mi si\234 dowiedzie\230 do tej pory? "
gameforge.new_quest_lv75._177_say = "Wygl\185da na to, \191e nie brakuje zbyt du\191o stron. "
gameforge.new_quest_lv75._178_say = "Chcesz us\179ysze\230 czego uda\179o mi si\234 dowiedzie\230 do[ENTER]tej pory? "
