gameforge.new_quest_lv75._210_say = "Przy ludzkich szcz\185tkach le\191\185 3 kartki pergaminu.[ENTER]Wygl\185da na to, \191e kto\156 je wyrwa\179 z ksi\185\191ki. Pismo[ENTER]jednak ju\191 wyblak\179o i trudno odczyta\230 co jest tam[ENTER]napisane. "
gameforge.new_quest_lv75._220_say = "S\185dz\234, \191e to wystarczy. Zanios\234 to co znalaz\179em[ENTER]do Heuk-Young. "
