gameforge.new_quest_lv75._280_say = "Zobacz, zrobi\179em dla Ciebie ksi\185\191k\234. Zszy\179em[ENTER]wszystkie strony razem i doda\179am jeszcze kilka[ENTER]moich notatek. Mo\191e Ci si\234 przydadz\185. Je\156li[ENTER]chcesz opowiem Ci histori\234 do ko\241ca. "
gameforge.new_quest_lv75._290_1_select = "Tak, opowiedz co\156 wi\234cej! "
gameforge.new_quest_lv75._290_2_select = "Nie, to mnie nie interesuje! "
