gameforge.new_quest_lv80._040_say = "To pierwszy raz gdy s\179ysz\234, \191e komu\156 uda\179o si\234[ENTER]stamt\185d powr\243ci\230. Musz\234 przyzna\230, to bardzo[ENTER]ciekawe... "
gameforge.new_quest_lv80._050_1_say = "Mam dla Ciebie misj\234, kt\243ra jest bardzo[ENTER]niebezpieczna. Jednak my\156l\234, \191e osoba tak zdolna[ENTER]jak ty powinna sobie poradzi\230. "
gameforge.new_quest_lv80._050_2_say = "Mam dla Ciebie misj\234, kt\243ra jest bardzo[ENTER]niebezpieczna. Jednak my\156l\234, \191e kobieta tak[ENTER]zdolna jak ty powinna sobie poradzi\230 bez[ENTER]problemu. "
gameforge.new_quest_lv80._060_say = "We\159 Pos\234pn\185 Drewnian\185 Mask\234 i udaj si\234 do[ENTER]Doyyumhwan. Poszukaj tam Ognistych Duch\243w.[ENTER]Mo\191liwe, \191e ju\191 je kiedy\156 spotka\179e\156 - s\185 to[ENTER]stworzenia, kt\243re ca\179y czas otacza ogie\241. "
gameforge.new_quest_lv80._070_say = "Je\156li zabijesz jednego z nich, Pos\234pna Drewniana[ENTER]Maska zareaguje i przemieni si\234 w popi\243\179. Nie[ENTER]tra\230 odwagi, gdy nie uda si\234 za pierwszym razem. "
