gameforge.new_quest_lv80._190_say_reward = "ze sob\185. Zgodnie z tym, co powiedzia\179 Soon, Maska[ENTER]zamieni si\234 w Zaczarowany Popi\243\179 podczas walki z[ENTER]Ognistymi Duchami. "
