gameforge.npc_talk = {}
gameforge.npc_talk._100_say = "Jestem ju\191 naprawd\234 starym cz\179owiekiem jednak[ENTER]nadal jestem zdrowy i sprawny, poniewa\191 znam[ENTER]pewien sekret. Odkry\179em, \191e mikstura zrobiona z[ENTER]korzeni Gango i Grzyb\243w Tue wyd\179u\191a \191ycie.[ENTER]Je\156li chcia\179by\156 j\185 wypr\243bowa\230, zanie\156 potrzebne[ENTER]materia\179y do Yu-Hwan. Jestem pewny, \191e z ch\234ci\185[ENTER]przygotuje Ci tak\185 mikstur\234. "
gameforge.npc_talk._10_say = "B\185d\159 cicho i zachowaj dyscyplin\234. Zachowuj si\234 i[ENTER]nie sprawiaj \191adnych k\179opot\243w. Powiniene\156[ENTER]szanowa\230 ludzi w Metin2. Zrozumia\179e\156? "
gameforge.npc_talk._110_npcChat = "Wygl\185dasz na silnego... "
gameforge.npc_talk._120_say = "Od wielu pokole\241, sekret wielkiej si\179y jest[ENTER]przekazywany w mojej rodzinie z pokolenia na[ENTER]pokolenie. M\243j ojciec powiedzia\179 mi kiedy\156, \191e[ENTER]je\156li we w\179a\156ciwy spos\243b przygotuje si\234 Pokrzyw\234,[ENTER]to mo\191na otrzyma\230 mikstur\234 zwi\234kszaj\185c\185 si\179\234 na[ENTER]kr\243tki okres czasu. Z tego co wiem, Baek-Go zna[ENTER]t\234 receptur\234. Musisz tylko dostarczy\230 mu[ENTER]odpowiednie sk\179adniki.  "
gameforge.npc_talk._130_npcChat = "Sz\179a dzieweczka do laseczka. Do zielonego... "
gameforge.npc_talk._140_sayTitle = "Muzyk Yu-Hwan: "
gameforge.npc_talk._150_say = "...do zielonego, do zielonego. Napotka\179a[ENTER]my\156liweczka ...[ENTER]Lubisz \156piewa\230? \140piewam sobie czasem w[ENTER]samotno\156ci, dzi\234ki temu nie my\156l\234 o wojnie.[ENTER]Ale bez Kr\243lestwa, kt\243re mnie ochroni, nie b\234d\234[ENTER]m\243g\179 robi\230 tego co lubi\234. "
gameforge.npc_talk._160_npcChat = "Dlaczego czytasz tak du\191o? "
gameforge.npc_talk._170_sayTitle = "Mol Ksi\185\191kowy Soon: "
gameforge.npc_talk._180_say = "Oh, poszukiwacz przyg\243d. \140wiat to jedno wielkie[ENTER]wyzwanie, tylko maj\185c wiedz\234 mo\191na przetrwa\230.[ENTER]Zawsze szanuj swoje ksi\185\191ki. Pomog\185 Ci w z\179ych[ENTER]czasach. Mo\191esz mi wierzy\230! "
gameforge.npc_talk._190_npcChat = "Masz dzieci? "
gameforge.npc_talk._200_say = "W\179a\156ciwie nie chcia\179em dzieci, ale... Od czasu do[ENTER]czas zbieram kwiaty Kaki, poniewa\191 zwi\234kszaj\185 one[ENTER]magiczn\185 energi\234. Baek-Go odkry\179 spos\243b na[ENTER]wytwarzanie z nich mikstur. Potrzebuje on tylko[ENTER]jeden kwiat Kaki, aby przyrz\185dzi\230 100 mikstur.[ENTER]Niestety kwiaty Kaki maj\185 tak\191e efekty uboczne,[ENTER]je\191eli kobieta ma na sobie naszyjnik z tych[ENTER]kwiat\243w, to urodzi syna. M\243wi\185c mi\234dzy nami, moja[ENTER]\191ona wykorzysta\179a to bezwstydnie. "
gameforge.npc_talk._20_npcChat = "Co za cudowny zapach... "
gameforge.npc_talk._210_npcChat = "Co z Twoj\185 nog\185? "
gameforge.npc_talk._220_sayTitle = "Handu-Up: "
gameforge.npc_talk._230_say = "Znowu si\234 zacz\234\179o. Ostatnio podczas wyprawy[ENTER]potkn\234\179am si\234 o Korze\241 Gango i skr\234ci\179am kostk\234.[ENTER]Na szcz\234\156cie znam uzdrawiacza Baek-Go, kt\243ry[ENTER]opatrzy\179 mi kostk\234. Powiedzia\179 mi, \191e z korzeni[ENTER]Gango mo\191na przygotowa\230 mikstury, kt\243re s\185 w[ENTER]stanie uleczy\230 niewielkie rany. A wi\234c zrobi\179am[ENTER]herbatk\234 ze sprawcy mojej skr\234conej kostki i tym[ENTER]sposobem naprawi\179 szkody jakie wyrz\185dzi\179... "
gameforge.npc_talk._240_npcChat = "Kim jeste\156? "
gameforge.npc_talk._250_sayTitle = "Wonda-Rim: "
gameforge.npc_talk._260_say = "Jestem Wonda-Rim, bratanek Chaegiraba. M\243j wujek[ENTER]jest bardzo s\179awnym biologiem! Znasz go? Zajmuje[ENTER]si\234 sporz\185dzaniem mikstur z przer\243\191nych zi\243\179.[ENTER]Odkry\179, \191e je\156li zmiesza si\234 100 W\243d Bo z Morw\185,[ENTER]to mo\191na otrzyma\230 bardzo siln\185 ochron\234 przed[ENTER]magi\185. Z tego co wiem, Huahn-So jest w stanie[ENTER]przygotowa\230 tak\185 mikstur\234. Wystarczy, \191e dasz mu[ENTER]odpowiednie sk\179adniki. "
gameforge.npc_talk._270_npcChat = "Dlaczego masz tyle blizn? "
gameforge.npc_talk._280_sayTitle = "Zdrajca Balso: "
gameforge.npc_talk._290_say = "Chyba nie jestem najlepszym wojownikiem, poniewa\191[ENTER]cz\234sto by\179em ranny podczas walk. Poprosi\179em[ENTER]kiedy\156 Yu-Hwann, aby sporz\185dzi\179 dla mnie mikstur\234[ENTER]chroni\185c\185 moje cia\179o przed atakami innych.[ENTER]Przygotowa\179 mikstur\234 z Pokrzywy i Bzu, ale nie[ENTER]dzia\179a ona tak jak chcia\179em. A mo\191e po prostu[ENTER]jestem kiepskim wojownikiem. S\185dz\234 jednak, \191e[ENTER]Tobie taka mikstura na pewno pomo\191e w walkach. "
gameforge.npc_talk._300_npcChat = "Dlaczego nazywaj\185 Ci\234 zdrajc\185? "
gameforge.npc_talk._30_sayTitle = "W\179a\156ciciel Restauracji, Octavio: "
gameforge.npc_talk._310_say = "Kiedy\156 uciek\179em przed wojn\185 i do\179\185czy\179em do Gangu[ENTER]Czarnego Wiatru. Moi towarzysze nigdy mi tego nie[ENTER]wybaczyli. Z biegiem czasu przekona\179em si\234 o[ENTER]bestialskich metodach wojownik\243w Czarnego Wiatru.[ENTER]Zabijali niewinnych ludzi. Nie mog\179em ju\191 d\179u\191ej[ENTER]tego znie\156\230 i natychmiast odszed\179em. Co za[ENTER]okropno\156\230! "
gameforge.npc_talk._320_say = "Masz na sumieniu niewinnych ludzi? W takim razie[ENTER]w pe\179ni zas\179ugujesz na to, by Ci\234 nazwano[ENTER]zdrajc\185. To ty odebra\179e\156 im mo\191liwo\156\230 spokojnego[ENTER]\191ycia. "
gameforge.npc_talk._330_say = "To \156wiat bezprawia. Postanowi\179em jednak, \191e nie[ENTER]uczyni\234 ju\191 niczego z\179ego. Nie chc\234, aby mnie[ENTER]ludzie nazywali zdrajc\185.[ENTER][ENTER][ENTER]Masz dla mnie troch\234 Yang? "
gameforge.npc_talk._340_npcChat = "To Ciebie nazywaj\185 m\234drcem? "
gameforge.npc_talk._350_sayTitle = "M\234drzec Uriel: "
gameforge.npc_talk._360_say = "Jest tak wiele rzeczy do nauczenia si\234 w tym[ENTER]szerokim \156wiecie. Ignorancja wyposa\191ona w si\179\234[ENTER]militarn\185, to z\179a kombinacja. Nie chcesz \191y\230, jak[ENTER]Ci ignoranccy \191o\179nierze, prawda? Wiedza to si\179a! "
gameforge.npc_talk._370_npcChat = "Powiedziano mi, \191e jeste\156 uzdrawiaczem. Czy to prawda? "
gameforge.npc_talk._380_say = "Robi\234 co mog\234. Niestety, w tym niebezpiecznym[ENTER]\156wiecie coraz wi\234cej jest rannych. Nie mamy[ENTER]wystarczaj\185cej ilo\156ci lek\243w ani pomocnik\243w.[ENTER]Nasta\179y ci\234\191kie czasy! Czy jest jaka\156 szansa, \191e[ENTER]mi p\243\159niej pomo\191esz? "
gameforge.npc_talk._390_npcChat = "Jak tam \179owy? "
gameforge.npc_talk._400_sayTitle = "\163owca Yang-Shin: "
gameforge.npc_talk._40_say = "Witaj! Nasza Restauracja jest cz\234\156ci\185 wielkiego[ENTER]mi\234dzynarodowego kompleksu. Wejd\159 i sprawd\159 nas. "
gameforge.npc_talk._410_say = "Hmm, od czasu upadku Kamieni Metin, zwierz\234ta[ENTER]sta\179y si\234 dzikie. W dzisiejszych czasach,[ENTER]zab\243jcze mo\191e by\230 nawet polowanie na kury.[ENTER]Nasta\179y niebezpieczne czasy dla wszystkich[ENTER]\163owc\243w. Na szcz\234\156cie nale\191\234 do grona najlepszych! "
gameforge.npc_talk._420_npcChat = "Sk\185d bierze si\234 Twoja celno\156\230 strza\179\243w? "
gameforge.npc_talk._430_say = "W strzelaniu z \179uku jestem nie do pokonania. A to[ENTER]wszystko dlatego, \191e znam specjaln\185 receptur\234,[ENTER]hehe! Je\156li zmieszasz Sok z Kwiatu Brzoskwini i[ENTER]Bez, otrzymasz wspania\179\185 mikstur\234.[ENTER]Mo\191e ona zwi\234kszy\230 celno\156\230 Twoich cios\243w. Je\156li[ENTER]chcesz j\185 wypr\243bowa\230, zanie\156 sk\179adniki do Yu-Hwan[ENTER]i popro\156 go o przyrz\185dzenie odpowiedniego naparu. "
gameforge.npc_talk._440_npcChat = "Och, jaki pi\234kny wianek z kwiat\243w... "
gameforge.npc_talk._450_say = "Dawniej zawsze zbiera\179am Kwiaty Brzoskwi\241 z moim[ENTER]bratem, dzisiaj musz\234 to robi\230 sama. Kwiaty s\185[ENTER]nie tylko pi\234kne i pachn\185ce, ale te\191 posiadaj\185[ENTER]szczeg\243lne dzia\179anie. Je\156li zaniesiesz Kwiat[ENTER]Brzoskwini do Baek-Go, to sporz\185dzi on z niego[ENTER]mikstur\234, kt\243ra uczyni Ci\234 bardzo zwinnym! "
gameforge.npc_talk._460_npcChat = "Gdzie jest tw\243j brat? "
gameforge.npc_talk._470_say = "Ostatnio m\243j brat du\191o podr\243\191uje. Bardzo si\234 o[ENTER]niego martwi\234. "
gameforge.npc_talk._480_npcChat = "Sprzedajesz Ciastka Ry\191owe? "
gameforge.npc_talk._490_sayTitle = "Yu-Rang, Sprzedawca Tort\243w: "
gameforge.npc_talk._500_say = "Podczas wojny ci\234\191ko jest sprzedawa\230 Ciastka[ENTER]Ry\191owe. Dzi\234ki bandytom, stracili\156my wi\234kszo\156\230[ENTER]klient\243w. Nie wiem ile jeszcze poci\185gn\234 ten[ENTER]interes. "
gameforge.npc_talk._50_say = "Pomimo, \191e jest to du\191a restauracja, dekoracja[ENTER]jest ca\179kiem prosta. "
gameforge.npc_talk._510_npcChat = "Kto kupuje u Ciebie? "
gameforge.npc_talk._520_say = "Najwi\234cej Ciastek Ry\191owych sprzedaj\234 podczas[ENTER]moich podr\243\191y. Pewnego dnia tajemniczy rycerz w[ENTER]czerni stan\185\179 przede mn\185 i chcia\179 kupi\230 ciastko.[ENTER]Okaza\179o si\234 jednak, \191e nie ma Yang. W zamian za[ENTER]ciastko, da\179 mi pewn\185 receptur\234. Receptura ta[ENTER]opisywa\179a krok po kroku przygotowa\230 Wod\234 Zin.[ENTER]Mikstura jest w stanie poprawi\230 Si\179\234 Ataku.[ENTER]Sprzeda\179am j\185 Huahn-Son. Je\156li zaniesiesz[ENTER]Huahn-Son Wod\234 Sim i R\243\191\234 Alpejsk\185 na pewno z[ENTER]ch\234ci\185 sporz\185dzi tak\185 mikstur\234 dla Ciebie. "
gameforge.npc_talk._530_npcChat = "Dlaczego spogl\185dasz tak smutno? "
gameforge.npc_talk._540_say = "Oh, kto by pomy\156la\179, \191e nasze s\179odkie marzenia[ENTER]m\179odej pary zostan\185 tak bezlito\156nie zniszczone.[ENTER]M\243j biedny m\185\191... poleg\179 na polu bitwy![ENTER]Prosz\234, pom\156cij jego \156mier\230. "
gameforge.npc_talk._550_npcChat = "Wielu ginie podczas wojny... "
gameforge.npc_talk._560_say = "Coraz wi\234cej m\234\191czyzn ginie na wojnie, wi\234c my,[ENTER]kobiety z wioski, postanowi\179y\156my poprosi\230[ENTER]Huahn-So aby stworzy\179 lepsze mikstury uleczaj\185ce.[ENTER]Po bardzo d\179ugich badaniach i eksperymentach[ENTER]uda\179o mu si\234 znale\159\230 spos\243b na wyprodukowanie[ENTER]mikstury, kt\243ra zwi\234ksza obron\234 - dzi\234ki temu[ENTER]zu\191ywa si\234 mniej zwyk\179ych mikstur leczniczych.[ENTER]Id\159 i z nim porozmawiaj. Na pewno Ci pomo\191e.[ENTER]Odkryt\185 mikstur\234 nazwa\179 Wod\185 SamBo. Aby j\185[ENTER]wyprodukowa\230 potrzebuje Wod\234 Dok i R\243\191\234 Alpejsk\185. "
gameforge.npc_talk._570_npcChat = "Och, co za s\179odki brzd\185c... "
gameforge.npc_talk._580_sayTitle = "Ah-Yu: "
gameforge.npc_talk._590_say = "Znowu zaczyna krzycze\230...[ENTER]Ju\191 nie wiem czy chce troch\234 s\179odyczy czy.... och[ENTER]nie! "
gameforge.npc_talk._600_npcChat = "Co u was s\179ycha\230? "
gameforge.npc_talk._60_npcChat = "Opowiedz mi troch\234 o ceramice. "
gameforge.npc_talk._610_say = "Moje dziecko! Jestem taka nerwowa... Teraz, kiedy[ENTER]m\243j m\185\191 poleg\179 na wojnie, musz\234 si\234 odnale\159\230....[ENTER]Pr\243buj\234 utrzyma\230 mnie i moje dziecko sama. To[ENTER]dzi\234ki Wodzie Bo mog\234 zapewni\230 utrzymanie mojej[ENTER]rodzinie. Musz\234 dostarczy\230 do Yu-Hwan 100 Sok\243w z[ENTER]Kwiat\243w Kaki i jeden Grzyb Tue. Za dostarczenie[ENTER]tych sk\179adnik\243w dostan\234 Wod\234 Bo, kt\243r\185 b\234d\234 mog\179a[ENTER]sprzeda\230. Musz\234 jako\156 dostarczy\230 te materia\179y... "
gameforge.npc_talk._620_npcChat = "Co s\179ycha\230 u Twojego m\234\191a? "
gameforge.npc_talk._630_sayTitle = "Aranyo: "
gameforge.npc_talk._640_say = "M\243j tak zwany m\185\191 o\191eni\179 si\234 z w\179asnymi[ENTER]ksi\185\191kami. On ledwie na mnie spogl\185da.[ENTER]A ja nie jestem brzydk\185 kobiet\185. "
gameforge.npc_talk._650_npcChat = "Jak tam Twoje interesy? "
gameforge.npc_talk._660_say = "Od czasu rozpocz\234cia wojny, bardzo trudno na[ENTER]siebie zarobi\230. Zwi\185zek Handlowy kiedy\156 by\179[ENTER]bardzo pot\234\191ny, ale jego czasy \156wietno\156ci min\234\179y.[ENTER]Nie mo\191emy ju\191 d\179u\191ej ignorowa\230 dzikus\243w,[ENTER]Zaprzysi\234\191onych \175o\179nierzy i \175o\179nierzy Czarnego[ENTER]Wiatru tak jak by\179o do tej pory. "
gameforge.npc_talk._670_npcChat = "Dlaczego jeste\156 w z\179ym nastroju? "
gameforge.npc_talk._680_sayTitle = "Taurean: "
gameforge.npc_talk._690_say = "Harang to niedobra dziewczyna![ENTER]Nienawidz\234 jej! Jestem s\179aby, a ona cz\234sto mnie[ENTER]zaczepia! "
gameforge.npc_talk._700_say = "Jeste\156 facetem i masz mi\234\156nie.[ENTER]Po\230wicz je troch\234! "
gameforge.npc_talk._70_sayTitle = "Garncarz Yonah: "
gameforge.npc_talk._710_npcChat = "Co ty robisz? "
gameforge.npc_talk._720_sayTitle = "Harang: "
gameforge.npc_talk._730_say = "Czekam na Taurean! Cz\234sto bawimy si\234 razem i[ENTER]walczymy ze sob\185. Co za tch\243rz! Je\156li nie[ENTER]przyjdzie sam, to oberwie po uszach! "
gameforge.npc_talk._740_npcChat = "Taurean boi si\234 Ciebie. "
gameforge.npc_talk._750_say = "Taurean jest silniejszy ode mnie, dlatego te\191[ENTER]wymy\156li\179am spos\243b na pokonanie go w walce. Wiem[ENTER]od pewnego m\185drego ninja, \191e je\156li pomieszam Wod\234[ENTER]Young z Morw\185, to otrzymam mikstur\234, kt\243ra[ENTER]umo\191liwia szybsze zadawanie cios\243w. Z tak\185[ENTER]mikstur\185 jestem w stanie pokona\230 Taurean, nawet,[ENTER]je\156li jest silniejszy. Je\156li chcia\179by\156 szybciej[ENTER]zadawa\230 ciosy, to udaj si\234 do Huahn-So z[ENTER]odpowiednimi sk\179adnikami i popro\156 go, aby[ENTER]przygotowa\179 tak\185 mikstur\234 dla Ciebie. "
gameforge.npc_talk._760_npcChat = "Nowy wgl\185d... "
gameforge.npc_talk._770_say_title = "Seon-Pyeong: "
gameforge.npc_talk._780_say = "M\243j przyjacielu, \156wiat jest pe\179en pyta\241 bez[ENTER]odpowiedzi. A ja jestem cz\179owiekiem poszukuj\185cym[ENTER]odpowiedzi i nowej wiedzy. Czy s\179ysza\179e\156 kiedy\156 o[ENTER]epickich broniach i Kamieniach Duszy? "
gameforge.npc_talk._790_npcChat = "Co ty robisz? "
gameforge.npc_talk._800_say = "Prawdopodobnie ju\191 wiesz, \191e na co dzie\241 zajmuj\234[ENTER]si\234 studiowaniem wyj\185tkowych rzeczy. Obecnie[ENTER]badam metod\234 ulepszania broni i Kamieni Duszy. "
gameforge.npc_talk._80_say = "Garncarstwo to wdzi\234czne zaj\234cie. Lubi\234 wyrabia\230[ENTER]z glinki r\243\191ne przedmioty, nadawa\230 im kszta\179t i[ENTER]obserwowa\230 jak one powstaj\185... Wyrabiam proste[ENTER]rzeczy. Na wschodzie, poza tym kontynentem s\185[ENTER]metody produkcji du\191o dalej rozwini\234te. Raz[ENTER]widzia\179em przedmioty wykonane z gliny przez[ENTER]garncarza stamt\185d i by\179em pod wra\191eniem. Nadal[ENTER]badam ich przedmioty. Chc\234 wiedzie\230 jakich[ENTER]sztuczek oni u\191ywaj\185. "
gameforge.npc_talk._810_npcChat = "Badania dotycz\185ce broni... "
gameforge.npc_talk._820_say = "Interesuj\185ce, nieprawda\191? Czy chcesz wiedzie\230[ENTER]wi\234cej? W takim razie przynie\156 mi najprawdziwsz\185[ENTER]bro\241 +9 na poziomie 65.[ENTER]B\234d\234 r\243wnie\191 potrzebowa\179 Broszury Szermierki i[ENTER]dw\243ch Zwoj\243w B\179ogos\179awie\241stwa. Z tych sk\179adnik\243w[ENTER]spr\243buj\234 wytworzy\230 epick\185 bro\241. "
gameforge.npc_talk._830_say = "Jednak nie mog\234 obieca\230, \191e to zadzia\179a. "
gameforge.npc_talk._840_npcChat = "Kamienie Duszy... "
gameforge.npc_talk._850_say = "Kamienie Duszy s\185 powszechnie u\191ywane, ale mimo[ENTER]to, wi\234kszo\156\230 os\243b nie zna ich prawdziwej mocy.[ENTER]Dzi\234ki moim badaniom dowiedzia\179em si\234 o nich[ENTER]znacznie wi\234cej! Je\191eli przyniesiesz mi Kamie\241[ENTER]Duszy, mog\234 go dla Ciebie ulepszy\230. "
gameforge.npc_talk._90_npcChat = "Wygl\185dasz na silnego i zdrowego jak na Twoje lata... "
gameforge.olympic_badge = {}
gameforge.olympic_badge._010_npcChat = "Medal Bohatera "
gameforge.olympic_badge._020_say = "Pomocy! "
gameforge.olympic_badge._030_say = "Co za z\179odziejskie szumowiny...[ENTER]Wczoraj w nocy kto\156 si\234 do mnie w\179ama\179 i ukrad\179[ENTER]m\243j Medal Bohatera! By\179a to pami\185tka po moim[ENTER]przodku, kt\243ry otrzyma\179 go, gdy przeby\179 42,195[ENTER]kilometr\243w z pola bitwy do cesarza, aby[ENTER]poinformowa\230 go o zwyci\234stwie.[ENTER]Przepad\179! "
gameforge.olympic_badge._040_say = "A niech to... dla mojej rodziny jest on bezcenny.[ENTER]Co ja teraz poczyni\234? "
gameforge.olympic_badge._050_say = "Pomo\191esz mi? "
gameforge.olympic_badge._060_npcChat = "Medal Bohatera "
gameforge.olympic_badge._070_say = "Nareszcie wracasz![ENTER]I co? Masz m\243j Medal Bohatera? "
gameforge.olympic_badge._080_say = "Ale dlaczego? Po co jakim\156 rabusiom m\243j medal? Ma[ENTER]on przecie\191 tylko warto\156\230 sentymentaln\185![ENTER]Pomo\191esz mi go odzyska\230? "
gameforge.olympic_badge._090_npcChat = "Znajd\159 Medal Bohatera! "
gameforge.olympic_badge._100_say = "Wracasz z pustymi r\234koma? O nie, jestem[ENTER]zrozpaczony. Je\156li ty mi nie mo\191esz pom\243c, to w[ENTER]takim razie kto? Kontynuuj poszukiwania, prosz\234! "
gameforge.olympic_badge._110_say = "Masz m\243j medal![ENTER]Ale zaczekaj no... to jest tylko jego cz\234\156\230! Co[ENTER]za dranie, po\179amali go![ENTER]Przynie\156 im prosz\234 wszystkie jego cz\234\156ci, a by\230[ENTER]mo\191e uda mi si\234 go poskleja\230. "
gameforge.olympic_badge._120_say = "Ci podli z\179oczy\241cy po\179amali moj\185 bezcenn\185[ENTER]rodzinn\185 pami\185tk\234![ENTER]Dzi\234kuj\234 ci bardzo za odnalezienie wszystkich[ENTER]cz\234\156ci. Teraz b\234d\234 je m\243g\179 poskleja\230. "
gameforge.olympic_badge._130_say = "Stokrotne dzi\234ki! Zwr\243ci\179e\156 honor mojej rodziny.[ENTER]Oczywi\156cie pragn\234 ci si\234 odwdzi\234czy\230. Oto twoja[ENTER]nagroda! "
gameforge.olympic_badge._140_say = "Na pewno chcesz odrzuci\230 to zlecenie?[ENTER]Je\156li wybierzesz 'Tak', nie b\234dziesz w stanie[ENTER]przyj\185\230 go ponownie. "
gameforge.olympic_badge._150_say = "Rozumiem... nie masz po prostu czasu. No c\243\191,[ENTER]wr\243\230 jak poza\179atwiasz swoje pilne sprawy. Ale nie[ENTER]guzdraj si\234 zbyt d\179ugo! "
gameforge.olympic_badge._160_say = "Niestety przybywasz zbyt p\243\159no i nie mo\191esz mi[ENTER]ju\191 pom\243c. \175ycz\234 ci mn\243stwa sukces\243w podczas[ENTER]twoich bohaterskich podr\243\191y! "
gameforge.olympic_badge._170_say = "Zapoluj na te potwory, kt\243re mnie okrad\179y! Ale[ENTER]uwa\191aj, s\185 one bardzo silne - co najmniej poziomu[ENTER]30. Je\156li odzyskasz dla mnie m\243j Medal Bohatera,[ENTER]hojnie ci\234 wynagrodz\234. "
gameforge.olympic_badge._180_say = "Znajd\159 Medal Bohatera i zanie\156 go do Yu-Hwan. "
gameforge.olympic_badge._190_say = "Yu-Hwan prosi ci\234 o pomoc. Udaj si\234 do niego![ENTER]Znajdziesz go w drugiej wiosce. "
