gameforge.spider_dungeon_3floor_boss._100_say = "Nie powiesz mi chyba, \191e zabrak\179o ci odwagi do[ENTER]przeszukania Lochu Paj\185k\243w? Przecie\191 posiadasz[ENTER]mn\243stwo do\156wiadczenia w boju, tak \191e kilka[ENTER]bezm\243zgich paj\234czak\243w nie powinno stanowi\230 dla[ENTER]ciebie wi\234kszego problemu. Wiesz jednak, \191e[ENTER]potrzebujesz przepustki, aby wej\156\230 do tej[ENTER]jaskini, prawda? "
gameforge.spider_dungeon_3floor_boss._10_npcChat = "Wej\156cie do kryj\243wki Baron\243wny "
gameforge.spider_dungeon_3floor_boss._110_sendLetter = "Nowe niebezpiecze\241stwo "
gameforge.spider_dungeon_3floor_boss._120_say = "Uda\179o ci si\234 wykona\230 dok\179adn\185 kopi\234 inskrypcji.[ENTER]Poka\191 j\185 Kapitanowi. "
gameforge.spider_dungeon_3floor_boss._130_say = "\140wietnie, dobra robota! Niechaj zerkn\234... hmmm,[ENTER]nie kojarz\234 tych znak\243w, nic z tego nie rozumiem.[ENTER]Mo\191e trzeba by zapyta\230 m\234drca Uriela? "
gameforge.spider_dungeon_3floor_boss._140_say = "Udaj si\234 do m\234drca Uriela i poka\191 mu inskrypcj\234.[ENTER]On na pewno b\234dzie w stanie j\185 rozszyfrowa\230. "
gameforge.spider_dungeon_3floor_boss._150_say = "Kapitan chce, abym mu przet\179umaczy\179 t\234 tajemnicz\185[ENTER]inskrypcj\234? Nie ma sprawy, uwielbiam takie[ENTER]wyzwania. Poka\191 no...[ENTER]To... to nies\179ychane! Zaczekaj, zaraz spisz\234 ci[ENTER]t\179umaczenie. Masz! Zanie\156 to jak najszybciej[ENTER]Kapitanowi, po czym wr\243\230 do mnie. Je\156li ta[ENTER]inskrypcja m\243wi prawd\234, to wszyscy jeste\156my w[ENTER]strasznym niebezpiecze\241stwie. Le\230 ju\191, le\230! "
gameforge.spider_dungeon_3floor_boss._160_say = "Nie uda\179o ci si\234 jeszcze dotrze\230 do Kapitana?[ENTER]Prosz\234, musisz si\234 po\156pieszy\230, sprawa jest bardzo[ENTER]powa\191na! Kapitan musi koniecznie przeczyta\230 ten[ENTER]list. "
gameforge.spider_dungeon_3floor_boss._170_sayTitle = "Przeka\191 list Uriela "
gameforge.spider_dungeon_3floor_boss._180_say = "Ach, ten uparty stary gadu\179a... przyda\179oby si\234[ENTER]przynajmniej jakie\156 'dzi\234kuj\234'. Ale niech mu[ENTER]b\234dzie. Twierdzi, \191e te informacje s\185 bardzo[ENTER]wa\191ne, wi\234c lepiej dostarcz\234 je czym pr\234dzej[ENTER]Kapitanowi. "
gameforge.spider_dungeon_3floor_boss._190_npcChat = "List Uriela "
gameforge.spider_dungeon_3floor_boss._200_say = "A niech mnie szlag! Na trzecim poziomie Lochu[ENTER]Paj\185k\243w zagnie\159dzi\179 si\234 pot\234\191ny paj\234czy demon -[ENTER]Baron\243wna Paj\185k\243w! Wed\179ug inskrypcji potrzebny[ENTER]jest jaki\156 specjalny klucz, aby wkroczy\230 do tej[ENTER]ukrytej jaskini. Udaj si\234 do Uriela i spytaj go o[ENTER]ten klucz. Potem zwerbuj ekip\234 do\156wiadczonych[ENTER]wojownik\243w i wsp\243lnie zaatakujcie kryj\243wk\234[ENTER]Baron\243wny Paj\185k\243w! Masz, mam dla ciebie kolejn\185[ENTER]przepustk\234. "
gameforge.spider_dungeon_3floor_boss._20_say = "Wrota te mo\191na otworzy\230 wy\179\185cznie za pomoc\185[ENTER]Paj\234czego Klucza. "
gameforge.spider_dungeon_3floor_boss._210_npcChat = "Paj\234czy Klucz "
gameforge.spider_dungeon_3floor_boss._220_say = "No nic, trzeba jak najszybciej uda\230 si\234 do Uriela. "
gameforge.spider_dungeon_3floor_boss._230_say = "Ach, dobrze, \191e jeste\156 ju\191 z powrotem. A wi\234c[ENTER]Kapitan wyda\179 ci rozkaz zg\179adzenia Baron\243wny[ENTER]Paj\185k\243w? Jednak wej\156cie do jej kryj\243wki jest[ENTER]zablokowane, a otworzy\230 je mo\191na wy\179\185cznie za[ENTER]pomoc\185 Paj\234czego Klucza. Wykonanie takiego klucza[ENTER]jest bardzo skomplikowane. Ale je\156li przyniesiesz[ENTER]mi Worek z Paj\234cz\185 Trucizn\185, Worek z Paj\234czymi[ENTER]Jajami, Paj\234cz\185 Sie\230, Oczy Paj\185ka, Nogi Paj\185ka[ENTER]oraz Jad Kr\243lowej Paj\185k\243w, to powinienem by\230 w[ENTER]stanie tego dokona\230. "
gameforge.spider_dungeon_3floor_boss._240_say = "Chcesz, aby skonstruowa\179 dla ciebie Paj\234czy[ENTER]Klucz? Potrzebuj\234 do tego Worek z Paj\234cz\185[ENTER]Trucizn\185, Worek z Paj\234czymi Jajami, Paj\234cz\185 Sie\230,[ENTER]Oczy Paj\185ka, Nogi Paj\185ka oraz Jad Kr\243lowej[ENTER]Paj\185k\243w. Uda\179o ci si\234 znale\159\230 wszystkie[ENTER]sk\179adniki? "
gameforge.spider_dungeon_3floor_boss._250_say = "\140wietnie! Masz wszystkie sk\179adniki! Poczekaj[ENTER]chwil\234, nie potrwa to zbyt d\179ugo... "
gameforge.spider_dungeon_3floor_boss._260_say = "No i prosz\234! Oto Paj\234czy Klucz, kt\243ry umo\191liwi ci[ENTER]wej\156cie do kryj\243wki Baron\243wny Paj\185k\243w. A tobie[ENTER]oraz twoim kompanom \191ycz\234 powodzenia w walce z t\185[ENTER]d\179ugonog\185 besti\185. Musicie si\234 jednak pospieszy\230,[ENTER]poniewa\191 klucz ten jest bardzo niestabilny i[ENTER]rozpadnie si\234 po up\179ywie 24 godzin. "
gameforge.spider_dungeon_3floor_boss._270_say = "No i... ech, no niestety, proces wykuwania tego[ENTER]klucza jest bardzo skomplikowany i nie zawsze si\234[ENTER]udaje. Wystarczy drobny b\179\185d, aby spartaczy\230 ca\179\185[ENTER]robot\234. Niestety wraz z kluczem przepad\179y r\243wnie\191[ENTER]wszystkie sk\179adniki, kt\243re od ciebie otrzyma\179em.[ENTER]Wybacz, \191e twoja \191mudna zbieranina posz\179a na[ENTER]marne. Nast\234pnym razem na pewno wszystko wypali! "
gameforge.spider_dungeon_3floor_boss._280_say = "Nie, nie posiadasz jeszcze wszystkich sk\179adnik\243w,[ENTER]dla przypomnienia: potrzebujemy Worek z Paj\234cz\185[ENTER]Trucizn\185, Worek z Paj\234czymi Jajami, Paj\234cz\185 Sie\230,[ENTER]Oczy Paj\185ka, Nogi Paj\185ka oraz Jad Kr\243lowej[ENTER]Paj\185k\243w. "
gameforge.spider_dungeon_3floor_boss._300_say = "Przyw\243dca twojej grupy wkroczy\179 do lochu. Chcesz[ENTER]do niego do\179\185czy\230? "
