gameforge.spider_dungeon_3floor_boss._320_say = "W kryj\243wce Baron\243wny znajduje si\234 ju\191 jaka\156 grupa[ENTER]atakuj\185ca Baron\243wn\234 Paj\185k\243w. "
gameforge.spider_dungeon_3floor_boss._330_say = "Wej\156cie b\234dzie mo\191liwe dopiero, gdy obecnie[ENTER]znajduj\185ca si\234 tam grupa uko\241czy swoje zadanie.[ENTER]Wr\243\230 za %s min. "
