gameforge.subquest_01._140_sayTitle = "Yonah: "
gameforge.subquest_01._150_say = "Argh! Do diab\179a![ENTER]Nie mog\234 przesta\230 kaszle\230! Jak ja mog\234 w tym[ENTER]stanie pracowa\230?[ENTER]Przys\179a\179a Ci\234 Handlarka R\243\191no\156ci? Sprzedaj\234 Puste[ENTER]Butelki, a nie rozdaje za darmo. "
gameforge.subquest_01._160_say = "Jestem astmatykiem. Powiedziano mi, \191e Nasionka[ENTER]Brzoskwini by\179y by \156wietnym lekarstwem na kaszel.[ENTER]Je\156li zdob\234dziesz dla Nasionko, dam Ci w zamian[ENTER]Pust\185 Butelk\234. Mo\191esz zdoby\230 Nasionka Brzoskwini[ENTER]od Dzik\243w na obrze\191ach wioski. Jak tylko farmerzy[ENTER]zasadz\185 Nasionka Brzoskwi\241, Dziki wykopuj\185 je i[ENTER]zjadaj\185. "
gameforge.subquest_01._170_sendLetter = "Zdob\185d\159 Nasionko Brzoskwini. "
gameforge.subquest_01._180_sayReward = "Handlarka R\243\191no\156ci potrzebuje Pustej Butelki.[ENTER]Yonah, kt\243ry jest astmatykiem, da Ci Pust\185[ENTER]Butelk\234 je\156li przyniesiesz mu Nasionko[ENTER]Brzoskwini. Nasionka szukaj u Dzik\243w. "
gameforge.subquest_01._190_npcChat = "Aby zdoby\230 Nasionko Brzoskwini... "
gameforge.subquest_01._200_say = "Nasionko Brzoskwini mo\191esz zdoby\230 od Dzik\243w na[ENTER]obrze\191ach wioski. Jak tylko farmerzy zasadz\185[ENTER]Nasiona, Dziki wykopuj\185 je.[ENTER]Dzi\234kuj\234 z g\243ry. (kaszle) "
gameforge.subquest_01._20_npcChat = "Zdob\185d\159 Pust\185 Butelk\234 "
gameforge.subquest_01._210_sendLetter = "Wr\243\230 do Yonah "
gameforge.subquest_01._220_sayTitle = "Wr\243\230 do Yonah. "
gameforge.subquest_01._230_sayReward = "Znalaz\179e\156 Nasionko Brzoskwini, zanie\156 je do Yonah. "
gameforge.subquest_01._240_say = "Oh, masz! "
gameforge.subquest_01._250_say = "Dzi\234ki. Teraz mog\234 wyleczy\230 moj\185 astm\234.[ENTER]Mog\234 w ko\241cu pracowa\230. "
gameforge.subquest_01._260_say = "Oto Pusta Butelka.[ENTER]Zanie\156 j\185 do Handlarki R\243\191no\156ci. "
gameforge.subquest_01._270_sendLetter = "Dostarcz Pust\185 Butelk\234 "
gameforge.subquest_01._280_sayReward = "Handlarka R\243\191no\156ci potrzebuje Pustej Butelki.[ENTER]Zanie\156 j\185 do niej. "
gameforge.subquest_01._290_sayTitle = "Handlarka R\243\191no\156ci: "
gameforge.subquest_01._300_say = "Dzi\234ki. Mam nadziej\234, \191e zdobycie Butelki nie[ENTER]sprawi\179o Ci du\191ego k\179opotu. Daj\234 Ci to jako moje[ENTER]podzi\234kowanie. Jeszcze raz, wielkie dzi\234ki! "
gameforge.subquest_01._30_say = "Prosz\234 mi wybaczy\230, je\156li nie jeste\156 aktualnie[ENTER]zaj\234ty, mo\191esz co\156 dla mnie zrobi\230? Potrzebuj\234[ENTER]Pustej Butelki na moj\185 Czerwon\185 Mikstur\234. "
gameforge.subquest_01._310_sayReward = "Otrzyma\179e\156 1500 Punkt\243w Do\156wiadczenia.[ENTER]Otrzyma\179e\156 1000 Yang. "
gameforge.subquest_01._320_say = "Nie znalaz\179e\156 jeszcze Pustej Butelki? "
gameforge.subquest_01._330_say = "Chcesz zapolowa\230 ponownie na Dziki, aby dosta\230[ENTER]kolejn\185 Pust\185 Butelk\234 czy chcesz przerwa\230[ENTER]zadanie? "
gameforge.subquest_01._340_select = "Tak, chc\234 zapolowa\230 na Dziki. "
gameforge.subquest_01._350_select = "Nie, rezygnuj\234 z zadania. "
gameforge.subquest_01._360_say = "Naprawd\234 chcesz zrezygnowa\230? "
gameforge.subquest_01._370_say = "Dzi\234kuj\234 za pomoc. "
gameforge.subquest_01._380_say = "To dla mnie za trudne. Przepraszam. "
gameforge.subquest_01._40_say = "Jestem zaj\234ta tutaj w sklepie i nie mog\234 sama jej[ENTER]zdoby\230. Je\156li przyniesiesz mi Butelk\234,[ENTER]odpowiednio Ci\234 wynagrodz\234. "
gameforge.subquest_01._50_select = "Przyjmij "
gameforge.subquest_01._60_select = "Odrzu\230 "
gameforge.subquest_01._70_say = "Czy chcesz anulowa\230 t\185 misj\234? "
gameforge.subquest_01._80_say = "Och, jak to mi\179o, \191e chcesz mi pom\243c.[ENTER]Odwied\159 mnie, jak b\234dziesz mia\179 chwil\234 czasu. "
gameforge.subquest_01._90_say = "Mi\179ego dnia. I zapraszam ponownie. "
