gameforge.subquest_02._100_sayTitle = "Handlarz Zbrojami: "
gameforge.subquest_02._10_targetVid = "Obiad "
gameforge.subquest_02._110_say = "Dzi\234ki tej rozmowie o jedzeniu zrobi\179em si\234[ENTER]g\179odny i naprawd\234 t\234skni\234 za mi\234sem duszonym,[ENTER]piwem, kapust\185 i dwoma jajkami. "
gameforge.subquest_02._120_say = "Czy m\243j ojciec powiedzia\179 Ci, co chcia\179by zje\156\230[ENTER]na obiad? "
gameforge.subquest_02._121_select = "Mi\234so wieprzowe, piwo, kapusta i jajko. "
gameforge.subquest_02._122_select = "Mi\234so duszone, piwo, kapusta i jajko. "
