gameforge.subquest_02._124_select = "Eh... zapomnia\179em... "
gameforge.subquest_02._130_say = "Dzi\234kuj\234, \191e dostarczy\179e\156 mi tak szybko te[ENTER]informacje.[ENTER]A oto Twoja nagroda. "
gameforge.subquest_02._140_sayReward = "Otrzyma\179e\156 1000 Punkt\243w Do\156wiadczenia.[ENTER]Otrzyma\179e\156 1500 Yang. "
gameforge.subquest_02._150_say = "Handlarka R\243\191no\156ci:[ENTER]Nazwa tego posi\179ku by\179a bardzo d\179uga, prawda?[ENTER]M\243g\179by\156 spyta\230 go ponownie? "
gameforge.subquest_02._160_say = "Handlarka R\243\191no\156ci:[ENTER]Naprawd\234 to powiedzia\179? To dziwne![ENTER]Nigdy nie lubi\179 tego dania... Mo\191esz spyta\230[ENTER]ponownie?[ENTER]W\185tpi\234, \191e my\156la\179 o tym posi\179ku. "
gameforge.subquest_02._20_say = "Znasz mojego ojca, kt\243ry handluje zbrojami?[ENTER]Chc\234 przygotowa\230 dla niego obiad, ale nie wiem co[ENTER]by chcia\179 zje\156\230. M\243g\179by\156 p\243j\156\230 do niego i spyta\230,[ENTER]co by chcia\179 mie\230 przygotowane. Z pewno\156ci\185[ENTER]wynagrodz\234 Ci\234 za ten k\179opot. "
gameforge.subquest_02._30_sayReward = "Handlarka R\243\191no\156ci chce wiedzie\230, co jej ojciec,[ENTER]Handlarz Zbrojami, chce zje\156\230 na obiad. "
gameforge.subquest_02._40_sayReward = "Id\159 do Handlarza Zbrojami i spytaj go. "
gameforge.subquest_02._50_say = "Witaj![ENTER][ENTER]Mam zbroje, kt\243re uchroni\185 Ci\234 od atak\243w no\191ami i[ENTER]mieczami. "
gameforge.subquest_02._60_say = "Ach, moja c\243rka Ci\234 wys\179a\179a? Pewnie zastanawia[ENTER]si\234 co powinna przygotowa\230 na obiad. Niech[ENTER]pomy\156l\234, Hmm... Chcia\179bym ostre mi\234so duszone,[ENTER]piwo, aromatyczn\185 kapust\234 i dwa jajka. To jest[ENTER]potrawa, na kt\243r\185 czekam od dawna! "
gameforge.subquest_02._70_targetVid = "Obiad "
gameforge.subquest_02._80_sayReward = "Handlarka R\243\191no\156ci chce wiedzie\230, co jej ojciec,[ENTER]Handlarz Zbrojami, chce zje\156\230 na obiad. "
gameforge.subquest_02._90_sayReward = "Wr\243\230 do niej i poinformuj j\185 o tym, czego si\234[ENTER]dowiedzia\179e\156. "
