gameforge.subquest_03._100_sayTitle = "Wr\243\230 do Baek-Go. "
gameforge.subquest_03._10_targetVid = "Sk\179adnik na lekarstwo "
gameforge.subquest_03._110_sayReward = "Znalaz\179e\156 W\185trob\234 Wilka, zanie\156 j\185 do Baek-Go. "
gameforge.subquest_03._120_say = "Dzi\234kuj\234! Mamy u Ciebie d\179ug! "
gameforge.subquest_03._130_say = "Pacjenci b\234d\185 Ci\234 wychwala\230. "
gameforge.subquest_03._140_say = "Masz, we\159 to jako moje podzi\234kowanie.[ENTER]Z pewno\156ci\185 b\234dziesz kiedy\156 tego potrzebowa\179. "
gameforge.subquest_03._150_sayReward = "Otrzyma\179e\156 3000 Punkt\243w Do\156wiadczenia.[ENTER]Otrzyma\179e\156 5000 Yang.[ENTER]Otrzyma\179e\156 Futro Wilka. "
gameforge.subquest_03._20_say = "Czy m\243g\179by\156 mi pom\243c? Od czasu upadku Kamieni[ENTER]Metin, pojawi\179a si\234 nieznana choroba. Wielu[ENTER]doktor\243w pracowa\179o nad ni\185, jednak potrzebny jest[ENTER]brakuj\185cy sk\179adnik, aby wyprodukowa\230 lekarstwo.[ENTER]Na obrze\191ach wioski \191yj\185 dzikie zwierz\234ta, a my[ENTER]nie mo\191emy si\234 tam swobodnie porusza\230. "
gameforge.subquest_03._30_say = "Czy m\243g\179by\156 dostarczy\230 mi ten sk\179adnik na[ENTER]lekarstwo? Pytam Ci\234, dlatego \191e wygl\185dasz na[ENTER]odwa\191nego. Potrzebuj\234 W\185troby Wilka na lekarstwo. "
gameforge.subquest_03._40_say = "Prosz\234, dostarcz mi W\185trob\234 Niebieskiego Wilka.[ENTER]Poinformuj mnie jak tylko j\185 zdob\234dziesz. "
gameforge.subquest_03._50_sayReward = "Od czasu upadku Kamieni Metin pojawi\179a si\234[ENTER]nieznana choroba. Aby wyprodukowa\230 lek przeciwko[ENTER]tej chorobie, Baek-Go potrzebuje W\185troby[ENTER]Niebieskiego Wilka. Dostarcz mu potrzebn\185[ENTER]W\185trob\234. "
gameforge.subquest_03._60_npcChat = "Jak zdoby\230 W\185trob\234 Wilka? "
gameforge.subquest_03._70_say = "Nie ma innego wyj\156cia: aby zdoby\230 W\185trob\234, musisz[ENTER]zapolowa\230 na Niebieskie Wilki. "
gameforge.subquest_03._80_say = "Szkoda mi Niebieskich Wilk\243w, ale potrzebujemy[ENTER]tej W\185troby aby wyprodukowa\230 lek. Dzi\234kuj\234 z[ENTER]g\243ry. "
gameforge.subquest_03._90_sendLetter = "Wr\243\230 do Baek-Go "
gameforge.subquest_04 = {}
gameforge.subquest_04._100_say = "Przed tob\185 d\179uga droga! B\185d\159 ostro\191ny! I[ENTER]pami\234taj, musisz u\191y\230 portal, kt\243ry jest[ENTER]oznaczony niebiesk\185 kropk\185. "
gameforge.subquest_04._10_targetVid = "Co s\179ycha\230 u Deokbae? "
gameforge.subquest_04._110_sayReward = "Udaj si\234 w drog\234 do drwala Deokbae i dostarcz mu[ENTER]list od kowala. Znajdziesz go w drugiej wiosce,[ENTER]do kt\243rej mo\191esz si\234 dosta\230 tylko u\191ywaj\185c[ENTER]portal. "
gameforge.subquest_04._120_sendLetter = "List od Kowala. "
gameforge.subquest_04._130_targetVid = "Znajd\159 drwala Deokbae. "
gameforge.subquest_04._140_npcChat = "List od Kowala. "
gameforge.subquest_04._150_sayTitle = "Deokbae: "
gameforge.subquest_04._160_say = "Serdecznie witam go\156cia! Mam kilka dobrych[ENTER]topor\243w. Chcesz jeden z nich kupi\230? Co? Nie[ENTER]potrzebujesz? To dlaczego w\179a\156ciwie przyszed\179e\156[ENTER]do mnie? Ach! List od kowala. Dzi\234ki. Jak wiesz[ENTER]jestem drwalem, ale sprzedaj\234 nie tylko topory,[ENTER]lecz te\191 kilofy i inne narz\234dzia. Od czasu do[ENTER]czasu zamawiam je u kowala. W ten spos\243b[ENTER]zostali\156my dobrymi przyjaci\243\179mi. "
gameforge.subquest_04._170_say = "Naprawd\234 musz\234 z nim wypi\230 ponownie jaki\156 trunek[ENTER]w barze Seo-Pyung. Dzi\234kuj\234 za dostarczenie mi[ENTER]tego listu. Przeka\191 Kowalowi moje pozdrowienia. "
gameforge.subquest_04._180_say = "List od Kowala? Cz\179owieku, to by\179o dawno temu.[ENTER]Gdzie on jest? Chyba nie zgubi\179e\156 go po drodze,[ENTER]prawda? "
gameforge.subquest_04._190_select = "Oto on. "
gameforge.subquest_04._200_select = "Ech, nie mam go. "
gameforge.subquest_04._20_say = "Witam, nowy poszukiwaczu przyg\243d! Chcia\179em prosi\230[ENTER]o przys\179ug\234. Znasz m\234\191czyzn\234 zwanego Deokbae?[ENTER]Jest drwalem i moim dobrym przyjacielem.[ENTER]Mo\191e jest nieco nudny, ale jest jednym z[ENTER]ostatnich ci\234\191ko pracuj\185cych drwali. "
gameforge.subquest_04._210_say = "Przerwa\230 zadanie? "
gameforge.subquest_04._220_say = "Mi\179o... wr\243\230 nied\179ugo. "
gameforge.subquest_04._230_say = "Zgubi\179e\156 go? Odejd\159 st\185d. "
gameforge.subquest_04._240_say = "Udaj si\234 do Kowala i zdob\185d\159 list.[ENTER]Nie zgub go ponownie. "
gameforge.subquest_04._250_sayReward = "Wr\243\230 do Kowala i odbierz nagrod\234. "
gameforge.subquest_04._260_targetVid = "Z powrotem do Kowala "
gameforge.subquest_04._270_npcChat = "Przekaza\179em list. "
gameforge.subquest_04._280_say = "Wi\234c, jak si\234 ma Deokbae? Hehe.[ENTER]Nie zmieni\179 si\234 ani troch\234. Dzi\234ki! We\159 to jako[ENTER]nagrod\234. Nie jest tego du\191o, ale my\156l\234, \191e przyda[ENTER]Ci si\234 kiedy\156. Jeszcze raz[ENTER]dzi\234kuj\234.  "
gameforge.subquest_04._290_sayReward = "Otrzyma\179e\156 4000 Punkt\243w Do\156wiadczenia.[ENTER]Otrzyma\179e\156 3000 Yang. "
gameforge.subquest_04._30_say = "Nie widzia\179em go od d\179u\191szego czasu i napisa\179em[ENTER]do niego list z pytaniem czy wszystko w[ENTER]porz\185dku... Chc\234, aby\156 dostarczy\179 mu ten list.[ENTER]Dzi\156 jest wiele problem\243w w wiosce. Wi\234c b\185d\159[ENTER]ostro\191ny. I prosz\234, nie zgub listu! "
gameforge.subquest_04._40_say = "Ech, nie wiesz jak dotrze\230 do nast\234pnej wioski?[ENTER]Naci\156nij M, aby w\179\185czy\230 mini-map\234. Wioska jest[ENTER]oznaczona na niej niebiesk\185 kropk\185, kt\243ra[ENTER]wyznacza portal, za pomoc\185 kt\243rego mo\191esz si\234[ENTER]przenie\156 do s\185siedniego obszaru. Tam znajduj\234 si\234[ENTER]druga wioska. "
gameforge.subquest_04._50_select = "Zrobi\234 to. "
gameforge.subquest_04._60_select = "Nie, dzi\234ki. "
gameforge.subquest_04._70_say = "Czy chcesz zrezygnowa\230 z zadania? "
gameforge.subquest_04._80_say = "Wr\243\230 jak najszybciej... "
gameforge.subquest_04._90_say = "Szkoda, mimo wszystko dzi\234ki. "
