gameforge.subquest_06._120_sayReward = "Udaj si\234 do Kowala i zapytaj si\234 go, kiedy[ENTER]sko\241czy zbroj\234, zam\243wion\185 przez Handlarz[ENTER]Zbrojami. "
gameforge.subquest_06._130_npcChat = "Zbroja dla Handlarza Zbrojami "
gameforge.subquest_06._140_say = "Co tym razem? Czemu mi przeszkadzasz? Ach,[ENTER]Handlarz Zbrojami Ci\234 przys\179a\179? Ten stary[ENTER]cz\179owiek jest naprawd\234 niecierpliwy. To nie jest[ENTER]tak, \191e nie chc\234 jej zrobi\230. Po prostu nie mam[ENTER]wymaganych materia\179\243w. Mo\191esz je dla mnie zdoby\230?[ENTER]Aby zrobi\230 zbroj\234, potrzebuj\234 Rud\234 \175elaza, Sk\243r\234[ENTER]i W\234giel. Rud\234 \175elaza dostaniesz od Uriel, Sk\243r\234[ENTER]od Octavio, a W\234giel od Yonah. "
