gameforge.subquest_06._270_say = "Dzi\234kuj\234, \191e przynios\179e\156 mi moj\185 ksi\185\191k\234! Teraz[ENTER]mog\234 doko\241czy\230 badania. Prosz\234, oto troch\234 Rudy[ENTER]\175elaza. Zabierz j\185 i u\191yj z po\191ytkiem. "
gameforge.subquest_06._280_say = "Potrzebujesz Rudy \175elaza? Mog\234 Ci troszk\234 da\230.[ENTER]Mam jednak ma\179\185 pro\156b\234. Ostatnio zgubi\179em[ENTER]Ksi\185\191k\234, gdy by\179em \156cigany przez watah\234 Dzikich[ENTER]Ps\243w. Przypuszczam, \191e te Dzikie Psy j\185 nadal[ENTER]maj\185. Dostarcz mi t\185 Ksi\185\191k\234, wtedy dam Ci[ENTER]troszk\234 Rudy \175elaza. "
gameforge.subquest_06._285_say = "Uriel da Ci Rud\234 \175elaza, je\156li przyniesiesz mu[ENTER]Ksi\185\191k\234 od Dzikich Ps\243w. "
gameforge.subquest_06._290_npcChat = "Ich brauche Eisenerz "
gameforge.subquest_06._300_say = "Potrzebujesz jeszcze wi\234cej Rudy \175elaza.?[ENTER]Da\179em Ci przecie\191 co\156 nie co\156.[ENTER]Nie mam ju\191 wi\234cej. "
gameforge.subquest_06._30_say = "Dzi\234kuj\234, \191e pomog\179e\156 mojej c\243rce. Teraz ja musz\234[ENTER]prosi\230 Ci\234 o przys\179ug\234. Zam\243wi\179em u Kowala w[ENTER]wiosce pewn\185 zbroj\234, ale nie dosta\179em od niego[ENTER]\191adnej informacji. Mo\191esz si\234 dowiedzie\230, jak[ENTER]stoi z tym zam\243wieniem? "
gameforge.subquest_06._310_npcChat = "Potrzebuj\234 troch\234 Sk\243ry. "
gameforge.subquest_06._320_sayTitle = "Octavio: "
gameforge.subquest_06._330_say = "Dzi\234ki za \175\243\179\230! W ko\241cu mog\234 przyrz\185dzi\230 moje[ENTER]nadzwyczaj smaczne potrawy! Mniam...mniam...[ENTER]pyszno\156ci. Prosz\234, oto twoja nagroda. We\159 t\185[ENTER]Sk\243r\234 jako wyraz mojej wdzi\234czno\156ci. "
gameforge.subquest_06._340_say = "Mog\234 da\230 ci troch\234 sk\243ry.[ENTER]Ale nic na tym \156wiecie nie jest za darmo.[ENTER]Co powiesz na wymian\234? Dostaniesz ode mnie troch\234[ENTER]sk\243ry, je\156li dostarczysz mi \191\243\179\230.[ENTER]Cz\234sto potrzebuj\234 \191\243\179ci do gotowania moich[ENTER]ulubionych smako\179yk\243w.[ENTER]Je\156li nie chcesz mi pom\243c, no c\243\191, jako\156 sobie[ENTER]sam poradz\234. "
gameforge.subquest_06._345_say = "Octavio da ci sk\243r\234, je\156li mu przyniesiesz \191\243\179\230. "
gameforge.subquest_06._350_npcChat = "Potrzebuj\234 troch\234 Sk\243ry. "
gameforge.subquest_06._360_say = "Da\179em Ci ju\191 Sk\243r\234. Zgubi\179e\156 j\185?[ENTER]Nie mam ju\191 wi\234cej... "
gameforge.subquest_06._370_npcChat = "Potrzebuj\234 troch\234 W\234gla. "
gameforge.subquest_06._380_say = "Dzi\234ki za Glin\234. R\234ka r\234k\234 myje. Mam racj\234? A oto[ENTER]W\234giel. Do zobaczenia wkr\243tce. "
gameforge.subquest_06._390_say = "Co tam? Przyszed\179e\156 tu po troch\234 W\234gla? Mam go[ENTER]du\191o. Ale nic za darmo. Je\156li zrobi\179by\156 co\156 dla[ENTER]mnie, da\179bym Ci troch\234. "
gameforge.subquest_06._395_say = "Yonah da ci w\234giel, je\156li przyniesiesz mu glin\234.[ENTER]Musisz zapolowa\230 za to na Czerwone Dziki. "
gameforge.subquest_06._400_say = "Nie mam ju\191 za du\191o Gliny. Je\156li przyniesiesz mi[ENTER]troszeczk\234 Gliny, to dam ci W\234giel. Najlepiej jak[ENTER]zabijesz par\234 Czerwonych Dzik\243w, kt\243re jedz\185[ENTER]glin\234, wierz w to lub nie. Dzi\234kuj\234 z g\243ry! "
gameforge.subquest_06._40_select = "Tak, zrobi\234 to. "
gameforge.subquest_06._410_npcChat = "Potrzebuj\234 troch\234 W\234gla. "
gameforge.subquest_06._420_say = "Co? Przecie\191 ju\191 Ci da\179em W\234giel! Pr\243bujesz[ENTER]zrobi\230 mnie w konia? "
