gameforge.subquest_07._100_say = "Poczekaj chwilk\234, musz\234 si\234 upewni\230, \191e to jest[ENTER]w\179a\156ciwa Ksi\185\191ka... Hmm, tak, to naprawd\234[ENTER]fantastyczna Ksi\185\191ka Kucharska. Z pewno\156ci\185[ENTER]przygotuj\234 ten posi\179ek! Dzi\234ki! "
