gameforge.subquest_07._150_sayReward = "Otrzyma\179e\156 12000 Punkt\243w Do\156wiadczenia.[ENTER]Otrzyma\179e\156 5000 Yang.[ENTER]Otrzyma\179e\156 Szpon Wilka. "
gameforge.subquest_07._160_say = "Potrzebuj\234 Kiszki Szarego Wilka.[ENTER]Prosz\234, przynie\156 mi jedn\185. "
gameforge.subquest_07._20_npcChat = "Najlepsza Ksi\185\191ka Kucharska "
gameforge.subquest_07._30_say = "Hm, mo\191ne znasz Soon? To mol ksi\185\191kowy, kt\243ry[ENTER]sp\234dza sw\243j czas wy\179\185cznie na czytaniu.[ENTER]S\179ysza\179em, \191e Soon ma \156wietn\185 Ksi\185\191k\234 Kucharsk\185.[ENTER]Prosz\234, sprawd\159, czy faktycznie tak jest. M\243wi[ENTER]si\234, \191e ta Ksi\185\191ka jest pe\179na rzadkich i[ENTER]egzotycznych przepis\243w, kt\243rych chc\234 si\234 nauczy\230. "
gameforge.subquest_07._40_targetVid = "Spytaj Soon "
gameforge.subquest_07._50_sayReward = "Zapytaj Soon, czy ma zagraniczn\185 Ksi\185\191k\234[ENTER]Kucharsk\185. "
