gameforge.subquest_07._70_say = "Ble, ble ... Och! To znowu ty, co s\179ycha\230? Tak,[ENTER]mam Ksi\185\191k\234 Kucharsk\185 z egzotycznymi potrawami.[ENTER]Zabierz j\185, ja nie potrzebuj\234 jej. Ale prosz\234,[ENTER]nie przeszkadzaj mi wi\234cej podczas czytania! "
