gameforge.subquest_08._110_npcChat = "Co wiesz o Ciastkach Ry\191owych? "
gameforge.subquest_08._120_sayTitle = "Handlarz Broni\185: "
gameforge.subquest_08._130_say = "Ekhm, co? Ciastka Ry\191owe? Czemu o to pytasz?[ENTER]S\179ysz\234 o takiej broni pierwszy raz. Nie[ENTER]rozumiem...[ENTER]Ach, Ciastka Ry\191owe, co\156 do jedzenia. Powiniene\156[ENTER]zapyta\230 o niego Octavio, on wie wszystko o[ENTER]jedzeniu. "
