gameforge.subquest_08._150_sayReward = "Udaj si\234 do Octavio i zapytaj si\234 go, co wie na[ENTER]temat Ciastek Ry\191owych. "
gameforge.subquest_08._160_say = "Hmm, to takie mi\234kkie ciastko z czerwonymi[ENTER]wi\156niami i cukrem, prawda? Tak, kiedy\156 mia\179em[ENTER]okazje skosztowa\230 tego smako\179yku. Mo\191esz je[ENTER]zdoby\230 od sprzedawcy, kt\243ry kr\234ci si\234 w drugiej[ENTER]wiosce. "
