gameforge.subquest_08._190_say = "Zapewniam Ci\234, przegapi\179e\156 co\156... Szkoda. Do[ENTER]zobaczenia! "
gameforge.subquest_08._200_say = "Zobaczysz, warto. Mi\179ej podr\243\191y. "
gameforge.subquest_08._20_say = "Wybacz mi, czy m\243g\179by\156 mi pom\243c? Jak s\179yszysz,[ENTER]moje dziecko p\179acze i nie mog\234 go uspokoi\230.[ENTER]Nie wiem co robi\230. Wiem, \191e uwielbia Ciastka[ENTER]Ry\191owe i my\156l\234, \191e takie Ciastko powinno pom\243c.[ENTER]Wydaje mi si\234, \191e Handlarz Broni\185 wie gdzie mo\191na[ENTER]je zdoby\230. Mo\191esz go o nie zapyta\230? "
