gameforge.subquest_08._220_targetVid = "Ciastko Ry\191owe "
gameforge.subquest_08._230_sayReward = "Udaj si\234 do Handlarki Ciastek Ry\191owych Yu-Rang.[ENTER]Znajdziesz j\185 w nast\234pnej wiosce. "
gameforge.subquest_08._240_sayTitle = "Yu-Rang: "
gameforge.subquest_08._250_say = "W czym mog\234 pom\243c? Och! Ciastka Ry\191owe.[ENTER]Oczywi\156cie, \191e mog\234 Ci da\230 takie Ciastko! Ale...[ENTER]jeden ch\179opak, Taurean, cz\234sto tu przychodzi i[ENTER]mnie zaczepia. Nie wiem czemu, ale zaczepia mnie[ENTER]i od razu ucieka. Je\156li dasz nauczk\234 Taurean,[ENTER]dostaniesz ode mnie Ciastko Ry\191owe,[ENTER]OK?  "
gameforge.subquest_08._260_makequestbutton = "Odszukaj Taurean. "
gameforge.subquest_08._270_sayReward = "Taurean ci\185gle dokucza Yu-Rang. Ukarz go, a[ENTER]dostaniesz od niej Ciastko Ry\191owe. "
gameforge.subquest_08._280_npcChat = "Czemu zaczepiasz Yu-Rang? "
gameforge.subquest_08._290_say = "Kogo zaczepiam? Ach, dziewczyn\234 sprzedaj\185c\185[ENTER]Ciastka Ry\191owe? Chcia\179em si\234 tylko z ni\185 pobawi\230.[ENTER]Wiesz o czym m\243wi\234? To nie jest tak jak my\156lisz![ENTER]Nie chcia\179em jej dokucza\230! Nudzi\179em si\234,[ENTER]wygl\185da\179o na to, \191e ona nie mia\179a du\191o pracy,[ENTER]wi\234c chcia\179em tylko j\185 zabawi\230. Nie chcia\179em jej[ENTER]skrzywdzi\230. Nie zrobi\234 tego ponownie, obiecuj\234! "
