gameforge.subquest_08._320_sayReward = "Taurean ju\191 nie b\234dzie dokucza\179 Yu-Rang. Udaj si\234[ENTER]do niej i odbierz obiecane Ciastko Ry\191owe. "
gameforge.subquest_08._330_say = "Hehe, da\179e\156 nauczk\234 Taurean?[ENTER]Dzi\234ki, masz za to Ciastko Ry\191owe.[ENTER]Nie wiem co z nim zrobisz, ale \191ycz\234 smacznego. "
