gameforge.subquest_10._150_say = "Co? My\156lisz, \191e to ja ukrad\179em Spink\234 Handlarki?[ENTER]Nie, nigdy. Nie zrobi\179em tego! Naprawd\234![ENTER][ENTER]By\179em tam w odwiedzinach u Handlarki! Ale nie[ENTER]by\179o jej tam, zamiast niej spotka\179em[ENTER]Zaprzysi\234\191on\185 \163uczniczk\234. W chwili gdy mnie[ENTER]ujrza\179a, uciek\179a.[ENTER]Mo\191e ona ma skradzion\185 Spink\234 do w\179os\243w? "
gameforge.subquest_10._160_sayReward = "Odbierz Spink\234 Do W\179os\243w Zaprzysi\234\191onej[ENTER]\163uczniczce! "
gameforge.subquest_10._170_sendLetter = "Znalaz\179e\156 Spink\234 Do W\179os\243w "
gameforge.subquest_10._180_targetVid = "Id\159 do Handlarki R\243\191no\156ciami. "
gameforge.subquest_10._190_npcChat = "Mam Twoj\185 Spinka Do W\179os\243w. "
gameforge.subquest_10._200_say = "Och, wielkie dzi\234ki. Jestem bardzo szcz\234\156liwa,[ENTER]ostatecznie odzyska\179am moj\185 ukochan\185 Spink\234![ENTER]Ostatnio pomagasz mi zbyt cz\234sto. Jak ja Ci si\234[ENTER]odwdzi\234cz\234? Mam Bilet Na Jazd\234 Konn\185. To co\156[ENTER]ma\179ego, ale ju\191 go nie potrzebuj\234, poniewa\191 nie[ENTER]b\234d\234 opuszcza\179a sklepu tak cz\234sto. We\159 to jako[ENTER]dow\243d mojej wdzi\234czno\156ci. Dzi\234kuj\234. "
gameforge.subquest_10._20_say = "Prosz\234, pos\179uchaj mnie... jestem w z\179ym stanie.[ENTER]Opu\156ci\179am na chwil\234 sklep, aby zrobi\230 co\156[ENTER]wa\191nego. Podczas mojej nieobecno\156ci, kto\156 mi[ENTER]ukrad\179 Spink\234. "
gameforge.subquest_10._210_sayReward = "Otrzyma\179e\156 60.000 Punkt\243w Do\156wiadczenia.[ENTER]Otrzyma\179e\156 10.000 Yang.[ENTER]Otrzyma\179e\156 Bilet na Jazd\234 Konn\185. "
gameforge.subquest_10._220_say = "Nie znalaz\179e\156 jeszcze Spinki?[ENTER]Mam nadziej\234, \191e j\185 kiedy\156 znajdziesz. "
gameforge.subquest_10._230_select = "Zrezygnuj "
gameforge.subquest_10._240_say = "Naprawd\234 chcesz zrezygnowa\230? "
gameforge.subquest_10._250_say = "Zgadza si\234, to uparci przeciwnicy... Odpocznij i[ENTER]spr\243bowa\230 jeszcze raz p\243\159niej? "
gameforge.subquest_10._260_say = "Gdzie jest moja ulubiona Szpilka do w\179os\243w?[ENTER]Zgaduj\234, \191e mi nie pomo\191esz... \191egnaj. "
gameforge.subquest_10._270_say = "Bardzo Ci dzi\234kuj\234. Ona znaczy dla mnie bardzo[ENTER]du\191o. "
gameforge.subquest_10._30_say = "M\243j ojciec da\179 mi t\185 cudown\185 Spink\234 na urodziny i[ENTER]bardzo j\185 kocham. Nie mog\234 wi\234cej opuszcza\230[ENTER]mojego sklepu, w przeciwnym wypadku, zgin\185\230 mo\191e[ENTER]co\156 bardziej warto\156ciowego... Mo\191esz jej dla mnie[ENTER]poszuka\230? Podejrzewam Kowala, poniewa\191, kiedy\156[ENTER]powiedzia\179, \191e takiej poszukuje. "
gameforge.subquest_10._40_select = "Poszukam jej. "
gameforge.subquest_10._50_say = "Naprawd\234 chcesz zrezygnowa\230? "
gameforge.subquest_10._60_say = "Do zobaczenia p\243\159niej. Baw si\234 dobrze! "
gameforge.subquest_10._70_say = "Gdzie jest moja Spinka? \175egnaj... "
gameforge.subquest_10._80_say = "Poszukasz jej? Oh, to \156wietnie! "
gameforge.subquest_10._90_targetVid = "Udaj si\234 do Kowala. "
gameforge.subquest_11 = {}
gameforge.subquest_11._100_targetVid = "Spytaj muzyka Yu-Hwan o brata Mirine. "
gameforge.subquest_11._10_targetVid = "Znajd\159 mojego brata "
gameforge.subquest_11._110_npcChat = "Widzia\179e\156 brata Mirine? "
gameforge.subquest_11._120_say = "Zakocha\179em si\234, nie wiedz\185c, \191e mi\179o\156\230 oznacza[ENTER]po\191egnanie... Kogo szukasz? Brata Mirine?[ENTER]Rozmawiali\156my troszk\234 przed jego p\243j\156ciem w G\243ry[ENTER]w poszukiwaniu rzadkich zi\243\179... Nie wiem gdzie[ENTER]jest teraz. \163owca z tej wioski, cz\234sto wybiera[ENTER]si\234 w G\243ry. Czemu nie zapytasz jego?[ENTER]La, la, la, mi\179o\156\230 jest smutna ale pi\234kna... "
gameforge.subquest_11._130_targetVid = "Spytaj Yang-Shin o brata Mirine. "
gameforge.subquest_11._140_say = "Kto? Brat Mirine? Poszukiwa\179 rzadkich zi\243\179 w[ENTER]g\243rach. By\179 bardzo szcz\234\156liwy, \191e znalaz\179 kilka[ENTER]naprawd\234 wyj\185tkowych okaz\243w. Chcia\179 kupi\230 swojej[ENTER]siostrze nowe ubrania za Yang ze sprzedanych[ENTER]zi\243\179. Jest bardzo mi\179y. Na pewno wr\243ci za kilka[ENTER]dni, nie s\185dzisz? "
gameforge.subquest_11._150_targetVid = "Przeka\191 Mirine nowiny. "
gameforge.subquest_11._160_npcChat = "Nowiny o Bracie Mirine. "
gameforge.subquest_11._170_say = "Och! Otrzyma\179am list od mojego Brata! Pisze, \191e[ENTER]znalaz\179 miejsce gdzie ro\156nie wiele zi\243\179, dlatego[ENTER]te\191 potrwa to troch\234 zanim wr\243ci. Przepraszam,[ENTER]nie powinnam by\179a Ci\234 prosi\230. Nie jest to du\191o,[ENTER]ale mam nadziej\234, \191e przyjmiesz to i wybaczysz.[ENTER]Dzi\234kuj\234 za przybycie! "
gameforge.subquest_11._180_sayReward = "Otrzyma\179e\156 122.000 Punkt\243w Do\156wiadczenia.[ENTER]Otrzyma\179e\156 5.000 Yang. "
gameforge.subquest_11._20_npcChat = "Znajd\159 mojego brata "
gameforge.subquest_11._30_say = "Czy mog\234 prosi\230 Ci\234 o przys\179ug\234? M\243j Brat jest[ENTER]poza domem ju\191 zbyt d\179ugo, nie mam od niego[ENTER]\191adnej wiadomo\156ci. Zaczynam si\234 martwi\230. M\243g\179by\156[ENTER]go poszuka\230, oczywi\156cie je\156li znajdziesz czas? "
gameforge.subquest_11._40_say = "M\243j brat chcia\179 odwiedzi\230 muzyka Yu-Hwan w[ENTER]s\185siedniej wiosce. Je\156li udasz si\234 do niego, z[ENTER]pewno\156ci\185 b\234dziesz mia\179 informacje o moim bracie.[ENTER]Dzi\234kuj\234 z g\243ry. "
gameforge.subquest_11._50_select = "Tak, zrobi\234 to. "
gameforge.subquest_11._60_say = "Czy chcesz na zawsze zrezygnowa\230 z tego zadania? "
gameforge.subquest_11._70_say = "Dzi\234kuj\234.[ENTER]Prosz\234, poszukaj go.[ENTER]Jestem bardzo zmartwiona.[ENTER]Do zobaczenia... "
gameforge.subquest_11._80_say = "Szkoda, \191e mi nie pomo\191esz...[ENTER]Do zobaczenia. "
gameforge.subquest_11._90_say = "Poszukasz go?[ENTER]Wielkie dzi\234ki! Bardzo martwi\234 si\234 o niego.[ENTER]Powodzenia! "
