gameforge.subquest_12._130_sayReward = "Id\159 i zabij Mi-Jung z Zaprzysi\234\191onych.[ENTER]Po wykonaniu zadania, wr\243\230 do Stra\191nika Wsi. "
gameforge.subquest_12._140_targetVid = "Id\159 do Stra\191nika Wsi. "
gameforge.subquest_12._150_sayTitle = "Zabi\179e\156 Mi-Jung z Zaprzysi\234\191onych "
gameforge.subquest_12._160_sayReward = "Wr\243\230 do Stra\191nika Wsi aby otrzyma\230 nagrod\234. "
gameforge.subquest_12._170_npcChat = "Zabi\179em Mi-Jung. "
gameforge.subquest_12._180_say = "Och! Jeste\156 naprawd\234 taki dobry jak s\179ysza\179em.[ENTER]Jeste\156 zadziwiaj\185co dobry. Dzi\234ki Tobie[ENTER]rozwi\185zanie problem\243w z Klanem Zaprzysi\234\191onych[ENTER]sta\179o si\234 o wiele \179atwiejsze. Dobra robota! "
gameforge.subquest_12._190_sayReward = "Otrzyma\179e\156 122.000 Punkt\243w Do\156wiadczenia.[ENTER]Otrzyma\179e\156 20.000 Yang.[ENTER]Otrzyma\179e\156 Srebrn\185 Bransoletk\234. "
gameforge.subquest_12._20_say = "Podejd\159 tu na moment. Jeste\156 dobrym wojownikiem.[ENTER]Wiele s\179ysza\179em o tobie od Kapitana. "
gameforge.subquest_12._30_say = "Czy mo\191esz uda\230 si\234 za Mi-Jung z Klanu[ENTER]Zaprzysi\234\191onych, kt\243ra sprawia nam tyle[ENTER]problem\243w? Ci\234\191ko jest chroni\230 wiosk\234 i jej[ENTER]mieszka\241c\243w przed atakami Bia\179ych[ENTER]Zaprzysi\234\191onych. Je\156li zabijemy Mi-Jung, jedn\185 z[ENTER]przyw\243dczy\241, sytuacja ulegnie zmianie.[ENTER]Bezpiecze\241stwo wioski spoczywa w Twoich r\234kach.[ENTER]Ufam Ci. "
gameforge.subquest_12._40_select = "Tak, zrobi\234 to. "
gameforge.subquest_12._50_select = "Nie dam sobie rady. "
gameforge.subquest_12._60_say = "Naprawd\234 nie chcesz nam pom\243c? "
gameforge.subquest_12._70_say = "Wygl\185da na to, \191e nie jest to w\179a\156ciwy moment.[ENTER]Wpadnij p\243\159niej. "
gameforge.subquest_12._80_say = "Je\156li nie chcesz, nic nie mo\191emy zrobi\230.[ENTER]Odejd\159. "
gameforge.subquest_12._90_say = "Naprawd\234 nie chcesz nam pom\243c? "
