gameforge.subquest_13._100_targetVid = "Udaj si\234 do Ariyoung "
gameforge.subquest_13._10_targetVid = "Materia\179y do wytwarzania broni. "
gameforge.subquest_13._110_targetVid = "Id\159 do Ah-Yu. "
gameforge.subquest_13._120_sayReward = "Handlarz Broni\185 potrzebuje Twojej pomocy. Zdob\185d\159[ENTER]dla niego Rud\234 \175elaza od Uriela i P\179\243tno od[ENTER]Ariyoung. "
gameforge.subquest_13._130_npcChat = "Ich brauche Eisenerz "
gameforge.subquest_13._140_say = "Potrzebujesz Rudy \175elaza?[ENTER]Mog\234 Ci j\185 da\230 w zamian za przys\179ug\234. "
gameforge.subquest_13._150_say = "Tygrysy ukrad\179y mi moj\185 torb\234.[ENTER]Musia\179em ratowa\230 si\234 ucieczk\185, w torbie jednak s\185[ENTER]wa\191ne dla mnie informacje.[ENTER]Je\156li ich nie odzyskam, nie b\234d\234 m\243g\179 dalej bada\230[ENTER]Kamieni Metin. Przynie\156 mi moj\185 paczk\234, a ja dam[ENTER]Ci w zamian troch\234 Rudy \175elaza. "
gameforge.subquest_13._160_npcChat = "Mam Twoj\185 Przesy\179k\234. "
gameforge.subquest_13._170_say = "Dzi\234ki![ENTER]Zbyt cz\234sto prosz\234 Ci\234 o przys\179ugi.[ENTER]Prosz\234, masz troch\234 Rudy \175elaza.[ENTER]Mam nadziej\234, \191e znajdziesz dla niej u\191ytek. "
gameforge.subquest_13._180_say = "Co? Potrzebujesz wi\234cej Rudy \175elaza?[ENTER]Wiesz, \191e nie ro\156nie na drzewach?![ENTER]Dam Ci troch\234 Rudy \175elaza, ale musisz wy\156wiadczy\230[ENTER]mi ma\179\185 przys\179ug\234.[ENTER]Tygrysy ukrad\179y mi moj\185 paczk\234.[ENTER]Musia\179em ratowa\230 si\234 ucieczk\185, a w tej paczce s\185[ENTER]wa\191ne dla mnie dokumenty.[ENTER]Bez nich nie mog\234 kontynuowa\230 bada\241 Kamieni[ENTER]Metin. Prosz\234 odzyskaj paczk\234, kt\243r\185 ukrad\179y[ENTER]Tygrysy. "
gameforge.subquest_13._190_say = "Ju\191 Ci j\185 da\179em![ENTER]Zapomnia\179e\156 o tym?! "
gameforge.subquest_13._200_sayTitle = "Przesy\179ka odnaleziona "
gameforge.subquest_13._20_npcChat = "Materia\179y na bro\241 "
gameforge.subquest_13._210_say = "Znalaz\179e\156 Przesy\179k\234 Uriela![ENTER]Wr\243\230 do niego. "
gameforge.subquest_13._220_npcChat = "Potrzebuj\234 troch\234 P\179\243tna. "
gameforge.subquest_13._230_say = "Potrzebujesz P\179\243tna? Da\179am je Ah-Yu.[ENTER]Ale poczekaj![ENTER]Skoro i tak zamierzasz si\234 z ni\185 spotka\230, prosz\234,[ENTER]dostarcz jej ten list. To moja dobra przyjaci\243\179ka[ENTER]i nie widzia\179y\156my si\234 ju\191 od bardzo dawna.[ENTER]Dostarcz do niej ten list i powiedz, \191e[ENTER]poprosi\179am Ci\234 o odebranie mojego P\179\243tna.[ENTER]Koniecznie pozdr\243w j\185 ode mnie. "
gameforge.subquest_13._240_say = "Ariyoung:[ENTER]Dosta\179e\156 ju\191 P\179\243tno od Ah-Yu. "
gameforge.subquest_13._250_npcChat = "List Ariyoung "
gameforge.subquest_13._260_say = "List od Ariyoung? To naprawd\234 mi\179o z jej strony.[ENTER]Kiedy\156 cz\234sto spotyka\179y\156my si\234 na pogaduchach,[ENTER]ale w ostatnim czasie by\179o to utrudnione. Prosz\234,[ENTER]poczekaj chwilk\234. A wi\234c chce, abym da\179a Ci[ENTER]P\179\243tno? Nie ma problemu. Jeszcze raz dzi\234kuje za[ENTER]dostarczenie listu. Zaraz zabior\234 si\234 za pisanie[ENTER]odpowiedzi... "
gameforge.subquest_13._270_qSetTitle = "Id\159 do Handlarza Broni\185 "
gameforge.subquest_13._280_targetVid = "Id\159 do Handlarza Broni\185. "
gameforge.subquest_13._290_sayTitle = "Dostarcz Materia\179y "
gameforge.subquest_13._300_sayReward = "Mam wszystkie materia\179y![ENTER]Id\159 do Handlarza Broni\185. "
gameforge.subquest_13._30_say = "Hej, ty! M\243g\179by\156 mi troszk\234 pom\243c?[ENTER]Pr\243buj\234 stworzy\230 nowe typy broni.[ENTER]Bardzo trudno jest znale\159\230 odpowiednie materia\179y.[ENTER]Mam du\191o zam\243wie\241 i nie mog\234 poszuka\230 ich sam.[ENTER]Czy m\243g\179by\156 je dla mnie zdoby\230? Prosz\234... "
gameforge.subquest_13._310_say = "Dobra robota. Jeste\156 naprawd\234 dobry i szybki.[ENTER]Teraz pozw\243l mi popracowa\230 nad t\185 broni\185![ENTER]*Uderzenie m\179otem*[ENTER]Oto nowa bro\241.[ENTER]Da\179em z siebie wszystko i mam nadziej\234, \191e[ENTER]polubisz now\185 bro\241. Mi\179ej zabawy! "
gameforge.subquest_13._320_sayTitle = "Nagroda: "
gameforge.subquest_13._330_sayReward = "Otrzyma\179e\156 122.000 Punkt\243w Do\156wiadczenia.[ENTER]Otrzyma\179e\156 20.000 Yang. "
gameforge.subquest_13._340_sayReward = "Otrzyma\179e\156 Szeroki Miecz+3. "
gameforge.subquest_13._350_sayReward = "Otrzyma\179e\156 Sztylet No\191ycowy+3. "
gameforge.subquest_13._360_sayReward = "Otrzyma\179e\156 Pawi Wachlarz+3. "
gameforge.subquest_13._40_say = "Oczywi\156cie wynagrodz\234 Ci\234 za to.[ENTER]Jak tylko bro\241 zostanie uko\241czona, dam Ci jedn\185.[ENTER]Potrzebuj\234 nast\234puj\185cych materia\179\243w: Rud\234 \175elaza[ENTER]i P\179\243tno. Pierwsze dostaniesz od Uriel, P\179\243tno od[ENTER]Ariyoung. Daj mi zna\230 jak zbierzesz wszystko. "
gameforge.subquest_13._50_say = "Naprawd\234 nie mo\191esz mi pom\243c? "
gameforge.subquest_13._60_say = "Wygl\185da na to, \191e zadanie Ci\234 przeros\179o.[ENTER]Wr\243\230 gdy b\234dziesz mia\179 wi\234cej czasu! "
gameforge.subquest_13._70_say = "Je\156li nie chcesz mi pom\243c, nic nie mo\191emy z tym[ENTER]zrobi\230. Do zobaczenia. "
gameforge.subquest_13._80_say = "Bardzo dobrze![ENTER]Jak tylko bro\241 zostanie uko\241czona, dostaniesz[ENTER]jedn\185 sztuk\234. Powodzenia. "
