gameforge.subquest_15._10_targetVid = "Eun-Jung z Klanu Zaprzysi\234\191onych "
gameforge.subquest_15._110_sayReward = "Zabi\179e\156 Eun-Jung z Klanu Zaprzysi\234\191onych. Udaj[ENTER]si\234 do Stra\191nika Wsi i poinformuj go o tym. "
gameforge.subquest_15._120_say = "Jeste\156 najlepszy! Posz\179o Ci lepiej ni\191 si\234[ENTER]spodziewa\179em. Nie daliby\156my sobie rady bez[ENTER]Ciebie. Pokona\179e\156 dw\243ch lider\243w Klanu[ENTER]Zaprzysi\234\191onych tak \179atwo! To niesamowite. "
gameforge.subquest_15._130_say = "To niesamowite. Otrzymasz odpowiedni\185 nagrod\234.[ENTER]Prosz\234, we\159 to, mam nadziej\234, \191e nadal b\234dziesz[ENTER]pracowa\179 dla naszego Kr\243lestwa! "
gameforge.subquest_15._140_sayReward = "Otrzyma\179e\156 150.000 Punkt\243w Do\156wiadczenia.[ENTER]Otrzyma\179e\156 25.000 Yang.[ENTER]Otrzyma\179e\156 Z\179oty Naszyjnik+4. "
gameforge.subquest_15._20_say = "Podejd\159 na chwilk\234.[ENTER]S\179ysza\179em o Tobie sporo dobrych rzeczy od[ENTER]Kapitana. Wydajesz si\234 by\230 nieustraszonym.[ENTER]W\179a\156nie dlatego potrzebuj\234 Twojej pomocy: Klan[ENTER]Zaprzysi\234\191onych zachowuje si\234 jeszcze gorzej ni\191[ENTER]zwykle. "
gameforge.subquest_15._30_say = "Pokona\179e\156 Mi-Jung, przyw\243dczyni\234 Zaprzysi\234\191onych.[ENTER]Jednak nadal jeste\156my w niebezpiecze\241stwie![ENTER]Zagro\191enie ze strony Klanu Zaprzysi\234\191onych nie[ENTER]zmala\179o, teraz jest jeszcze gorzej! "
gameforge.subquest_15._40_say = "Aby to zako\241czy\230, musimy zabi\230 g\179\243wnego kapitana,[ENTER]czyli Eun-Jung. Reszta nie powinna sprawia\230[ENTER]problemu. Id\159 i zabij Eun-Jung! Nasz los jest w[ENTER]twoich r\234kach! "
gameforge.subquest_15._50_sayTitle = "Stra\191nik: "
gameforge.subquest_15._60_say = "Wr\243cisz p\243\159niej? Nadajesz si\234 do tego zadania. "
gameforge.subquest_15._70_say = "Nie mo\191esz tego zrobi\230? W porz\185dku, trzymaj si\234. "
gameforge.subquest_15._80_say = "Wiedzia\179em, \191e nam pomo\191esz![ENTER]Zabij Eun-Jung, my zajmiemy si\234 reszt\185.[ENTER]Powodzenia! "
gameforge.subquest_15._90_sayReward = "Zabij lidera Eun-Jung. Wtedy Zaprzysi\234\191eni nie[ENTER]powinni sprawia\230 tylu problem\243w. "
