gameforge.subquest_16._100_qSetTitle = "Zapytaj Yu-Hwan "
gameforge.subquest_16._10_targetVid = "Poszukiwanie Uzbrojonej Kawalerii "
gameforge.subquest_16._110_targetVid = "Id\159 do Yu-Hwan "
gameforge.subquest_16._120_say = "\175ycie jest takie pi\234kne... ach, mi\179o\156\230, cudowna[ENTER]mi\179o\156\230... ![ENTER]Znowu ty. Czego tym razem chcesz?[ENTER]Informacji o Uzbrojonej Kawalerii?[ENTER]Dlaczego o to pytasz?[ENTER]Kapitan ma zapewne ambitne plany? "
gameforge.subquest_16._130_sayTitle = "Yu-Hwan: "
gameforge.subquest_16._140_say = "Zachowa\179y si\234 jedynie nieliczne oryginalne teksty[ENTER]z tamtych czas\243w, ale znam kilka pie\156ni o[ENTER]Uzbrojonej Kawalerii. Chwila, nastroj\234 tylko sw\243j[ENTER]instrument...[ENTER]Ach, \156pieszysz si\234? W dzisiejszych czasach ludzie[ENTER]nie maj\185 cierpliwo\156ci do s\179uchania...[ENTER]No Dobrze, streszcz\234 si\234. Kawaleria Isupsa by\179a[ENTER]niemal\191e nie do pokonania. Doskonale wyszkoleni[ENTER]\191o\179nierze, ci\234\191kie metalowe zbroje a przy tym[ENTER]szybka i zwinna. "
gameforge.subquest_16._150_say = "To by\179a najlepsza armia, jaka kiedykolwiek[ENTER]st\185pa\179a po tym kontynencie. Wiele kraj\243w musia\179o[ENTER]polec, jako \191e nic nie by\179o w stanie zatrzyma\230[ENTER]tej kawalerii. Dzisiaj nie by\179oby inaczej. Do[ENTER]stworzenia takiej armii nieodzowny jest jednak[ENTER]ci\234\191ki trening oraz du\191o metalu najwy\191szej[ENTER]jako\156ci. Powiniene\156 zapyta\230 Domokr\185\191cy oraz[ENTER]uczonego Uriela. Na pewno znaj\185 wi\234cej[ENTER]szczeg\243\179\243w. "
gameforge.subquest_16._160_makequestbutton = "Do Domokr\185\191cy "
gameforge.subquest_16._170_qSetTitle = "Uzbrojona Kawaleria. "
gameforge.subquest_16._180_targetVid = "Domokr\185\191ca: "
gameforge.subquest_16._190_sayReward = "Muzyk Yu-Hwan twierdzi, \191e Domokr\185\191ca i M\234drzec[ENTER]Uriel mog\185 mie\230 informacje o Uzbrojonej[ENTER]Kawalerii. Id\159 najpierw do Domokr\185\191cy. "
gameforge.subquest_16._200_sayTitle = "Domokr\185\191ca: "
gameforge.subquest_16._20_npcChat = "Uzbrojona Kawaleria. "
gameforge.subquest_16._210_say = "Czego chcesz od prostego Domokr\185\191cy jak ja?[ENTER]\175elazne Zbroje Uzbrojonej Kawalerii? To przecie\191[ENTER]stare bajki. Kogo to dzisiaj jeszcze interesuje?[ENTER]Ja musz\234 zarabia\230 na \191ycie i nie mam czasu na[ENTER]ca\179odniowe pogaw\234dki! "
gameforge.subquest_16._220_say = "Coraz ci\234\191ej wi\185za\230 koniec z ko\241cem. Od kiedy te[ENTER]kamienie spadaj\185 z nieba, zacz\185\179em... co takiego?[ENTER]A w\179a\156nie, Kawaleria.[ENTER]O ile mi wiadomo, nosili specjalne zbroje,[ENTER]kt\243rych produkcja wymaga\179a niezwyk\179ych[ENTER]umiej\234tno\156ci. S\185 to najlepsze zbroje wszech[ENTER]czas\243w! Zwyk\179e no\191e, ba, nawet strza\179y po prostu[ENTER]si\234 odbijaj\185! "
gameforge.subquest_16._230_say = "To, \191e pancerze Uzbrojonej Kawalerii by\179y czym\156[ENTER]wyj\185tkowym, wida\230 cho\230by po ilo\156ci pieni\234dzy[ENTER]potrzebnych do stworzenia Kawalerii. M\243wi si\234, \191e[ENTER]poch\179on\234\179a skarbce ca\179ych kr\243lestw! Gdybym[ENTER]sprzedawa\179 takie zbroje, nie musia\179bym si\234 ju\191[ENTER]nigdy martwi\230 o pieni\185dze! "
gameforge.subquest_16._240_say = "Dzisiaj mo\191na nawet wykuwa\230 zbroje z Kamieni[ENTER]Metin. Stworzenie drugiej Uzbrojonej Kawalerii[ENTER]wydaj\234 si\234 dzi\234ki tej nowej technice zbrojeniowej[ENTER]wcale nie takie niemo\191liwe! Ale za du\191o gadam.[ENTER]Musz\234 ju\191 i\156\230. Na razie! "
gameforge.subquest_16._250_sayTitle = "Uzbrojona Kawaleria. "
gameforge.subquest_16._260_say = "Domokr\185\191ca wiedzia\179 co\156 na temat metalowych zbroi[ENTER]Uzbrojonej Kawalerii. Id\159 teraz do m\234drca Uriela[ENTER]w s\185siedniej wiosce i spytaj si\234 go o trening. "
gameforge.subquest_16._270_sayTitle = "Uriel: "
gameforge.subquest_16._280_say = "Co tym razem jest powodem twojego przybycia?[ENTER]Uzbrojona Kawaleria? Oczywi\156cie, \191e wiem co\156 o[ENTER]niej, ka\191dy wie. Po wsze czasy armia ta b\234dzie[ENTER]zapami\234tana jako najlepsza w historii![ENTER]Wiele z tego, co ludzie sobie opowiadaj\185, jest[ENTER]zapewne przesad\185, je\159d\159cy ci wzbudzali jednak[ENTER]niesamowit\185 groz\234. I to nie bez powodu. "
gameforge.subquest_16._290_say = "Uzbrojona Kawaleria g\243rowa\179a nad ka\191d\185 inna[ENTER]armi\185. By\179a to przede wszystkim zas\179uga nieludzko[ENTER]ci\234\191kiego treningu. Tylko najlepsi byli w stanie[ENTER]uko\241czy\230 szkolenie, niejeden zgin\185\179 pr\243buj\185c.[ENTER]Podejrzewam, \191e gdyby zastosowa\230 te same metody[ENTER]szkolenia w naszych czasach, ani jeden \191o\179nierz[ENTER]nie pozosta\179by przy \191yciu. "
gameforge.subquest_16._300_say = "Niekt\243re metody szkolenia si\234 zachowa\179y. Dam ci[ENTER]par\234 wskaz\243wek, aby\156 sam m\243g\179 przekona\230 si\234 o ich[ENTER]skuteczno\156ci.[ENTER]Wiem, \191e szalej\185 straszne wojny, ale nie jestem[ENTER]pewien czy ponowne stworzenie tak pot\234\191nej armii[ENTER]to dobry pomys\179. "
gameforge.subquest_16._30_say = "Mam nowe zadanie dla Ciebie. Masz rozkaz zdobycia[ENTER]informacji o Uzbrojonej Kawalerii. By\179a ona[ENTER]najwa\191niejsz\185 cz\234\156ci\185 armii Isupa, Kr\243la[ENTER]za\179o\191yciela, kt\243ry dawno temu zjednoczy\179 ca\179y[ENTER]kontynent. Uzbrojona Kawaleria by\179a postrachem[ENTER]dla innych nacji ze wzgl\234du na swoj\185 niezwyk\179\185[ENTER]szybko\156\230 i si\179\234 ataku. "
gameforge.subquest_16._310_say = "Id\159 do Kapitana i opowiedz o wszystkim, czego si\234[ENTER]dowiedzia\179e\156 o Uzbrojonej Kawalerii. "
gameforge.subquest_16._320_makequestbutton = "Id\159 do Kapitana. "
gameforge.subquest_16._330_npcChat = "Raport o Uzbrojonej Kawalerii. "
gameforge.subquest_16._340_sayTitle = "Kapitan "
gameforge.subquest_16._350_say = "Zdoby\179e\156 jakie\156 u\191yteczne informacje? Opowiedz![ENTER]...[ENTER]Hm, to bardzo interesuj\185ce. Wymagane s\185 jedynie[ENTER]silne zbroje oraz ci\234\191ki trening, nic wi\234cej? W[ENTER]takim razie jest to do zrobienia! Taka armia[ENTER]mog\179aby ponownie zjednoczy\230 trzy kr\243lestwa! "
gameforge.subquest_16._360_say = "Potrzebowa\179bym jednak bardzo du\191o pieni\234dzy,[ENTER]wielu zdolnych kowali oraz rekrut\243w, kt\243rzy[ENTER]dobrowolnie przeszliby przez piek\179o, aby sta\230 si\234[ENTER]najlepszymi z najlepszych![ENTER]Nie, nie. Nie spogl\185daj na mnie w ten spos\243b. Nie[ENTER]martw si\234, p\243ki co zrobi\179e\156 wystarczaj\185co. "
gameforge.subquest_16._370_say = "Prosz\234, we\159 t\234 nagrod\234 i odpocznij.[ENTER]Zobaczymy si\234 p\243\159niej! "
gameforge.subquest_16._380_sayReward = "Otrzyma\179e\156 150.000 Punkt\243w Do\156wiadczenia.[ENTER]Otrzyma\179e\156 30.000 Yang.[ENTER]Otrzyma\179e\156 Z\179ote Kolczyki. "
gameforge.subquest_16._40_say = "Dzi\234ki zdobytym przez ciebie informacjom mo\191emy[ENTER]wzmocni\230 si\179\234 uderzeniow\185 naszych wojsk. Odwied\159[ENTER]najpierw muzyka Yu-Hwan. Jestem pewien, \191e ma on[ENTER]jakie\156 informacje o Uzbrojonej Kawalerii. "
gameforge.subquest_16._50_say = "Hm, jak uwa\191asz. Zatem do zobaczenia! "
gameforge.subquest_16._60_say = "Czy b\234d\234 kiedy\156 dowodzi\179 tak\185 kawaleri\185?[ENTER]Uwa\191aj na siebie. "
gameforge.subquest_16._70_say = "Dzi\234kuj\234. Trzymaj si\234. "
gameforge.subquest_16._80_sayTitle = "Uzbrojona Kawaleria. "
gameforge.subquest_16._90_sayReward = "Kapitan szuka informacji na temat legendarnej[ENTER]kawalerii kr\243la-za\179o\191yciela Isup. Muzyk Yu-Hwan[ENTER]wie zapewne co\156 na ten temat. Id\159 i spytaj si\234[ENTER]go. "
gameforge.subquest_17 = {}
gameforge.subquest_17._100_targetVid = "Porozmawiaj z Handlark\185 R\243\191no\156ciami. "
gameforge.subquest_17._10_targetVid = "Historia m\234\191a Ariyoung "
gameforge.subquest_17._110_say = "Id\159 do Handlarki i zapytaj o m\234\191a Ariyoung. "
gameforge.subquest_17._120_npcChat = "M\185\191 Ariyoung "
gameforge.subquest_17._130_say = "To bardzo smutna historia. Ona jeszcze nie wie,[ENTER]co si\234 sta\179o z jej m\234\191em? Przebywa w miejscu, z[ENTER]kt\243rego nikt ju\191 nie powraca...[ENTER]Kiedy wraca\179 do wioski z towarem, zosta\179 pojmany[ENTER]i zabity przez Gang Czarnego Wiatru. "
gameforge.subquest_17._140_say = "Obawiam si\234, \191e b\234dzie bardzo zdesperowana, gdy[ENTER]si\234 o tym dowie. Tak bardzo si\234 kochali...[ENTER]Ale powinna o tym wiedzie\230, w przeciwnym razie[ENTER]zabije j\185 ta niepewno\156\230. "
gameforge.subquest_17._150_targetVid = "Smutna wiadomo\156\230 "
gameforge.subquest_17._160_sayTitle = "Ariyoung: "
gameforge.subquest_17._170_say = "Handlarka R\243\191no\156ciami ma z\179\185 nowin\234. Udaj si\234 do[ENTER]Ariyoung i przeka\191 jej wiadomo\156\230 o \156mierci jej[ENTER]m\234\191a. "
gameforge.subquest_17._180_npcChat = "Tw\243j m\185\191 nie \191yje... "
gameforge.subquest_17._190_say = "Co... co ty m\243wisz?! Zosta\179 zabity przez kogo\156 z[ENTER]Gangu Czarnego Wiatru? Och nie... jest martwy...[ENTER]Nie wiem co ja zrobi\234 bez niego! "
gameforge.subquest_17._200_say = "Czy m\243g\179by\156 dostarczy\230 mi cia\179o mojego m\234\191a?[ENTER]Prosz\234, wtedy b\234d\234 mog\179a si\234 z nim przynajmniej[ENTER]po\191egna\230. Je\156li to nie b\234dzie mo\191liwe, wystarczy[ENTER]cokolwiek z jego rzeczy. Wszystko co mo\191esz[ENTER]znale\159\230 po moim m\234\191u. Goo-Pae z Gangu Czarnego[ENTER]Wiatru na pewno b\234dzie co\156 po nim mia\179.[ENTER]Prosz\234 przynie\156 mi co\156. "
gameforge.subquest_17._20_say = "Min\234\179o du\191o czasu od ostatniego razu, gdy co\156[ENTER]s\179ysza\179am o moim m\234\191u. Martwi\234 si\234 o niego, mam[ENTER]nadziej\234, \191e nic mu si\234 nie sta\179o.[ENTER][ENTER]Wydaje mi si\234, \191e zamartwianie nie jest dobrym[ENTER]pomys\179em, jednak moje serce strasznie to znosi.[ENTER]Nie mog\234 si\234 uspokoi\230. "
gameforge.subquest_17._210_select = "Tak, pomog\234 Ci. "
gameforge.subquest_17._220_say = "Wr\243\230 do mnie, gdy to przemy\156lisz. Prosz\234... "
gameforge.subquest_17._230_say = "Nic nie znalaz\179e\156? Mimo tego, dzi\234kuj\234...[ENTER]Och, tak mi przykro! "
gameforge.subquest_17._240_say = "Nawet nie wiesz, jak bardzo jestem Ci wdzi\234czna.[ENTER]B\234d\234 si\234 za Ciebie modli\179a. "
gameforge.subquest_17._250_sendLetter = "Zabij Goo-Pae "
gameforge.subquest_17._260_say = "Gang Czarnego Wiatru zabi\179 i okrad\179 m\234\191a[ENTER]Ariyoung. Zabijaj tak d\179ugo Goo-Pae, a\191[ENTER]zdob\234dziesz pami\185tk\234 po m\234\191u Ariyoung. "
gameforge.subquest_17._270_npcChat = "Z powodu Twojego m\234\191a... "
gameforge.subquest_17._280_say = "Jak posz\179o? Uda\179o Ci si\234 zdoby\230 pami\185tk\234 po moim[ENTER]m\234\191u? By\179 dla mnie wszystkim. To jak? "
gameforge.subquest_17._290_select = "Jeszcze nie. Szukam dalej! "
gameforge.subquest_17._300_say = "Goo-Pae z Gangu Czarnego Wiatru jest twardy.[ENTER]Odpocznij troszk\234. Dzi\234kuj\234 za twoj\185 pomoc. "
gameforge.subquest_17._30_say = "Mam nadziej\234, \191e Handlarka co\156 s\179ysza\179a o moim[ENTER]m\234\191u. Ma wielu klient\243w, kt\243rzy mog\185 co\156[ENTER]wiedzie\230. "
gameforge.subquest_17._310_say = "B\234d\234 musia\179a poczeka\230 na innego bohatera, kt\243ry[ENTER]mi pomo\191e.[ENTER]Do widzenia. "
gameforge.subquest_17._320_say = "Och, jeste\156 taki mi\179y. Prosz\234, przynie\156 mi co\156 co[ENTER]nale\191a\179o do mojego m\234\191a. "
gameforge.subquest_17._330_sendLetter = "Obr\185czka Ariyoung "
gameforge.subquest_17._340_targetVid = "Udaj si\234 do Ariyoung "
gameforge.subquest_17._350_sayTitle = "Udaj si\234 do Ariyoung "
gameforge.subquest_17._360_say = "Przy jednym z zabitych Goo-Pae znalaz\179e\156 Obr\185czk\234[ENTER]m\234\191a Ariyoung. To wspania\179a pami\185tka po jej m\234\191u.[ENTER]Dostarcz Obr\185czk\234 do Ariyoung. "
gameforge.subquest_17._370_npcChat = "Znalaz\179em ten Pier\156cie\241. "
gameforge.subquest_17._380_say = "Ten... pier\156cie\241... to moja Obr\185czka! Teraz m\243j[ENTER]m\185\191 mo\191e spoczywa\230 w pokoju... Schowam t\185[ENTER]Obr\185czk\234 razem z listem ode mnie. Od teraz b\234d\234[ENTER]\191y\179a samotnie. Odzyska\179am chocia\191 Obr\185czk\234. To[ENTER]mi\179e uczucie. Jestem Ci bardzo wdzi\234czna. "
gameforge.subquest_17._390_sendLetter = "Zadanie wykonane! "
gameforge.subquest_17._400_say = "Informacja o Twojej pomocy Ariyoung roznosi si\234.[ENTER]Wiele os\243b chwali Twoj\185 pomoc. "
gameforge.subquest_17._40_select = "P\243jd\234 do Handlarki. "
gameforge.subquest_17._410_sayReward = "Otrzyma\179e\156 300.000 Punkt\243w Do\156wiadczenia. "
gameforge.subquest_17._420_sayReward = "Otrzyma\179e\156 10.000 Yang. "
gameforge.subquest_17._50_select = "Nie, nie mam na to czasu. "
gameforge.subquest_17._60_say = "Czy chcesz na zawsze zrezygnowa\230 z tego zadania? "
gameforge.subquest_17._70_say = "Wr\243\230 do mnie, gdy to przemy\156lisz. Prosz\234... "
gameforge.subquest_17._80_say = "Nie masz czasu na wykonanie tak \179atwego zadania?[ENTER]No dobrze, w takim razie... "
gameforge.subquest_17._90_say = "Dzi\234kuj\234 za Twoj\185 dobro\230. Bo\191e, gdzie jest m\243j[ENTER]m\185\191... "
