gameforge.subquest_18._100_say = "Poszukaj m\234\191czyzny czytaj\185cego wiersze i[ENTER]odzianego w \179achmany. Zwr\243\230 si\234 do niego. "
gameforge.subquest_18._10_targetVid = "Gdzie on si\234 ukrywa? "
gameforge.subquest_18._110_npcChat = "Gdzie jest tw\243j m\185\191? "
gameforge.subquest_18._120_say = "Nie wiem, gdzie si\234 schowa\179. W mi\234dzyczasie robi[ENTER]to tak dobrze, \191e ci\234\191ko go znale\159\230. Mo\191e[ENTER]powinnam rzeczywi\156cie powiesi\230 dzwonek u jego[ENTER]szyi, tak jak poleci\179 mi Handlarz. "
gameforge.subquest_18._130_npcChat = "Znajd\159 Soon! "
gameforge.subquest_18._140_say = "S\179yszysz cudowny wiersz. Uj\234ty s\179owami pod\185\191asz[ENTER]za d\159wi\234kiem g\179osu, a\191 stajesz przed m\234\191czyzn\185 w[ENTER]podartych \179achmanach.[ENTER][ENTER]To musi by\230 m\185\191 Aranyo![ENTER][ENTER]W\179a\156nie chcesz si\234 odwr\243ci\230, aby powr\243ci\230 do[ENTER]Aranyo, gdy m\234\191czyzna \179apie ci\234 za rami\234. "
gameforge.subquest_18._150_say = "Nie jeste\156 st\185d. Czy wys\179a\179a Ci\234 moja \191ona?[ENTER][ENTER]Och nie! On wie kim ja jestem! Co mu odpowiedzie\230? "
gameforge.subquest_18._153_select = "Heh, jestem tu przypadkiem... "
gameforge.subquest_18._157_select = "Dobrze... "
gameforge.subquest_18._160_say = "Ahm, mi\179o mi Ci\234 pozna\230. Pi\234kna pogoda, prawda?[ENTER]Czyta\179e\156 mo\191e ostatnio jak\185\156 dobr\185 ksi\185\191k\234?[ENTER]Ja aktualnie czytam ksi\185\191k\234 napisan\185 przez Oja.[ENTER]Powiniene\156 j\185 przeczyta\230. "
gameforge.subquest_18._170_say = "Mam racj\234, prawda? \175ona mi dokucza tak bardzo, \191e[ENTER]nie mog\234 w domu czyta\230 w spokoju. Ona w og\243le[ENTER]mnie nie rozumie. Mo\191e i znalaz\179e\156 mnie tutaj,[ENTER]ale mog\234 si\234 uda\230 w inne miejsce. Co powiesz na[ENTER]to, \191eby jej nic nie m\243wi\230? W zamian dam Ci dobr\185[ENTER]rad\234 o polowaniu. "
gameforge.subquest_18._180_sendLetter = "Wr\243\230 do Aranyo. "
gameforge.subquest_18._190_say = "Wr\243\230 do Aranyo i przeka\191, \191e nie by\179e\156 w stanie[ENTER]odnale\159\230 Soon. "
gameforge.subquest_18._200_npcChat = "Tajemnica Soon. "
gameforge.subquest_18._20_sayTitle = "Aranyo: "
gameforge.subquest_18._210_say = "Nie mog\179e\156 go znale\159\230? Przygotowa\179am nawet[ENTER]pu\179apki. Gdzie on do cholery si\234 schowa\179?[ENTER]Jestem taka zaj\234ta. Co za smutny los. "
gameforge.subquest_18._220_sendLetter = "Powr\243t do Soon "
gameforge.subquest_18._230_say = "Wr\243\230 do Soon i przeka\191, \191e Ci si\234 uda\179o. "
gameforge.subquest_18._240_npcChat = "Oto jestem. "
gameforge.subquest_18._250_say = "Wszystko posz\179o po naszej my\156li? Ocali\179e\156 moje[ENTER]\191ycie! We\159 to, poszukiwaczu przyg\243d. Tak jak[ENTER]obieca\179em, wr\234czam ci nagrod\234. "
gameforge.subquest_18._260_sayReward = "Otrzymujesz 7.000 Punkt\243w Do\156wiadczenia. "
gameforge.subquest_18._270_sayReward = "Otrzyma\179e\156 10.000 Yang. "
gameforge.subquest_18._280_say = "Wr\243\230 do Aranyo i powiedz, gdzie znajduje si\234 Soon. "
gameforge.subquest_18._290_npcChat = "Ukrywanie si\234 jest trudne... "
gameforge.subquest_18._300_say = "Dzi\234ki, \191e nie mnie nie ujawni\179e\156.[ENTER]Ci\234\191ko jest si\234 ukry\230 przed moj\185 \191on\185.[ENTER]Chc\234 tylko si\234 tu pouczy\230... w spokoju... "
gameforge.subquest_18._30_say = "M\243j m\185\191 sprawia mi najwi\234kszy b\243l. Nazywa siebie[ENTER]uczonym! W czasie, gdy my walczymy ka\191dego dnia o[ENTER]co\156 do jedzenia, on tylko czyta ksi\185\191ki.[ENTER]Widzia\179e\156 go mo\191e? Dlaczego po\156lubi\179am mola[ENTER]ksi\185\191kowego... "
gameforge.subquest_18._310_npcChat = "Gdzie jest Soon? "
gameforge.subquest_18._320_say = "Znalaz\179e\156 go? Wielkie, wielkie dzi\234ki! Je\156li[ENTER]dowie si\234, \191e zosta\179 odkryty, mo\191e czmychn\185\230.[ENTER]Udam si\234 tam natychmiast. Tym razem go dorw\234![ENTER]A ty przyjmij to jako dow\243d mojej wdzi\234czno\156ci.[ENTER]Poczekaj no, draniu...! "
gameforge.subquest_18._33_select = "Pomog\234 Ci. "
gameforge.subquest_18._37_select = "Nie mam na to czasu. "
gameforge.subquest_18._40_say = "Czy chcesz zrezygnowa\230 z tej misji? "
gameforge.subquest_18._50_say = "Dobrze... mo\191e p\243\159niej znajdziesz chwilk\234 aby go[ENTER]poszuka\230... "
gameforge.subquest_18._60_say = "Mo\191e uda mi si\234 go jako\156 znale\159\230... "
gameforge.subquest_18._70_say = "By\179abym bardzo wdzi\234czna. Kiedy znajdziesz[ENTER]kiepskiego pisarza, daj mi zna\230. On z pewno\156ci\185[ENTER]jest jedyny w wiosce. Mo\191e rozmy\156la o nowym[ENTER]wierszu i przesiaduje w samotno\156ci z tego powodu.[ENTER]Kiedy us\179yszy, \191e go szukam, mo\191e czmychn\185\230.[ENTER]Wi\234c b\185d\159 ostro\191ny. "
gameforge.subquest_18._80_sendLetter = "Znajd\159 Soon. "
gameforge.subquest_18._90_sayTitle = "Znajd\159 Soon! "
