gameforge.subquest_19._110_sayTitle = "Zdob\185d\159 Sk\243r\234 Wilka "
gameforge.subquest_19._120_sayReward = "Zdob\185d\159 Sk\243r\234 Wilka, dzi\234ki kt\243rej Starsza Pani[ENTER]b\234dzie mog\179a wysprz\185ta\230 dom.[ENTER]Mo\191esz j\185 zdoby\230 od Szarych Wilk\243w. "
gameforge.subquest_19._130_targetVid = "Wr\243\230 do Starszej Pani. "
gameforge.subquest_19._140_npcChat = "Dostarcz Sk\243r\234 Wilka "
gameforge.subquest_19._150_say = "To jest... och, nie. To nie jest odpowiednia[ENTER]Sk\243ra Wilka. Powiniene\156 poszuka\230 jeszcze raz.[ENTER]Prosz\234, tym razem przynie\156 mi odpowiedni\185 Sk\243r\234. "
gameforge.subquest_19._160_say = "Potrzebuj\234 prawdziwego Futro Szarego Wilka.[ENTER]Przykro mi, ale z tym nic nie mog\234 zrobi\230. "
gameforge.subquest_19._170_select = "Spr\243buj\234 ponownie. "
gameforge.subquest_19._180_select = "Nie chc\234... "
gameforge.subquest_19._190_say = "Czy naprawd\234 chcesz zrezygnowa\230 z tej misji? "
gameforge.subquest_19._200_say = "Po prostu przyjd\159 p\243\159niej. "
gameforge.subquest_19._20_say = "M\243j drogi, ten kaszel mnie wyko\241czy. Nie mam[ENTER]niczego, czym mog\179abym odkurzy\230 dom... wi\234c ca\179y[ENTER]kurz zostaje w \156rodku. Czemu nie mam \156cierki do[ENTER]kurzu? M\243j syn wzi\185\179 j\185 do pracy aby wyczy\156ci\230[ENTER]pewn\185 bro\241. Moje w\179asne cia\179o i krew mnie[ENTER]zabijaj\185. "
gameforge.subquest_19._210_say = "Wiem, \191e to trudne, ale spr\243buj ponownie. Prosz\234. "
gameforge.subquest_19._220_say = "Dzi\234kuj\234 za to, \191e si\234 tym zajmiesz. "
gameforge.subquest_19._230_say = "Jeste\156 \179owc\185 przyg\243d! Wci\185\191 mocno kaszl\234.[ENTER]Jak s\179yszysz, nadal mam ten okropny kaszel.[ENTER]Dom jest pe\179en kurzu. Och, przynios\179e\156 mi Sk\243r\234[ENTER]Wilka? Tak! Ta jest odpowiednia![ENTER]Dzi\234kuj\234 bardzo. Prosz\234, poczekaj tu chwil\234. "
gameforge.subquest_19._240_say = "Raz, dwa, raz dwa. Krok po kroku...[ENTER]Dobrze, jestem z powrotem. Dzi\234ki, w ko\241cu mog\179am[ENTER]dok\179adnie posprz\185ta\230 sw\243j dom. Podczas sprz\185tania[ENTER]znalaz\179am co\156, co chcia\179abym Ci podarowa\230. Nie[ENTER]wiem, czy jest to cokolwiek warte, ale mo\191e ci[ENTER]si\234 przyda. Jeszcze raz dzi\234kuj\234. Bywaj! "
gameforge.subquest_19._250_sendLetter = "Zakurzone co\156 "
gameforge.subquest_19._260_say = "Jako nagrod\234 dosta\179e\156 co\156 wygl\185daj\185cego jak[ENTER]rupie\230. Ciekawo\156\230 zwyci\234\191y\179a, \156cierasz kurz. "
gameforge.subquest_19._270_say = "To stara i warto\156ciowa Zbroja. Jedna z lepszych[ENTER]zrobionych przez Kowala. Szcz\234\156ciarz! "
gameforge.subquest_19._280_say = "Jest stara, ale nadal do u\191ytku. Zawsze co\156! "
gameforge.subquest_19._290_say = "To Zbroja, jednak pomimo twoich wielkich nadziei,[ENTER]jest ca\179kowicie bezu\191yteczna. "
gameforge.subquest_19._300_sayReward = "Otrzymujesz 15.000 Punkt\243w Do\156wiadczenia. "
gameforge.subquest_19._30_select = "Dam Ci now\185. "
gameforge.subquest_19._40_say = "(kaszle)(kaszle) Wszystko jest zakurzone...[ENTER]Potrzebuj\234 czego\156 do wycierania kurzu.[ENTER]Czy m\243g\179by\156 mi pom\243c? "
gameforge.subquest_19._50_say = "Min\185\179 ju\191 jaki\156 czas, ale pami\234tam, \191e m\243j m\185\191,[ENTER]Panie \156wie\230 nad jego dusz\185, zrobi\179 szczotk\234 do[ENTER]kurzu ze Sk\243ry Wilka. Mo\191esz zdoby\230 kawa\179ek[ENTER]takiej Sk\243ry dla starej, biednej kobiety? Mo\191esz[ENTER]j\185 zdoby\230 od Szarych Wilk\243w.[ENTER]Bardzo by mi to pomog\179o. "
gameforge.subquest_19._60_say = "Czy naprawd\234 chcesz zrezygnowa\230 z misji? "
gameforge.subquest_19._70_say = "Uh, wstyd... my\156la\179am \191e mi pomo\191esz.[ENTER]Mo\191e to przemy\156lisz i jeszcze do mnie wr\243cisz? "
gameforge.subquest_19._80_say = "Jakiej nagrody m\243g\179by kto\156 oczekiwa\230 od takiej[ENTER]starej i biednej kobiety? "
gameforge.subquest_19._90_say = "Nie tak \179atwo jest zdoby\230 Sk\243r\234 Wilka. Ale mimo[ENTER]wszystko spr\243buj\234. W ko\241cu kiedy\156 chc\234 zosta\230[ENTER]wielkim bohaterem! "
gameforge.subquest_20 = {}
gameforge.subquest_20._100_say = "Chcesz zrezygnowa\230? "
gameforge.subquest_20._10_targetVid = "Pom\243\191 Ah-Yu! "
gameforge.subquest_20._110_say = "Ok, wr\243\230 gdy znajdziesz troszk\234 wolnego czasu. "
gameforge.subquest_20._120_say = "Jeste\156 tch\243rzem. I tak by\156 uciek\179, na widok tych[ENTER]Dzikus\243w. Id\159 sobie! "
gameforge.subquest_20._130_say = "Dzi\234kuj\234 za to, \191e chcesz mi pom\243c.[ENTER]Chodzi o trzy Oszczepy. "
gameforge.subquest_20._140_sendLetter = "Oszczepy "
gameforge.subquest_20._150_targetVid = "Ah-Yu: "
gameforge.subquest_20._160_sayTitle = "Trzy Oszczepy "
gameforge.subquest_20._170_say = "Znalaz\179e\156 wszystkie trzy Oszczepy nale\191\185ce do[ENTER]m\234\191a Ah-Yu. Wr\243\230 do niej. "
gameforge.subquest_20._180_sayTitle = "Znajd\159 Oszczepy! "
gameforge.subquest_20._190_say = "Dziki \175o\179nierz Piechoty, Dziki S\179uga, Dziki[ENTER]\163ucznik, Dziki Genera\179: to oni ukradli Oszczepy.[ENTER]Spr\243buj je od nich odzyska\230. "
gameforge.subquest_20._200_sayReward = "Musisz odnale\159\230 trzy Oszczepy i zanie\156\230 je do[ENTER]Ah-Yu. (Ilo\156\230 Oszczep\243w: %s) "
gameforge.subquest_20._20_npcChat = "Pami\185tka po m\234\191u. "
gameforge.subquest_20._210_npcChat = "Gdzie znajd\234 Oszczepy? "
gameforge.subquest_20._220_say = "Bardzo prawdopodobne, \191e Dzikusy maj\185 Oszczepy[ENTER]mojego m\234\191a. Kto wie. Mam tylko nadziej\234, \191e nie[ENTER]ich nie zniszczyli. To s\185 bardzo dobre Oszczepy.[ENTER][ENTER]Kontynuowa\230 poszukiwania? "
gameforge.subquest_20._230_select = "Tak, kontynuuj\234 poszukiwania. "
gameforge.subquest_20._240_say = "Jeste\156 tch\243rzem! Ok, wi\234c zrobi\234 to sama.[ENTER][ENTER]Naprawd\234 chcesz zrezygnowa\230 z poszukiwa\241? "
gameforge.subquest_20._250_select = "Tak. "
gameforge.subquest_20._260_say = "Zrobi\179abym to sama, ale musz\234 opiekowa\230 si\234[ENTER]dzieckiem. Wr\243\230, gdy znajdziesz wszystkie[ENTER]Oszczepy! "
gameforge.subquest_20._270_say = "Zrezygnowa\179e\156 z poszukiwa\241 Oszczep\243w m\234\191a Ah-Yu. "
gameforge.subquest_20._280_say = "Dzi\234kuj\234 Ci bardzo. Na pewno niebawem je[ENTER]znajdziesz! "
gameforge.subquest_20._290_npcChat = "Odzyskaj Oszczepy. "
gameforge.subquest_20._300_sayTitle = "Ah-Yu: "
gameforge.subquest_20._30_say = "O m\243j Bo\191e. Nie p\179acz kochanie.[ENTER]Twoja mama jest tak\191e w z\179ym nastroju.[ENTER]Je\156li b\234dziesz ca\179y czas p\179aka\230, b\234dzie jeszcze[ENTER]gorzej. Prosz\234, przesta\241 p\179aka\230. "
gameforge.subquest_20._310_say = "To, \191e przynios\179e\156 mi jeden Oszczep, to ju\191 jest[ENTER]dla mnie \156wietnie. Mo\191esz jeszcze poszuka\230[ENTER]pozosta\179ych? One musz\185 by\230 w komplecie. Dzi\234ki. "
gameforge.subquest_20._320_select = "Spr\243buj\234 ponownie. "
gameforge.subquest_20._330_select = "Poddaj\234 si\234. "
gameforge.subquest_20._340_say = "Zrezygnowa\179e\156 z poszukiwa\241 Oszczep\243w m\234\191a Ah-Yu. "
gameforge.subquest_20._350_say = "Dzi\234kuj\234, \191e si\234 nie poddajesz! "
gameforge.subquest_20._360_say = "Oh, odzyska\179e\156 je! Jestem bardzo szcz\234\156liwa,[ENTER]dzi\234kuj\234. Nie jest to du\191o Yang, ale we\159 je. "
gameforge.subquest_20._370_sayReward = "Otrzymujesz 300.000 Punkt\243w Do\156wiadczenia.[ENTER]Otrzymujesz 20.000 Yang. "
gameforge.subquest_20._40_say = "Jeste\156 dzisiaj nie do poznania. Zazwyczaj jeste\156[ENTER]przecie\191 weso\179a! Sta\179o si\234 co\156? "
gameforge.subquest_20._50_say = "M\243j m\185\191 zawsze opiekowa\179 si\234 wszystkimi dooko\179a i[ENTER]dba\179 o to, \191eby nie spotka\179o mnie nic z\179ego.[ENTER]Ale teraz nie ma go ju\191 w\156r\243d nas, poleg\179 na[ENTER]wojnie. Jedyn\185 rzecz\185 jaka mi po nim pozosta\179a[ENTER]jest dziecko i jego Oszczepy. "
gameforge.subquest_20._60_say = "Gdy posz\179am do pracy, kto\156 ukrad\179 mi te Oszczepy.[ENTER]S\185siedzi oskar\191aj\185 Dzikus\243w. Jako \191e mam ma\179e[ENTER]dziecko, nie mog\234 ich poszuka\230 sama. "
gameforge.subquest_20._70_say = "Czy m\243g\179by\156 odzyska\230 dla mnie te Oszczepy?[ENTER]Z pewno\156ci\185 znajdziesz je u Dzikus\243w. "
gameforge.subquest_20._80_select = "Ok, poszukam. "
gameforge.subquest_20._90_select = "Nie mam czasu. "
gameforge.subquest_21 = {}
gameforge.subquest_21._100_say = "Dzi\234kuj\234 ci, przyjacielu![ENTER]Mam nadziej\234, \191e odniesiesz sukces! "
gameforge.subquest_21._10_targetVid = "Balso? "
gameforge.subquest_21._110_sendLetter = "Lekarstwo dla Balso "
gameforge.subquest_21._120_targetVid = "Id\159 do Balso "
gameforge.subquest_21._130_sayReward = "Znalaz\179e\156 lekarstwo dla Balso kt\243ry zarazi\179 si\234[ENTER]nieznan\185 chorob\185. Dostarcz to lekarstwo do Balso. "
gameforge.subquest_21._140_sayTitle = "Zdob\185d\159 Lekarstwo "
gameforge.subquest_21._150_say = "W jego d\179ugiej ucieczce, Balso zarazi\179 si\234[ENTER]nieznan\185 chorob\185. Zdob\185d\159 Lekarstwo od Zara\191onego[ENTER]Cz\179owieka na G\243rze Sohan. "
gameforge.subquest_21._160_npcChat = "Mam Lekarstwo! "
gameforge.subquest_21._170_say = "Oh, bardzo Ci dzi\234kuj\234. Ci\234\191ko jest \191y\230 \191yciem[ENTER]uchod\159cy. Jeste\156 nara\191ony na r\243\191ne choroby.[ENTER]Dzi\234ki tobie, teraz mog\234 zdrowie\230. Dzi\234ki! "
gameforge.subquest_21._180_sayTitle = "Nagroda: "
gameforge.subquest_21._190_sayReward = "Otrzymujesz 1.900.000 Punkt\243w Do\156wiadczenia.[ENTER]Otrzymujesz 30.000 Yang. "
gameforge.subquest_21._20_npcChat = "Tak strasznie sw\234dzi... "
gameforge.subquest_21._30_sayTitle = "Zdrajca Balso: "
gameforge.subquest_21._40_say = "Mog\234 prosi\230 Ci\234 o przys\179ug\234? Jak wiesz jestem[ENTER]zdrajc\185, a jako zdrajca ci\234\191ko teraz wy\191y\230.[ENTER]Kiedy\156 \191y\179em bardzo dostatnie, ale teraz jest[ENTER]dok\179adnie na odwr\243t... Od tamtej pory zawsze[ENTER]uciekam i nie mog\234 odpocz\185\230. A dodatkowo mam[ENTER]kontakt z du\191\185 ilo\156ci\185 chor\243b. "
gameforge.subquest_21._50_say = "Kilka dni temu by\179em na terenach G\243ry Sohan i[ENTER]jako\156 wpad\179em na Zara\191onego Cz\179owieka.[ENTER]Na szcz\234\156cie uda\179o mi si\234 umkn\185\230. Jednak teraz[ENTER]widz\234, \191e kontakt z jego sk\243r\185 zarazi\179 mnie jak\185\156[ENTER]straszn\185 chorob\185. Czy mo\191esz mi pom\243c i zdoby\230[ENTER]jakie\156 Lekarstwo? Na pewno maj\185 je ze sob\185. Nie[ENTER]lubi\234 tego robi\230, ale prosz\234, mo\191esz pom\243c mi? "
gameforge.subquest_21._60_select = "Tak, pomog\234 Ci. "
gameforge.subquest_21._70_say = "Czy chcesz przerwa\230 poszukiwania? "
gameforge.subquest_21._80_say = "Zawsze mi si\234 to przydarza. Wsz\234dzie mnie nie[ENTER]lubi\185. Jak to przemy\156lisz, odwied\159 mnie jeszcze[ENTER]raz. "
gameforge.subquest_21._90_say = "Precz! I nigdy tutaj nie wracaj! Zawsze to samo... "
