gameforge.subquest_22._170_sayTitle = "Deokbae: "
gameforge.subquest_22._180_say = "Bez Twojej pomocy nigdy nie odzyska\179bym tego[ENTER]Topora. Wielkie dzi\234ki. Na przysz\179o\156\230 b\234d\234[ENTER]bardziej uwa\191a\179 i nosi\179 go zawsze przy sobie. "
gameforge.subquest_22._190_sayReward = "Otrzyma\179e\156 400.000 Punkt\243w Do\156wiadczenia. "
