gameforge.subquest_22._20_npcChat = "Co si\234 tyczy Twojego Z\179otego Topora... "
gameforge.subquest_22._30_sayTitle = "Deokbae: "
gameforge.subquest_22._40_say = "O nie, o nie! Straci\179em top\243r. Mo\191e Ty wiesz o[ENTER]jakim toporze m\243wi\234? O tak .. Wiesz?[ENTER]To Z\179oty Top\243r, kt\243ry dosta\179em od Kowala. Jaki\156[ENTER]Dzikus mi go ukrad\179! "
gameforge.subquest_22._50_say = "Jak Kowal si\234 dowie to si\234 w\156cieknie i nie b\234dzie[ENTER]naprawia\179 mi ju\191 topor\243w. Poza tym by\179 to[ENTER]naprawd\234 dobry Top\243r. Czy mo\191esz go dla mnie[ENTER]odzyska\230? "
