gameforge.subquest_22._70_say = "Czy chcesz przerwa\230 poszukiwania? "
gameforge.subquest_22._80_say = "Oh, wr\243\230 gdy b\234dziesz mia\179 troszk\234 czasu. "
gameforge.subquest_22._90_say = "Za trudne dla ciebie? Wi\234c ja tym bardziej nic[ENTER]nie poradz\234. Uwa\191aj na siebie... "
