gameforge.subquest_23._10_targetVid = "Poszukiwania starszego Brata Mirine! "
gameforge.subquest_23._110_targetVid = "Id\159 do Yu-Hwan. "
gameforge.subquest_23._120_say = "Starszy brat Mirine znikn\185\179 ponownie. Nie da\179[ENTER]znaku \191ycia od d\179u\191szego czasu. List, kt\243ry[ENTER]dostarczy\179e\156 jej ostatnio, by\179 ostatnim[ENTER]kontaktem. Id\159 do Yu-Hwan i poszukaj starszego[ENTER]brata Mirine. "
gameforge.subquest_23._130_npcChat = "Widzia\179e\156 brata Mirine? "
gameforge.subquest_23._140_say = "Brat Mirine? Nie, niestety nie mog\234 Ci pom\243c. Od[ENTER]d\179u\191szego czasu nie mam ju\191 z nim kontaktu. Chyba[ENTER]nawet nie pami\234tam, kiedy go ostatnio widzia\179em.[ENTER]Ja r\243wnie\191 si\234 martwi\234. Mo\191e co\156 si\234 sta\179o?[ENTER]Zapytaj \163owcy Yang-Shin. On du\191o podr\243\191uje i[ENTER]mo\191liwe, \191e go spotka\179. "
gameforge.subquest_23._150_sendLetter = "Poszukaj Yang-Shin "
