gameforge.subquest_23._170_say = "\163owca Yang-Shin du\191o podr\243\191uje. Mo\191e spotka\179[ENTER]gdzie\156 starszego brata Mirine. "
gameforge.subquest_23._180_npcChat = "Widzia\179e\156 brata Mirine? "
gameforge.subquest_23._190_say = "Starszego brata Mirine? Ostatnim razem, gdy go[ENTER]spotka\179em, by\179 w drodze do Doliny Seungryong, aby[ENTER]zbiera\230 zio\179a lecznicze. By\179em zaskoczony,[ENTER]poniewa\191 to bardzo niebezpieczne miejsce. Nie[ENTER]przej\185\179em si\234 tym jednak. "
gameforge.subquest_23._200_say = "Powinienem by\179 go powstrzyma\230. Je\191eli nadal nie[ENTER]wr\243ci\179, to najprawdopodobniej co\156 mu si\234[ENTER]przydarzy\179o. Lepiej id\159 do Doliny Seungryong i go[ENTER]poszukaj. "
gameforge.subquest_23._20_npcChat = "Dlaczego p\179aczesz? "
gameforge.subquest_23._210_select = "Rozpocznij poszukiwania "
gameforge.subquest_23._220_say = "Przerwa\230 poszukiwanie? "
gameforge.subquest_23._230_say = "Mirine by\179a naprawd\234 bardzo smutna.[ENTER]Wr\243c\234 p\243\159niej. "
gameforge.subquest_23._240_say = "To, \191e nie by\179o \191adnego znaku \191ycia od starszego[ENTER]brata Mirine nie musi oznacza\230, \191e co\156 mu si\234[ENTER]sta\179o. Nie musisz i\156\230 do niebezpiecznej Doliny[ENTER]tylko dlatego, \191e poprosi\179a Ci\234 o to jaka\156[ENTER]dziewczyna. "
gameforge.subquest_23._250_say = "Misja nie jest taka prosta jak mog\179oby si\234[ENTER]wydawa\230. Dolina Seungryong jest niebezpiecznym[ENTER]miejscem. Ale obieca\179em, wi\234c to zrobi\234. "
gameforge.subquest_23._260_sendLetter = "Zaginiony brat "
gameforge.subquest_23._270_targetVid = "Poszukaj starszego brata w Dolinie Seungryong. "
gameforge.subquest_23._280_sayTitle = "Poszukaj brata Mirine "
gameforge.subquest_23._290_say = "Starszy brat Mirine szuka zi\243\179 leczniczych w[ENTER]Dolinie Seungryong. Udaj si\234 tam i sprawd\159, czy[ENTER]wszystko jest w porz\185dku. Je\156li szukasz skr\243tu,[ENTER]skorzystaj z Teleportera. "
gameforge.subquest_23._300_npcChat = "Cia\179o! "
gameforge.subquest_23._30_say = "Chwileczk\234 prosz\234... Da\179e\156 mi kiedy\156 list od[ENTER]mojego brata, prawda? Jestem Ci bardzo wdzi\234czna.[ENTER]Ale teraz znowu nie mam z nim kontaktu. M\243j brat[ENTER]nadal jest poza domem. Poszukuje zi\243\179. "
gameforge.subquest_23._310_say = "Le\191y tam jakie\156 cia\179o m\234\191czyzny. Jest m\179ody i[ENTER]chudy, wygl\185da na to, \191e zbiera\179 jakie\156 zio\179a.[ENTER]Obawiam si\234, \191e to mo\191e by\230 starszy brat Mirine.[ENTER]Na szyi ma naszyjnik z wisiorkiem. Zdejm\234 go i[ENTER]zanios\234 do Mirine. "
gameforge.subquest_23._320_sendLetter = "Id\159 do Mirine. "
gameforge.subquest_23._330_sayTitle = "Smutna wiadomo\156\230 "
gameforge.subquest_23._340_say = "Na ciele znalezionym w Dolinie Seungryong,[ENTER]znajdowa\179 si\234 Amulet, na kt\243rym jest[ENTER]wygrawerowane imi\234 Mirine. Id\159 do Mirine i daj[ENTER]jej znaleziony naszyjnik i Amulet. "
gameforge.subquest_23._350_npcChat = "Poznajesz ten naszyjnik? "
gameforge.subquest_23._360_say = "Och, ten naszyjnik... m\243j brat nosi\179 go ca\179y[ENTER]czas. Ja mam podobny naszyjnik. Zawsze nosili\156my[ENTER]te naszyjniki aby zawsze o sobie pami\234ta\230 i[ENTER]zawsze si\234 odnale\159\230.[ENTER]Ale... m\243j brat nie jest ju\191 tutaj ze mn\185...[ENTER]wr\243ci\179 tylko sam naszyjnik... "
gameforge.subquest_23._370_say = "M\243j biedny brat...[ENTER]Wszystko z powodu wojny. M\243j brat sprzedawa\179[ENTER]zio\179a lecznicze, to by\179o nasze jedyne \159r\243d\179o[ENTER]dochod\243w. W ten spos\243b mieli\156my za co je\156\230. Brat[ENTER]zawsze du\191o pracowa\179, abym nie musia\179a g\179odowa\230.[ENTER]A teraz nie \191yje. I to przeze mnie... "
gameforge.subquest_23._380_say = "Dzi\234kuj\234, \191e przynios\179e\156 mi ten naszyjnik. Teraz[ENTER]wiem co mu si\234 przytrafi\179o. Gdyby nie twoja[ENTER]pomoc, nigdy bym si\234 nie dowiedzia\179a co si\234[ENTER]sta\179o. "
gameforge.subquest_23._390_say = "Zaopiekuj\234 si\234 wisiorem mojego brata, sam[ENTER]naszyjnik prosz\234 zachowaj jako moje[ENTER]podzi\234kowania. Z pewno\156ci\185 Ci pomo\191e.[ENTER][ENTER]Dzi\234kuj\234 za twoj\185 pomoc.[ENTER]Teraz na pewno jest ju\191 w niebie, nie uwa\191asz? "
gameforge.subquest_23._400_sayReward = "Otrzymujesz 600.000 Punkt\243w Do\156wiadczenia.[ENTER]Otrzymujesz 35.000 Yang. "
gameforge.subquest_23._40_say = "Martwi\234 si\234 o niego, nie ma \191adnego kontaktu ze[ENTER]mn\185. Przepraszam, ale czy m\243g\179by\156 ponownie[ENTER]poszuka\230 mojego brata? Mo\191e Yu-Hwan co\156 wie.... "
gameforge.subquest_23._50_select = "Odrzu\230. "
gameforge.subquest_23._60_say = "Chcesz zrezygnowa\230? "
gameforge.subquest_23._70_say = "Oh...[ENTER]Poczekam tutaj... mo\191e p\243\159niej? Prosz\234? "
gameforge.subquest_23._80_say = "Nie mam czasu![ENTER]\175ycz\234 Twojemu bratu du\191o szcz\234\156cia. "
gameforge.subquest_23._90_say = "Pomoc smutnej dziewczynie to szlachetny czyn.[ENTER]Dodatkowo, nie b\234d\234 si\234 musia\179 bardzo napracowa\230.[ENTER]W takim razie w drog\234! "
