gameforge.subquest_24._10_targetVid = "Ciastka Ry\191owe Yu-Rang "
gameforge.subquest_24._110_say = "Je\156li znajdziesz p\243\159niej czas, prosz\234 wpadnij[ENTER]ponownie. Nie wiem jak mamy przetrwa\230 bez[ENTER]sprzeda\191y Ciastek Ry\191owych. "
gameforge.subquest_24._120_say = "Zawsze wszystko kr\234ci si\234 wok\243\179 bogatych ludzi,[ENTER]kt\243rzy marnuj\185 Yang jakby by\179a to woda. A my nie[ENTER]wiemy, co mamy postawi\230 na st\243\179! Precz st\185d! "
gameforge.subquest_24._130_say = "Dzi\234kuj\234. Jeste\156 bardzo mi\179y.[ENTER]B\234d\234 czeka\230 na tw\243j powr\243t. "
gameforge.subquest_24._140_sendLetter = "Ukradzione ciastko ry\191owe "
gameforge.subquest_24._150_say = "Odzyskaj Ciastka Ry\191owe Yu-Rang od Paj\185k\243w na[ENTER]Pustyni. Je\156li si\234 nie po\156pieszysz, Paj\185ki zd\185\191\185[ENTER]je zje\156\230 lub po prostu wyschn\185 na s\179o\241cu. Prosz\234,[ENTER]po\156piesz si\234! "
gameforge.subquest_24._160_sayReward = "Zabij M\179ode Paj\185ki w pustyni Yongbi. "
gameforge.subquest_24._170_npcChat = "Co si\234 tyczy Twojego Ciastka Ry\191owego... "
gameforge.subquest_24._180_say = "Co si\234 sta\179o? Czy paj\185ki zjad\179y Ciastko Ry\191owe? O[ENTER]nie! Czy mo\191e wysch\179o? Prosz\234, nie m\243w mi, \191e[ENTER]wszystko stracone! "
gameforge.subquest_24._190_select = "Nie, wszystko jest w ok. "
gameforge.subquest_24._200_select = "Poddaj\234 si\234. "
gameforge.subquest_24._20_npcChat = "Twoje skradzione Ciastko Ry\191owe... "
gameforge.subquest_24._210_say = "Mo\191e jednak si\234 tym zajmiesz? Te Ciastko Ry\191owe[ENTER]jest dla mnie bardzo wa\191ne. Prosz\234 Ci\234.[ENTER][ENTER]Chcesz zrezygnowa\230 z zadania, znale\159\230 Ciastko[ENTER]Ry\191owe Yu-Rang w pustyni? "
gameforge.subquest_24._220_select = "Spr\243buj\234 ponownie. "
gameforge.subquest_24._230_select = "Przykro mi, to za trudne. "
gameforge.subquest_24._240_say = "Nie mog\234 w to uwierzy\230. I kto nam teraz pomo\191e? "
gameforge.subquest_24._250_say = "No dalej! Prosz\234, pom\243\191! "
gameforge.subquest_24._260_say = "B\234dziesz zatem szuka\179 dalej? Dzi\234kuj\234![ENTER]Prosz\234 znajd\159 Ciastko Ry\191owe tak szybko jak to[ENTER]mo\191liwe! "
gameforge.subquest_24._270_say = "Nie, jest za p\243\159no. Nawet gdyby\156 je odnalaz\179, na[ENTER]pewno wszystkie Ciastka ju\191 wysch\179y i nie nadaj\185[ENTER]si\234 do sprzeda\191y... "
gameforge.subquest_24._280_say = "Patrzysz na ziemi\234 i widzisz zostawione przez[ENTER]Paj\185ki Ciastka Ry\191owe. Za p\243\159no. Zd\185\191y\179y[ENTER]wyschn\185\230. "
gameforge.subquest_24._290_sayReward = "Zmarnowa\179e\156 zbyt du\191o czasu, Ciastka zd\185\191y\179y ju\191[ENTER]wyschn\185\230. Zadanie zako\241czone niepowodzeniem. "
gameforge.subquest_24._300_sendLetter = "Wr\243\230 do Yu-Rang "
gameforge.subquest_24._30_say = "Cze\156\230, jak si\234 ma twoja mama? "
gameforge.subquest_24._310_targetVid = "Wr\243\230 do Yu-Rang "
gameforge.subquest_24._320_say = "Zd\185\191y\179e\156 uratowa\230 Ciastko Ry\191owe Yu-Rang przed[ENTER]paj\185kami. Zanie\156 jej je. "
gameforge.subquest_24._330_npcChat = "Masz szcz\234\156cie. Oto Twoje Ciastko Ry\191owe. "
gameforge.subquest_24._340_say = "Jeste\156 naprawd\234 \156wietny. Nie wiem co[ENTER]powiedzie\230... Teraz mog\234 je jutro sprzeda\230 na[ENTER]rynku! Wielkie dzi\234ki! "
gameforge.subquest_24._350_sayReward = "Otrzymujesz 900.000 Punkt\243w Do\156wiadczenia. "
gameforge.subquest_24._360_sayReward = "Otrzyma\179e\156 25.000 Yang. "
gameforge.subquest_24._40_say = "Och, ma si\234 lepiej. Dzi\234kuj\234, \191e pytasz. "
gameforge.subquest_24._50_say = "Wygl\185dasz, jakby\156 mia\179a k\179opoty. Co si\234 dzieje? "
gameforge.subquest_24._60_say = "Sprzedaj\234 tutaj codziennie Ciastka Ry\191owe, ale[ENTER]dzi\156 wydarzy\179o si\234 co\156 strasznego. Pojawi\179y si\234[ENTER]ogromne paj\185ki i ukrad\179y mi Ciastko. Bardzo si\234[ENTER]ba\179am i nie broni\179am si\234. Teraz ju\191 nie mam[ENTER]Ciastka Ry\191owego na sprzeda\191. I jak ja mam teraz[ENTER]prze\191y\230? Moja rodzina nie ma innych dochod\243w... "
gameforge.subquest_24._70_select = "Znajd\234 je dla Ciebie. "
gameforge.subquest_24._80_select = "Przykro mi, nie mam czasu. "
gameforge.subquest_24._90_sayTitle = "Pytanie: "
gameforge.subquest_25 = {}
gameforge.subquest_25._100_npcChat = "Czym mog\234 sprawi\230 Ci przyjemno\156\230? "
gameforge.subquest_25._10_targetVid = "Huahn-So "
gameforge.subquest_25._110_say = "C\243\191, od kiedy straci\179am m\234\191a na wojnie, czuj\234 si\234[ENTER]bardzo samotna. Co mog\179oby sprawi\230, \191e poczuj\234[ENTER]si\234 lepiej? M\243j m\185\191 zawsze przynosi\179 mi pi\234kne[ENTER]Kwiaty. "
gameforge.subquest_25._120_say = "By\179y to Kwiaty rosn\185ce daleko od naszej wioski.[ENTER]Mimo, \191e by\179o to niebezpieczne, przynosi\179 je dla[ENTER]mnie. Nie widz\234 ju\191 wi\234cej tych Kwiat\243w, teraz[ENTER]m\243j m\185\191 nie \191yje. C\243\191, takie dni sprawiaj\185, \191e[ENTER]bardzo za nim t\234skni\234. Ekhm, co ja powiedzia\179am?[ENTER]To nie by\179o potrzebne... Prosz\234, po prostu[ENTER]zapomnij o tym co powiedzia\179am. "
gameforge.subquest_25._130_qSetTitle = "Powr\243t do Huahn-So "
gameforge.subquest_25._140_makequestbutton = "Powr\243t do Huahn-So "
gameforge.subquest_25._150_targetVid = "Huahn-So "
gameforge.subquest_25._160_say = "Ariyoung t\234skni za kwiatami, kt\243re przynosi\179 jej[ENTER]zawsze m\185\191. Udaj si\234 do Huahn-So i powiedz mu o[ENTER]tym. "
gameforge.subquest_25._170_npcChat = "Prezent dla Ariyoung... "
gameforge.subquest_25._180_say = "Wi\234c, co ona lubi? Nic jej o mnie nie[ENTER]powiedzia\179e\156? Hm, lubi Kwiaty, kt\243re m\185\191 zawsze[ENTER]jej przynosi\179? To jest raczej daleko od wioski i[ENTER]nie \179atwo jest je zdoby\230. Przynajmniej nie \179atwo[ENTER]dla mnie... Mog\185 tam przecie\191 by\230 dzikie[ENTER]zwierz\234ta! "
gameforge.subquest_25._190_say = "Hm... a mo\191e mi pomo\191esz? Mo\191e zebra\179by\156 dla mnie[ENTER]te Kwiaty? To b\234dzie przys\179uga dla nas obu. Co[ENTER]powiesz na taki uk\179ad? Oj daj spok\243j, nie widzisz[ENTER]jak bardzo chc\234 zdoby\230 jej mi\179o\156\230?[ENTER]Wynagrodz\234 Ci\234 za to du\191\185 ilo\156ci\185 Yang. "
gameforge.subquest_25._200_select = "Odrzu\230 "
gameforge.subquest_25._20_npcChat = "Och moja kochana Ariyoung "
gameforge.subquest_25._210_say = "Czy chcesz na zawsze zrezygnowa\230 z misji? "
gameforge.subquest_25._220_say = "Cholera. Jak ja mam zdoby\230 Kwiaty dla niej?[ENTER]Prosz\234, wr\243\230, gdy zmienisz zdanie. "
gameforge.subquest_25._230_say = "Czy Ty nigdy nie by\179e\156 zakochany? Nie masz[ENTER]poj\234cia co czuj\234 do Ariyoung? Och Ariyoung... "
gameforge.subquest_25._240_say = "Wielkie dzi\234ki! Prosz\234, przynie\156 mi te Kwiaty. "
gameforge.subquest_25._250_qSetTitle = "Zdob\185d\159 Kwiaty. "
gameforge.subquest_25._260_targetVid = "Kwiaty "
gameforge.subquest_25._270_sayTitle = "Kwiaty dla Ariyoung "
gameforge.subquest_25._280_say = "Aby u\179atwi\230 Huahn-So wyznanie tego co czuje do[ENTER]Ariyoung, musisz zdoby\230 dla niego wyj\185tkowe[ENTER]Kwiaty. Znajdziesz je w rogu mapy w pierwszej[ENTER]wiosce. "
gameforge.subquest_25._290_npcChat = "Nie znalaz\179em Kwiat\243w. "
gameforge.subquest_25._300_say = "Hm cholera... Chcia\179em jej powiedzie\230 co do niej[ENTER]czuj\234. Jest tak ci\234\191ko zdoby\230 jej mi\179o\156\230.[ENTER]Moja ukochana Ariyoung... "
gameforge.subquest_25._30_say = "Uhm... znasz mo\191e pann\234 Ariyoung? Wi\234c, ona[ENTER]jest... by\179a m\234\191atk\185, tak wi\234c nie jest ju\191[ENTER]pann\185. Ale to jest ma\179o wa\191ne, teraz jest wdow\185.[ENTER]Wi\234c... zakocha\179em si\234 w niej dawno temu, ale ona[ENTER]wysz\179a za m\185\191, gdy by\179a bardzo m\179oda...[ENTER]Zgaduj\234, \191e po prostu mia\179em pecha... "
gameforge.subquest_25._310_select = "Spr\243buj\234 ponownie. "
gameforge.subquest_25._320_select = "Rezygnuj\234. "
gameforge.subquest_25._330_say = "Czy chcesz zrezygnowa\230 z zadania? "
gameforge.subquest_25._340_say = "Ech...[ENTER]Je\156li zmienisz zdanie, b\234d\234 tu na Ciebie czeka\230.[ENTER]Prosz\234, pom\243\191 mi... "
gameforge.subquest_25._350_say = "Czy moja mi\179o\156\230 tak si\234 zako\241czy?[ENTER]Ariyoung... "
gameforge.subquest_25._360_say = "Dzi\234kuj\234 Ci bardzo. Musisz by\230 tak\191e zakochany.[ENTER]Skoro wiesz co ja czuj\234 do Ariyoung... "
gameforge.subquest_25._370_npcChat = "Ulubione Kwiaty Ariyoung "
gameforge.subquest_25._380_say = "Te Kwiaty wygl\185daj\185 tak, jak opisywa\179a Ariyoung.[ENTER]Wezm\234 kilka z nich. "
gameforge.subquest_25._390_qSetTitle = "Powr\243t do Huahn-So "
gameforge.subquest_25._400_say = "Znalaz\179em w ko\241cu ulubione Kwiaty Ariyoung i[ENTER]zerwa\179em kilka z nich. Musz\234 zanie\156\230 je do[ENTER]Huahn-So, by m\243g\179 Ariyoung wyzna\230 swoj\185 mi\179o\156\230. "
gameforge.subquest_25._40_say = "Teraz, jej m\185\191 zgin\185\179 na wojnie i jest raczej[ENTER]m\179od\185 wdow\185. Pomimo, \191e by\179a m\234\191atk\185... hm...[ENTER]chcia\179bym \191eby wiedzia\179a jak ja si\234 czuj\234. Wiem,[ENTER]\191e to dziwna pro\156ba, ale czy m\243g\179by\156 mi pom\243c? "
gameforge.subquest_25._410_npcChat = "Oto ulubione Kwiaty Ariyoung. "
gameforge.subquest_25._420_say = "Och, to s\185 te Kwiaty? Teraz mog\234 jej powiedzie\230[ENTER]co do niej czuj\234! My\156lisz, \191e to nadal za[ENTER]wcze\156nie? To ju\191 niewa\191ne. Musz\234 jej to[ENTER]powiedzie\230, w przeciwnym razie zwariuj\234. Dzi\234kuj\234[ENTER]Ci bardzo. Oto Twoja nagroda! "
gameforge.subquest_25._430_sayReward = "Otrzyma\179e\156 400.000 Punkt\243w Do\156wiadczenia. "
gameforge.subquest_25._440_sayReward = "Otrzyma\179e\156 12.000 Yang. "
gameforge.subquest_25._50_say = "My\156lisz, \191e lubi przystojnych m\234\191czyzn? I pi\234kne[ENTER]ubrania? Najpierw musz\234 wiedzie\230 co ona lubi.[ENTER]Mo\191e wtedy b\234d\234 m\243g\179 z ni\185 porozmawia\230. Mo\191esz[ENTER]si\234 tego dowiedzie\230? Ale nie m\243w jej nic o mnie![ENTER]Prosz\234 Ci\234, na pewno Ci\234 za to wynagrodz\234. "
gameforge.subquest_25._60_qSetTitle = "Udaj si\234 do Ariyoung "
gameforge.subquest_25._70_makequestbutton = "Udaj si\234 do Ariyoung "
gameforge.subquest_25._80_targetVid = "Id\159 do Ariyoung "
gameforge.subquest_25._90_say = "Huahn-So kocha owdowia\179\185 Ariyoung.[ENTER]Aby pom\243c Huahn-So w powiedzeniu Ariyoung tego co[ENTER]do niej czuje, musisz dowiedzie\230 si\234 co ona lubi.[ENTER]Wi\234c, zapytaj j\185 o to. Tylko uwa\191aj, \191eby za du\191o[ENTER]jej nie powiedzie\230. "
