gameforge.subquest_26._110_say = "Wspaniale! Wiedzia\179em, \191e si\234 tym zainteresujesz.[ENTER]Gdyby\156 zdoby\179 troch\234, to wr\243\230 do mnie i podziel[ENTER]si\234 ze mn\185! "
