gameforge.subquest_26._130_targetVid = "Ok-gu "
gameforge.subquest_26._140_sayTitle = "Id\159 do Octavio "
gameforge.subquest_26._150_say = "Dozorca da\179 Ci przydatn\185 wskaz\243wk\234: Zupa z \175abich[ENTER]Udek jest wspania\179a na bezsilno\156\230 i zm\234czenie.[ENTER]Spytaj si\234 Octavio, przy m\243g\179by przyrz\185dzi\230 t\234[ENTER]zup\234. "
gameforge.subquest_26._160_npcChat = "Zupa z \175abich Udek? "
gameforge.subquest_26._170_say = "Zupa z \175abich Udek... Tak, robi\179em tak\185 w[ENTER]przesz\179o\156ci. Ale teraz ju\191 jej nie robi\234... Dawno[ENTER]temu nie obawia\179em si\234 dzikich zwierz\185t i[ENTER]potwor\243w, wi\234c mog\179em bez problemu zdoby\230 Tylne[ENTER]Nogi \175aby. "
gameforge.subquest_26._180_say = "Ale teraz... Jestem ju\191 stary i zm\234czony.[ENTER]Dzi\234ki tej zupie, m\243g\179bym odzyska\230 energi\234, ale[ENTER]\191aby nie s\185 \179atwym celem. Je\156li dostarczysz mi[ENTER]\175abie Udka, przygotuj\234 Ci najlepsz\185 zup\234 na[ENTER]\156wiecie. "
gameforge.subquest_26._190_select = "Pewnie, zrobi\234 to. "
gameforge.subquest_26._200_select = "Nie, nie mog\234. "
gameforge.subquest_26._20_npcChat = "Jak si\234 masz? "
gameforge.subquest_26._210_say = "Czy chcesz zrezygnowa\230 z zadania? "
gameforge.subquest_26._220_say = "Jeste\156 zaj\234ty? Wr\243\230 gdy zmienisz zdanie. "
gameforge.subquest_26._230_say = "Moja zupa nie jest dobrze znana. Gdyby\156 j\185 zna\179,[ENTER]na pewno by\156 mi pom\243g\179. Ech, \191egnaj. "
gameforge.subquest_26._240_say = "Wi\234c \156piesz si\234. Przygotuj\234 wszystko na Zup\234 z[ENTER]Tylnych N\243g \175ab. "
gameforge.subquest_26._250_sendLetter = "Otrzyma\179e\156 \175abie Udka "
gameforge.subquest_26._260_targetVid = "Octavio: "
gameforge.subquest_26._270_sendLetter = "Zdob\185d\159 \175abie Udka "
gameforge.subquest_26._280_say = "Otrzyma\179e\156 ogromne \175abie Udko.[ENTER]Wr\243\230 do Octavio. "
gameforge.subquest_26._290_sayTitle = "Zabij Drzewnego \175abiego Przyw\243dce "
gameforge.subquest_26._300_say = "Octavio potrzebuje \175abie Udka, aby sporz\185dzi\230[ENTER]zup\234. Mo\191esz je zdoby\230 poluj\185c na Drzewnego[ENTER]\175abiego Przyw\243dce w \140wi\185tyni Hwang. "
gameforge.subquest_26._30_sayTitle = "Dozorca: "
