gameforge.subquest_26._320_say = "o jest? Gdy by\179em w twoim wieku dostarcza\179em 10[ENTER]\175abich Udek dziennie. "
gameforge.subquest_26._330_select = "Spr\243buj ponownie "
gameforge.subquest_26._340_say = "Jeste\156 zm\234czony?[ENTER]Mo\191e zrobisz sobie przerw\234 i spr\243bujesz p\243\159niej? "
gameforge.subquest_26._350_say = "Bardzo by mi si\234 przyda\179a Zupa z \175abich Udek. Nic[ENTER]z tego jednak najwidoczniej nie b\234dzie. Szkoda.[ENTER]Na razie! "
gameforge.subquest_26._360_say = "To nie st\243j tutaj jak ko\179ek tylko ruszaj! Woda[ENTER]ju\191 si\234 gotuje i wszystko jest gotowe! "
gameforge.subquest_26._370_targetVid = "Id\159 do Octavio "
gameforge.subquest_26._380_say = "No, to jest \175abie Udko \191e hej! Za moich czas\243w[ENTER]by\179y one nieco mniejsze. Ale te tutaj te\191 zapewne[ENTER]smakuje. Poczekaj chwil\234... To ju\191 nie\159le[ENTER]pachnie. Jeszcze szczypta soli... Ha! Oto Twoja[ENTER]porcja. Ha ha ha, teraz mam znowu wystarczaj\185co[ENTER]du\191o si\179y na ca\179y tydzie\241 pracy! "
gameforge.subquest_26._390_say = "Upewnij si\234, \191e nikt nie dowie o tej si\234 o[ENTER]istnieniu tej Zupy. Mam tu na my\156li szczeg\243lnie[ENTER]Dozorc\234... Bardzo rzadko robi\234 t\185 Zup\234. Je\156li nie[ENTER]zachowasz tego w tajemnicy, to wszyscy b\234d\185[ENTER]chcieli jej spr\243bowa\230. "
gameforge.subquest_26._400_sayReward = "Otrzymujesz 5.000.000 Punkt\243w Do\156wiadczenia. "
gameforge.subquest_26._40_say = "Ostatnio nie czuj\234 si\234 najlepiej. Moje cia\179o nie[ENTER]jest ju\191 tym, czym kiedy\156 by\179o. Gdy by\179em m\179ody[ENTER]mog\179em pracowa\230 do p\243\159na w nocy i to codziennie.[ENTER]A przy tym jeszcze pi\230 alkohol. Ale teraz ledwo[ENTER]co potrafi\234 wsta\230 rano z \179\243\191ka. Przyda\179aby mi si\234[ENTER]spora porcja Zupy z \175abich Udek, aby znowu mie\230[ENTER]wystarczaj\185co energii. "
gameforge.subquest_26._410_sayReward = "Otrzyma\179e\156 50.000 Yang. "
gameforge.subquest_26._50_say = "Nie wiesz co to Zupa z \175abich Udek? Gdy wypijesz[ENTER]jedn\185 misk\234 tej zupy, stajesz si\234 od razu bardzo[ENTER]rze\156ki i rozpiera Ci\234 energia. Mo\191esz wtedy[ENTER]przepracowa\230 ca\179y tydzie\241 nie odczuwaj\185c \191adnego[ENTER]zm\234czenia. Octavio zwyk\179 przyrz\185dza\230 t\234 zup\234. Ale[ENTER]z nieznanych mi powod\243w niedawno tego zaniecha\179. "
gameforge.subquest_26._60_select = "P\243jd\234 porozmawia\230 z Octavio "
gameforge.subquest_26._70_select = "Jestem zaj\234ty. "
gameforge.subquest_26._80_say = "Czy chcesz zrezygnowa\230 z zadania? "
gameforge.subquest_26._90_say = "Ok, je\156li teraz jeste\156 zaj\234ty, wpadnij p\243\159niej[ENTER]je\156li chcesz. "
