gameforge.subquest_27._240_say = "Bardzo chcia\179bym przeczyta\230 t\185 Ksi\234g\234. Czy[ENTER]m\243g\179by\156 j\185 dla mnie zdoby\230? Je\156li to zrobisz, dam[ENTER]Ci co\156 w zamian, nawet je\156li musia\179bym sprzeda\230[ENTER]sw\243j dom. "
