gameforge.subquest_27._260_select = "Nie mog\234, przykro mi. "
gameforge.subquest_27._270_say = "Czy chcesz zrezygnowa\230 z zadania? "
gameforge.subquest_27._280_say = "No dalej, nie chcesz mi pom\243c?[ENTER]Je\156li nie teraz, to p\243\159niej. B\234d\234 czeka\179. "
gameforge.subquest_27._290_say = "Naprawd\234 nie chcesz mi pom\243c? Potrzebujesz[ENTER]urlopu. Ta ksi\185\191ka jest dla mnie na prawd\234[ENTER]wa\191na... Co ja mam teraz zrobi\230. Cholera! "
