gameforge.subquest_27._40_say = "Mi\234dzy stronami w tej ksi\185\191ce pulsuje \191ycie! Ca\179a[ENTER]wiedza na wyci\185gni\234cie r\234ki! Wyobra\159 sobie jak[ENTER]marne by\179oby moje \191ycie bez ksi\185\191ek... Problem w[ENTER]tym... \191e moja \191ona tego nie rozumie.[ENTER]Mo\191e m\243g\179by\156 j\185 przekona\230? "
gameforge.subquest_27._410_sayReward = "Otrzyma\179e\156 20.000 Yang. "
gameforge.subquest_27._420_say = "Hej... Jeszcze jej nie zdoby\179e\156? Je\156li[ENTER]podejmujesz si\234 jakiego\156 zadania, to wypada je[ENTER]wykona\230... A teraz, wykonaj zadanie! "
