gameforge.subquest_27._80_npcChat = "Dlaczego jeste\156 taka wzburzona? "
gameforge.subquest_27._90_say = "Wzburzona? Zaraz spal\234 si\234 ze z\179o\156ci! Czy m\243j m\185\191[ENTER]pracuje? Nie. Czy przynosi do domu Yang? Nie.[ENTER]Woli skrywa\230 si\234 po k\185tach i zatapia\230 nos w[ENTER]ksi\234gi! Nies\179ychane! Nic tylko czyta! Ksi\185\191ka[ENTER]przecie\191 nic nie daje, ani ubrania ani chleba! "
