gameforge.subquest_30._200_say = "Czy na pewno chcesz si\234 podda\230? "
gameforge.subquest_30._20_say = "Hej, Ty tam! Tak, o Ciebie chodzi! Nie jeste\156 ju\191[ENTER]amatorem. A dlaczego? Bo powierzy\179em Ci[ENTER]skomplikowane zadania! To wszystko by\179o wy\179\185cznie[ENTER]dla Twojego dobra, he he he. Ale teraz poprosz\234[ENTER]Cie o prawdziw\185 przys\179ug\234. "
