gameforge.subquest_32._160_say = "Zrobienie Nici to dosy\230 prosta sprawa. Jednak[ENTER]wtedy nie b\234d\234 w stanie wykonywa\230 swojej pracy.[ENTER]Dzisiaj \179ata\179am porwane ubrania Ah-Yu i w\179a\156nie[ENTER]chcia\179am je jej zanie\156\230... "
