gameforge.subquest_32._220_sayTitle = "Ariyoung: "
gameforge.subquest_32._230_say = "Gdy wr\243cisz z s\185siedniej wioski, twoje Nici b\234d\185[ENTER]ju\191 gotowe. Pami\234ta\179e\156 o dostarczeniu Ah-Yu jej[ENTER]ubra\241, prawda? Wzi\234\179aby mi to za z\179e... "
