gameforge.subquest_32._270_sayTitle = "Ah-Yu: "
gameforge.subquest_32._280_say = "Ach, wspaniale. Posz\179o to naprawd\234 szybko. O[ENTER]dobr\185 przyja\159\241 trzeba dba\230, prawda? A my cz\234sto[ENTER]sobie nawzajem pomagamy...[ENTER]Dzi\234kuj\234, \191e przynios\179e\156 mi ubrania.[ENTER]Przeka\191 Ariyoung ode mnie pozdrowienia. "
gameforge.subquest_32._290_npcChat = "Potrzebuj\234 Ozdobnego Diamentu. "
gameforge.subquest_32._300_say = "Szukasz Ozdobnego Diamentu? Mog\234 Ci go da\230, je\156li[ENTER]mi troch\234 pomo\191esz. W tym momencie pracuje nad[ENTER]lekiem na b\243l, ale brakuje mi jednego sk\179adnika.[ENTER]Do leku potrzebuj\234 W\185troby Tygrys\243w. S\185 one[ENTER]ci\234\191kie do zdobycia a potrzebuje a\191 100 sztuk. "
gameforge.subquest_32._30_say = "Nam, Domokr\185\191com, nie jest \179atwo podczas wojny.[ENTER]Co prawda wsz\234dzie brakuje towar\243w, ale[ENTER]zapotrzebowanie zmienia si\234 tak szybko, \191e nigdy[ENTER]nie wiem, w co si\234 mam zaopatrzy\230. Nie wspomn\234[ENTER]nawet o d\179ugich przeprawach przez puszcz\234, gdzie[ENTER]na ka\191dym kroku jaki\156 potw\243r czyha na[ENTER]nieostro\191nych w\234drowc\243w. A mo\191e Ty chcia\179by\156[ENTER]zarobi\230 par\234 Yang? Przyda\179aby si\234 mi twoja pomoc. "
gameforge.subquest_32._310_say = "Poza tym potrzebuje jeszcze specjalne zio\179a z[ENTER]uzdrawiaj\185cymi w\179a\156ciwo\156ciami. Je r\243wnie\191[ENTER]zdob\234dziesz od Tygrys\243w, kt\243re lubi\185 si\234 w nich[ENTER]tarza\230, poniewa\191 uwielbiaj\185 ich zapach. W zamian[ENTER]za te Zio\179a Lecznicze i W\185troby Tygrys\243w[ENTER]dostaniesz Ozdobny Diament. "
gameforge.subquest_32._320_say = "Poluj na Tygrysy lub Bia\179e Tygrysy. "
gameforge.subquest_32._330_say = "Co Ty na to? Ubijemy interes? "
gameforge.subquest_32._340_say = "Czy moje zadanie jest dla Ciebie za trudne? Nie[ENTER]wierz\234! Przyjd\159 ponownie, jak zmienisz zdanie. "
gameforge.subquest_32._350_say = "Przeby\179e\156 dla Handlarza taki kawa\179 drogi a teraz[ENTER]si\234 poddajesz? Jak chcesz...[ENTER]Mi\179ego dnia \191ycz\234. "
gameforge.subquest_32._360_say = "Wspaniale. Oboje na tym skorzystamy, prawda?[ENTER]Dzi\234kuj\234 i powodzenia! "
gameforge.subquest_32._370_npcChat = "Otrzymam teraz Ozdobny Diament? "
gameforge.subquest_32._380_say = "Niech no zerkn\234... 100 W\185tr\243b Tygrys\243w i Zio\179a[ENTER]Lecznicze, wszystko si\234 zgadza. Dzi\234kuj\234 Ci[ENTER]bardzo! Prosz\234, zas\179u\191y\179e\156 sobie na ten Ozdobny[ENTER]Diament. Na razie! "
gameforge.subquest_32._390_qSetTitle = "Wr\243\230 do Domokr\185\191cy "
gameforge.subquest_32._400_targetVid = "Wr\243\230 do Domokr\185\191cy "
gameforge.subquest_32._40_say = "Naszyjniki z K\179\243w Orka s\185 obecnie bardzo[ENTER]po\191\185danym towarem. K\179y Ork\243w s\185 du\191e i twarde i[ENTER]doskonale nadaj\185 si\234 na tworzenie najr\243\191niejszych[ENTER]ozd\243b. K\179y Ork\243w Czarodziei s\185 poza tym u\191ywane[ENTER]przez \191o\179nierzy jako talizmany. M\243g\179by\156 je dla[ENTER]mnie zdoby\230? 100 powinno wystarczy\230, na pocz\185tek. "
