gameforge.subquest_32._450_say = "Uda\179o Ci si\234 zdoby\230 wszystkie materia\179y? Poka\191[ENTER]no... Rzeczywi\156cie, wszystko jest. Dzi\234ki twojej[ENTER]pomocy mog\234 poszerzy\230 swoj\185 ofert\234, wspaniale![ENTER]Oto twoja dzia\179ka. Niechaj Ci dobrze pos\179u\191y![ENTER]Do mnie ludzie, do mnie! Dla ka\191dego co\156 dobrego! "
gameforge.subquest_32._460_sayReward = "Otrzyma\179e\156 1.100.000 Punkt\243w Do\156wiadczenia. "
gameforge.subquest_32._470_sayReward = "Otrzyma\179e\156 Z\179ot\185 Bransolet\234, Z\179oty Naszyjnik i[ENTER]Z\179ote Kolczyki. "
gameforge.subquest_32._480_say = "Hmm, przykro mi, ale nadal czego\156 brakuje.[ENTER]Niekompletnych dostaw nie przyjmuj\234. B\234dziesz[ENTER]nadal pr\243bowa\179? "
gameforge.subquest_32._490_say = "Czy chcesz zrezygnowa\230 z zadania? "
gameforge.subquest_32._500_say = "Dzi\234kuj\234, \191e tak \179atwo si\234 nie poddajesz.[ENTER]Szcz\234\156cie sprzyja tym, kt\243rzy si\234 staraj\185! B\234d\234[ENTER]czeka\179 na Ciebie tutaj. "
gameforge.subquest_32._50_say = "Potrzebuj\234 jeszcze Ozdobny Diament oraz Nici.[ENTER]Diament otrzymasz od Handlarki R\243\191no\156ciami, Nici[ENTER]od Ariyoung. Zdobycie tylu r\243\191nych rzeczy nie[ENTER]jest proste, ale sprzeda\191 Naszyjnik\243w jest bardzo[ENTER]op\179acalna, a na Ciebie czeka oczywi\156cie hojna[ENTER]nagroda. Co Ty na to, zainteresowany? "
gameforge.subquest_32._510_say = "Czy\191by te zadanie Ci\234 przerasta\179o? No c\243\191,[ENTER]przynajmniej spr\243bowa\179e\156. Gdybym w przysz\179o\156ci[ENTER]mia\179 dla Ciebie co\156 prostszego, to dam Ci zna\230.[ENTER]Bywaj. "
gameforge.subquest_32._520_say = "Spr\243bujesz ponownie? Dzi\234kuj\234.[ENTER]B\234d\234 na Ciebie czeka\230. "
gameforge.subquest_32._60_say = "Czy chcesz zrezygnowa\230 z zadania? "
gameforge.subquest_32._70_say = "Jeste\156 zaj\234ty? Nie ma sprawy, rozumiem.[ENTER]Ale przyjd\159 prosz\234 ponownie, jak tylko znajdziesz[ENTER]czas. "
gameforge.subquest_32._80_say = "Ach jej, i jak ja mam teraz wykona\230 swoje[ENTER]zlecenia? Na razie! "
gameforge.subquest_32._90_say = "Cudownie. B\234d\234 tu na Ciebie czeka\230. "
