gameforge.subquest_33._175_npcChat = "Mam wszystkie cz\234\156ci mapy. "
gameforge.subquest_33._180_say = "Och! Fantastycznie! Wreszcie mam wszystkie[ENTER]cz\234\156ci. Nawet o tym nie \156ni\179em... Teraz po\179\185cz\234[ENTER]cz\234\156ci w jedn\185 ca\179o\156\230...dobrze... "
gameforge.subquest_33._190_say = "Hmm...dziwne. Mapa pokazuje, \191e skarb jest ukryty[ENTER]przy ska\179ach, w pobli\191u Staruszka. Jako\156 nie chce[ENTER]mi si\234 w to wierzy\230. Hmm, to by by\179o za proste.[ENTER]Wydaje mi si\234, \191e to jaki\156 dowcip. Chcesz[ENTER]sprawdzi\230, czy mam spali\230 map\234? "
gameforge.subquest_33._200_select = "Sprawdz\234. "
gameforge.subquest_33._20_npcChat = "Z powodu Mapy Skarb\243w... "
gameforge.subquest_33._210_select = "Spal j\185. "
gameforge.subquest_33._220_say = "Jeste\156 pewny, \191e nie potrzebujesz mapy? "
gameforge.subquest_33._230_say = "Tak, to bardzo g\179upia historyjka! Przykro mi, \191e[ENTER]Ci\234 w to wpl\185ta\179em i wys\179a\179em na poszukiwanie[ENTER]cz\234\156ci mapy. Spal\234 wszystko, aby nikt inny nie[ENTER]da\179 si\234 nabra\230. To wszystko. \175egnaj. "
gameforge.subquest_33._240_say = "Dlaczego si\234 wahasz? Ju\191 zebra\179e\156 cz\234\156ci Mapy,[ENTER]wi\234c id\159 i sprawd\159. Prosz\234, zabierze ze sob\185[ENTER]Map\234. "
gameforge.subquest_33._250_say = "Jak chcesz. To b\234dzie wielka niespodzianka, je\156li[ENTER]co\156 znajdziesz, ale i tak \191ycz\234 Ci powodzenia![ENTER]Nie zapomnij Mapy! "
gameforge.subquest_33._260_say = "Mapa zosta\179a podzielona na cztery cz\234\156ci.[ENTER]Potrzebujemy wszystkie cz\234\156ci, by j\185 z\179o\191y\230 w[ENTER]ca\179o\156\230. "
gameforge.subquest_33._270_select = "Spr\243buj ponownie. "
gameforge.subquest_33._280_say = "Poddajesz si\234? Och, wi\234c tak musi by\230. \175egnaj. "
gameforge.subquest_33._290_say = "Wiedzia\179em, \191e si\234 nie poddasz.[ENTER]Wierz\234 w Ciebie!  "
gameforge.subquest_33._300_targetVid = "Ska\179a przy Staruszku "
gameforge.subquest_33._30_say = "Witaj! Znalaz\179em dziwne informacje o tym, \191e[ENTER]gdzie\156 w naszej wiosce mog\185 by\230 ukryte Mapy[ENTER]Skarb\243w. Czy znasz bog\243w chroni\185cych miasto? B\243g[ENTER]Pies, B\243g Tygrys, B\243g Nied\159wied\159 i B\243g \140winia. "
gameforge.subquest_33._310_sayTitle = "Poszukiwanie Skarbu... "
gameforge.subquest_33._320_say = "Hmm, pod kamieniem blisko Staruszka...[ENTER]Nie mam poj\234cia. Powinienem najpierw zapyta\230[ENTER]Staruszka. Dlaczego to jest tak daleko? Cholera! "
gameforge.subquest_33._330_sayTitle = "Staruszek: "
gameforge.subquest_33._340_say = "Czego szukasz? Skarbu? Mo\191esz d\179ugo szuka\230! Poka\191[ENTER]map\234... Hm, to musi by\230 tam. Powodzenia,[ENTER]hahaha... "
gameforge.subquest_33._350_say = "To musi by\230 to miejsce. Cholera, ziemia w tym[ENTER]miejscu jest wyj\185tkowo twarda. Hmm...[ENTER][ENTER]Hey, widz\234 jak\185\156 Skrzynk\234! "
gameforge.subquest_33._360_sendLetter = "Skarb naprawd\234 istnieje! "
gameforge.subquest_33._370_sayTitle = "Powr\243t do Soon "
gameforge.subquest_33._380_say = "Kopa\179e\156 w miejscu oznaczonym na Mapie Bog\243w[ENTER]Zwierz\185t i rzeczywi\156cie znalaz\179e\156 Szkatu\179\234! Udaj[ENTER]si\234 do Soon i opowiedz mu o tym nieoczekiwanym[ENTER]sukcesie. "
gameforge.subquest_33._390_npcChat = "Znalaz\179em Skarb! "
gameforge.subquest_33._400_say = "Och! To Ci niespodzianka! Poka\191... Niesamowite.[ENTER]Dok\179adnie tak by\179a opisywana Szkatu\179ka w starych[ENTER]ksi\234gach. Teraz musz\234 jeszcze dowiedzie\230 si\234, jak[ENTER]j\185 otworzy\230. Ale to ju\191 nie Twoje zmartwienie.[ENTER]Dzi\234ki! Prosz\234, we\159 to na znak mojej wdzi\234czno\156ci. "
gameforge.subquest_33._40_say = "Cztery boskie stworzenia podzieli\179y Map\234 na[ENTER]cztery cz\234\156ci i teraz ich strzeg\185. To naprawd\234[ENTER]stara historia, wi\234c nie jestem pewien czy to[ENTER]prawda... Co ty na to, \191eby poszuka\230 jakiego\156[ENTER]dowodu? Prosz\234. Nie wytrzymam tej niepewno\156ci...[ENTER]Pom\243\191 mi! "
gameforge.subquest_33._410_sayReward = "Otrzyma\179e\156 1.400.000 Punkt\243w Do\156wiadczenia. "
gameforge.subquest_33._420_sayReward = "Otrzyma\179e\156 25.000 Yang. "
gameforge.subquest_33._430_sayReward = "Otrzyma\179e\156 Upiorn\185 Mask\234+1. "
gameforge.subquest_33._440_sayReward = "Otrzyma\179e\156 Zamkowy He\179m+1. "
gameforge.subquest_33._450_sayReward = "Otrzyma\179e\156 Stalow\185 Mask\234+1. "
gameforge.subquest_33._460_sayReward = "Otrzyma\179e\156 \140wietlist\185 Czapk\234+1. "
gameforge.subquest_33._470_say = "No i gdzie on jest? Stroisz sobie ze mnie \191arty?[ENTER]Jeszcze go nie znalaz\179e\156, prawda? "
gameforge.subquest_33._50_say = "Niezainteresowany starymi Mapami Skarb\243w? Jeste\156[ENTER]jaki\156 dziwny... Nadal b\234d\234 szuka\179 wskaz\243wek w[ENTER]ksi\234gach. Wr\243\230 gdy zmienisz zdanie. "
gameforge.subquest_33._60_say = "Nie lubisz takich wyzwa\241? Jak ja teraz zdob\234d\234[ENTER]cz\234\156ci tej tajemniczej Mapy?[ENTER][ENTER]Dobrze wi\234c... do widzenia. "
gameforge.subquest_33._70_say = "Jeste\156 prawdziwym przyjacielem. Ufam, \191e j\185[ENTER]znajdziesz. "
gameforge.subquest_33._80_sendLetter = "Mapa Skarb\243w. "
