gameforge.subquest_34._100_say = "Kapitan nie mo\191e sobie poradzi\230 z wojownikami[ENTER]Czarnego Wiatru. Zabij ich Genera\179\243w: Jak-To,[ENTER]To-Su oraz Gu-Ryung. Mo\191e wtedy w ko\241cu si\234[ENTER]uspokoj\185. "
gameforge.subquest_34._10_npcChat = "I co z Gangiem Czarnego Wiatru? "
gameforge.subquest_34._110_say = "Zabi\179e\156 genera\179\243w! "
gameforge.subquest_34._120_select = "Spr\243buj ponownie... "
gameforge.subquest_34._130_say = "Czy chcesz zrezygnowa\230 z zadania? "
gameforge.subquest_34._140_say = "Nie jest \179atwo wygra\230, zw\179aszcza z genera\179ami.[ENTER]Spr\243buj ponownie. "
gameforge.subquest_34._150_say = "Jak ju\191 m\243wi\179em, Czarny Wiatr jest silny. \175egnaj. "
gameforge.subquest_34._160_say = "Jeste\156 bardzo odwa\191ny.[ENTER]My\156l\234, \191e mo\191esz pokona\230 ten Gang. "
gameforge.subquest_34._170_targetVid = "Zdaj raport Kapitanowi "
gameforge.subquest_34._180_say = "Wr\243\230 do Kapitana i poinformuj go o \156mierci[ENTER]genera\179\243w Gangu Czarnego Wiatru. "
gameforge.subquest_34._185_npcChat = "Zabi\179em Genera\179\243w! "
gameforge.subquest_34._190_say = "Pokona\179e\156 genera\179\243w. Inni b\234d\185 \179atwi do[ENTER]przezwyci\234\191enia bez dow\243dztwa. Mieli\156my prawdziwy[ENTER]zawr\243t g\179owy z ich powodu, ale dzi\234ki tobie ju\191[ENTER]po wszystkim. Oto ma\179a nagroda. Mam nadziej\234, \191e[ENTER]jeszcze si\234 zobaczymy. "
gameforge.subquest_34._200_sayReward = "Otrzyma\179e\156 1.000.000 Punkt\243w Do\156wiadczenia. "
gameforge.subquest_34._20_sayTitle = "Kapitan "
gameforge.subquest_34._210_sayReward = "Otrzyma\179e\156 Pier\156cie\241 J\234zyka. "
gameforge.subquest_34._30_say = "Mimo, \191e pokona\179e\156 kilku cz\179onk\243w Gangu Czarnego[ENTER]Wiatru, nie poddaj\185 si\234. Zamiast siedzie\230[ENTER]spokojnie, staj\185 si\234 dzik\185 hord\185. Je\156li chcemy[ENTER]ich pokona\230, musimy zabi\230 genera\179\243w Gangu. "
gameforge.subquest_34._40_say = "Jak tylko genera\179owie zostan\185 pokonani, inni[ENTER]szybko polegn\185. B\234dzie to ci\234\191ka robota, ale[ENTER]musimy zwyci\234\191y\230 przeciwko Gangu Czarnego Wiatru.[ENTER]Imiona genera\179\243w to: Jak-To, To-Su i Gu-Ryung.[ENTER]Kiedy ich zabijemy, Gang nie sprawi nam wi\234cej[ENTER]problem\243w. Powodzenia i udanych \179ow\243w. "
gameforge.subquest_34._50_say = "Czy chcesz zrezygnowa\230 z zadania? "
gameforge.subquest_34._60_say = "Kiedy b\234dziesz gotowy, przyjd\159 do mnie ponownie.[ENTER]Nie ma wielu tak silnych os\243b jak ty. "
gameforge.subquest_34._70_say = "Tak po prostu?! Jak my ich teraz pokonamy? "
gameforge.subquest_34._80_say = "Wiedzia\179em, \191e na Tobie mog\234 polega\230! Jak tylko[ENTER]Genera\179owie zostan\185 zabici, inni szybko si\234[ENTER]poddadz\185. Powodzenia! "
