gameforge.subquest_36._120_sayTitle = "Siano dla stajni "
gameforge.subquest_36._130_say = "W stajniach brakuje pokarmu. Zdob\185d\159 10 balot\243w[ENTER]siana i zanie\156 je Stajennemu, zanim konie[ENTER]pozdychaj\185 z g\179odu![ENTER]Siano mo\191esz zdoby\230 podczas polowania. "
gameforge.subquest_36._140_npcChat = "Potrzebujesz Siana? "
gameforge.subquest_36._150_say = "Przysy\179a Ci\234 zapewne Yonah?[ENTER]Du\191o o Tobie s\179ysza\179em.[ENTER]Ach, nasze konie cierpi\185 z powodu niedo\191ywienia.[ENTER]Musimy zadba\230, aby prze\191y\179y. Pom\243\191 mi i zdob\185d\159[ENTER]Siano dla koni! "
gameforge.subquest_36._160_say = "Obietnica to obietnica. Poza tym chcia\179bym w[ENTER]przysz\179o\156ci spr\243bowa\230 jazdy konno. Koniecznie[ENTER]musz\234 znale\159\230 Siano! "
gameforge.subquest_36._170_say = "Bardzo mi przykro. Staram si\234, ale po prostu[ENTER]nigdzie nie ma Siana. "
gameforge.subquest_36._180_say = "Poczekam i mam nadzieje, \191e Ci si\234 uda.[ENTER]Nie jest fajnie zwala\230 na Ciebie moj\185 prac\234.[ENTER]Ale, czy m\243g\179by\156 spr\243bowa\230 jeszcze raz?[ENTER][ENTER]Znam pewn\185 osob\234 w innym Kr\243lestwie. Jest bardzo[ENTER]silny. Jak mi pomo\191esz, poprosz\234 go aby pom\243g\179[ENTER]tobie. "
gameforge.subquest_36._190_select = "Kontynuuj poszukiwania "
gameforge.subquest_36._200_say = "Oczywi\156cie, pomog\234 Ci. Nie mam tyle si\179y. "
gameforge.subquest_36._20_npcChat = "Konie maj\185 k\179opoty. "
gameforge.subquest_36._210_say = "Nie mam tyle energii. Chcia\179bym pom\243c, ale nie[ENTER]mog\234. Nie jestem do\156\230 silny. "
gameforge.subquest_36._220_npcChat = "Mam Siano dla koni. "
gameforge.subquest_36._230_say = "Zdoby\179e\156 Siano? Och, dzi\234kuj\234.[ENTER]Brakowa\179o pokarmu dla koni i powiedzia\179em o tym[ENTER]Yonah. Jest on moim dobrym przyjacielem. Mia\179em[ENTER]nadziej\234, \191e poprosi kogo\156 o pomoc. Nie my\156la\179em[ENTER]jednak, \191e pomoc ta nadejdzie tak pr\234dko. Sp\243jrz[ENTER]tylko z jakim apetytem konie jedz\185! "
gameforge.subquest_36._240_sayReward = "Otrzyma\179e\156 1.800.000 Punkt\243w Do\156wiadczenia. "
gameforge.subquest_36._250_sendLetter = "Powr\243t do Yonah "
gameforge.subquest_36._260_sayTitle = "Powr\243t do Yonah "
gameforge.subquest_36._270_say = "Dostarczy\179e\156 Stajennemu 10 balot\243w Siana dla[ENTER]g\179odnych koni. Poinformuj Yonah o swoim sukcesie. "
gameforge.subquest_36._280_npcChat = "Konie s\185 nakarmione! "
gameforge.subquest_36._290_say = "Witaj ponownie![ENTER]Znalezienie takiej ilo\156ci Siana na pewno nie by\179o[ENTER]\179atwe. Dzi\234kuj\234, \191e si\234 nie podda\179e\156! Oto drobne[ENTER]wynagrodzenia dla Ciebie. "
gameforge.subquest_36._300_sayReward = "Otrzyma\179e\156 Ksi\234g\234 Misji. "
gameforge.subquest_36._30_say = "Hey, mam pytanie! Wiem, \191e kto\156 inny jest[ENTER]odpowiedzialny za Konie, ale osoba ta ma du\191y[ENTER]problem... Konie s\185 bardzo wyczerpane przez[ENTER]wojn\234. Jak wszystkie zwierz\234ta, one r\243wnie\191 musz\185[ENTER]co\156 je\156\230... "
gameforge.subquest_36._40_say = "Jest du\191o koni, ale ma\179o pokarmu. Du\191o koni[ENTER]umiera. Czy m\243g\179by\156 za\179atwi\230 jakie\156 jedzenie dla[ENTER]nich? Tylko ty mo\191esz wype\179ni\230 to zadanie. Zbierz[ENTER]10 porcji jedzenia dla koni i zanie\156 je do[ENTER]Stajennego. On b\234dzie wiedzia\179 o co chodzi, gdy[ENTER]powiesz, \191e to ja Ci\234 przys\179a\179em. "
gameforge.subquest_36._50_select = "Wyruszam niezw\179ocznie! "
gameforge.subquest_36._60_select = "Nie, jest to praca poni\191ej mojej godno\156ci. "
gameforge.subquest_36._70_say = "Teraz coraz wi\234cej ludzi chce je\159dzi\230 konno.[ENTER]Jednak nie mo\191na w pe\179ni rozwin\185\230 hodowli koni z[ENTER]powodu niewystarczaj\185cej ilo\156ci jedzenia.[ENTER]Konie g\179oduj\185. Wr\243\230 je\156li zmienisz zdanie. "
gameforge.subquest_36._80_say = "Ahh, konie b\234d\185 cierpie\230...[ENTER]Musisz si\234 z tym pogodzi\230... "
gameforge.subquest_36._90_say = "Wiem, \191e jeste\156 bardzo zaj\234ty i doceniam twoj\185[ENTER]dotychczasow\185 pomoc, ale czy nie mo\191esz zrobi\230[ENTER]wyj\185tku? Konie s\185 teraz bardzo wa\191ne. No i[ENTER]naprawd\234 potrzebujemy Siana. "
gameforge.subquest_37 = {}
gameforge.subquest_37._100_say = "Yonah robi co mo\191e, aby produkowa\230 now\185[ENTER]porcelan\234, ale niestety stoi w miejscu ze swoimi[ENTER]do\156wiadczeniami. Udaj si\234 do Uriela i zapytaj si\234[ENTER]mo\191e on zna si\234 na Seledynowej Porcelanie. "
gameforge.subquest_37._10_targetVid = "Sekret seledynowej porcelany "
gameforge.subquest_37._110_npcChat = "Wiesz co\156 o Seledynowej Porcelanie? "
gameforge.subquest_37._120_sayTitle = "Uriel: "
gameforge.subquest_37._130_say = "Seledynowa Porcelana? Znam si\234 na historii i mam[ENTER]du\191y zas\243b wiedzy z fizyki, ale nie interesuje[ENTER]mnie sztuka. Nic Ci nie powiem o Seledynowej[ENTER]Porcelanie. Ale mo\191e Soon co\156 wie... ja za nim[ENTER]nie przepadam... ale czyta on tak du\191o r\243\191nych[ENTER]ksi\185\191ek... mo\191liwe, \191e b\234dzie co\156 o niej[ENTER]wiedzia\179. "
gameforge.subquest_37._140_makequestbutton = "Id\159 do Soon. "
gameforge.subquest_37._150_targetVid = "Id\159 do Soon "
gameforge.subquest_37._160_say = "Uriel nie wie nic o Seledynowej Porcelanie, ale[ENTER]Mol Ksi\185\191kowy, Soon, jest bardzo oczytany. Udaj[ENTER]si\234 do niego i zapytaj si\234, czy wie co\156 na temat[ENTER]metod produkcji. "
gameforge.subquest_37._170_sayTitle = "Soon: "
gameforge.subquest_37._180_say = "Czego chcesz? Nie przeszkadzaj mi podczas[ENTER]czytania! Co? Seledynowa Porcelana? Pewnie, \191e[ENTER]znam. Jakby nie by\179o przeczyta\179em tuzin ksi\185\191ek[ENTER]po\156wi\234conych porcelanie. Czemu pytasz? Nie bez[ENTER]powodu nazywaj\185 mnie Molem Ksi\185\191kowym! Wszystko[ENTER]doskonale rozumiem, co napisane jest w ksi\234gach! "
gameforge.subquest_37._190_say = "Znam na pami\234\230 metody produkcji Seledynowej[ENTER]Porcelany, ale dlaczego mam Ci je wyja\156ni\230? Hmm,[ENTER]poczekaj. Mam pomys\179! Poprosi\179em jednego[ENTER]Domokr\185\191c\234 z s\185siaduj\185cej wioski o ksi\185\191k\234, kt\243r\185[ENTER]potrzebuj\234, ale nie mam czasu sam j\185 odebra\230.[ENTER]Prosz\234, przynie\156\230 mi j\185, a pomog\234 Ci z porcelan\185.[ENTER]Ruszaj! "
gameforge.subquest_37._200_makequestbutton = "Udaj si\234 do Domokr\185\191cy. "
gameforge.subquest_37._20_sayTitle = "Yonah: "
gameforge.subquest_37._210_targetVid = "Id\159 do Domokr\185\191cy "
gameforge.subquest_37._220_say = "Mol ksi\185\191kowy Soon wie co\156 na temat Seledynowej[ENTER]Porcelany. Ale powie Ci to tylko wtedy, gdy[ENTER]przyniesiesz mu ksi\185\191k\234 zam\243wion\185 u Domokr\185\191cy. W[ENTER]drog\234! "
gameforge.subquest_37._230_npcChat = "Przys\179a\179 mnie Soon... "
gameforge.subquest_37._240_say = "Hej! Przyszed\179e\156, aby mi pom\243c? Aaa, chcesz[ENTER]ksi\185\191k\234 dla Soona? Mia\179em zamiar uda\230 si\234 wkr\243tce[ENTER]do wioski, no c\243\191, on jest zbyt niecierpliwy.[ENTER]Wysy\179a innych po swoje rzeczy. Hmm... oto[ENTER]Ksi\185\191ka. Nie wiem, co jest takiego wa\191nego w tym[ENTER]stosie papier\243w. Przecie\191 o wiele wa\191niejsze jest[ENTER]zarabianie Yang! "
gameforge.subquest_37._250_qSetTitle = "Wr\243\230 do Soon "
gameforge.subquest_37._260_targetVid = "Wr\243\230 do Soon "
gameforge.subquest_37._270_say = "Odebra\179e\156 Ksi\185\191k\234 u Domokr\185\191cy. Udaj si\234 wi\234c do[ENTER]Soona i daj mu j\185, by w ko\241cu zdradzi\179 metody[ENTER]produkcji Porcelany. "
gameforge.subquest_37._280_npcChat = "Mam Ksi\185\191k\234! "
gameforge.subquest_37._290_say = "Yay! Wreszcie mam moj\185 Ksi\185\191k\234! Dzi\234kuj\234 Ci. Nie[ENTER]zosta\179o du\191o ksi\185\191ek, kt\243re jeszcze nie[ENTER]przeczyta\179em...[ENTER]Zapisz\234 Ci wszystko, co wiem o tej Seledynowej[ENTER]Porcelanie. Trzymaj si\234 wskaz\243wek, a[ENTER]wyprodukujesz cudown\185 porcelan\234. A teraz czas na[ENTER]czytanie nowej ksi\185\191ki. \175egnaj. "
gameforge.subquest_37._300_makequestbutton = "Powr\243t do Yonah "
gameforge.subquest_37._30_say = "Hm... to si\234 nie nadaje. I to te\191 nie...Och,[ENTER]zobacz! Produkuje nieprzerwanie Porcelan\234, ale[ENTER]wi\234kszo\156\230 rzeczy p\234ka. Wydaje mi si\234, \191e[ENTER]potrzebuje nowej receptury na wyr\243b Porcelany. "
gameforge.subquest_37._310_targetVid = "Dostarcz notatki do Yonah. "
gameforge.subquest_37._320_say = "Soon dotrzyma\179 obietnicy i zapisa\179 Ci receptur\234[ENTER]na wyr\243b Porcelany. Dostarcz j\185 do Yonah. "
gameforge.subquest_37._330_say = "Ooch!!! Tu jest wszystko o wyrobie Seledynowej[ENTER]Porcelany! Dzi\234ki tej recepturze przejd\234 do[ENTER]historii jako mistrz porcelany. Dzi\234kuj\234 Ci za[ENTER]pomoc. Wkr\243tce zaprezentuj\234 Ci najlepsz\185[ENTER]ceramik\234! Zaufaj mi.[ENTER]Moja Porcelana przetrwa wieki! "
gameforge.subquest_37._340_sayReward = "Otrzyma\179e\156 2.500.000 Punkt\243w Do\156wiadczenia. "
gameforge.subquest_37._350_sayReward = "Otrzyma\179e\156 35.000 Yang. "
gameforge.subquest_37._360_sayReward = "Otrzyma\179e\156 Jadeitowe Buty+3. "
gameforge.subquest_37._40_say = "Spr\243buje nowej metody... Nie jest \179atwo[ENTER]wyprodukowa\230 Seledynow\185 Porcelan\234. Dlatego tylko[ENTER]niewielu wie, jak to zrobi\230. Potrzebuj\234 jej[ENTER]jednak do mojej sztuki. W tym wypadku... tak,[ENTER]Uriel m\243g\179by mi z tym pom\243c. Prosz\234, p\243jd\159 do[ENTER]Uriela i zapytaj o to jak robi\230 tak\185 Porcelan\234.[ENTER]On na pewno b\234dzie w stanie pom\243c! "
gameforge.subquest_37._50_say = "Czy chcesz zrezygnowa\230 z zadania? "
gameforge.subquest_37._60_say = "Hm, jeste\156 zaj\234ty?[ENTER]Pami\234taj o tym, by mnie ponownie odwiedzi\230, je\156li[ENTER]b\234dziesz mia\179 wi\234cej czasu. "
gameforge.subquest_37._70_say = "Chc\234 produkowa\230 najlepsz\185 porcelan\234...[ENTER]Rozumiem... do zobaczenia! "
gameforge.subquest_37._80_say = "Dzi\234kuj\234. Uriel na pewno pomo\191e. Na razie! "
gameforge.subquest_37._90_targetVid = "Id\159 do Uriela "
gameforge.subquest_38 = {}
gameforge.subquest_38._100_say = "\163owcy Yang-Shin ukradziono Ozdobiony \163uk,[ENTER]pami\185tk\234 rodzinn\185.[ENTER]Udaj si\234 do Sangsun Dong i odzyskaj \163uk od[ENTER]z\179odziejskich ma\179p. "
gameforge.subquest_38._10_targetVid = "Skarb \163owcy "
gameforge.subquest_38._110_sendLetter = "Znalaz\179e\156 Ozdobiony \163uk! "
gameforge.subquest_38._120_targetVid = "Id\159 do \163owcy Yang-Shin "
gameforge.subquest_38._125_say = "Znalaz\179e\156 Ozdobiony \163uk \163owcy.[ENTER]Zwr\243\230 go Yang-Shin. "
gameforge.subquest_38._130_npcChat = "Oto \163uk... "
gameforge.subquest_38._140_say = "Wow, oto on! M\243j \163uk, jestem pod wra\191eniem![ENTER]M\243j honor zosta\179 uratowany.[ENTER]Huh... cierpia\179em tak d\179ugo z powodu jego zguby.[ENTER]Jestem bardzo wdzi\234czny za pomoc. Honorem b\234dzie[ENTER]wr\234czenie Ci tego. Mo\191e to niewiele, ale pochodzi[ENTER]z g\179\234bi serca, a to jest najwa\191niejsze. Dzi\234ki[ENTER]tobie mog\234 \191y\230 w spokoju. "
gameforge.subquest_38._150_sayReward = "Otrzyma\179e\156 1.500.000 Punkt\243w Do\156wiadczenia. "
gameforge.subquest_38._160_sayReward = "Otrzyma\179e\156 35.000 Yang. "
gameforge.subquest_38._170_sayReward = "Otrzyma\179e\156 Peleryn\234 M\234stwa. "
gameforge.subquest_38._180_say = "Znalaz\179e\156 m\243j \163uk? I gdzie on teraz jest? Czy\191by\156[ENTER]go ju\191 zgubi\179? "
gameforge.subquest_38._190_select = "B\234d\234 szuka\230 dalej. "
gameforge.subquest_38._200_say = "Niech tak b\234dzie.[ENTER]Uwa\191aj na siebie. "
gameforge.subquest_38._20_say = "Hey, masz chwilk\234? Jak widzisz, jestem \163owc\185,[ENTER]moja rodzina poluje od pokole\241. Wszyscy w mojej[ENTER]rodzinie byli \179owcami, to rodzina z tradycjami.[ENTER]Ale ja pope\179ni\179em wielki b\179\185d, kt\243ry zha\241bi mnie[ENTER]w oczach rodziny... "
gameforge.subquest_38._210_say = "Spr\243bujesz jeszcze raz? Dzi\234kuj\234 Ci.[ENTER]Z twoimi umiej\234tno\156ciami na pewno Ci si\234 uda. "
gameforge.subquest_38._30_say = "Chodzi o Rozrzutnie Ozdobiony \163uk, kt\243ry w\179a\156nie[ENTER]zosta\179 skradziony przez Ma\179py. By\179em na polowaniu[ENTER]w Lochu Ma\179p, odwr\243ci\179em si\234 tylko na chwilk\234, a[ENTER]one wykorzysta\179y sytuacj\234 i mi go ukrad\179y. "
gameforge.subquest_38._40_say = "Nigdy nie zaszed\179em g\179\234boko do Lochu Ma\179p i nie[ENTER]wiem jak on wygl\185da. Potrzebuj\234 twojej pomocy.[ENTER]S\179ysza\179em od kilku os\243b, \191e jeste\156 bardzo[ENTER]utalentowan\185 osob\185. Dlatego prosz\234 w\179a\156nie Ciebie[ENTER]o t\185 przys\179ug\234. Nie mog\234 i\156\230 do rodziny bez tego[ENTER]\163uku. "
gameforge.subquest_38._50_sayTitle = "Yang-Shin: "
gameforge.subquest_38._60_say = "Musz\234 go szybko odzyska\230... Prosz\234, wr\243\230 gdy[ENTER]b\234dziesz mia\179 czas. Pozdrawiam. "
gameforge.subquest_38._70_say = "A wi\234c...[ENTER]B\185d\159 czujny podczas twoich podr\243\191y. "
gameforge.subquest_38._80_say = "Nietrudno go znale\159\230, poniewa\191 jest bardzo[ENTER]pysznie ozdobiony. Dobrze Ci\234 za to wynagrodz\234! "
gameforge.subquest_38._90_sayTitle = "Znajd\159 Ozdobiony \163uk "
