gameforge.subquest_39._100_sayTitle = "Sytuacja Balso "
gameforge.subquest_39._10_targetVid = "Przesy\179ka dla zdrajcy Balso "
gameforge.subquest_39._110_say = "Stan zdrowia Zdrajcy Balso pogorszy\179 si\234. Id\159 do[ENTER]Baek-Go i spytaj si\234 go, w jaki spos\243b mo\191na[ENTER]pom\243c Balso. "
gameforge.subquest_39._120_makequestbutton = "Id\159 do Baek-Go "
gameforge.subquest_39._130_qSetTitle = "Id\159 do Baek-Go "
gameforge.subquest_39._140_targetVid = "Id\159 do Baek-Go. "
gameforge.subquest_39._150_npcChat = "Mam pacjenta... "
gameforge.subquest_39._160_sayTitle = "Baek-Go: "
gameforge.subquest_39._170_say = "Och, to Ty, jak si\234 masz?[ENTER]Leczysz chorego? A co mu dolega... Hmm...[ENTER]A jakie lekarstwa do tej pory przyjmowa\179?[ENTER]Co prosz\234? Nic dziwnego, \191e jego stan si\234[ENTER]pogorszy\179! Te lekarstwa s\185 zupe\179nie[ENTER]nieodpowiednie! "
gameforge.subquest_39._180_say = "Ma szcz\234\156cie, \191e jeszcze jest przy \191yciu![ENTER]Nieodpowiednie leczenie chorego jest bardzo[ENTER]niebezpieczne! Ale wiem, jak mu pom\243c. Istnieje[ENTER]pewne zio\179o, kt\243re oczyszcza organizm z[ENTER]substancji truj\185cych i wspomaga rekonwalescencj\234.[ENTER]Zdobycie tego zio\179a jest jednak zwi\185zane z du\191ym[ENTER]ryzykiem. "
gameforge.subquest_39._190_say = "O ile mi wiadomo zio\179o te ro\156nie jedynie w[ENTER]Sangsun Dong. \140cinane jest zawsze dla Lorda Ma\179p,[ENTER]kt\243ry je bardzo ch\234tnie je. B\234dziesz go musia\179[ENTER]zabi\230, aby uzyska\230 te zio\179o.[ENTER]Je\156li mi je przyniesiesz, przygotuj\234 Ci z niego[ENTER]odpowiednie lekarstwo. "
gameforge.subquest_39._200_select = "Dobrze, zdob\234d\234 je. "
gameforge.subquest_39._20_npcChat = "Co si\234 tyczy twojego lekarstwa... "
gameforge.subquest_39._210_select = "Nie mog\234 tego zrobi\230. "
gameforge.subquest_39._220_say = "Czy chcesz zrezygnowa\230 z zadania? "
gameforge.subquest_39._230_select = "Tak "
gameforge.subquest_39._240_say = "Wi\234c mo\191e potem, gdy b\234dziesz mia\179 wi\234cej czasu.[ENTER]Du\191o ludzi jest chorych, a tak ma\179o szuka dla[ENTER]nich lekarstw. "
gameforge.subquest_39._250_say = "Hmm, niestety w\179a\156nie tak jest. Szkoda, \191e nikt[ENTER]nie ma na tyle odwagi. Nie wiem jak to ma by\230[ENTER]dalej... "
gameforge.subquest_39._260_say = "Och, Dzi\234kuj\234. Zadanie nie jest proste, ale[ENTER]wype\179niaj\185c je pomo\191esz wielu ludziom! "
gameforge.subquest_39._270_makequestbutton = "Zio\179o Lorda Ma\179p "
gameforge.subquest_39._280_targetVid = "Wr\243\230 do Baek-Go. "
gameforge.subquest_39._290_sayTitle = "Znalaz\179e\156 Zio\179o z Trudnych Ma\179p "
gameforge.subquest_39._300_say = "Odebra\179e\156 Lordowi Ma\179p Zio\179o z Trudnych Ma\179p.[ENTER]Zanie\156 je Baek-Go, aby m\243g\179 przyrz\185dzi\230 lekarstwo[ENTER]dla Balso. "
gameforge.subquest_39._30_say = "Dzi\234ki. Przynios\179e\156 mi wreszcie to lekarstwo. Ale[ENTER]jest pewien problem... Lekarstwo ju\191 mi nie[ENTER]pomaga. Wszystko chyba posz\179o nie tak.[ENTER](kicha) Chyba potrzebuj\234 intensywnej terapii. "
gameforge.subquest_39._310_sayTitle = "Zdob\185d\159 Zio\179o z Sangsung Dong "
gameforge.subquest_39._320_say = "Baek-Go potrafi przyrz\185dzi\230 lekarstwo na chorob\234[ENTER]Zdrajcy Balso. Potrzebuj\234 jednak Zio\179o z Trudnych[ENTER]Ma\179p. Otrzymasz je od Lorda Ma\179p w Trudnym Lochu[ENTER]Ma\179p. "
gameforge.subquest_39._330_npcChat = "Zio\179o z Trudnych Ma\179p... "
gameforge.subquest_39._340_say = "Wydaj\234 si\234, \191e nied\179ugo dojdzie do wybuchu[ENTER]epidemii, nie wiemy jednak jaki jest tego pow\243d.[ENTER]Ca\179e szcz\234\156cie Towarzystwo akademickie odkry\179o[ENTER]spos\243b leczenia za pomoc\185 ma\179piego Ziela. Co[ENTER]takiego? Znalaz\179e\156 ju\191 te Ziele? "
gameforge.subquest_39._350_select = "Jeszcze nie. Ale nied\179ugo! "
gameforge.subquest_39._360_select = "Nie zdob\234d\234 Zio\179a... "
gameforge.subquest_39._370_say = "Naprawd\234 chcesz si\234 podda\230? W porz\185dku, nic[ENTER]wi\234cej nie da si\234 zrobi\230. Eh, co ja teraz mam[ENTER]zrobi\230? To Zio\179o mog\179oby by\230 bardzo pomocne... "
gameforge.subquest_39._380_select = "Nie dam rady. "
gameforge.subquest_39._390_select = "Chc\234 pom\243c! "
gameforge.subquest_39._400_say = "Te ma\179py s\185 dla mnie za silne. Nie wiem, jak[ENTER]zdoby\230 te zio\179o. Bardzo mi przykro. "
gameforge.subquest_39._40_say = "Wiem, \191e w s\185siedniej wiosce mieszka doktor. Czy[ENTER]mo\191esz do niego p\243j\156\230 i opisa\230 jak si\234 czuj\234? Mam[ENTER]nadziej\234, \191e powie co robi\230... Jak widzisz, nie[ENTER]mog\234 si\234 st\185d ruszy\230 w takim stanie. Jestem[ENTER]bardzo wdzi\234czny za pomoc ostatnim razem, wi\234c i[ENTER]tym razem Ci\234 wynagrodz\234. "
gameforge.subquest_39._410_say = "Odmawiasz pomocy ludziom cierpi\185cym na t\234[ENTER]straszn\185, tajemnicz\185 chorob\234? Precz mi z oczu! "
gameforge.subquest_39._420_say = "Masz racj\234. Kto\156 musi zdoby\230 te Zio\179o, w[ENTER]przeciwnym razie ci chorzy b\234d\185 strasznie[ENTER]cierpie\230. Zajm\234 si\234 tym. "
gameforge.subquest_39._430_say = "Wi\234c na co czekasz? W drog\234! "
gameforge.subquest_39._440_say = "Och, uda\179o ci si\234 zdoby\230 ma\179pie Zio\179o. Wspaniale![ENTER]Mam nadziej\234, \191e dzi\234ki niemu uda nam si\234 pokona\230[ENTER]t\185 tajemnicz\185 chorob\234! Zaczekaj chwil\234, zaraz[ENTER]sporz\185dz\234 lekarstwo... "
gameforge.subquest_39._450_sayTitle = "Baek-Go: "
gameforge.subquest_39._460_say = "Oto lekarstwo. Udaj si\234 czym pr\234dzej do swojego[ENTER]pacjenta i daj mu je. Powinien poczu\230 si\234 lepiej.[ENTER]I przypomnij mu, aby nast\234pnym razem zapyta\179[ENTER]lekarza, jaki lek jest odpowiedni! "
gameforge.subquest_39._470_makequestbutton = "Zanie\156 Lekarstwo do Balso "
gameforge.subquest_39._480_targetVid = "Daj Lekarstwo Balso. "
gameforge.subquest_39._490_sayTitle = "Lekarstwo Balso "
gameforge.subquest_39._500_say = "Baek-Go przyrz\185dzi\179 lekarstwo z Zio\179a z Trudnych[ENTER]Ma\179p. Potrafi ono uleczy\230 wiele ci\234\191kich chor\243b.[ENTER]Zanie\156 je Zdrajcy Balso w s\185siedniej wiosce. "
gameforge.subquest_39._50_say = "Czy chcesz na zawsze zrezygnowa\230 z misji? "
gameforge.subquest_39._510_npcChat = "Oto lekarstwo. "
gameforge.subquest_39._520_say = "Przynosisz mi nowe lekarstwo? S\185 zatem jakie\156[ENTER]post\234py w medycynie? Wybacz, \191e stwarzam Ci tyle[ENTER]k\179opotu. Powinienem od razu zapyta\230 si\234 lekarza.[ENTER]Ale c\243\191, teraz ju\191 nie mam wyboru, musz\234[ENTER]spr\243bowa\230 tego lekarstwa. "
gameforge.subquest_39._530_say = "Dzi\234kuj\234 Ci stokrotnie, \191e poratowa\179e\156 mnie w[ENTER]biedzie. Nie mam zbyt du\191o przyjaci\243\179.[ENTER]We\159 to, nie jest zbyt wiele ale pochodzi od[ENTER]serca. Gdyby kiedykolwiek uda\179o mi si\234 odnie\156\230[ENTER]wielki sukces, wiedz, \191e o Tobie nie zapomn\234! "
gameforge.subquest_39._540_sayReward = "Otrzyma\179e\156 4.000.000 Punkt\243w Do\156wiadczenia. "
gameforge.subquest_39._550_sayReward = "Otrzyma\179e\156 65.000 Yang. "
gameforge.subquest_39._60_say = "Gdy b\234dziesz wiedzia\179 jak mi pom\243c, przyjd\159. "
gameforge.subquest_39._70_sayTitle = "Zdrajca Balso: "
gameforge.subquest_39._80_say = "Chyba b\234d\234 zmuszony \191y\230 w ten spos\243b do ko\241ca...[ENTER]\175egnaj. "
gameforge.subquest_39._90_say = "Dzi\234kuj\234... b\185d\159 ostro\191ny. "
gameforge.subquest_40 = {}
gameforge.subquest_40._100_say = "Wiedzia\179em, \191e mog\234 na Ciebie liczy\230! Nie jest to[ENTER]proste zadanie, ale na pewno dasz sobie rad\234.[ENTER]Powodzenia! "
gameforge.subquest_40._10_targetVid = "Wsparcie wojenne "
gameforge.subquest_40._110_targetVid = "Wr\243\230 do Kapitana. "
gameforge.subquest_40._120_say = "Masz wszystkie 5000 Grot\243w Strza\179.[ENTER]Zanie\156 je Kapitanowi. "
gameforge.subquest_40._130_say = "Naszej armii brakuje strza\179. Zabij Zara\191onych[ENTER]\163ucznik\243w na g\243rze Sohan i pozbieraj ich Groty[ENTER]Strza\179 dla Kapitana. 5000 sztuk powinno[ENTER]wystarczy\230. "
gameforge.subquest_40._140_npcChat = "Co si\234 tyczy Grot\243w Strza\179... "
gameforge.subquest_40._150_say = "Zara\191eni \163ucznicy cierpi\185 na jak\185\156 dziwn\185[ENTER]chorob\234, kt\243ra rozprzestrzeni\179a si\234 po[ENTER]kontynencie. Nawet nasi lekarze nie potrafi\185[ENTER]sobie tego wyt\179umaczy\230. Wi\234kszo\156\230 grot\243w ich[ENTER]strza\179 jeszcze nie jest zatruta, ale tych[ENTER]zatrutych jest coraz wi\234cej. "
gameforge.subquest_40._160_select = "W takim razie b\234d\234 kontynuowa\230. "
gameforge.subquest_40._170_say = "Czy chcesz zrezygnowa\230 z zadania? "
gameforge.subquest_40._180_say = "Boisz si\234 zachorowa\230?[ENTER]Uspok\243j si\234 i wr\243\230 do mnie p\243\159niej. "
gameforge.subquest_40._190_say = "Czy na pewno chcesz zrezygnowa\230?[ENTER]Hmm, mo\191e to jest za trudne...[ENTER]Zapytam kogo\156 innego. Ok, do zobaczenia. "
gameforge.subquest_40._200_say = "Aha...[ENTER]Nigdy si\234 nie poddajesz, co?[ENTER]W takim razie, ruszaj! "
gameforge.subquest_40._20_say = "Uwaga, wojownicy! Jak na pewno ju\191 zd\185\191y\179e\156[ENTER]zauwa\191y\230, ataki naszych wrog\243w nasilaj\185 si\234. Poza[ENTER]tym otrzymali\156my bardzo niepokoj\185ce informacje od[ENTER]Yu-Hwan. Kr\243tko m\243wi\185c: Mamy za ma\179o strza\179! "
gameforge.subquest_40._210_npcChat = "Oto 5000 Grot\243w Strza\179! "
gameforge.subquest_40._220_say = "\140wietna robota! Dzi\234ki twojej pomocy mo\191emy si\234[ENTER]przygotowywa\230 na atak. Wydam od razu rozkaz, \191eby[ENTER]rozpocz\185\230 produkcj\234 strza\179. Bardzo nam pomog\179e\156.[ENTER]Mam nadziej\234, \191e w przysz\179o\156ci r\243wnie\191 b\234dziemy[ENTER]mogli na Ciebie liczy\230. "
gameforge.subquest_40._230_say = "Oto twoja nagroda. Nast\234pnym razem gdy b\234d\234 mia\179[ENTER]wa\191ne rozkazy b\234dziesz pierwszym, kt\243rego o nich[ENTER]poinformuj\234. Powodzenia i do rych\179ego zobaczenia! "
gameforge.subquest_40._240_sayReward = "Otrzyma\179e\156 4.500.000 Punkt\243w Do\156wiadczenia. "
gameforge.subquest_40._250_sayReward = "Otrzyma\179e\156 50.000 Yang. "
gameforge.subquest_40._260_sayReward = "Otrzyma\179e\156 3x D\179o\241 Krytyka.[ENTER]Otrzyma\179e\156 3x D\179o\241 Przebicia. "
gameforge.subquest_40._30_say = "\163ucznicy s\185 nieodzownym elementem strategicznego[ENTER]planowania. Jak tylko nasi wrogowie znajd\185 si\234 w[ENTER]zasi\234gu strza\179, nasi \179ucznicy rusz\185 do ataku. W[ENTER]ten spos\243b od razu zmusimy ich do ucieczki albo[ENTER]przynajmniej przerzedzimy ich szeregi. Je\156li[ENTER]jednak przyjdzie odeprze\230 wiele atak\243w w kr\243tkim[ENTER]czasie, szybko sko\241cz\185 nam si\234 strza\179y. "
gameforge.subquest_40._40_say = "Dlatego potrzebujemy Ciebie! Udaj si\234 do G\243ry[ENTER]Sohan. Tam musisz pozabija\230 Zara\191onych \163ucznik\243w[ENTER]i pozbiera\230 ich Groty Strza\179. Groty te s\185[ENTER]zatrute. Pomo\191e na to niezmiernie podczas[ENTER]zra\191enia z wrogiem. Potrzebne nam 5000 sztuk. Co[ENTER]Ty na to? "
gameforge.subquest_40._50_select = "Akceptuj\234. "
gameforge.subquest_40._60_select = "To dla mnie za trudne. "
gameforge.subquest_40._70_say = "Czy chcesz zrezygnowa\230 z zadania? "
gameforge.subquest_40._80_say = "Czy\191by G\243ra Sohan by\179a dla Ciebie za daleko?[ENTER]Przemy\156l to. To zadanie najwy\191szej rangi! "
gameforge.subquest_40._90_say = "Hum, obawiasz si\234 Zara\191onych \163ucznik\243w?[ENTER]Chyba przeceni\179em twoje mo\191liwo\156ci.[ENTER]Teraz nie ma ju\191 nadziei... "
gameforge.subquest_41 = {}
gameforge.subquest_41._015_npcChat = "Co czytasz? "
gameforge.subquest_41._100_say = "Zdoby\179e\156 wszystkie 100 sztuk Oczu Paj\185k\243w[ENTER]potrzebnych do nowej receptury Octavio.[ENTER]Pospiesz si\234 i zanie\156 je do niego. "
gameforge.subquest_41._10_targetVid = "Specja\179 z oczu paj\185k\243w "
gameforge.subquest_41._110_sayTitle = "Zdob\185d\159 Oczy Paj\185k\243w "
gameforge.subquest_41._120_say = "Octavio chce wypr\243bowa\230 nowy przepis o nazwie[ENTER]'Specja\179 z Oczu Paj\185k\243w'. Aby m\243g\179 przyst\185pi\230 do[ENTER]przygotowywania potrawy, potrzebuje 100 Oczu[ENTER]Paj\185k\243w, kt\243re mo\191na zdoby\230 od paj\185k\243w na Pustyni[ENTER]Yongbi. "
gameforge.subquest_41._130_targetVid = "Wr\243\230 do Octavio "
gameforge.subquest_41._140_npcChat = "Mam Oczy Paj\185k\243w. "
gameforge.subquest_41._150_sayTitle = "Octavio: "
gameforge.subquest_41._160_say = "Poka\191. Tak, dok\179adnie sto sztuk, doskonale.[ENTER]Hum, zobaczmy...[ENTER]Mmhhh, gotowe! Chcesz spr\243bowa\230? Nie b\243j si\234. To[ENTER]Ci\234 nie zabije. "
gameforge.subquest_41._170_say = "Hmm, hmm... c\243\191 za do\156wiadczenie! Bardzo po\191ywne,[ENTER]ale nie za s\179odkie... naprawd\234 niesamowity smak![ENTER]Wiedzia\179em, \191e by\179o warto. Samemu nigdy by mi si\234[ENTER]nie uda\179o. Bardzo dzi\234kuj\234 za Twoj\185 pomoc! "
gameforge.subquest_41._180_sayReward = "Otrzyma\179e\156 2.100.000 Punkt\243w Do\156wiadczenia. "
gameforge.subquest_41._190_say = "O czym ty m\243wisz? To na pewno nie jest sto sztuk,[ENTER]wiem to nawet bez przeliczania! Zdob\185d\159 dla mnie[ENTER]wi\234cej, prosz\234. "
gameforge.subquest_41._200_say = "Naprawd\234 chc\234 zrobi\230 to danie...[ENTER]Niewa\191ne... dzi\234ki. \175egnaj. "
gameforge.subquest_41._20_say = "Hej, jak si\234 masz? W\179a\156nie przegl\185dam ksi\185\191k\234[ENTER]kucharsk\185, kt\243r\185 otrzyma\179em od Soon. Znalaz\179em w[ENTER]niej przepis na danie, kt\243re nazywa si\234 'Specja\179[ENTER]z Oczu Paj\185k\243w'. Nigdy o czym\156 takim nie[ENTER]s\179ysza\179em, a ty? Najprawdopodobniej jest to[ENTER]wyj\185tkowa potrawa pochodz\185ca z innego kraju. "
gameforge.subquest_41._210_say = "Dzi\234kuj\234 za to, \191e nie zostawiasz mnie w[ENTER]potrzebie. Jeste\156 bardzo mi\179y! "
gameforge.subquest_41._30_say = "Bardzo chcia\179bym spr\243bowa\230 tego dania, ale niby[ENTER]jak sam zdob\234d\234 Oczy Paj\185ka? Naprawd\234, ponownie[ENTER]potrzebuj\234 twojej pomocy! Prosz\234, zdob\185d\159 dla[ENTER]mnie Oczy Paj\185k\243w. Mo\191na je otrzyma\230 od paj\185k\243w,[ENTER]kt\243re \191yj\185 na Pustyni Yongbi. "
gameforge.subquest_41._40_say = "Czy mo\191esz to dla mnie zrobi\230? B\234d\234 bardzo[ENTER]wdzi\234czny. Aby przygotowa\230 odpowiednio du\191\185[ENTER]porcj\234 tego dania, potrzebuj\234 sto sztuk oczu.[ENTER]Jestem naprawd\234 podekscytowany... "
gameforge.subquest_41._50_say = "Czy chcesz zrezygnowa\230 z zadania? "
gameforge.subquest_41._60_say = "Naprawd\234 chc\234 przygotowa\230 to danie. Je\156li[ENTER]znajdziesz dla mnie czas, po prostu wr\243\230. "
gameforge.subquest_41._70_say = "Hm, sk\185d wzi\185\230 te oczy?[ENTER]Ok... do zobaczenia. "
gameforge.subquest_41._80_say = "Dzi\234ki, wiedzia\179em, \191e mog\234 na Ciebie liczy\230![ENTER]Za to ugotuj\234 Ci wspania\179y posi\179ek. "
gameforge.subquest_41._90_sayTitle = "Wr\243\230 do Octavio "
gameforge.subquest_42 = {}
gameforge.subquest_42._100_say = "Przykro mi to s\179ysze\230. S\179ysz\234 tyle g\179os\243w[ENTER]poleg\179ych, kt\243rzy nie mog\185 zazna\230 spokoju.[ENTER]Naprawd\234 musimy im pom\243c.[ENTER]Poprosz\234 o pomoc kogo\156 innego. \175egnaj. "
