gameforge.subquest_42._110_say = "Jeste\156 taki odwa\191ny. Dzi\234ki twojej pomocy, ju\191[ENTER]nied\179ugo odwa\191ni wojownicy zaznaj\185 spokoju. "
gameforge.subquest_42._120_say = "Straszne wojny powi\234kszaj\185 liczb\234 zabitych ludzi.[ENTER]Wojownicy walcz\185 na linii frontu dla siebie, dla[ENTER]swoich rodzin i dla swojego Kr\243lestwa.[ENTER]Ale po \156mierci, cz\234\156\230 z nich nie idzie do nieba,[ENTER]pozostaj\185c na tym \156wiecie. "
gameforge.subquest_42._130_say = "S\179ysza\179em, \191e Elitarni Ezoteryczni Wodzowie w[ENTER]\140wi\185tyni Ciemno\156ci posiadaj\185 \140wi\185tynny Szal i[ENTER]\140wi\185tynn\185 Doktryn\234. Prosz\234, pom\243\191 mi i moim[ENTER]towarzyszom uspokoi\230 dusze poleg\179ych, kt\243rzy[ENTER]zgin\234li w obronie kr\243lestwa. "
gameforge.subquest_42._140_sayTitle = "Wr\243\230 do Trenera Mocy Smoka "
gameforge.subquest_42._150_say = "Znalaz\179e\156 \140wi\185tynny Szal i \140wi\185tynn\185 Doktryn\234.[ENTER]Zanie\156 je do Trenera Mocy Smoka, aby szamani[ENTER]mogli rozpocz\185\230 rytua\179, kt\243rego celem jest[ENTER]uspokojenie poleg\179ych. "
gameforge.subquest_42._160_sayTitle = "Zdob\185d\159 \140wi\185tynny Szal i \140wi\185tynn\185 Doktryn\234. "
gameforge.subquest_42._170_say = "Szamani potrzebuj\185 \140wi\185tynnego Szala oraz[ENTER]\140wi\185tynnej Doktryny, aby przeprowadzi\230 ceremoni\234[ENTER]maj\185c\185 na celu uspokojenie dusz poleg\179ych na[ENTER]wojnie wojownik\243w. Zabij Elitarnego Ezoterycznego[ENTER]Wodza, kt\243ry znajduje si\234 w \140wi\185tyni Hwang, aby[ENTER]zdoby\230 niezb\234dne przedmioty. "
gameforge.subquest_42._180_npcChat = "Mam Szal i Doktryn\234. "
gameforge.subquest_42._190_say = "To by\179o niesamowite. Teraz mo\191emy uspokoi\230 dusze[ENTER]poleg\179ych \191o\179nierzy. \140wietnie si\234 spisali. Teraz[ENTER]mog\185 zazna\230 spokoju. Pozw\243l, \191e dam Ci nagrod\234 za[ENTER]ten szlachetny czyn. "
