gameforge.subquest_42._20_sayTitle = "Nauczyciel Mocy Smoka: "
gameforge.subquest_42._210_sayReward = "Otrzyma\179e\156 30.000 Yang. "
gameforge.subquest_42._220_sayReward = "Otrzyma\179e\156 3 Diamenty. "
gameforge.subquest_42._230_say = "To by\179o niesamowite. Teraz mo\191emy uspokoi\230 dusze[ENTER]poleg\179ych \191o\179nierzy. \140wietnie si\234 spisali. Teraz[ENTER]mog\185 zazna\230 spokoju. Pozw\243l, \191e dam Ci nagrod\234 za[ENTER]ten szlachetny czyn. "
gameforge.subquest_42._30_say = "Straszne wojny powi\234kszaj\185 liczb\234 zabitych ludzi.[ENTER]Wojownicy walcz\185 na linii frontu dla siebie, dla[ENTER]swoich rodzin i dla swojego Kr\243lestwa.[ENTER]Ale po \156mierci, cz\234\156\230 z nich nie idzie do nieba,[ENTER]pozostaj\185c na tym \156wiecie. "
gameforge.subquest_42._40_say = "Podobno podczas wojny byli odporni na \156mier\230.[ENTER]Ca\179y czas wierz\185, \191e musz\185 broni\230 swojego[ENTER]kr\243lestwa. Nasi szamani chc\185 odprawi\230 rytua\179,[ENTER]kt\243ry uspokoi ich dusze. Aby tego dokona\230,[ENTER]potrzebny b\234dzie specjalny \140wi\185tynny Szal oraz[ENTER]\140wi\185tynna Doktryna. Trudno je znale\159\230 w[ENTER]dzisiejszych czasach. Czy m\243g\179by\156 zdoby\230 te[ENTER]przedmioty? "
gameforge.subquest_42._50_say = "S\179ysza\179em, \191e Elitarni Ezoteryczni Wodzowie w[ENTER]\140wi\185tyni Ciemno\156ci posiadaj\185 \140wi\185tynny Szal i[ENTER]\140wi\185tynn\185 Doktryn\234. Prosz\234, pom\243\191 mi i moim[ENTER]towarzyszom uspokoi\230 dusze poleg\179ych, kt\243rzy[ENTER]zgin\234li w obronie kr\243lestwa. "
