gameforge.subquest_44._10_targetVid = "Paj\185k "
gameforge.subquest_44._110_say = "Taurean powiedzia\179, \191e zawiesi\179 dzwonek na[ENTER]Paj\185ku. A teraz Yu-Rang chce si\234 przekona\230, czy[ENTER]rzeczywi\156cie jej przyjaciel jest tak odwa\191ny.[ENTER]Odnajd\159 tego Paj\185ka na Pustyni. "
gameforge.subquest_44._120_say = "Znalaz\179e\156 Paj\185ka z Dzwoneczkiem? Nie?[ENTER]Prawdopodobnie nie znajdziesz go nigdy. Taurean[ENTER]jest tch\243rzem i tylko si\234 tak przechwala\179! "
gameforge.subquest_44._130_sendLetter = "Nie znalaz\179e\156 dzwonka "
gameforge.subquest_44._140_sayTitle = "Wiele paj\185k\243w, \191adnego dzwonka "
gameforge.subquest_44._150_say = "Zabi\179e\156 ju\191 niejednego Paj\185ka, ale jeszcze nie[ENTER]znalaz\179e\156 jakiego\156 z Dzwoneczkiem. Przecie\191 nie[ENTER]mo\191esz go wiecznie szuka\230. Chyba du\191o pro\156ciej[ENTER]b\234dzie, znale\159\230 Taurean i spyta\230 go o prawd\234? "
gameforge.subquest_44._160_sendLetter = "Id\159 do Taurean "
gameforge.subquest_44._170_targetVid = "Spytaj Taurean o dzwonek "
gameforge.subquest_44._180_say = "Trudno uwierzy\230, \191e Taurean jest tak odwa\191ny. To[ENTER]nie takie proste zawiesi\230 Dzwoneczek Paj\185kowi.[ENTER]Po prostu zapytaj go, czy to prawda. "
gameforge.subquest_44._190_npcChat = "Opowiedz o twoim zak\179adzie z Yu-Rang... "
gameforge.subquest_44._200_say = "Tak! Wiesz ju\191 o zak\179adzie z Yu-Rang? Ona tak[ENTER]naprawd\234 to mi nie wierzy i my\156li, \191e tego nie[ENTER]zrobi\179em. Uwa\191a, \191e na sam widok Paj\185ka padn\234[ENTER]martwy. "
gameforge.subquest_44._20_npcChat = "Paj\185k z dzwonkiem...? "
gameforge.subquest_44._210_say = "Prawd\234 powiedziawszy... no tak, w\179a\156ciwe to ma[ENTER]ona racj\234. Nie odwa\191y\179em si\234, powiedzie\230 prawdy,[ENTER]poniewa\191 jestem zbyt dumny. "
gameforge.subquest_44._220_say = "Wygl\185dasz na bardzo silnego! Czy nie m\243g\179by\156[ENTER]zawiesi\230 Dzwoneczek M\179odemu Paj\185kowi i[ENTER]powiedzie\230, \191e to ja zrobi\179em? Prosz\234 Ci\234! W[ENTER]przeciwnym razie b\234dzie si\234 ze mnie wy\156miewa\230[ENTER]przez ca\179e \191ycie. "
gameforge.subquest_44._230_say = "Czy chcesz zrezygnowa\230 z zadania? "
gameforge.subquest_44._240_say = "Nie chcesz tego zrobi\230? Ale nie powiesz o[ENTER]wszystkim Yu-Rang?! Prosz\234, pom\243\191 mi. Je\156li[ENTER]b\234dziesz mia\179 troch\234 czasu, wpadnij do mnie[ENTER]ponownie! "
gameforge.subquest_44._250_say = "Teraz Yu-Rang ju\191 nigdy si\234 do mnie nie odezwie,[ENTER]albo wy\156mieje mnie... "
gameforge.subquest_44._260_say = "Ty jeste\156 naprawd\234 bardzo mi\179y. Dzi\234kuj\234 za[ENTER]pomoc. Powodzenia! "
gameforge.subquest_44._270_sendLetter = "Wr\243\230 do Yu-Rang "
gameforge.subquest_44._280_say = "Wr\243\230 do Yu-Rang i powiedz jej, \191e Taurean[ENTER]k\179amie.  "
gameforge.subquest_44._290_npcChat = "Yu-Rang zawiod\179a sie na tobie. "
gameforge.subquest_44._300_say = "Powiedzia\179e\156 jej?![ENTER]Teraz mog\234 zrozumie\230, dlaczego nie chce by\230 moj\185[ENTER]przyjaci\243\179k\185. Zasmuci\179o mnie to, ale nadal mam[ENTER]nadziej\234, \191e pewnego dnia zmieni zdanie. Mo\191e[ENTER]przyjdzie mi co\156 wspania\179ego do g\179owy, czym[ENTER]m\243g\179bym j\185 zaskoczy\230... "
gameforge.subquest_44._30_say = "Hej, mo\191esz co\156 dla mnie zrobi\230? M\243j przyjaciel[ENTER]Taurean jest na mnie cz\234sto z\179y, bo nazywam go[ENTER]tch\243rzem. M\243wi, \191e jest wr\234cz odwrotnie i jest[ENTER]bardzo odwa\191ny. Za\179o\191yli\156my si\234 o to, czy uda mu[ENTER]si\234 powiesi\230 Dzwonek na M\179odym Paj\185ku. Powiedzia\179[ENTER]mi, \191e tego dokona\179, ale jako\156 nie chc\234 mi si\234 w[ENTER]to wierzy\230. "
gameforge.subquest_44._310_npcChat = "Taurean k\179ama\179. "
gameforge.subquest_44._320_say = "A wi\234c ok\179ama\179 mnie?[ENTER]Hmm, nie chodzi ju\191 o k\179amstwo, rozumiem[ENTER]przecie\191, \191e nikt nie chc\234 by\230 uwa\191any za[ENTER]niezdar\234. Ale przynajmniej powinien spr\243bowa\230, by[ENTER]ta historia wygl\185da\179a na prawdziw\185. Nie chc\234 by\230[ENTER]zaprzyja\159niona z takim tch\243rzem. "
gameforge.subquest_44._330_sayReward = "Yu-Rang da Ci nagrod\234 za twoj\185 szczero\156\230. "
gameforge.subquest_44._340_sayReward = "Otrzyma\179e\156 30.000 Yang. "
gameforge.subquest_44._350_sayReward = "Otrzyma\179e\156 350.000 Punkt\243w Do\156wiadczenia. "
gameforge.subquest_44._360_sendLetter = "Dzwonek dla paj\185ka "
gameforge.subquest_44._370_say = "Udaj si\234 na Pustyni\234 do M\179odych Paj\185k\243w i spr\243buj[ENTER]powiesi\230 Dzwonek, kt\243ry otrzyma\179e\156 od Taurean, na[ENTER]jednym z nich. "
gameforge.subquest_44._380_npcChat = "O dzwonku... "
gameforge.subquest_44._390_say = "Czy zawiesi\179e\156 ju\191 Dzwonek? Jeszcze nie? To[ENTER]po\156piesz si\234, prosz\234. I uwa\191aj, by ci\234 Yu-Rang[ENTER]nie przy\179apa\179a na tym. "
gameforge.subquest_44._400_sendLetter = "Zrobione! "
gameforge.subquest_44._40_say = "Wiem, \191e powinnam ufa\230 mojemu przyjacielowi, ale[ENTER]chc\234 wiedzie\230, czy faktycznie tego dokona\179. Dla[ENTER]mnie to zbyt niebezpieczne, \191eby tam i\156\230 i to[ENTER]sprawdzi\230. Ty wygl\185dasz na bardzo silnego, na[ENTER]pewno dasz sobie rady. M\243g\179by\156 tam p\243j\156\230 i[ENTER]sprawdzi\230 to dla mnie? "
gameforge.subquest_44._410_say = "To by\179o bardzo trudne, ale w ko\241cu uda\179o Ci si\234[ENTER]zawiesi\230 Dzwonek na M\179odym Paj\185ku. Wr\243\230 teraz do[ENTER]Yu-Rang i powied\159 jej, \191e Dzwonek na Paj\185ku[ENTER]zawiesi\179 Taurean. "
gameforge.subquest_44._420_npcChat = "Dzwonek zosta\179 zawieszony na paj\185ku. "
gameforge.subquest_44._430_say = "Dokona\179e\156 tego? Wspaniale![ENTER]Prosz\234, opowiedz teraz o tym Yu-Rang, by mi w[ENTER]ko\241cu uwierzy\179a. "
gameforge.subquest_44._440_npcChat = "Taurean nie k\179ama\179. "
gameforge.subquest_44._450_say = "Co? Naprawd\234 znalaz\179e\156 Paj\185ka z Dzwonkiem? To[ENTER]oznacza, \191e Taurean naprawd\234 to zrobi\179. S\185dzi\179am,[ENTER]\191e to nie mo\191liwe. Mo\191e kiedy\156 stanie si\234[ENTER]prawdziwym m\234\191czyzn\185. Dzi\234kuj\234, \191e sprawdzi\179e\156 to[ENTER]dla mnie. Oto Twoja nagroda. "
gameforge.subquest_44._460_sendLetter = "Wr\243\230 do Taurean "
gameforge.subquest_44._470_targetVid = "Wr\243\230 do Taurean "
gameforge.subquest_44._480_say = "Powiedzia\179e\156 Yu-Rang, \191e jej przyjaciel naprawd\234[ENTER]powiesi\179 dzwonek na M\179odym Paj\185ku.[ENTER]Teraz wr\243\230 do Taurean i o wszystkim mu opowiedz. "
gameforge.subquest_44._490_npcChat = "Yu-Rang Ci wierzy. "
gameforge.subquest_44._500_say = "Bardzo dzi\234kuj\234. Teraz Yu-Rang nie b\234dzie mnie[ENTER]lekcewa\191y\230. Niech to b\234dzie nasza tajemnica, na[ENTER]zawsze. Obiecujesz? Do zobaczenia wkr\243tce! "
gameforge.subquest_44._50_select = "Przyjmij "
gameforge.subquest_44._510_sayReward = "Taurean daje Ci nagrod\234 za pomoc w k\179amaniu:[ENTER]otrzyma\179e\156 30.000 Yang. "
