gameforge.subquest_45._110_say = "Masz \140wi\185tynn\185 Doktryn\234, \140wi\185tynny Szal i[ENTER]T\179umaczenie Ksi\234gi Kl\185tw. Zanie\156 te przedmioty do[ENTER]Soon. "
gameforge.subquest_45._120_say = "Je\156li pomo\191esz Soon, Molowi Ksi\185\191kowemu, b\234dzie[ENTER]on m\243g\179 kontynuowa\230 badania zwi\185zane ze \140wi\185tyni\185[ENTER]Ciemno\156ci. Dalsze badania b\234d\185 mo\191liwe dopiero po[ENTER]zdobyciu nast\234puj\185cych przedmiot\243w: \140wi\185tynna[ENTER]Doktryna, \140wi\185tynny Szal i T\179umaczenie Ksi\234gi[ENTER]Kl\185tw. Zdob\185d\159 te przedmioty i zabierz je do[ENTER]Soon. Znajdziesz je w \140wi\185tyni Hwang, w Dolinie[ENTER]Seungryong. "
gameforge.subquest_45._130_npcChat = "Rzeczy ze \140wi\185tyni Ciemno\156ci "
gameforge.subquest_45._140_say = "Ach, Znalaz\179e\156 o co prosi\179em! Dzi\234kuj\234.[ENTER]Co si\234 tyczy istot w \156wi\185tyni, to jest to prosta[ENTER]sprawa. One s\185 niebezpieczne, co odczu\179e\156 na[ENTER]w\179asnej sk\243rze.[ENTER]Poza tym s\179u\191\185 z\179ym bogom. Nie znane mi s\185[ENTER]szczeg\243\179y ale podejrzewam, \191e maj\185 niecne plany. "
gameforge.subquest_45._150_say = "Teraz, posiadaj\185c niekt\243re z ich \156wi\234tych[ENTER]relikt\243w, powinienem dowiedzie\230 si\234 wi\234cej.[ENTER]Zaczn\234 chyba ze \140wi\185tynn\185 Doktryn\185.[ENTER]Chwila.... hmmm... aha...[ENTER]Dlaczego nadal tu stoisz? Nie masz nic lepszego[ENTER]do roboty? "
