gameforge.subquest_46._190_sayReward = "Otrzyma\179e\156 30.000 Yang. "
gameforge.subquest_46._20_say = "Witaj poszukiwaczu przyg\243d! Czy to nie Ty[ENTER]przynios\179e\156 mi ostatnio recept\234 Soon na[ENTER]wytwarzanie Seledynowej Porcelany? Mam jednak[ENTER]jeszcze jeden problem... mimo i\191 ju\191 znam[ENTER]technik\234, nie potrafi\234 wytworzy\230 prawdziwej[ENTER]Seledynowej Porcelany. Prawdopodobnie dlatego, bo[ENTER]pr\243buj\234 tego dokona\230 za pomoc\185 moich[ENTER]standardowych sk\179adnik\243w, a nie tych ci\234\191kich do[ENTER]zdobycia z recepty. "
gameforge.subquest_46._30_say = "Potrzebuj\234 specjalnego Pustynnego Piasku na[ENTER]glin\234, Rud\234 Kryszta\179u i Krwi Ma\179py. Je\156li zmiesza[ENTER]si\234 te sk\179adniki i doda si\234 je do Gliny, stanie[ENTER]si\234 ona podczas wypalania bardzo twarda. Glazura[ENTER]nabiera wtedy typowy seledynowy odcie\241[ENTER]przypominaj\185cy Jadeit. Kolor ten jest bardzo[ENTER]popularny w\156r\243d klient\243w i musz\234 jak najpr\234dzej[ENTER]sprzeda\230 wi\234cej! "
gameforge.subquest_46._40_say = "Pustynny Piasek zdob\234dziesz u Pustynnych[ENTER]Zawadiak\243w, Rud\234 Kryszta\179u znajdziesz w \175yle[ENTER]Kryszta\179u a dla uzyskania Krwi Ma\179py musisz zabi\230[ENTER]Ma\179py w Sangsung Dong. Zdob\234dziesz dla mnie te[ENTER]materia\179y? Wiem, \191e nie b\234dzie to \179atwe, ale[ENTER]hojnie Ciebie wynagrodz\234. "
