gameforge.subquest_48._110_say = "Jeden ze szpieg\243w Kapitana mieszka pod[ENTER]przykryciem Rybaka w wiosce Pyungmo w Kr\243lestwie[ENTER]Jinno. Spr\243buj si\234 z nimi niepostrze\191enie[ENTER]skontaktowa\230. Jak tylko zdob\234dziesz potrzebne[ENTER]informacje, przeka\191 je Kapitanowi. "
gameforge.subquest_48._120_say = "Jeden ze szpieg\243w Kapitana mieszka pod[ENTER]przykryciem Rybaka w wiosce Yongan, w Kr\243lestwie[ENTER]Shinsoo. Spr\243buj si\234 z nimi niepostrze\191enie[ENTER]skontaktowa\230. Jak tylko zdob\234dziesz potrzebne[ENTER]informacje, przeka\191 je Kapitanowi. "
gameforge.subquest_48._130_say = "Jeden ze szpieg\243w Kapitana mieszka pod[ENTER]przykryciem Rybaka w wiosce Joan, w Kr\243lestwie[ENTER]Chunjo. Spr\243buj si\234 z nimi niepostrze\191enie[ENTER]skontaktowa\230. Jak tylko zdob\234dziesz potrzebne[ENTER]informacje, przeka\191 je Kapitanowi. "
gameforge.subquest_48._140_npcChat = "Co ty robisz? "
gameforge.subquest_48._150_say = "Ciii, b\185d\159 cicho! Wystraszysz wszystkie ryby. Co[ENTER]tu tak w og\243le robisz? Jeste\156 tak g\179o\156ny i[ENTER]niezdarny, \191e na pewno nie przyszed\179e\156 tu[ENTER]pow\234dkowa\230. "
gameforge.subquest_48._160_say = "Ach, ju\191 rozumiem. Czeka\179em na Ciebie jaki\156 czas[ENTER]temu, sp\243\159ni\179e\156 si\234. Nie by\179o \179atwo zdoby\230 te[ENTER]informacje i nie zosta\230 z\179apanym. Musisz[ENTER]wiedzie\230, \191e wr\243g czyha wsz\234dzie i tylko czeka,[ENTER]a\191 si\234 ujawnimy. "
gameforge.subquest_48._170_say = "Wi\234c, zr\243bmy to szybko, zanim kto\156 nas zobaczy.[ENTER]Tutaj masz dokumenty. Zanie\156 je natychmiast do[ENTER]Kapitana i tylko do niego. "
gameforge.subquest_48._180_say = "Chwileczk\234! Mam co\156 dla Ciebie. Ma\179y prezent.[ENTER]Teraz ruszaj. Powodzenia. "
gameforge.subquest_48._190_sayReward = "Zaciekawiony otwierasz paczk\234, aby zobaczy\230, co[ENTER]podarowa\179 Ci szpieg. "
gameforge.subquest_48._200_say = "\140wietnie! Pieczona Krasnopi\243rka! Niew\185tpliwie[ENTER]Szpieg zna si\234 znakomicie na rybach. "
gameforge.subquest_48._20_say = "Spocznij \191o\179nierzu! Poniewa\191 s\185siednie Kr\243lestwa[ENTER]s\185 naszymi wrogami, wa\191ne jest, \191eby\156my mieli tam[ENTER]przyjaci\243\179, kt\243rzy b\234d\185 potajemnie zbiera\230 dla[ENTER]nas informacje. Dzi\234ki temu b\234dziemy w stanie[ENTER]przygotowa\230 si\234 do odpierania atak\243w. Niezwykle[ENTER]wa\191ne jest to, aby nie odkryto tych szpieg\243w. "
gameforge.subquest_48._210_sayReward = "Otrzyma\179e\156 3 Pieczone Krasnopi\243rki. "
