gameforge.subquest_48._230_targetVid = "Kapitan "
gameforge.subquest_48._240_say = "Podr\243\191 do Pyungmoo, do Kr\243lestwa Jinno by\179a[ENTER]bardzo niebezpieczna: Otrzyma\179e\156 raport szpiega[ENTER]przebranego za rybaka. A teraz powr\243\230 szybko do[ENTER]swojego Kr\243lestwa i przeka\191 zdobyte informacje[ENTER]Kapitanowi. "
gameforge.subquest_48._250_say = "Podr\243\191 do Yongan, do Kr\243lestwa Shinsoo by\179a[ENTER]bardzo niebezpieczna: Otrzyma\179e\156 raport szpiega[ENTER]przebranego za rybaka. A teraz powr\243\230 szybko do[ENTER]swojego Kr\243lestwa i przeka\191 zdobyte informacje[ENTER]Kapitanowi. "
gameforge.subquest_48._260_say = "Podr\243\191 do Joan, do Kr\243lestwa Chunjo by\179a bardzo[ENTER]niebezpieczna: Otrzyma\179e\156 raport szpiega[ENTER]przebranego za rybaka. A teraz powr\243\230 szybko do[ENTER]swojego Kr\243lestwa i przeka\191 zdobyte informacje[ENTER]Kapitanowi. "
gameforge.subquest_48._270_npcChat = "Misja wykonana! "
gameforge.subquest_48._280_say = "To s\185 te dokumenty? \140wietnie! Dzi\234kuj\234.[ENTER]Teraz wiemy o planach naszego wroga i mo\191emy[ENTER]poczyni\230 odpowiednie przygotowania.[ENTER]Teraz nie musimy si\234 ju\191 wi\234cej obawia\230.[ENTER]Wy\156wiadczy\179e\156 Kr\243lestwu ogromn\185 przys\179ug\234. "
