gameforge.subquest_48._30_say = "Pewnie znasz muzyka o imieniu Yu-Hwan?[ENTER]Jest naszym szpiegiem, pracuje pod przykrywk\185[ENTER]muzyka. Jeden szpieg nie zdzia\179a za wiele,[ENTER]dlatego mamy kilku rozproszonych po ca\179ym[ENTER]\156wiecie. Kilku z nich, to rybacy w pierwszej[ENTER]wiosce. "
gameforge.subquest_48._40_say = "Jako, \191e nie mog\234 si\234 z nimi skontaktowa\230 bez[ENTER]zdemaskowania ich, potrzebuj\234 pomocy od bardzo[ENTER]odwa\191nych \191o\179nierzy takich jak Ty. Czy m\243g\179by\156[ENTER]uda\230 si\234 do rybaka i zdoby\230 dla mnie informacje,[ENTER]kt\243rych pilnie potrzebuj\234, aby m\243c chroni\230 nasze[ENTER]Kr\243lestwo? "
gameforge.subquest_48._50_say = "Czy chcesz zrezygnowa\230 z zadania? "
gameforge.subquest_48._60_say = "Chcesz si\234 najpierw przygotowa\230? Wi\234c wpadnij[ENTER]p\243\159niej. Oczekuj\234 Ci\234. Ale prosz\234, \156piesz si\234, to[ENTER]bardzo wa\191ne! Potrzebuj\234 tego raportu! "
gameforge.subquest_48._70_say = "Co z Tob\185? Ostatnim razem wykona\179e\156 \156wietn\185[ENTER]robot\234 dla nas! Nie mog\234 uwierzy\230, \191e ot tak[ENTER]zostawiasz kr\243lestwo w potrzebie. Ale to Tw\243j[ENTER]wyb\243r, nic nie mo\191emy zrobi\230... Do zobaczenia. "
gameforge.subquest_48._80_say = "\140wietnie! Wiedzia\179em, \191e mo\191na na tobie polega\230.[ENTER]Powodzenia i uwa\191aj na siebie. "
