gameforge.subquest_49._130_targetVid = "Spytaj Harang "
gameforge.subquest_49._140_npcChat = "Czym jest Bingsu? "
gameforge.subquest_49._150_say = "A to Taurean! Nie wie co to jest Bingsu, ale[ENTER]twierdzi, \191e wie wszystko. Jak kto\156 mo\191e nie zna\230[ENTER]takiego dania? Co za g\179uptas. Ty tak\191e nie masz[ENTER]poj\234cia czym jest Bingsu? Najlepiej jakby\156 uda\179[ENTER]si\234 do Octavio, kt\243ry mieszka w nast\234pnej wiosce.[ENTER]Jest znanym kucharzem i zna wszystkie dobre[ENTER]przepisy. Zrobi\179 pewnego razu dla mnie Bingsu,[ENTER]hmm... On Ci udowodni, \191e mam racj\234! "
gameforge.subquest_49._160_makequestbutton = "Id\159 do Octavio "
gameforge.subquest_49._170_say = "Taurean chce koniecznie si\234 dowiedzie\230, czym jest[ENTER]Bingsu. Udaj si\234 do w\179a\156ciciela restauracji[ENTER]Octavio. On z pewno\156ci\185 b\234dzie w stanie Ci pom\243c. "
gameforge.subquest_49._180_npcChat = "Wiesz, czy jest Bingsu? "
gameforge.subquest_49._190_say = "Bingsu? Oczywi\156cie \191e wiem, co to jest. Ka\191dy[ENTER]dobry kucharz wie, jak przyrz\185dzi\230 Bingsu! Na[ENTER]pocz\185tek potrzebny jest na drobno zmielony l\243d.[ENTER]Do tego dochodzi cukier, cienko poci\234te ciastko[ENTER]ry\191owe oraz \156wie\191e owoce dla ozdoby. "
gameforge.subquest_49._200_say = "Dlaczego si\234 pytasz? Poniewa\191 Taurean k\179\243ci si\234 z[ENTER]Harang? To nic nowego. Ale Harang ma racj\234.[ENTER]Szczeg\243lnie w gor\185ce lata Bingsu stanowi bardzo[ENTER]popularne danie.[ENTER]Taurean to dobry ch\179opak, nawet je\156li czasami[ENTER]zdaje si\234 nieco ograniczony. Je\156li za\179atwisz mi[ENTER]sk\179adniki, mog\234 przyrz\185dzi\230 Ci Bingsu. "
gameforge.subquest_49._20_npcChat = "Bingsu? "
gameforge.subquest_49._210_say = "Chcia\179bym sprawi\230 Taurean przyjemno\156\230 i[ENTER]pocz\234stowa\230 go Bingsu. Jak my\156lisz? M\243g\179by\156 mi[ENTER]przynie\156\230 nieco Lodu z G\243ry Sohan? "
gameforge.subquest_49._220_say = "Czy chcesz na zawsze zrezygnowa\230 z misji? "
gameforge.subquest_49._230_say = "Nie lubisz lod\243w? A mo\191e zjad\179e\156 ich za du\191o? To[ENTER]jest przys\179uga dla Taurean, wi\234c prosz\234 przemy\156l[ENTER]to jeszcze raz. "
gameforge.subquest_49._240_say = "Szkoda. Taurean b\234dzie bardzo rozczarowany. Na[ENTER]razie. "
gameforge.subquest_49._250_say = "Wspaniale. Potrzebuj\234 Kawa\179 Lodu z Zaczarowanego[ENTER]Lodu na G\243rze Sohan. Przynie\156 mi 50 sztuk a[ENTER]przyrz\185dz\234 smaczne Bingsu. "
gameforge.subquest_49._260_targetVid = "Id\159 do Octavio "
gameforge.subquest_49._270_say = "%s[ENTER]Mam Kawa\179 Lodu na Bingsu dla Taurean.[ENTER]Zanie\156 go do Octavio. "
gameforge.subquest_49._275_say = "Otrzymano Kawa\179 Lodu "
gameforge.subquest_49._280_say = "Octavio przyrz\185dzi bingsu dla Taurean, potrzebuj\234[ENTER]do tego jednak lodu. Zabij Zaczarowany L\243d na[ENTER]G\243rze Sohan i uzbieraj 50 kawa\179\243w lodu, po czym[ENTER]zanie\156 je Octavio. "
gameforge.subquest_49._285_say = "Poszukiwania Lodu "
gameforge.subquest_49._290_npcChat = "Trzymaj, przynios\179em Kawa\179ki Lodu. "
gameforge.subquest_49._300_say = "Ach, wspaniale! Najtrudniejszy etap przyrz\185dzenia[ENTER]Bingsu mamy wi\234c za sob\185. Teraz dodam tylko[ENTER]jeszcze troch\234 cukru... oraz owoc\243w... i prosz\234[ENTER]bardzo! L\243d dla Taurean. Zanie\156 mu go od razu a[ENTER]wkr\243tce zapomni o swoim gniewie. "
gameforge.subquest_49._30_sayTitle = "Taurean: "
gameforge.subquest_49._310_say = "Bardzo mi przykro, ale jest to za ma\179o. Musisz[ENTER]przynie\156\230 mi wi\234cej, w przeciwnym razie b\234dzie z[ENTER]tego jedynie malutka porcja! "
gameforge.subquest_49._320_select = "Spr\243buj ponownie... "
gameforge.subquest_49._330_say = "Wiem, \191e droga daleka a potwory niebezpieczne.[ENTER]Je\156li nie czujesz si\234 na si\179ach, to trudno. Na[ENTER]razie. "
gameforge.subquest_49._340_say = "Mo\191esz oczywi\156cie spr\243bowa\230 ponownie. Z twoj\185[ENTER]odwag\185 i wytrzyma\179o\156ci\185 na pewno w ko\241cu[ENTER]osi\185gniesz sukces! "
gameforge.subquest_49._350_targetVid = "Bingsu? "
gameforge.subquest_49._360_say = "Uda\179o si\234! Octavio przyrz\185dzi\179 Bingsu z Lodu z[ENTER]G\243ry Sohan. Teraz czym pr\234dzej do Taurean, zanim[ENTER]Bingsu si\234 roztopi. "
gameforge.subquest_49._370_npcChat = "Tutaj! Bingsu! "
gameforge.subquest_49._380_say = "To jest Bingsu? Smakuje naprawd\234 znakomicie.[ENTER]S\179odkie i ch\179odne. Jeszcze nigdy nie jad\179em[ENTER]czego\156 takiego, dzi\234kuj\234! Harang mia\179a zatem[ENTER]racj\234. B\234d\234 musia\179 j\185 przeprosi\230... "
gameforge.subquest_49._390_sayReward = "Otrzyma\179e\156 6.000.000 Punkt\243w Do\156wiadczenia. "
gameforge.subquest_49._400_sayReward = "Otrzyma\179e\156 70.000 Yang. "
gameforge.subquest_49._40_say = "Dzisiaj pok\179\243ci\179em si\234 z Harang. M\243g\179bym j\185[ENTER]normalnie...[ENTER]Twierdzi, \191e istnieje bardzo smaczna potrawa,[ENTER]przyrz\185dzana z na drobno kruszonego Lodu. Nazywa[ENTER]si\234 Bingsu. "
gameforge.subquest_49._410_sayReward = "Otrzyma\179e\156 Zw\243j Wojny. "
gameforge.subquest_49._420_say = "Bingsu dla mnie, pami\234tasz? "
gameforge.subquest_49._430_say = "Ojej, zupe\179nie o tym zapomnia\179em! Hmm, mam nadal[ENTER]pr\243bowa\230 czy mo\191e sobie darowa\230? "
gameforge.subquest_49._440_select = "Chc\234 kontynuowa\230. "
gameforge.subquest_49._450_select = "Poddaj\234 si\234. "
gameforge.subquest_49._460_say = "Nie mog\234 tego zrobi\230, przykro mi. "
gameforge.subquest_49._50_say = "Takie co\156 jest zazwyczaj mo\191liwe jedynie podczas[ENTER]zimny, gdy jest bardzo zimno. A ona ca\179y czas[ENTER]twierdzi, \191e to jest mo\191liwe. M\243g\179by\156 si\234[ENTER]dowiedzie\230, czy mo\191na przyrz\185dzi\230 Bingsu tak\191e w[ENTER]lecie? Je\156li takie co\156 w og\243le istnieje... "
gameforge.subquest_49._60_say = "To Bingsu jest na pewno pyszne! Jeste\156 pewien, \191e[ENTER]nigdy nie b\234dziesz chcia\179 mi pom\243c w jego[ENTER]przyrz\185dzeniu? "
gameforge.subquest_49._70_say = "Je\156li b\234dziesz chcia\179 to zrobi\230 p\243\159niej, daj mi[ENTER]zna\230. "
gameforge.subquest_49._80_say = "Tak bardzo chcia\179bym kiedy\156 spr\243bowa\230 tego[ENTER]Bingsu... ale masz racj\234. Harang pewnie chcia\179a[ENTER]tylko si\234 pochwali\230, a tak naprawd\234 nie ma[ENTER]\191adnego Bingsu! Bywaj. "
gameforge.subquest_49._90_say = "Dzi\234kuj\234, \191e mi pomagasz. Daj mi zna\230, gdy si\234[ENTER]czego\156 dowiesz. B\234d\234 m\243g\179 wtedy powiedzie\230[ENTER]Harang, co o tym wszystkim my\156l\234! "
