gameforge.training_mount = {}
gameforge.training_mount._01_say = "Bardzo mi przykro ale nie posiadasz jeszcze[ENTER]wystarczaj\185cego do\156wiadczenia, aby ulepszy\230[ENTER]swojego wierzchowca. Potrzebujesz co najmniej[ENTER]licencji konia bojowego. "
gameforge.training_mount._02_say = "Bardzo mi przykro ale bez wymaganych dokument\243w[ENTER]nic tutaj nie zdzia\179am. A jak jeszcze raz[ENTER]spr\243bujesz zrobi\230 mnie w konia, to Ci si\234 za to[ENTER]\179adnie odwdzi\234cz\234... "
gameforge.training_mount._03_say = "A gdzie jest twoja piecz\234\230 wierzchowca? Bez niej[ENTER]nie mog\234 ulepszy\230 wierzchowca. Zerknij u do\179u na[ENTER]symbol obracaj\185cej si\234 monety. Znajdziesz tam[ENTER]\156wiadectwa, kt\243re mo\191esz wymieni\230 u mnie na[ENTER]odpowiednie piecz\234cie. "
gameforge.training_mount._04_say = "Chc\234 dosi\185\156\230 nowego wierzchowca! "
gameforge.training_mount._05_say = "Hej! Siedzisz na koniu? Nies\179ychane! Przecie\191[ENTER]mo\191emy ju\191 oswaja\230 dzikie zwierz\234ta! "
gameforge.training_mount._06_say = "Aby trenowa\230 dzikie zwierz\234ta do walki, musisz[ENTER]mie\230 spore do\156wiadczenie w ich uje\191d\191aniu. Poza[ENTER]tym potrzebujesz nast\234puj\185ce przedmioty: Zw\243j[ENTER]Ewolucji, aby ulepszy\230 swojego wierzchowca do[ENTER]poziomu Dzikiego Wierzchowca, oraz Zw\243j Mutacji,[ENTER]aby uczyni\230 z niego Dzielnego Wierzchowca. "
gameforge.training_mount._07_say = "Je\156li b\234dziesz mie\230 jeszcze jakie\156 pytania, to[ENTER]mo\191esz w ka\191dej chwili mnie odwiedzi\230. Pomog\234 ci[ENTER]najlepiej, jak potrafi\234. "
gameforge.training_mount._08_say = "Chc\234 ulepszy\230 mojego wierzchowca! "
gameforge.training_mount._09_say = "A wi\234c chcesz ulepszy\230 swojego wierzchowca? A[ENTER]wiesz w og\243le, jak to uczyni\230? No dobra, wszystko[ENTER]ci wyt\179umacz\234. "
gameforge.training_mount._10_say = "Aby ulepszy\230 swojego wierzchowca do poziomu[ENTER]Dzikiego Wierzchowca, musisz zdoby\230 Zw\243j[ENTER]Ewolucji. Gdy znajdziesz Zw\243j Mutacji, mo\191esz[ENTER]ulepszy\230 swojego pupila do poziomu Dzielnego[ENTER]Wierzchowca. Fama niesie, \191e zwoje te znajduj\185[ENTER]si\234 w dalekiej krainie, kt\243r\185 zamieszkuj\185 gro\159ne[ENTER]giganty. "
gameforge.training_mount._11_say = "Przynie\156 mi jeden z tych zwoj\243w, a ja ulepsz\234[ENTER]twojego wierzchowca. No chyba, \191e ju\191 je masz? "
gameforge.training_mount._12_say = "Tak, chc\234 ulepszy\230 swojego wierzchowca! "
gameforge.training_mount._13_say = "Nie, nie teraz. "
gameforge.training_mount._14_say = "Aaa, widz\234, \191e posiadasz ju\191 jeden zw\243j. A kt\243ry[ENTER]dok\179adnie? Za pomoc\185 Zwoju Ewolucji mo\191esz[ENTER]zahartowa\230 swojego m\179odzika do boju. Za pomoc\185[ENTER]Zwoju Mutacji mo\191esz go ulepszy\230 do poziomu[ENTER]Dzielnego Wierzchowca. "
gameforge.training_mount._15_2_say = "Posiadam Zw\243j Mutacji. "
gameforge.training_mount._15_say = "Posiadam Zw\243j Ewolucji. "
gameforge.training_mount._16_say = "Nie posiadam \191adnego zwoju. "
gameforge.training_mount._17_say = "Popatrz, popatrz... Zw\243j Ewolucji! W takim razie[ENTER]poka\191 mi jeszcze swoj\185 Piecz\234\230 Wierzchowca.[ENTER]Niejeden pr\243bowa\179 wcisn\185\230 mi jak\185\156 marn\185[ENTER]podr\243bk\234! Musz\234 wi\234c sprawdzi\230 jej autentyczno\156\230.[ENTER]Poka\191 no t\234 piecz\234\230. (Przeci\185gnij piecz\234\230 na[ENTER]ch\179opca stajennego.) "
gameforge.training_mount._18_say = "Zw\243j Mutacji! Znam ten przedmiot wy\179\185cznie z[ENTER]opowiada\241. Jeszcze nigdy nie mia\179em tego cude\241ka[ENTER]w d\179oniach. A teraz poka\191 mi jeszcze Piecz\234\230[ENTER]Wierzchowca, musz\234 sprawdzi\230 jej autentyczno\156\230.[ENTER](Przeci\185gnij piecz\234\230 na ch\179opca stajennego.) "
gameforge.training_mount._19_say = "Gdy ju\191 znajdziesz piecz\234\230, odwied\159 mnie[ENTER]ponownie, a ja wymieni\234 j\185 na pot\234\191niejsz\185[ENTER]piecz\234\230. "
gameforge.training_mount._20_say = "Twoja Piecz\234\230 Wierzchowca ma ju\191 swoje lata...[ENTER]zaczekaj, zaraz dam ci now\185. No, prosz\234! Teraz[ENTER]mo\191esz przywo\179a\230 Dzikiego Wierzchowca. Odwied\159[ENTER]mnie ponownie, gdy znajdziesz Zw\243j Mutacji, a[ENTER]zmajstruj\234 Ci jeszcze pot\234\191niejsz\185 piecz\234\230. "
gameforge.training_mount._21_say = "To jest Piecz\234\230 Wierzchowca, kt\243r\185 da\179em ci ju\191[ENTER]pewien czas temu. Jest ju\191 jednak nieco zu\191yta.[ENTER]Daj mi j\185, a dostaniesz w zamian pot\234\191niejsz\185[ENTER]Piecz\234\230 Wierzchowca! "
gameforge.training_mount._22_say = "Za pomoc\185 tej piecz\234ci mo\191esz przywo\179a\230 swojego[ENTER]nowego wierzchowca. Jest to bardzo pot\234\191ny[ENTER]przedmiot! "
gameforge.training_mount._23_say = "Mog\234 u\191ywa\230 umiej\234tno\156ci konnych? "
gameforge.training_mount._24_say = "Chcesz u\191ywa\230 umiej\234tno\156ci konnych? No, no, no...[ENTER]masz wysokie wymagania! No c\243\191, jest to mo\191liwe,[ENTER]ale musisz przestrzega\230 paru wa\191nych zasad. "
gameforge.training_mount._25_say = "Po pierwsze musisz posiada\230 spore do\156wiadczenie w[ENTER]uje\191d\191aniu wierzchowc\243w, w przeciwnym razie[ENTER]mo\191esz si\234 nie\159le poturbowa\230. Poza tym tw\243j[ENTER]wierzchowiec musi by\230 zdatny do boju, bo tylko[ENTER]wtedy jest w stanie zastosowa\230 umiej\234tno\156ci[ENTER]konne. "
gameforge.training_mount._26_say = "Czy tw\243j wierzchowiec jest w stanie przyswoi\230[ENTER]sobie umiej\234tno\156ci konne? W przeciwnym razie nie[ENTER]mog\234 zezwoli\230 na trening. Co chcesz uczyni\230? "
gameforge.training_mount._27_say = "Rozumiem... musz\234 jeszcze oceni\230 twoj\185 si\179\234 i[ENTER]twoje umiej\234tno\156ci je\159dzieckie. Zaczekaj[ENTER]chwil\234... "
gameforge.training_mount._28_say = "Hmm... mocny kr\234gos\179up, szerokie bary i solidne[ENTER]umiej\234tno\156ci je\159dzieckie... a na dodatek tw\243j[ENTER]wierzchowiec wydaje si\234 by\230 dosy\230 skory do walki.[ENTER]Mo\191esz zatem u\191ywa\230 umiej\234tno\156ci konnych. "
gameforge.training_mount._29_say = "Teraz tw\243j wierzchowiec mo\191e stosowa\230[ENTER]umiej\234tno\156ci konne. Je\156li nab\234dziesz nowego[ENTER]wierzchowca, b\234dzie on musia\179 zacz\185\230 nauk\234 od[ENTER]nowa. Wtedy po prostu odwied\159 mnie ponownie. "
gameforge.training_mount._30_say = "Co to ma by\230? Przecie\191 wiesz, \191e jest to zbyt[ENTER]niebezpieczne, je\156li nie posiadasz odpowiedniego[ENTER]do\156wiadczenia. Wr\243\230 do mnie, gdy nieco si\234[ENTER]podszkolisz. "
gameforge.training_mount._31_say = "Obawiam si\234, \191e tw\243j wierzchowiec nie jest[ENTER]jeszcze gotowy. Wr\243\230 do mnie, gdy b\234dzie ju\191[ENTER]nieco bardziej zaprawiony w boju. "
gameforge.training_mount._32_say = "Zsi\185d\159 prosz\234 ze swojego wierzchowca, gdy ze mn\185[ENTER]rozmawiasz. Kark mnie boli od ci\185g\179ego[ENTER]spogl\185dania w g\243r\234. "
gameforge.training_mount._33_say = "Nie posiadasz odpowiedniej licencji je\159dzieckiej,[ENTER]aby ulepszy\230 swojego wierzchowca. Potrzebujesz co[ENTER]najmniej licencji Konia Bojowego, aby oswoi\230[ENTER]Dzikiego Wierzchowca. Aby oswoi\230 Dzielnego[ENTER]Wierzchowca, potrzebujesz z kolei licencj\234 Konia[ENTER]Wojskowego. "
gameforge.training_mount._34_say = "Widz\234, \191e posiadasz Mega Przek\185sk\234. Te[ENTER]niesamowite zio\179o lecznicze zawiera w sobie[ENTER]czyst\185 energi\234, kt\243ra przed\179u\191a \191ycie Twojego[ENTER]Mega Wierzchowca o par\234 dni. Co mog\234 dla Ciebie[ENTER]zrobi\230? Chcesz przed\179u\191y\230 \191ycie swojego Mega[ENTER]Wierzchowca czy chcesz go mo\191e ulepszy\230? "
gameforge.training_mount._35_select_1 = "Przed\179u\191 "
gameforge.training_mount._35_select_2 = "Ulepsz "
