gameforge.training_mount._37_say = "Niestety nie posiadasz odpowiedniej Mega[ENTER]Przek\185ski na wybrany przez Ciebie czas[ENTER]przed\179u\191enia. Znajdziesz j\185 za symbole[ENTER]obracaj\185cej si\234 monety. "
gameforge.training_mount._38_say = "Zw\243j Mutacji zawiera niesamowit\185 moc! Mo\191e[ENTER]przed\179u\191y\230 \191ycie Twojego wiernego wierzchowca[ENTER]nawet o cztery dni. Pr\243ba przed\179u\191enia kosztuje[ENTER]200.000 Yang. Tw\243j wierzchowiec musi by\230 jednak[ENTER]ju\191 bardzo wycie\241czony i posiada\230 mniej ni\191 jeden[ENTER]dzie\241 \191ycia. Oczywi\156cie potrzebujesz r\243wnie\191[ENTER]odrobin\234 szcz\234\156cia! Je\156li przed\179u\191enie si\234 nie[ENTER]powiedzie, mo\191e to jednak naprawi\230 Mega[ENTER]Przek\185sk\185. Znajdziesz j\185 za symbolem obracaj\185cej[ENTER]si\234 monety. "
gameforge.training_mount._39_say = "Tw\243j Mega Wierzchowiec jest jeszcze zbyt silny.[ENTER]Zw\243j Mutacji na nic si\234 tutaj nie zda. Wr\243\230, gdy[ENTER]pozostanie mu mniej ni\191 jeden dzie\241 \191ycia. "
